-- 北帝玄天大帝灵签 D1 seed data (51签)
-- Source: https://github.com/LeoonLiang/xuanwu-fozu-lingqian

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  1,
  '宋太祖登基',
  '吉胜无疑之兆',
  '上上之卦',
  '申猴',
  '公元960年，后周大将赵匡胤黄袍加身，起陈桥兵变，废后周帝，改国号宋，定都东京，继而结束五代十国割据局面，一统江山。',
  '一箭射红心，人人说好音；日长鸡唱午，真火炼真金。',
  '飞龙变化',
  '{"签号":"第一签","签名":"宋太祖登基","签文类型":"吉胜无疑之兆","卦象":"上上之卦","生肖":"申猴","签文简介":{"戏文":"公元960年，后周大将赵匡胤黄袍加身，起陈桥兵变，废后周帝，改国号宋，定都东京，继而结束五代十国割据局面，一统江山。","诗曰":"一箭射红心，人人说好音；日长鸡唱午，真火炼真金。","内兆":"飞龙变化"},"家宅运势":{"签文":"三阳交泰转洪钓，瑞气盈门百事新。岁秽时丰财禄旺，又添人口许相亲。","解曰":"吉宅人口之卦可得喜气，但防夏月疾难是非涉财火厄，皆因厝前受煞冲伤，吓佛祖令旗安门上祭化又嫌水道不美，有利宜修整，则居住平安。"},"岁君签":{"总诗":"飞龙变化喜逢时，此日升腾果遂期。某望求财皆得利，求官进职更无疑。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，八字成格旺益上人并茂，夏月小疾无妨，吉星守命平安。","女":"小女根基足养，有旺益上人并茂，虽有小疾无妨，吉星守命出入平安。"},{"年龄":"4-7岁","男":"小儿运限叶吉，生性天真活泼，夏月宜知避暑，小皮疾无妨，吉星守命平安。","女":"小女运限顺遂，活泼伶俐，旺益上人，夏月小疾无妨，吉星守命平安。"},{"年龄":"8-12岁","男":"小儿今年交上美运，伶俐天真，可入学校读书，定卜进步。","女":"小女现年交上美运，有旺益上人并茂，吉星守命平安。"},{"年龄":"13-15岁","男":"童造上运亨通聪明开窍，培养入学读书，定卜进步。","女":"小女之卦运度顺遂，各事伶俐精通旺益上人。"},{"年龄":"16-17岁","男":"祥造步运亨通，如飞龙变化，做事通能特达，宜多学文化，远景无限。","女":"玉造现年交上美运，如飞龙变化，八字清秀技巧助益家庭。"},{"年龄":"18-29岁","男":"英造步运亨通，如飞龙变化，奇才特达，年轻有为，有贵人辅助。","女":"玉造行运交泰，如飞龙变化，各事贤玉，多学艺业。"},{"年龄":"30-55岁","男":"乾造步运亨通，如飞龙变化，做事老练，有贵人辅助。","女":"坤造行运交泰，如飞龙变化，娴熟智慧。"},{"年龄":"56-69岁","男":"台造步运亨通，如飞龙变化，为人老练忠诚。","女":"坤造行运交泰，如飞龙变化，底子有旺宜家庭。"},{"年龄":"70岁以上","男":"福造老运虽绵长，但卦旺须防跌伤之厄。","女":"妇造老运旺益子孙，但防暗疾风气。"}]},"生意":{"生意":"春月生意欲失财，夏月财利丝丝来。待到秋冬两季节，壮胆经营利路开。","生意解曰":"生意初时有阻，交易宜正直，刻苦经营，候五、八、十一月返运，可得厚财利。","开铺":"开铺签文叶吉，各事宜小心，可以成功。","合伙":"多人多福，各人同心协力经营，可得厚财利。","置货":"置货须立胆智，初时价败，但见机可得厚利。"},"出外":{"出外":"初有阻隔，但三、五、八月往外，有贵人扶助，名利双全。"},"谋望求财":{"谋望":"冲霄志气上心头，君子安宁久困穷。岁稔时丰财禄旺，万人头上逞英雄。","谋望解曰":"谋事初有阻隔，但刻苦谋之到底可成。","求财":"正财初有波折，三、五、八月返运可得大利，偏财须大胆谨慎。"},"学艺功名":{"学艺":"签文叶吉，专心学习，有贵人扶助，定卜成功。","功名":"功名多波折，但最终可成功。"},"行舟六畜":{"行舟":"行舟顺风，秋后可得大利。","六畜":"饲养六畜能平安。","猪羊":"猪羊养殖顺利，可得厚利。","草龙":"水草调和，养之兴旺。","三鸟":"精心饲养，有利可收。","田蚕":"四季雨水大吉。"},"移徙":{"移徙":"移徙吉，宜请华光爷镇宅。"},"行人":{"解曰":"行人在外有贵人扶助，五、八、十一月有消息。","签文":"卦得飞龙莫问亲，千山万水受艰辛。"},"婚姻":{"解曰":"婚姻天配良缘，情投意合，白头偕老。","签文":"世间天理定婚姻，天配良缘。"},"官讼":{"解曰":"宜和不宜告，赢官司可能输财。","签文":"未发文书不要陈。"},"失物":{"解曰":"向南方向寻找，定有音讯。","签文":"偶失货物莫怨天。"},"占病":{"解曰":"老年多风湿气咳，青壮年多肾疾焦躁。","签文":"焚香祷告，修德行善。"},"其他":{"灶君":"灶位分金合课，但需避窗煞。","阳基":"阳宅财丁可旺，但青龙方向有煞。","六甲":"六甲生男，合家欢喜。","子息":"子息先花后果。","祖山":"祖山气脉足，修整可旺财丁。","青草":"墓地气脉足旺，但初时有阻。"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  2,
  '薛仁贵困白虎关',
  '遁而复吉之兆',
  '平安之卦',
  '未羊',
  '薛仁贵回窑。误射丁山后薛攻白虎关，被杨凡诱上白虎山，撒豆为兵困之。薛饥饿化白虎觅食，复为从朱雀关赶来救父之薛丁山射杀。',
  '入户须防狗，登山遇虎狼。西施身不洁，人被四围藏。',
  '白虎星占度',
  '{"签号":"第二签","签名":"薛仁贵困白虎关","签文类型":"遁而复吉之兆","卦象":"平安之卦","生肖":"未羊","签文简介":{"戏文":"薛仁贵回窑。误射丁山后薛攻白虎关，被杨凡诱上白虎山，撒豆为兵困之。薛饥饿化白虎觅食，复为从朱雀关赶来救父之薛丁山射杀。","诗曰":"入户须防狗，登山遇虎狼。西施身不洁，人被四围藏。","内兆":"白虎星占度"},"家宅运势":{"签文":"久淹漏屋欲更新，怎奈伊家欠福神。不但忧惊并怪梦，更添人口及阴人。","解曰":"吉宅人口有喜可得，但防四，七，九月灾疾是非失财，吓佛祖保佑平安，外嫌祖山不顺，内是灶君不美，有利宜修整，先人伯叔祖香灯查明，奉拜。"},"岁君签":{"总诗":"虎出山林惊动民，乡民见了却忧疑。虽然不是伤人物，亦是虚惊事可知。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗虽足，但恐正、四、九月灾难波阻，六甲妇勿近抱，吓伯公运返平安。","女":"小女根基浅薄，虽有旺益上人，但恐正、四、九月小疾波阻，吓伯公化吉平安。"},{"年龄":"4-7岁","男":"小儿现年运限未美，虽天真，但恐正、四、九月小疾多事，吓伯公化吉平安。","女":"小女运度未美，但防正、四、九月灾疾之厄，宜守旧，吓伯公化吉出入平安。"},{"年龄":"8-12岁","男":"小儿之卦时运未美遂，正、四、九月恐有波阻，夜勿外出，吓月娘化吉出入平安。","女":"小女现年运度未美，虽有旺益上人，但恐正、四、九月灾难之厄，吓月娘化吉平安。"},{"年龄":"13-15岁","男":"童造现运未美，虽聪明，但正、四、九月恐皮肤小疾，吓伯公化吉平安。","女":"小女时令未美，但嫌执僻，正、四、九月惟防皮肤小疾，宜守旧，吓伯公化吉出入平安。"},{"年龄":"16-17岁","男":"祥造现年时令未美，白虎星占度，但恐正、四、九月多生小疾，不可自执己僻，吓月娘化吉平安。","女":"玉造现年运度美中不足，白虎星占度，正、四、九月夜时东北方勿往，守旧，吓天地保平安。"},{"年龄":"18-29岁","男":"英造步运未美，虽通能，但嫌内心迫什，恐正、四、九月小人口舌，凡事戒忍，吓伯公化吉平安。","女":"玉造行运美中不足，惟恐灾难之厄，正、四、九月夜时单人勿独行，吓伯公化吉交秋转运安康。"},{"年龄":"30-55岁","男":"乾造步运不美，签文白虎星占度，内心操迫，正、四、九月小人口舌祸非，戒忍性情，吓天地平安。","女":"坤造行运美中不足，但防正、四九月暗疾口舌不测之祸，吞忍性情，宜吓天地平安。"},{"年龄":"56-69岁","男":"台造步运不佳，人老心迫，但防正、四、九月小人祸非，平地风波闲事切勿近理，底子平安。","女":"坤造步运未美，虽有旺益家庭，但防暗疾口舌，凡事吞忍，正、四、九月守旧，底子平安。"},{"年龄":"70岁以上","男":"福造老运不旺，人老心直，但防灾难虚惊，忌看病人，正、四、九月守旧，底子大造平安。","女":"妇造老运不旺，虽有旺益子孙，但恐暗疾虚惊，四、九月守旧，上落小心，底子平安。"}]},"生意":{"生意":"白虎凶星当头开，要防阻失惊险来,正材可取偏财失，求神保佑能得财。","生意解曰":"白虎星当头，恐防小人波累，三、六、九月阻隔，宜细心防避，从正道，财得可安。","开铺":"卜开铺之卦，应防小人累劫、惊阻，凡事宜小心注意，宜请佛祖令旗安门上化吉保平安。","合伙":"卜合伙之卦，有利可得，但不宜贪心、偏心，应忍口舌，则免亏本散伙。","置货":"卜置货须防口舌是非，忍则吉，货物勿停留，宜现买现卖，可得厚财利。"},"出外":{"出外":"出外之卦，白虎当头，恐有小人波阻，凡事宜从正道，吓赵元帅爷化吉保安。"},"谋望求财":{"谋望":"不凭天理强支持,妄作胡为岂可基,君子虽贪终有道,莫教失计被人欺。","谋望解曰":"混杂谋事，不凭天理，定生是非口舌，若要成事宜从正道，做事免生祸非。","求财":"正财库取利，恐防小人耗动，宜从正道经营，勤谨工作，切勿与人代担银项，则财得之安稳，偏财不可取，取之危险。"},"学艺功名":{"学艺":"卜学技艺之卦，因君时运未至，心欲学习，但恐不成功，候以后时运交至，学之可成也。","功名":"功名文武皆不得，肖猴者勿进科场有失。"},"行舟六畜":{"行舟":"行舟不利，若行之恐失也，宜守旧待时。","六畜":"饲养六畜有不安，不可多养费时间。若要多养也少利，守旧经营财利全。","猪羊":"饲养猪羊，要防四、七、九月阻隔，勿贪养多只，少利也，宜吓伯公保佑平安。","草龙":"饲养草龙，水草调和，但防四、七、九月教疾等阻隔，宜吓伯公保平安。","三鸟":"饲养三鸟，初阻失，后虽有利，但必用心智养之，防歹人祸害，吓神保平安。","田蚕":"早冬中平，晚冬大吉，四季雨水大顺。"},"移徙":{"移徙":"迁徙生祸，乱邦不入，乱邦不可居。"},"行人":{"解曰":"行人在外有小人阻隔，信息稀断，财利有虚无实，候五、十月有才信回家。","签文":"雁杳鱼沉讯息稀，空劳望断白云迷。相逢若遇寅辰日，鹊噪檐前犬马啼。"},"婚姻":{"解曰":"姻缘有阻隔，对方虽为美丽，但非是百年姻缘，不可强行成婚，恐生祸非。","签文":"自观相见好容仪，谁料中间一点非。不是婚姻休作对，何如撒手且由伊。"},"官讼":{"解曰":"官讼告之失理，不可告，劝君不要理人之闲事，凡事宜忍耐，则免生祸害。","签文":"只好安居守运时，莫经官府受鞭笞。劝君休管人闲事，惹得愁来悔后迟。"},"失物":{"解曰":"只是因为不慎，使物资失却，若要导得失物，候明月寅申，有人说去处，可寻见。","签文":"只为当初不小心，资财已失复何寻。直教月尽寅申日，才有傍人说信音。"},"占病":{"解曰":"老年肖猴者恐年命冲克，宜办寿衣，余者阴邪鬼缠身，宜向西北方改愿祭送。","签文":"闹中得病静中安，莫作寻常一例看。有愿在心宜早赛，免教积热变脾寒。"},"其他":{"灶君":"卜此灶位不美，但嫌灶迹秽气，灶前阴湿不净。","阳基":"卜老阳宅可居住，但防口舌，宜忍则吉，到底可得大利也，起造新阳宅恐有祸变，宜守旧待时。","六甲":"卜此胎六甲生女平安，生男恐有不测。须移房或拜契显神明保根基足养。","子息":"卜子息之卦，起初有花无果得，若存心不善，难望孩儿送终，宜修善作福，后自有子。","祖山":"卜贵祖佳城结穴，气脉足旺文雅，但嫌龙运不旺，坐向有利修整并掩祭寅戌两方煞气之后，财丁兴旺平安。","青草":"此地有结穴，气脉足旺文雅，但嫌旁边古穴阴怨，切须埋妥，葬时应修整掩祭寅戌两方风煞，则子孙财丁兴旺也。"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  3,
  '孟日红寻夫',
  '灾去终吉之兆',
  '大吉之卦',
  '午马',
  '孟日红之夫上京赴试，音讯杳然。家贫，孟割股以喂家姑。姑亡，孟上京寻夫，玉帝命力士移去挡山大路。孟赴京，寻夫不遇，充男入试，中状元。',
  '时凶遇太平，门中井水清。昌荣如日月，夜郎遇文星。',
  '如鱼化龙',
  '{"签号":"第三签","签名":"孟日红寻夫","签文类型":"灾去终吉之兆","卦象":"大吉之卦","生肖":"午马","签文简介":{"戏文":"孟日红之夫上京赴试，音讯杳然。家贫，孟割股以喂家姑。姑亡，孟上京寻夫，玉帝命力士移去挡山大路。孟赴京，寻夫不遇，充男入试，中状元。","诗曰":"时凶遇太平，门中井水清。昌荣如日月，夜郎遇文星。","内兆":"如鱼化龙"},"家宅运势":{"签文":"莫忧家宅久淹连，天理于人岂有偏，若是从今更改过，管教财谷胜当年。","解曰":"吉宅人口之卦可得喜气，但数年以来财丁阻失，是门庭水道以及灶君不美，宜修通水道，使之合课做过新灶君，则居住财丁昌盛也。"},"岁君签":{"总诗":"否极从今喜泰来，龙泉磨拂旧尘埃，暮然守旧无他事，闭门深居也获财。","年龄运势":[{"年龄":"1-3岁","男":"小儿根苗足养八字清秀，有旺益上人并茂，夏月小疾无妨，吉星守度平安。","女":"小女之卦，根苗足旺，利益上人并茂，夏月虽有小疾无妨，吉星守度出入平安。"},{"年龄":"4-7岁","男":"小儿之卦时令亨通，天真活泼，有旺益上人并茂，夏月小疾无妨，吉星守命平安。","女":"小女之卦运限顺遂，各事伶俐，有旺益上人并茂，夏月虽有小疾无妨，吉星守度平安。"},{"年龄":"8-12岁","男":"小童之卦，现年运度亨通，各事聪明开窍，宜入学校读书，定卜进步，夏月小疾无妨，出入平安。","女":"小女现年交上美运，有旺益上人并茂，夏月虽有小疾无妨，吉星守命平安。"},{"年龄":"13-15岁","男":"童造今年交上运，否极泰来，各事聪明开窍，宜入学校读书，定卜前途进步出入平安。","女":"玉造现年交上美运，各事伶俐精通，旺益上人并茂，夏月虽有小疾无妨，出入平安。"},{"年龄":"16-17岁","男":"祥造步运亨通，如脱衣换锦，各事通能，夏月虽有小疾无妨，有贵人辅助出入平安。","女":"玉造现年交上美运，否极泰来，做事技巧开明，夏月虽有小疾无妨，吉星守命出入平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如脱衣换锦，奇才通能，但勿迫性，虽有小疾口舌无妨，贵人扶助可得财喜出入平安。","女":"玉造现年交上美运，签文如脱衣换锦，做事贤淑技巧，助益家门财喜，夏月小疾无妨，吉星守命平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如脱衣换锦奇才特达，宜戒忍性情，有些小疾无妨，有贵人扶助，可得财喜平安。","女":"坤造行运交泰，丕基泰来，贤淑智慧，旺益家庭，但宜忍口舌，小疾无妨，吉星守命出入平安。"},{"年龄":"56-69岁","男":"乾造步运亨通，丕基泰来，老练忠诚，但凡事宜宽怀大量，夏月虽有小疾口舌无妨，贵人扶助平安。","女":"坤造行运交泰，如脱衣换锦，贤淑智慧，有内助之称，有些暗疾无妨，吉星守度出入平安。"},{"年龄":"70岁以上","男":"台造老运亨通，老当益壮，但常时上落小心，虽有小疾厄无至大害，贵人扶助晚景胜前平安。","女":"妇造老运叶吉，旺益子孙，虽有些暗疾无妨，但宜守旧，二、五、八月勿外出，幸卦中吉星照身无妨。"}]},"生意":{"生意":"有虚无实表皮红，恰似锦被盖鸡笼，幸有福力相扶助，秋冬时节利享通。","生意解曰":"生意初时有虚无实，面好看内部空交,五，八，十一月返运，可得厚利也。","开铺":"卜开铺之卦为灾去终吉之兆，应小心大量，防止意外事故，初有小利，到底大利也。","合伙":"卜合伙之卦可以成功，宜同心协力和气相处，忍口舌可保平安大吉。","置货":"卜置货初时恐行情败，要敢于停留，候交秋月货物振价，可得厚利也。"},"出外":{"出外":"卜出外一事叶吉，但谦心意未定，应有胆敢往于五、八、十一月贵人扶助，各事平安。"},"谋望求财":{"谋望":"几年踪迹在江湖，名利无成困路途，今日相逢官贵力，好番春色满皇都。","谋望解曰":"谋事初时有阻隔而且有虚无实,宜立胆智到底有贵人扶助定可成功。","求财":"正财库取利，波阻已过，凡事业宜立志经营，候交八，十一月有贵人扶助，可得财利入手偏财初有阻，秋后可得利。"},"学艺功名":{"学艺":"卜学技艺为大吉之卦，但各事宜小心，勿迫性，有贵人扶助，学之成功，平安大吉。","功名":"现科文武功名皆可得中，营伍能进之。"},"行舟六畜":{"行舟":"行舟不顺，如有择日出海又可顺风也。","六畜":"圈舍养有猪牛羊，灾难消除来吉祥。求吓神明添力佑，猪肥牛壮财利添。","猪羊":"饲养猪羊，饲料调和上有阻隔，现已过去，可以饲养，底子平安，可得厚利。","草龙":"草龙之卦，前有小阻已过，今水草调和，养之顺利，但母牛生牛仔时宜小心，吓大伯公保平安。","三鸟":"饲养鸡鹅鸭之卦，虽有小利，但防有小厄，宜精心料理，养之可平安夜。","田蚕":"早冬中平，晚冬大吉，四季雨水大顺。"},"移徙":{"移徙":"移徙未吉，宜守旧，良时吉日移之。"},"行人":{"解曰":"行人在外，否极泰来，波阻已过，有贵人扶助，于三、五、九月有佳音财信回家。","签文":"历涉江湖千万重家乡回首自云龙往来自有灵阴护人在春风和气中。"},"婚姻":{"解曰":"婚姻成之，但应从速说合，迟恐有变恐守空房无缘也。","签文":"有缘造物自安排，休叹无缘事不谐，此际好听琴瑟调，莫教夜漏滴空谐。"},"官讼":{"解曰":"君遭害费了周折，但积善之人神明暗佑，横祸恐要失财，和之为贵。","签文":"遇遭横祸迫身躯，冤枉应是费论理。幸有神明空里佑，不教善者系囚人。"},"失物":{"解曰":"失物皆是辛苦得来，但君时运欠佳，故物失也，且目下很难寻得，知音日后见。","签文":"几年沙里去淘金，失却才知枉用心。目下欲寻难得见，直逢日后好知音。"},"占病":{"解曰":"老年男妇防冲跳凶危，求佛祖保佑平安，青少年是性刚得病，宜祭送改愿服药。","签文":"刚强狠泪惹祸火，独卖肌肤皮似梨。有合道心从改过，枯枝花发一时开。"},"其他":{"灶君":"卜此灶位分金合课，地格清净，但嫌灶前秽气，常时宜修清净，则烹煮兴隆。","阳基":"卜此阳基，门须修整，嫌白虎方有煞气冲伤，宜阴祭改水道清妥，财丁可旺也。","六甲":"卜此胎六甲生男，合家欢喜，许吓天地保根基足养，养育平安大吉也。","子息":"卜此卦子息虽少，但带有主贵，宜耐心培养，定能成材，荣宗耀祖。","祖山":"卜贵祖佳城结穴，气脉足旺，但嫌水字不美，白虎畔受煞冲伤，有利宜修整水字归口并掩祭白虎畔煞气，又添油之后，财丁旺平安夜。","青草":"此地有结穴，气脉足旺，但前面宽阳左方有树木冲伤，葬时应沉阳，立唇配合，理妥左方树煞，则财丁兴旺。"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  4,
  '黄巢出寨',
  '借风行舟之卦',
  '中平之卦',
  '巳蛇',
  '黄巢以天下谋，择日试剑后山。密友林贯斗欲避其锋而窥其事，藏于后山空树中。适黄巢以空树为试物，不意而杀林贯斗。',
  '有盒原无剑，劳心弄一场;家中多怪异，一犬吠三羊。',
  '花木遭风',
  '{"签号":"第四签","签名":"黄巢出寨","签文类型":"借风行舟之卦","卦象":"中平之卦","生肖":"巳蛇","签文简介":{"戏文":"黄巢以天下谋，择日试剑后山。密友林贯斗欲避其锋而窥其事，藏于后山空树中。适黄巢以空树为试物，不意而杀林贯斗。","诗曰":"有盒原无剑，劳心弄一场;家中多怪异，一犬吠三羊。","内兆":"花木遭风"},"家宅运势":{"签文":"无由闲事费支持，枉用贪心不可欺，金产损伤有少失，更防人口有微疲。","解曰":"吉宅人口之卦可得喜气但防产妇月内惊阻有防三，六，九月灾疾是非失财之厄，皆因门轻重畔，埕口水字不美有利各宜修整则财丁可旺。"},"岁君签":{"总诗":"劳心费力欲成功，待到花开一阵风，多谢东风轻借力，望东别有一枝红。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足养，但恐三、六、九月小疾波阻，六甲妇勿近抱，吓太阳公化吉平安。","女":"小女之卦根苗浅薄，惟防三、六、九月灾难波阻，宜吓太阳公化平安。"},{"年龄":"4-7岁","男":"小儿现年运限未美，但防三、六、九月灾难多事，宜吓太阳公化平安。","女":"小女之卦运限未美，惟防三、六、九月小疾波阻，汤火小心，吓太阳公平安。"},{"年龄":"8-12岁","男":"小童之卦，时令未美，但恐三、六、九月灾难多事，夜时勿独行，吓太阳公化吉平安。","女":"小女之卦时令未美，惟防三、六、九月灾难之厄，吓太阳公化平安。"},{"年龄":"13-15岁","男":"童造时令未美，人虽聪明，但防三、六、九月小难波阻，守旧，吓太阳公化平安。","女":"小女现年时令未美，惟防三、六、九月小难波阻，宜守旧，吓太阳公化平安。"},{"年龄":"16-17岁","男":"祥造运度未美，签文花开遭风，但恐三、六、九月灾难口舌，凡事戒忍，吓太阳公化吉平安。","女":"玉造现年运度美中不足，人虽技巧，惟防三、六、九月灾难多事，夜时勿独行，吓太阳公化吉平安。"},{"年龄":"18-29岁","男":"英造步运未美，似花开遭风，人虽奇才，但恐三、六、九月小疾口舌，凡事戒忍，吓太阳公化方保平安。","女":"玉造行运未美，似花开遭风，虽有助益家庭，但防三、六、九月灾难口舌，凡事吞忍，吓太阳公化平安。"},{"年龄":"30-55岁","男":"乾造步运未美，人虽奇才，但恐三、六、九月小人祸非口舌，凡事戒忍性情，吓天地化吉平安。","女":"坤造行运美中不足，人虽贤淑智慧，但恐三、六、九月暗疾，口舌吞忍，吓太阳公化吉平安。"},{"年龄":"56-69岁","男":"台造步运不美，人虽老练，但恐三、六、九月不测之祸，闲事切勿近理，吓天地化吉保平安。","女":"坤造行运美中不足，花开遭风，虽有旺益家庭，但恐三、六、九月暗疾口舌，应吞忍性气，吓天地保平安。"},{"年龄":"70岁以上","男":"台造老运不旺，但恐三、六、九月灾难跌地之厄，早晚上落各宜小心平安。","女":"妇造老运不旺，但防暗疾之厄，三、六、九月守旧，喜孝物勿食则吉也。"}]},"生意":{"生意":"生意交易欲认真，偏财莫取正财伸，四七九月经营好，买卖求财遂君心。","生意解曰":"生意取利仍嫌有盒无剑既是空有交易宜谨慎，用苦心智谋秋后有财利。","开铺":"若是老铺宜守旧经营，若是新创建未开张铺宅恐有不妙之处，勿开为好。","合伙":"合伙不成合之不利，因为伙计间有败运者，不要合伙反而安稳大吉也。","置货":"卜置货暂时价败，可购货停存，候七、八月起可有振价，应以发售，不可失机。"},"出外":{"出外":"卜出外之卦美中不足恐防有些阻隔，若真心敢往于四，七月便可得到成就。"},"谋望求财":{"谋望":"用尽心机事不成，如今休要问前程，金乌直待震坤日，自然荣显名利成。","谋望解曰":"谋事初时有阻隔不能成功，但应耐心谋之于四，七月有贵人扶助名利双成。","求财":"正财库取利虽有得，恐有阻隔财不住手，应立志经营于四，七，九月一派大好有财利可得，偏财切不可取。"},"学艺功名":{"学艺":"卦中有劳心弄一场之句，恐枉费心机，又嫌心内紧杂未定，宜候时运才学。","功名":"功名不就人也，难中也，宜用钱财帮助。"},"行舟六畜":{"行舟":"行舟应择日开船，可顺风得利。","六畜":"勤勤恳恳弄一场，三六阻隔牛猪羊。好香求神力相佑，秋交冬至财添利。","猪羊":"饲养猪羊，恐防三、六、九月阻隔，宜精心饲养，中大只及时发售，吓伯公保平安。","草龙":"饲养草龙，恐有阻隔，应防小人祸害，宜吓伯公化吉，秋后转运平安。","三鸟":"饲养三鸟，恐防三、六、九月阻隔，用心智养之，才有小利收入也。","田蚕":"田蚕早冬凶，晚冬吉，司机雨水莫强求。"},"移徙":{"移徙":"移徙不利，家基不旺，恐防有阻失。"},"行人":{"解曰":"行人去后，身有疾病，同伴分散失群而致音信稀无，宜吓太阳星君保平安。","签文":"去时之望取番头，自首他乡自绊身。今日方知人事别，当初何必苦贪心。"},"婚姻":{"解曰":"姻缘在远方成之大吉，若是近处男女两方经常见面的恐难成也。","签文":"婚姻到日不须寻，何必区区枉用心，有意种花花不发，无心插柳柳成荫。"},"官讼":{"解曰":"和之为贵，讼之则凶，柔能胜刚，切不可凭一时之雄而误了大事，应三思而行。","签文":"自古刚强误了身，虽知有力胜于君。如今造化无他算，只知私和做好人。"},"失物":{"解曰":"货物是辛苦得来的，现已失去，寻找难也，穷富皆是由命定，不可乱猜疑人家。","签文":"艰辛受苦此资财，谁想今朝反受灾。得大富贵皆前定，如今不必乱猜疑。"},"占病":{"解曰":"占病是因为七情伤本体而引起，老者恐伤生命，中少者宜向西北方改愿祭送平安。","签文":"但知勤作是真奇，不想贪心惹祸基。若有七情伤本体，早求福力保无迟。"},"其他":{"灶君":"卜此灶位虽美，但嫌分金不端正，有利宜改作新灶，使分金端正，烹煮叶吉。","阳基":"卜吉宅龙运不旺，又嫌门水字不美，坐向有利宜理妥门字水神并修整龙运，起造新基恐防有失。","六甲":"六甲生女平安，若生男恐有不测，应移房过祖，吓太阳公保根基足养，大吉平安。","子息":"子息虽然稀少，但有前途可望，男者是贵儿，长大定能得名得利，女者也能利益双亲。","祖山":"卜贵祖佳城有结穴，气脉足，但龙运不旺，碑面分金倾斜，如坐向有利宜修整龙运壮旺，碑面须修端正，掩戌未方煞气之后财丁昌盛。","青草":"此地有结穴，气脉足旺，但葬时要注意局外分金，理妥局口水字归源，则各房财丁兴隆，葬时恐有口舌，应理妥。"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  5,
  '苏东坡游江',
  '心动意和之兆',
  '大吉之卦',
  '辰龙',
  '宋苏东坡与佛印善同游河，遇渔翁父女，邀过船饮，苏与佛印吟诗索对，渔翁欲唱和，两人自恃博学精思，笑置之。不料渔女精思敏捷，每求对，辄暗示其父，遂难倒苏学士，使苏两人作山外山之叹。',
  '威武逞英雄，时享运也通;鹿行方见马，遇贵喜重重。',
  '顺水行舟',
  '{"签号":"第五签","签名":"苏东坡游江","签文类型":"心动意和之兆","卦象":"大吉之卦","生肖":"辰龙","签文简介":{"戏文":"宋苏东坡与佛印善同游河，遇渔翁父女，邀过船饮，苏与佛印吟诗索对，渔翁欲唱和，两人自恃博学精思，笑置之。不料渔女精思敏捷，每求对，辄暗示其父，遂难倒苏学士，使苏两人作山外山之叹。","诗曰":"威武逞英雄，时享运也通;鹿行方见马，遇贵喜重重。","内兆":"顺水行舟"},"家宅运势":{"签文":"门庭兴旺福神多，人虽无灾百事和，春夏宜防官灾疾，秋冬财物满庭稼。","解曰":"喜气盈门，但防春夏月小疾,及火星之厄，早晚火烛小心，是厝内土神愿和久年香火神恩过旺宜安谢土地神恩则财丁昌盛。"},"岁君签":{"总诗":"舟行风顺去无虑，利涉江湖正遇时，万里程途只可到，所谋遂意事如期。","年龄运势":[{"年龄":"1-3岁","男":"小儿根基足养，八字清秀，有旺益上人并茂，夏月小疾无妨平安。","女":"小女根苗足养，旺益上人并茂，夏月小疾无妨，定卜出入平安。"},{"年龄":"4-7岁","男":"小儿运限叶吉，天真活泼，水边小心，幸有吉星照身，出入平安。","女":"小女之卦顺遂，有旺益上人并茂，虽有些小疾无妨，出入平安。"},{"年龄":"8-12岁","男":"小儿现年上运，各事聪明开窍，宜入学校读书，定卜进步，出入平安。","女":"玉造现年交上美运，旺益家门，虽有小疾无妨，吉星照身平安。"},{"年龄":"13-15岁","男":"童造运度亨通，聪明特达，培养入学校读书，前途有望，出入拍平安。","女":"玉造运度顺遂，技巧伶俐，夏月小疾无妨，吉星守命，出入平安。"},{"年龄":"16-17岁","男":"祥造步运亨通，做事通能特达，学习文化，远景有希望，出入平安。","女":"玉造行运交泰，如顺水行舟，助益家门财喜，小疾无妨，出入平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如顺水行舟，奇才特达，但勿迫性，贵人扶助，可得财喜，出入平安。","女":"玉造行运交泰，各事技巧贤淑，夏月虽有小疾无妨，卦中有吉星守度平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如顺水行舟，奇才通能，可向外发展，有贵人扶助，可得财喜，出入平安。","女":"坤造行运交泰，各事贤淑智慧，旺益家门财喜，虽有暗疾无妨，吉星守合平安。"},{"年龄":"56-69岁","男":"台造步运亨通，如顺水行舟，老练忠诚，虽有小疾无妨，贵人扶助，出入平安。","女":"坤造行运交泰，如顺水行舟，贤淑智慧，暗疾无妨，吉星守命平安。"},{"年龄":"70岁以上","男":"台造老运亨通，老当益壮，有些灾疾无妨，贵人扶助平安。","女":"妇造老运交泰，如顺水行舟，虽有暗疾无妨，吉星照身，晚景胜前平安。"}]},"生意":{"生意":"生意兴隆财利开，河有桥来天有阶，五洲四海皆可往，有勇有智有厚利。","生意解曰":"卜生意道路四通八达，与人交易不可乱猜，宜立智，五，八，十一月可得厚财利。","开铺":"卜开铺之卦叶吉但交易宜谨慎，应防人不仁，有贵人扶助财利兴隆。","合伙":"卜合伙之卦叶吉合之可成，但伙计应同心同德协力经营，有大财利可得。","置货":"卜置货者宜占前，不可乱疑，须立胆智置而存之，五、八、十一月有利可得也。"},"出外":{"出外":"卜出外一事时令当权，凡事勿猜测，大胆前往有贵人重重可得成就。"},"谋望求财":{"谋望":"欲求动止莫怀疑，名利相寻勿待迟，但得便中须速起，休教叹过运中时。","谋望解曰":"做事内心不要乱怀疑要有胆智,灵活谋之交秋后有贵人扶助定可成功。","求财":"正财库取利宜立智经宜,创举宜占先有贵人扶助可得厚财利，偏财取之恐有失，宜和人家合伙移他人之福也。"},"学艺功名":{"学艺":"卜学艺之卦，与君年命合局，但应忍口舌，刻苦学习，有贵人扶助，定能手艺随身。","功名":"功名准得，武者更为荣贵，营伍可升。"},"行舟六畜":{"行舟":"行舟初时不吉，到底可顺风得也。","六畜":"猪肥牛壮兴旺期，快速饲养莫延迟。天定财利合道理，大投资金收大利。","猪羊":"卜饲养猪羊，饲料调和，可大胆多养，平安顺利，大落资本便可得到大利。","草龙":"饲养草龙水草调和，养之顺利，可旺益家庭，有利可得也。","三鸟":"饲养鸡鹅鸭，大吉顺利，可投资金，大胆多养，各事宜精心管理，有财利也。","田蚕":"田蚕早晚冬大吉，四季风调雨顺也。"},"移徙":{"移徙":"移徙大吉，速速可移，新宅可居之。"},"行人":{"解曰":"行人去后无音信者，是因途中有小疾，吓佛祖保平安，有贵人扶助，五、八月有佳音。","签文":"归期眼望恨悠悠，争奈淹留不自由。若得福神添力佑，轻帆风送即登舟。"},"婚姻":{"解曰":"婚姻成就百说百合，小登科已到在吉顺也，要借此时运托人说亲也。","签文":"婚姻到日不须寻，何必区区枉用心，两边相许无他事，正好乘时射雀屏。"},"官讼":{"解曰":"官讼得理，无须忧疑，不用烦恐，定能伸张得理，但和之更妙，大吉平安。","签文":"理直何须问上真，纵经官府不受刑。虽然目下多惶恐，定保平安理直伸。"},"失物":{"解曰":"东西虽已失去，自然有贵人告诉知音，如数归回，君心上不必忧烦也。","签文":"昨日偏舟过洞庭，知君心上不安宁。虽然失却凡间物，终有还珠且莫惊。"},"占病":{"解曰":"占病者阴邪交缠，宜许吓土神，向四方祭送，请良医治之，病可治愈。","签文":"谁觉追来疾似风，巫医扁鹊枉施工。但望福神来保佑，病魔退却不相逢。"},"其他":{"灶君":"卜此灶位分金合于八宅之课，但嫌灶前秽气，常时宜修理清净，则烹煮叶吉也。","阳基":"卜阳宅欲起造吉，但嫌有些口舌宜忍可成，旧阳宅如坐南向北分金防白虎畔石煞及凶，有利修整则平安。","六甲":"此胎六甲定生男儿，平安也，若产妇相马者定生双胎男儿，吓佛祖天地平安。","子息":"子息之卦初时多花少果，宜为世人多做善事，日后定有贵子可得。","祖山":"卜贵祖佳城横龙结穴，气脉足旺，但嫌白穴低，坐向有利宜修高三五尺，沉阳做又消纳白虎畔相朝之后才兴旺。","青草":"卜此地横龙结穴，气脉足旺，但葬时须将穴位点高三五尺，沉阳做，清掩白虎畔，使之相朝，则葬后财丁兴旺。"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  6,
  '王昭君和番',
  '称心不遂之兆',
  '以为下卦',
  '卯兔',
  '汉王昭君，古美女。选入宫，家贫无以贿御苑画师毛延寿，乃失幸。后下嫁匈奴，帝恨相见之晚。王乃出塞。两朝修好，匈奴因息兵戈数十载。',
  '独步两重山，孤恋转又翻;长江无信锂，佳人去不返。',
  '如鸟失群',
  '{"签号":"第六签","签名":"王昭君和番","签文类型":"称心不遂之兆","卦象":"以为下卦","生肖":"卯兔","签文简介":{"戏文":"汉王昭君，古美女。选入宫，家贫无以贿御苑画师毛延寿，乃失幸。后下嫁匈奴，帝恨相见之晚。王乃出塞。两朝修好，匈奴因息兵戈数十载。","诗曰":"独步两重山，孤恋转又翻;长江无信锂，佳人去不返。","内兆":"如鸟失群"},"家宅运势":{"签文":"只望今年百事昌，谁知自小惹祸殃，如今喜得人才好，重把家神炷愿香。","解曰":"吉宅人口之卦恐防夏月疾难, 口舌破财,求佛祖保平安，皆因先人失记小童香灯，应查明安拜，灶位不旺宜做新灶，则居住财丁兴旺。"},"岁君签":{"总诗":"鸳鸯阻隔两分飞，谋望求财未遇时，守旧却宜休改革，如今进退两迟疑。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基虽足，但恐二、五、八月灾难波阻，六甲妇勿近抱，吓天地保平安。","女":"小女之卦未美，惟防二、五、八月灾难波阻，宜守旧，吓月娘化吉方保平安。"},{"年龄":"4-7岁","男":"小儿之卦时令未美，但恐二、五、八月小疾汤火小心，吓天地化吉平安。","女":"小女之卦运限未美，防小疾多事，二、五、八月守旧，吓月娘化吉平安。"},{"年龄":"8-12岁","男":"小童运度未美，虽伶俐，但防二、五、八月多生小疾，吓天地化吉方保平安。","女":"小女之卦运度未美，惟防二、五、八月小疾波阻，宜守旧，吓月娘化吉平安。"},{"年龄":"13-15岁","男":"童造现运未美，人虽聪明，但防二、五、八月小疾多灾，吓天地化吉平安。","女":"玉造时令未美，但防二、五、八月灾难波阻，吓月娘化吉平安。"},{"年龄":"16-17岁","男":"祥造现年运度未美，似鸟拆群，惟防二、五、八月小疾口舌，宜耐心学艺，并吓天地化吉保平安。","女":"玉造现年时令未美，似鸟拆群，惟防二、五、八月小疾口舌，夜时勿外出，吓天地保平安。"},{"年龄":"18-29岁","男":"英造步运未遂，签文似鸟拆群，二、五、八月惟恐小人祸非口舌，凡事戒忍，吓天地化吉方保平安。","女":"玉造时令未美，但防二、五、八月灾难波阻，吓月娘化吉平安。"},{"年龄":"30-55岁","男":"乾造步运不美，人虽奇才，但恐二、五、八月灾难，小人口舌，凡事戒忍性情，并吓天地化吉方保平安。","女":"坤造行运，人虽贤淑，但防暗疾口舌，凡事吞忍，二、五、八月守旧吓天地化吉方保玉体安康也。"},{"年龄":"56-69岁","男":"台造步运未美，似鸟拆群，虽是老练，但恐二、五、八月不测之祸，闲事切勿近理，吓天地化吉保平安。","女":"坤造美中不足，虽有旺益家庭，和睦邻居，但恐二、五、八月暗疾口舌，吓天地化吉方保平安。"},{"年龄":"70岁以上","男":"台造老运不旺，似鸟拆群，为空灾难跌地之厄，早晚上落小心，则吉。","女":"坤造老运不旺，惟防暗疾风气，二、五、八月守旧，喜孝物勿食则吉也。"}]},"生意":{"生意":"生意阻滞防有恒，春夏利少勤经营，秋冬两季相交接，千年古树枝又生。","生意解曰":"生意似鸬鹚限定,上春财喜稀少防阻隔勿执辟,宜见利取,水上生意秋好。","开铺":"卜开铺之卦未开勿开或冬尾开之，已开之铺应防火盗,欠账口舌，宜立财帛星君奉拜冬尾有财利","合伙":"卜合伙之卦不成因伙计三人四心，言行不一致勿合平安也。","置货":"卜置货防阻失，小人耗劫，但贪之定失，宜刻苦经营，多用心窍，则财利安也。"},"出外":{"出外":"卜出外之卦恐防称意不遂，有小人寄祸宜守旧经营则免生愁。"},"谋望求财":{"谋望":"名利从来不易求，茫茫世事水中鸥，天公不任人贫穷，致使白头空浮云。","谋望解曰":"谋事有些阻隔做事却不可执僻,宜用心窍,补贴些小利事自能成也。","求财":"正财库取财恐是称意不遂，有财利但是聚手经营，宜见利取利，不可贪也偏财恐失切不可取也。"},"学艺功名":{"学艺":"卜学艺之卦，时运未到，恐艺师不传，宜窗下自习，日后拜师，定学好技艺。","功名":"功名不得，定失，恐是小人重重。"},"行舟六畜":{"行舟":"行舟失舵难回，勿出港，若择日则吉。","六畜":"六畜遭雨又遭风，一片艰辛总成空。求吓神明力保佑，秋冬蓄利可亨通。","猪羊":"饲养猪羊，恐防阻失，不宜多养，只养一只，中大只知卖，吓伯公保平安。","草龙":"饲养草龙，恐防脚疾，使用宜小心，水草应适宜，未购勿购，已养了宜换过再购，吓伯公平安。","三鸟":"鸡鹅鸭之卦，勿贪多养，恐防阻失，宜精心料理，吓伯公保佑平安。","田蚕":"田蚕中平，四季雨水春多冬少。"},"移徙":{"移徙":"移徙不可移，移之不利，应请日头公镇宅。"},"行人":{"解曰":"行人在外有小人阻隔，音信稀断，财运不通，吓天地保佑平安，信息财利早回家。","签文":"去时多少弟和兄，岂料中途失了群。阻滞未来终久别，何须每日倚柴门。"},"婚姻":{"解曰":"婚姻不成年命不同,勉强求亲虽得成功，终日也要离别,各分东西。","签文":"不将年命合相同，勉强求成岂利通，从然有缘成一处，终须离别分东西。"},"官讼":{"解曰":"君要有主见，不要听旁人谗言片语，要以和为贵，忍气勿忧，神主平安。","签文":"休听人嗦入县衙，两边弄尔结冤家。不如撒手和平好，免得街头叫老爷。"},"失物":{"解曰":"财务失去，不能寻回，切勿乱怀疑人家，破财补平安，不用忧愁，是小事也。","签文":"失去凡财问圣真，如今莫把众人寻。失遭掠剩分毫定，衣食求来不害身。"},"占病":{"解曰":"老人占之恐危也，夫妻占之恐有失，定守孤凄，无配偶者能改，念救苦经安也。","签文":"妻占夫兮夫占妻，终期必定守孤凄，父兄伯叔占男女，患难虽沉尚可为。"},"其他":{"灶君":"卜此灶位不美，嫌地下秽气，灶前阴湿不净，宜起净灶迹土作新灶，灶前修净。","阳基":"卜起阳宅有阴人受怨，老阳宅水神不美，宜理妥，居之平安。","六甲":"卜此胎六甲生女，生男恐根基不足，切发求佛祖注生娘保佑养育平安。","子息":"子息带高贵，恐难望子成龙，宜多行善事或神前改愿有香灯断成。","祖山":"卜贵祖佳城有结穴，但嫌龙运不旺，水神散出，有利宜修水神归口井并修龙运，填青龙砂头相朝之后财利兴隆，子孙安然。","青草":"此地有结穴，但嫌龙运不旺，近边有古穴阴人抱怨勿取，若要取时须理妥，并填青龙畔砂相朝，葬之财丁兴旺。"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  7,
  '韩信得志',
  '暗中有喜之兆',
  '中平之卦',
  '寅虎',
  '韩信少贫，称淮阴饿夫，曾受胯下之辱。后为楚执载郎官，项羽轻之。张良知为帅才，说归汉。刘邦拜为师。韩信主练兵，明修栈道而暗渡陈仓，下三秦直迫中原，戎马五年，扶助刘邦，定鼎西汉。',
  '风起见云生，时享运也通;八龙交会日，方遇宝花缘。',
  '枯木逢春',
  '{"签号":"第七签","签名":"韩信得志","签文类型":"暗中有喜之兆","卦象":"中平之卦","生肖":"寅虎","签文简介":{"戏文":"韩信少贫，称淮阴饿夫，曾受胯下之辱。后为楚执载郎官，项羽轻之。张良知为帅才，说归汉。刘邦拜为师。韩信主练兵，明修栈道而暗渡陈仓，下三秦直迫中原，戎马五年，扶助刘邦，定鼎西汉。","诗曰":"风起见云生，时享运也通;八龙交会日，方遇宝花缘。","内兆":"枯木逢春"},"家宅运势":{"签文":"淹滞消除正可夸，福神明点照君家，从今莫听闲人说，树正何愁月影斜。","解曰":"吉宅喜气盈门，但防小孩生端祸非而分家，主事人勿听妇女人言，宜从正气公正理，则家道可圆，埕口水道不美要修通，厝前受煞求令旗安门。"},"岁君签":{"总诗":"枯木逢春色欲华，愿交树长发萌芽，时人莫把为柴砍，自待春来又发花。","年龄运势":[{"年龄":"1-3岁","男":"小儿根基足养，八字清格，旺益上人并茂，夏月小疾无妨，吉星守度寿命绵长。","女":"小女根苗足养，有旺益上人并茂，春夏月虽有效皮恙无妨，吉星守命平安。"},{"年龄":"4-7岁","男":"小儿之卦叶吉，天真活泼，有旺益上人并茂，春夏月虽有小皮疾无妨，吉星守度平安。","女":"小女之卦运度顺遂，各事伶俐，利益上人，春夏月虽有些小疾无妨，吉星照身出入平安。"},{"年龄":"8-12岁","男":"小儿今年运度亨通各事伶俐活泼，可培养入学校读书，定卜进步平安。","女":"小女之卦时运交泰，如枯木逢春，旺益上人，小疾无妨，吉星守度平安。"},{"年龄":"13-15岁","男":"童造现运亨通，聪明开窍，宜入学校读书，远景有望而且出入平安。","女":"小女现年交上美运，各事精通，旺益家门财喜，虽有小疾无妨，出入平安。"},{"年龄":"16-17岁","男":"祥造现年转交好运，如枯木逢春，宜学艺业，卦中有贵人扶助，出入平安。","女":"玉造行运交泰，如枯木逢春，助益家庭，春夏月虽有小疾无妨，吉星守度平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如枯木逢春，做事奇才通能，可向外争取，定卜有贵人扶助，可得财喜平安。","女":"玉造行运交泰，如枯木逢春，各事技巧贤玉，夏月虽有小疾无妨，贵人扶助平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如枯木逢春，奇才老练，宜向前发展，定卜有贵人扶助，可得财喜，出入平安。","女":"坤造行运交泰，各事贤淑智慧，有内助之称，虽有些暗疾无妨，吉星守命可卜出入平安。"},{"年龄":"56-69岁","男":"台造步运亨通，做事忠诚经济，但勿迫性，有些小疾口舌无妨，卦中贵人扶助，可得财运平安。","女":"坤造行运叶吉，虽旺益家庭，但嫌常时暗疾上身，春夏月守旧，幸吉星守度平安。"},{"年龄":"70岁以上","男":"台造得此卦，如枯木逢春，老当益壮，但三、五、八月上落小心，晚景胜前平安。","女":"妇造行运有旺益子孙，但防暗疾，喜孝物勿食，三、五、八月守旧，可吉也。"}]},"生意":{"生意":"春夏生意交易稀，秋冬运开有财利，偏财阻失不可取，正道经营防口舌。","生意解曰":"生意经营时令合局,宜刻苦维持经营交叁，五，八月生意兴隆，有大财利可得。","开铺":"卜开铺之卦应防小人口舌，防人不仁宜请招财得君镇宅，求佛祖令旗安门上祭化平安。","合伙":"卜合伙之卦大吉合之可成，但伙计应同心同德协力经营，有大财利可得!","置货":"置货之卦，初时有高价，此货可发售，若是存放货，价恐败也。"},"出外":{"出外":"卜出外一事，时令当权，凡事勿猜测，大胆前往，有贵人重重，可得成就。"},"谋望求财":{"谋望":"人在山中待好音，君人拨探说知音，如今借得东风力，万里扬帆渐转身。","谋望解曰":"谋事可成但初谋之有小人阻隔,待叁，五八月有贵人扶助，到底可以成功。","求财":"正财库取财除时利薄，宜刻苦经营立功志维持交二，五，十一月有厚利可取，偏财切不可取之，取之定失。"},"学艺功名":{"学艺":"学技艺之卦，但恐不成，宜细心寻师，按年岁配合吉日拜师，耐心学习可成。","功名":"功名前科不中者，此科如枯木逢春定中。"},"行舟六畜":{"行舟":"行舟上春不吉，下春顺风得利也。","六畜":"饲养猪羊欲认真，春夏平平也要勤。待到六秋寒冬月，定有财利报汝心。","猪羊":"猪羊养之，饲料调和，春夏虽有些阻隔，但不必忧烦，可卜底子平安得厚利也。","草龙":"饲养草龙，平安顺利，可旺益家庭，母牛可有产牛仔，宜吓伯公保佑平安。","三鸟":"卜三鸟之卦，春夏恐有小疾，不宜多养，吓伯公保佑，秋后转运，可得财利也。","田蚕":"田蚕早不吉，晚大吉，四季雨水略顺。"},"移徙":{"移徙":"移徙春夏不可移，待七、八月移之大吉。"},"行人":{"解曰":"卜此行似枯木逢春，有贵人扶助可得名利双成，交三、五、八月有佳音回家。","签文":"有书喜讯送君知，庭内人情小微微，且待三羊四马日，定然衣锦返回圆。"},"婚姻":{"解曰":"婚姻成之佳人出在远方，有缘千里能相会，若是近方的恐是对面不相逢。","签文":"几年久坐少人招，今日枯枝长嫩条，自是有缘千里合，无缘对面路迢迢。"},"官讼":{"解曰":"官讼可胜，但不可告，应以和为贵，若告之，虽赢输钱。","签文":"新事伤人旧事情，劝君休要逞高能。平生惟慎宪台上，此地从来不可登。"},"失物":{"解曰":"失物落在近处，认真迅速寻找，三、五日便可找到，若延迟，恐难找到也。","签文":"分明失落在篱边、不解追寻旧愿改。万事迟疑三五日，也须来复改依然。"},"占病":{"解曰":"占病只因有旧愿，应速还谢，宜扣许太阳太阴经保平安，四方祭送，不可迟疑。","签文":"为知不肯念弥陀，有事终思旧愿改。若肯有心从改过、不教善者见南柯。"},"其他":{"灶君":"卜此灶位分金合课，但嫌灶前秽气，应常时修理清净，则烹煮兴隆也。","阳基":"阳基起造有小人口舌，须忍之，并从慎起建或小财补贴老阳居，嫌白虎畔受塞，有利宜修整之则吉也。","六甲":"卜此胎六甲生男，但恐根基浅薄，宜吓天地化吉或拜契神明保养育平安。","子息":"子息之卦，如枯木逢春，莫嫌慢得，将来自有富贵之子，继承香灯，荣宗耀祖。","祖山":"卜贵祖佳城有横龙结穴，但嫌水神散出，白虎畔受路煞冲伤，坐向有利宜修水神归口并填浮白虎畔朝顾，又受兜池唇浮安葬之，则财丁可吉安。","青草":"卜此地横龙结穴，但嫌面前崎岖，葬时宜沉阳立唇，还嫌有口舌是非，宜用财帛补助解决，葬后财丁兴旺也。"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  8,
  '韩文公冻雪',
  '破船上滩之兆',
  '下下之卦',
  '丑牛',
  '唐韩愈因阻迎佛骨，触怒天颜，被贬潮州府，路过蓝关。遇入雪封冻，几丧生，幸侄韩湘相救助，始免其难。叔侄会于漂江之滨。韩湘劝登仙，韩愈志在家国，谢绝，又因感于世路艰险，乃作诗以宣其悲愤。',
  '水浅孤舟涸，风寒马不前;故人相别去，唱只鹧鸪天。',
  '破船上滩',
  '{"签号":"第八签","签名":"韩文公冻雪","签文类型":"破船上滩之兆","卦象":"下下之卦","生肖":"丑牛","签文简介":{"戏文":"唐韩愈因阻迎佛骨，触怒天颜，被贬潮州府，路过蓝关。遇入雪封冻，几丧生，幸侄韩湘相救助，始免其难。叔侄会于漂江之滨。韩湘劝登仙，韩愈志在家国，谢绝，又因感于世路艰险，乃作诗以宣其悲愤。","诗曰":"水浅孤舟涸，风寒马不前;故人相别去，唱只鹧鸪天。","内兆":"破船上滩"},"家宅运势":{"签文":"不能安分每奔波，惹得家中祸事多，春夏可忧人口病，秋冬又忙损田禾","解曰":"吉宅人口连年灾疾，口舌失财,吓佛祖相保平安，皆因失祀祖上香火应查明奉祀并做过新灶位，埕口水道宜修通，则居住财丁兴旺。"},"岁君签":{"总诗":"因见渔舟上逆滩，渔舟上岸且盘桓，前滩过了为闲事，惟有后滩过更难。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗浅薄，但防正、五、九月灾难波阻，六甲妇勿近抱，吓妈祖化吉方保平安。","女":"小女根苗不旺，正、五、九月防风寒灾难，宜守旧，吓月娘改化平安。"},{"年龄":"4-7岁","男":"小儿之卦时令未美，但恐正、五、九月多生灾难波阻，吓妈祖化吉方保平安。","女":"小女之卦未美，防正、五、九月小疾水厄，逢水边小心，吓妈祖化吉平安。"},{"年龄":"8-12岁","男":"小儿运度未美，但防正、五、九月小疾水厄，水边勿近，吓妈祖化吉方保平安。","女":"玉造运度未美，虽活泼，但防正、五、九月小疾水厄，宜守旧，吓月娘改化平安。"},{"年龄":"13-15岁","男":"童造运度未遂，虽聪明开窍，但正、五、九月水边小心，吓妈祖改化方保平安。","女":"玉造运度美中不足，防水厄小疾，二、五、九月池井边小心，吓妈祖化吉平安。"},{"年龄":"16-17岁","男":"祥造步运不美，似破船上滩，惟防正、五、九月小疾水厄，过渡小心，求神明化吉方保平安。","女":"玉造行运美中不足，似破船上滩，虽是技巧，惟防正、五、九月灾疾水厄，吓天地化吉平安。"},{"年龄":"18-29岁","男":"英造步运不美，签文似破船上滩，虽通能，正、五、九月小人口舌是非，凡事戒忍性情，吓妈祖平安。","女":"玉造行运美中不足，似破船上滩，惟防正、五、九月灾疾口舌，凡事吞忍勿执己意，吓妈祖平安。"},{"年龄":"30-55岁","男":"乾造步运不美，似破船上滩，虽有志难伸，正、五、九月小人不测之祸，凡事从正，吓天地化吉保平安。","女":"坤造行运未美，似破船上滩，但防暗疾口舌，凡事吞忍，正、五、九月守旧，吓天地化吉平安。"},{"年龄":"56-69岁","男":"台造步运不美，人虽老练，但防正、五、九月小人起风波，闲事切勿近理，守正业经营，可卜平安。","女":"坤造行运未美，操心暗疾又防口舌多事，凡事吞忍性气，切勿迫性，吓天地化吉平安。"},{"年龄":"70岁以上","男":"台造老运不旺，恐灾难跌地之厄，早晚上落小心，守旧，宽怀大量平安。","女":"妇造老运不旺，恐操心迫杂，暗疾之厄，上落小心，正、五、九月守旧，则吉也。"}]},"生意":{"生意":"破船上滩险其中，生意经营有劫凶，来往交易须谨慎，智慧谋取利兴隆。","生意解曰":"生意经营似破船上滩，财利跋涉，防小人阻隔累害，宜谨慎用智悲谋取利。","开铺":"卜开铺之卦不吉恐伙计不同心，有不美之事发生，勿合平安也。","合伙":"卜合伙之卦不吉，恐防伙计不同心，有不美之事发生，勿合平安也。","置货":"卜置货防小人耗动，失败也，若已失过者，可以置之，交秋冬月有财利可得也。"},"出外":{"出外":"出外之卦时令不通恐防小人累害，生端寄祸宜守旧则免生愁。"},"谋望求财":{"谋望":"命里无时莫强求，何须日夜泛渔舟，红鳞已在秋江上，用尽心机不上钩。","谋望解曰":"谋呈要托别人福，春夏谋之不成要待交秋月圆，托人帮助为便可成。","求财":"正财库取利正如镜内之银，看得见取不着，但宜立志气用谋之可得微利，偏财勿取之。"},"学艺功名":{"学艺":"学技艺之卦，因君年命不合时令，运遇未到，且寒窗自习，秋后寻名师学之成也。","功名":"功名只因运未到，不能得中，失也。"},"行舟六畜":{"行舟":"行舟不详，有出难入，待时行之免险也。","六畜":"圈舍饲养猪牛羊，多只阻隔不吉祥。风吹雨打要防失，至切谨记预告言。","猪羊":"猪羊之卦不吉少利，不可贪养，恐防二、五、八月阻失，大只出卖，吓伯公保平安。","草龙":"草龙之卦，恐防疾难之厄，勿贪心使用，应精心饲养，吓伯公保平安。","三鸟":"三鸟之卦，不宜多养，恐防二、五、八月阻失，大只及时出卖，吓伯公保平安。","田蚕":"田蚕早晚二冬少吉怕尾，四季雨水各人福。"},"移徙":{"移徙":"移徙不利，宜守旧待时，渐安旧居也。"},"行人":{"解曰":"行人在外身体健康，但恐小人阻隔，音信稀断，吓妈祖化吉保平安。","签文":"霸留常挂两头忧，阻隔关山不自由。惆怅凶多怨恨事，更无消息到扬州。"},"婚姻":{"解曰":"婚姻不可成就，因为小人语言不够真实，胸怀似虎狼不可相信。","签文":"旁人只说俩相当，难测胸怀损虎狼，口好不如心内好，不如独枕卧藤床。"},"官讼":{"解曰":"此讼有败无胜，宜和不宜告，若告之恐受奸害，不可乱说，要抽身不理为吉。","签文":"得知闲处且和闲，扪到人心有恶奸，莫说酒中胡乱语，岂知台上对词难。"},"失物":{"解曰":"失物是贪谋而得来电，因而失之难寻，不得回也，勿乱猜疑人家，免生祸非也。","签文":"为因不慎失马羊，触得心头日夜忧。人眼不如天眼现，分明教尔莫贪谋。"},"占病":{"解曰":"卜病是由小事操心而引起，应急速静下心来，请良医治疗，向四方祭送大吉。","签文":"只因小事恼心怀，惹得忧疑杂病来。急向静中求善福，莫教身躯堕尘埃。"},"其他":{"灶君":"卜此灶位不美，灶前嫌秽气，宜将灶位退后，做新灶，则烹煮平安大吉。","阳基":"卜阳基龙运不旺，又高低轻重畔，数年败失，宜修整过居住，造新阳基不成有阻，守旧待时吉之。","六甲":"六甲生男，恐防有阻，根基不足，速宜过继或拜契神明保佑，生女宜嫁出。","子息":"子息之卦，比如枝头生一果一果还遭水灾，宜多做善事，求神明保佑，终有麒麟入梦来也。","祖山":"贵祖佳城有结穴，但龙运不旺，水神阳走，坐向有利宜修整龙运并埋水神归口，又掩祭午方煞气之后，财丁兴旺，惟山子分金宜过别地，则子孙平安。","青草":"此地有结穴，但嫌龙运不旺，出水阳走，葬时宜修龙运并理妥水神归口，立唇掩祭午方煞气，葬之则财丁平安也。"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  9,
  '四太子初伐中原',
  '时秋晚节之兆',
  '中平之卦',
  '子鼠',
  '金四太子兀术初伐中原，破路安州，守将陆登自刎而挺立，兀术敬拜之始倒。因敬其英烈，乃收养其幼子陆文龙。后宋将王佐断臂诈降入金，得奶母助，策反双枪陆文龙归宋。祖父子四状元者是也。',
  '舟戏长江水，风在浪更涛;大蛇侵户俑，五鬼弄刀枪。',
  '兰菊芬菲',
  '{"签号":"第九签","签名":"四太子初伐中原","签文类型":"时秋晚节之兆","卦象":"中平之卦","生肖":"子鼠","签文简介":{"戏文":"金四太子兀术初伐中原，破路安州，守将陆登自刎而挺立，兀术敬拜之始倒。因敬其英烈，乃收养其幼子陆文龙。后宋将王佐断臂诈降入金，得奶母助，策反双枪陆文龙归宋。祖父子四状元者是也。","诗曰":"舟戏长江水，风在浪更涛;大蛇侵户俑，五鬼弄刀枪。","内兆":"兰菊芬菲"},"家宅运势":{"签文":"只望家和万事成，年来愁闷未曾伸，因何不把家神敬，门户无人有响声。","解曰":"吉宅人口可得喜气，家欲和气万事可成，但防夏月疾难祸非涉财，吓佛祖保平安，又嫌门轻重畔，灶位不美，各宜修整，祖上香灯要拜到则安。"},"岁君签":{"总诗":"芳兰春景真堪爱，菊吐秋光色又佳，乾坤各自惟消息，不假春风次第开。","年龄运势":[{"年龄":"1-3岁","男":"小儿根基足养，八字清格，有旺益上人并茂，四、五、七月小疾无妨，卦中吉星守度平安。","女":"小女根苗足养，有利益上人并茂，四、五、七月虽有小皮恙无妨，吉星守命平安。"},{"年龄":"4-7岁","男":"小儿之卦，运限精通，天真活泼，虽有小疾无妨，水边小心，幸有吉星守命平安。","女":"小女今年运限顺吉，各事伶俐，有旺益上人并茂，但池井边小心，幸有吉星守度平安。"},{"年龄":"8-12岁","男":"小儿之卦时令亨通，伶俐活泼，可培养入学，定卜进步平安，但池井边小心，幸吉星守度平安。","女":"小女今年时令顺遂，各事通窍，有旺益上人并茂，但水边小心，吉星守度平安。"},{"年龄":"13-15岁","男":"童造运度叶吉，做事聪明，可入学校读书，定卜进步，正、四、五月虽有小疾无妨，吉星守命平安。","女":"小女今年交上美运，各事精通，旺益家门，正、四、五月虽有小疾无妨，水边小心，底子平安。"},{"年龄":"16-17岁","男":"祥造步运亨通，如兰菊芬芳，做事通能，可培养入学，定卜前途进展，出入平安。","女":"玉造行运交泰，如兰菊芬芳，技巧聪明，正、四、五月虽有小疾无妨，吉星守度平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如兰菊芬芳，奇才通达，可得财喜，正、四、五月戒忍口舌，贵人扶助出入平安。","女":"美造行运顺遂，如兰菊芬芳，各事贤玉，助益家庭，正、四、五月小疾无妨，吉星守度平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，做事才能特达，虽可得财喜，但正、四、五月防小人口舌，幸贵人扶助平安。","女":"坤造行运交泰，如兰菊芬芳，但嫌操心，凡事吞忍，虽有小暗疾口舌无妨，吉星守命平安。"},{"年龄":"56-69岁","男":"台造步运亨通，为人老练忠诚，可得财运，但凡事宽怀大量，正、四、五月戒忍口舌，幸贵人扶助平安。","女":"坤造行运顺遂，可称内助，人贤惠，但防暗疾口舌，宜忍性，幸吉星守度出入平安。"},{"年龄":"70岁以上","男":"台造步运，随是老当益壮，但防灾难跌地之厄，正、四、五月上落小心，则大吉平安。","女":"妇造老运虽有旺益子孙，但防暗疾上身，正、四、五月喜孝物勿食，守旧，晚景胜前，底子平安。"}]},"生意":{"生意":"春夏时运还未通，生意平平利轻松，货物留下秋东卖，时到运开利倍浓。","生意解曰":"生意虽有利可得，但防夏月阻隔，交秋后有贵人扶助似兰菊芳芬得后利。","开铺":"开铺宜从正道应防歹人劫物，铺勿离人，财勿露眼，请佛祖令旗安门上平安。","合伙":"卜合伙之卦有利但伙计宜忠直勿贪心凡事要能同心协力，要忍口舌秋后可得顺利。","置货":"卜置货上春小利，宜现买现卖，候交秋冬月经营利路宏开。"},"出外":{"出外":"卜出外一事要有胆气坚定前往于二，四月有贵人扶助，可得名利双全。"},"谋望求财":{"谋望":"昔年许汝到春来，岂料经营意不谐，且待菊梅开结日，依然名利两成材。","谋望解曰":"卜谋事成，但须切防口舌候四，五月谋之并托人帮助，交秋冬时便可成功。","求财":"正财库取利夏月利少，但宜刻苦维持交九，十月起返运财源广进可得厚利，偏财有利可得，但切不得外涉消息。"},"学艺功名":{"学艺":"卜学艺之卦，上春时运未到，勿学为佳，候秋后择吉日，拜良师学之便可成功。","功名":"功名半吉，若勤奋用功学习，定能得吕。"},"行舟六畜":{"行舟":"行舟中吉，四、九月顺风大吉也。","六畜":"君若要养猪牛羊，成群有阻一二良。求吓神明力保佑，秋交冬至财利添。","猪羊":"卜猪羊之卦，不可成群，养一二只为佳，防阻失吓伯公保佑，有厚利。","草龙":"饲养草龙，应下功料理，可旺益家庭，宜求伯公香火带平安。","三鸟":"饲养三鸟，春夏养之恐有阻失，秋冬养之有大利，上年有失过者，今年二月起养之兴旺。","田蚕":"田蚕中吉，早晚冬一样，四季雨水皆同。"},"移徙":{"移徙":"移徙本乡勿移，移之不吉，他乡犹可。"},"行人":{"解曰":"行人在外身体平安，有贵人扶助，候四、七、九月有信息回家，此后捷报频传。","签文":"人坐依然音信稀，如今何用意踌躇。春兰秋菊因时候，各自根苗待吐枝。"},"婚姻":{"解曰":"婚姻成之但初时人心还未坚,不要急迫候待月圆便可说合下出聘也。","签文":"婚欲成时待月圆，不须心下意悬悬，虽然好段婚缘事，怎奈他人尚未坚。"},"官讼":{"解曰":"此讼宜和，不可告之，不要理它，百忍不灾也，若告之，恐大费精神，不顺也。","签文":"成人不用苦心头，恐有文词讼人交。凡事抽身归去好，闭门静坐做闲巢。"},"失物":{"解曰":"物已失去不可怨天也，不可猜疑邻居，要知真消息必须等待来年，或许得见。","签文":"自失如何却怨天，神公岂肯为谁怜。依君若要真消息，细心访寻须待年。"},"占病":{"解曰":"生病不可随便怨恨，此病不危，良医未到，到了便病好福来也。","签文":"此事厌厌怨满怀，未逢良药事和谐。平安等待三更后，获取从交福降来。"},"其他":{"灶君":"卜此灶位合课，但嫌窗前煞冲照，且灶前秽气，时常修洗干净，遮盖煞气，大吉。","阳基":"卜起造阳基嫌右方有庙煞，宜掩祭起造大吉，老阳宅嫌门前误会，宜修净居之大吉。","六甲":"卜此胎六甲生男，大吉顺，阖家老少欢喜，宜吓神明保佑养育平安。","子息":"卜子息之卦，以前多花，后必结果，现岁怀孕生男，昔年生女，后台即可生男。","祖山":"卜贵祖佳城横龙坠气结穴，气脉足旺，但嫌唇口出水分金不美，又嫌得西分前分金不旺，如坐向有利各宜修整，财丁旺也。","青草":"此地横龙坠气结穴气脉足旺，但嫌右方有煞冲伤，葬时宜消掩冲煞并修水神归口，葬后财丁兴旺，老少和美也。"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  10,
  '甘罗十二为丞相',
  '虑而即行之兆',
  '以为下卦',
  '亥猪',
  '甘罗幼聪慧，帝喜之，令其祖带甘罗入朝见驾。帝抱置腿上，摸其头而笑曰：真乃丞相头也。其祖父即命甘罗谢恩受封。帝以君无戏言封甘罗为丞相，时年方十二。',
  '哇在井中鸣，无影但闻声;月牢在底下，有影又无形。',
  '黄蜂采花',
  '{"签号":"第十签","签名":"甘罗十二为丞相","签文类型":"虑而即行之兆","卦象":"以为下卦","生肖":"亥猪","签文简介":{"戏文":"甘罗幼聪慧，帝喜之，令其祖带甘罗入朝见驾。帝抱置腿上，摸其头而笑曰：真乃丞相头也。其祖父即命甘罗谢恩受封。帝以君无戏言封甘罗为丞相，时年方十二。","诗曰":"哇在井中鸣，无影但闻声;月牢在底下，有影又无形。","内兆":"黄蜂采花"},"家宅运势":{"签文":"今年田蚕半吉祥，夏秋又恐损牛羊，冬深人口宜祷福，更防凶人跳矮墙。","解曰":"吉宅人口虽有喜气，但防夏月,疾难口舌，失财贼厄，肖牛者防生痛疾，吓佛祖保平安，皆因厝前受水冲伤求佛祖令旗安门上祭化则平安。"},"岁君签":{"总诗":"不论平地与山尖，无限风光总被占，采得百花成蜜后，到头辛苦为谁甜。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗虽稳固，但防夏秋月灾难波阻，六甲妇勿近抱，吓月娘保平安。","女":"小女根苗浅薄，惟防四、六、八、十二月灾难波阻，宜吓月娘化吉方保平安。"},{"年龄":"4-7岁","男":"小儿运限未美，四、六、八、十二月防灾难，不可登高玩耍，吓天地化吉方保平安。","女":"小女之卦时令未美，防灾疾波阻，四、六、八、十二月守旧，吓天地化吉方保平安。"},{"年龄":"8-12岁","男":"小童现年运度未美，但防四、六、八、十二月脚手痛疾，不可登高，吓天地化吉方保平安。","女":"小女现年运度未美，惟防四、六、八、十二月小疾波阻，守旧，吓天地化吉方保平安。"},{"年龄":"13-15岁","男":"童造现年未美，人虽聪明，但防脚手阻疾，四、六、八、十二月守旧，不可登高，吓天地平安。","女":"玉造现年未美，惟防脚手痛疾，四、六、八、十二月勿登高，守旧，吓天地化吉保平安。"},{"年龄":"16-17岁","男":"吉造运度未遂，似黄蜂采花，虽有才能，但防四、六、八、十二月小疾口舌，勿执僻，吓天地保平安。","女":"玉造运度美中不足，似黄蜂采花，惟防四、六、八、十二月脚手痛疾，夜时勿独行，吓天地化吉平安。"},{"年龄":"18-29岁","男":"英造步运未美，似黄蜂采花，人虽通能，惟防四、六、八、十二月小人口舌，凡事从正，吓天地平安。","女":"坤造行运未美，似黄蜂采花，虽助益家庭，但防四、六、八、十二月小疾口舌，凡事吞忍，吓天地平安。"},{"年龄":"30-55岁","男":"乾造步运不美，似黄蜂采花，防四、六、八、十二月小人祸非，宜戒忍性情，交接谨慎，吓天地化吉平安。","女":"坤造行运不美，人虽贤淑，但防暗疾口舌，凡事吞忍，四、六、八、十二月守旧，并吓天地化吉方保平安。"},{"年龄":"56-69岁","男":"台造步运未美，似黄蜂采花，虽是老练，但防四、六、八、十二月不测之祸，闲事勿理，吓天地平安。","女":"坤造行运未美，操心暗疾，凡事吞忍，四、六、八、十二月守旧，夜时勿运出，吓天地化吉保平安。"},{"年龄":"70岁以上","男":"台造老运不旺，人虽忠诚，但防灾疾跌地之厄，六、八、十二月上落小心，勿登高，守旧则吉。","女":"妇造老运不旺，虽有旺益子孙，但防暗疾风气，四、六、八、十二月喜孝物勿食，守旧则吉。"}]},"生意":{"生意":"今年生意欲认真，慎防盗贼劫财金，夏月莫挂人家账，秋到求财天有心。","生意解曰":"生意虽有财利可得，但恐小人,劫货，交易宜谨慎见利取利，则财利吉也。","开铺":"卜开铺之卦应防盗贼之厄应防小人诱劫财物，铺门有煞，宜请佛祖符令安门上保平安。","合伙":"不成三人四窍伙计不同心，财物恐有走漏，勿合为宜，合之有祸无利也。","置货":"置货恐防小人耗动，交易要认真谨慎，银项必须亲自点交，有小财利可得。"},"出外":{"出外":"卜出外之卦一事要有胆气坚定前往于二，四月有贵人扶助可得名利双全。"},"谋望求财":{"谋望":"托人去干心中事，口好如何心不好，早早回头归故里，痴只常惯受灾残。","谋望解曰":"卜谋事须防歹人阻隔拐骗或抢劫财帛，宜谨慎应防人不仁勿往外谋之。","求财":"正财库取财虽有得，但恐防小人负累，勿信直中直，须防仁不仁，宜从正道经营，偏财失之不可取，肖牛,羊者失更大。"},"学艺功名":{"学艺":"卜学技艺之卦，因时运未至，学而无成，勿枉费工本，自己学习待时机学之。","功名":"功名不中，勿取吉，肖牛羊者切勿取进。"},"行舟六畜":{"行舟":"行舟凶险，切勿行之，守之平安。","六畜":"夏秋凶险损牛羊，任你求神无应天。肥猪还需防盗贼，不如闲手度虚年。","猪羊":"饲养猪羊有失无得，恐防六、九、十二月阻隔，中大只肥猪要及时出卖，吓伯公保平安。","草龙":"草龙之卦，恐防六、九、十二月阻疾，又防盗厄，宜吓伯公保佑平安，如未养者，渐勿购也。","三鸟":"饲养三鸟，恐防六、九、十二月疾病，又防盗厄，三四只可养，多则不得也。","田蚕":"田蚕中平，防损失，四季雨水不吉。"},"移徙":{"移徙":"移徙应防不吉，因地基有灾险也。"},"行人":{"解曰":"行人在外凶险事多，恐防小人阻隔祸害，回之艰难，宜吓佛祖保佑身体健康。","签文":"艰难跋涉万重山，心事茫茫意未还。又恐路途中人毒，凡事凶险在其间。"},"婚姻":{"解曰":"不可轻信媒人话，是闲花野草也切不可取之，若取之欢乐一时有祸也。","签文":"野草闲花迷更乱，一朝乐极更生悲，虑心直待姻缘到，莫听旁人说是非。"},"官讼":{"解曰":"官讼要以和为贵，若告之，起初胜，后定败，因为对方有旁人协助支持。","签文":"世间难成是贪痴，身为螳螂不见机。只想鸣蝉遭汝捕，不知黄雀在后治。"},"失物":{"解曰":"失物已入盗贼之手，纵然到处寻找也难寻见，宜细心观察了解或可见踪迹。","签文":"失了财宝莫怨天，谁知贤者更为贤。眼见此物入盗手，只在芦花浅水边。"},"占病":{"解曰":"求神请良医治疗好也，但肖牛羊之人恶症缠身，求佛祖吓送太阳太阴经平安。","签文":"恶病缠身无奈何，只防沉重见阎罗。如今若要凶星退，速请僧人念弥陀。"},"其他":{"灶君":"卜此灶位不美，灶前迫塞，宜重新做新灶，烹煮兴隆，财丁兴旺也。","阳基":"卜阳宅生蚁，宜立白雄鸡掩祭化吉，欲起新阳宅有阻口舌，需小财利补办，旧阳宅丑未受煞。","六甲":"卜此胎六甲生女安，生男恐防有阻，根基浅薄，宜过拜契神明保平安。","子息":"前恐难得子，得者也少养，宜多行善事，后来自由子孙继承，平安吉祥也。","祖山":"贵祖佳城横龙结穴，但龙运不旺，丑未分金受煞冲伤，坐向有利宜修龙运壮旺并掩祭丑未方煞气，又理水字配合分明，葬之财丁兴旺也。","青草":"此地横龙有结穴，但嫌龙运不旺，应请有福先生做之财丁兴旺，但丑未分金山头勿取，因水字不美，财丁要破失。"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  11,
  '武吉卖柴',
  '久病逢医之兆',
  '大吉之卦',
  '戌狗',
  '武吉将入市，姜尚劝勿往，言必伤人命。武吉挑柴市卖，遇文王车架，忙避之，人担误毙门官王相，文王命画地为牢，竖木为吏囚之。武吉思母，恸。散宜生奏上允其先回家事母，然后归偿命。后武吉因引见姜尚，文王免其罪，并封为武德将军。',
  '红日当天照，光辉遍四方;西川人着锦，红紫满长春。',
  '如日之升',
  '{"签号":"第十一签","签名":"武吉卖柴","签文类型":"久病逢医之兆","卦象":"大吉之卦","生肖":"戌狗","签文简介":{"戏文":"武吉将入市，姜尚劝勿往，言必伤人命。武吉挑柴市卖，遇文王车架，忙避之，人担误毙门官王相，文王命画地为牢，竖木为吏囚之。武吉思母，恸。散宜生奏上允其先回家事母，然后归偿命。后武吉因引见姜尚，文王免其罪，并封为武德将军。","诗曰":"红日当天照，光辉遍四方;西川人着锦，红紫满长春。","内兆":"如日之升"},"家宅运势":{"签文":"家旺人兴百事宜，田蚕加倍在秋期，但防阴人生疾病，见喜消灾事可知。","解曰":"吉宅人口可得喜气，但防疾难口舌涉财，是厝内有神恩土德，宜择日改谢清楚，又嫌祖山不顺有利宜修整壮旺，可得财丁兴旺。"},"岁君签":{"总诗":"囚人出狱公事休，却买甜瓜上酒楼，偶遇故人同畅饮，酒钱不了义相绕。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，八字清格，旺益上人，上春月小疾无妨，吉星守岁平安。","女":"小女根苗足养，夏月虽有小皮疾无妨，卦中有吉星守命，出入平安。"},{"年龄":"4-7岁","男":"小儿之卦叶吉，生性天真活泼，旺益上人并茂，春夏月小疾无妨，出入平安。","女":"小女之卦顺遂，各事伶俐活泼，旺益上人并茂，春夏月小疾无妨，出入平安。"},{"年龄":"8-12岁","男":"童造现年交上运，各事开窍，宜培养入学读书，定卜进步，而且出入平安。","女":"玉造现年运度顺遂，技巧活泼，春夏月虽有小波阻无妨，吉星守命平安。"},{"年龄":"13-15岁","男":"童造运度亨通，聪明开窍，宜入学读书，定卜前途有望，出入平安。","女":"玉造现年交上美运，如月之明，技巧伶俐，春夏月虽有小疾无妨，吉星守命平安。"},{"年龄":"16-17岁","男":"吉造步运亨通，如日东升，做事聪明，培养入学，贵人扶助，小疾无妨平安。","女":"玉造今年交上美运，如月之明，技巧贤玉，春夏月小疾无妨，吉星守命平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如日东升，奇才特达，可向外发展，但勿迫性，有贵人扶助，可得财喜，出入平安。","女":"玉造行运交泰，如月之明，各事贤玉技巧，春夏月虽有小疾无妨，卦中有吉星守命平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如日东升，做事老练，春夏月小疾口舌无妨，宜从正经营，有贵人扶助可得财星。","女":"坤造行运交泰，如月之明，贤淑智慧，虽有小疾无妨，勿操迫，幸卦中有吉星守命出入平安。"},{"年龄":"56-69岁","男":"台造步运亨通，如日东升，老练忠诚，可向外发展，定卜有贵人扶助，可得财运出入平安。","女":"坤造行运交泰，如月之明，凡事勿操迫，春夏月虽有小疾无妨，幸吉星守度平安。"},{"年龄":"70岁以上","男":"台造老运安康，惟防春夏月灾疾，守旧，幸福星扶照晚景胜前平安。","女":"坤造老运康泰，旺益子孙，春夏月暗疾无妨，吉星守度，出入平安。"}]},"生意":{"生意":"灾过运来得意开，上年赫神恩要还，春夏应防风雨阻，秋冬时节财利来。","生意解曰":"生意初时利薄又防阻隔，交易宜从正道勿贪心妄取六，八，十一月有贵人可得厚财","开铺":"卜开铺之卦宜先改谢前年神恩，十一月应防劫厄，上春有阻勿灰心，秋后可得利。","合伙":"合伙经营必先改谢神恩伙计之间必须同心同德言行一致，六，八，十一月可得财利。","置货":"置货一事，因有神愿未谢，应及早改谢，后置货精心保管， 秋后可得大利。"},"出外":{"出外":"卜出外一事可大胆往前，凡事勿疑于二，三，五月一派好运自有贵人名利成就。"},"谋望求财":{"谋望":"沉迷踪迹未享通，今日承恩谢苍穹，改正前非行大道，自然财禄渐兴隆。","谋望解曰":"谋事前有阻隔，是无先许吓神恩，今欲重谋必先改谢神恩交秋后谋定成之","求财":"正财初时利薄，应求神后无谢神应当天改谢之宜正道经营交六，八，十二月地派兴旺重倍偏财勿取!"},"学艺功名":{"学艺":"卜学艺之卦，宜择吉日进艺门拜良师，勤学苦练定可学得手艺随身。","功名":"功名成就，荣宗耀祖，应谢天地浓恩。"},"行舟六畜":{"行舟":"行舟顺风得利，满载荣归，大吉大利。","六畜":"初时有阻宜谢神，喂养六畜手欲动。休教虚度年月日，可保平安利倍增。","猪羊":"饲养猪羊，应先改谢神恩，及后大胆精心喂养，多多益善，可卜平安得大利","草龙":"卜养草龙，水草调和，上春虽有小阻无妨，下春强壮漂亮，宜吓伯公保安","三鸟":"饲养三鸟，宜先改谢神恩，可以多养，精心料理，吓伯公保佑，可卜平安得大利。","田蚕":"田蚕早晚冬重倍大利，四季雨水大吉"},"移徙":{"移徙":"移徙大吉平安， 择其吉日，安然移之"},"行人":{"解曰":"数年来财信稀少，今年转运，有贵人重重，交三 五 九月定有佳音财帛回家","签文":"几年相别忆门闾，今日他乡遇故知，归期急如江上水，只争来早与来迟"},"婚姻":{"解曰":"婚姻是前缘配偶，不要计较资财轻重，自有贵人扶持定能成之","签文":"前缘配偶是今生，莫为资财重与轻，自有贵人扶持处，手攀丹桂上蟾宫。"},"官讼":{"解曰":"官司和之大吉，不可惹上忧愁是非，要有大量大福，但若告之 最后可得胜","签文":"夜来惧怯怕官方，事到头来险几场，自有贵人亲着眼，不须惆怅管无妨"},"失物":{"解曰":"东西失落在西方，求吓神明保佑，向西方向速寻找，可寻回 若迟难寻也","签文":"正奈傍人暗里持，分明失落在桥西，如今椅靠神灵佑，失去寻回不得迟"},"占病":{"解曰":"老年男妇应防凶跳，恐危也，宜移床位，中少年请，良医治之，吓神保佑，全俞平安","签文":"去年绝脱是非关，岂料天灾又染身，久雨得晴应在迩，良医手到卷浮尘"},"其他":{"灶君":"卜此灶位分金合于八宅之课，常时灶前修艷清净，烹煮大吉，可旺益財丁也","阳基":"卜阳宅土福不旺，宜安招财爷，修整门路居之，平安大吉","六甲":"此胎六甲生男，平安大吉，根基足养，可旺益父母，养育平安，应高谢天地浓恩","子息":"卜子息之卦，头二胎生子无妨，以后可生贵子，平安发达，能卦妻荫子也","祖山":"贵祖佳城横龙挂气结穴，气脉足旺，但嫌葬穴太低，坐向有利宜修葬穴高一位阴胎阳做并兜唇，又理唇口前水字分金配合清楚后，财丁兴旺，千子万孙","青草":"此地横龙挂气结穴，气脉足旺，点穴宜占高一位阴胎阳做并立兜唇，水字分金配合清楚，葬之昌盛，防口舌理妥"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  12,
  '襄王幢子',
  '小船出海之兆',
  '以为下卦',
  '酉鸡',
  '神女与王会于巫山十二峰，朝化为云，暮化为雨。然欢情有极，江水无情。王每亿梦，若有所失，意不能已。叹于佳期难再而世事飘零也。',
  '子有八张刀，安居事不劳;异风摇动处，犬吠万般高。',
  '杨花遭风',
  '{"签号":"第十二签","签名":"襄王幢子","签文类型":"小船出海之兆","卦象":"以为下卦","生肖":"酉鸡","签文简介":{"戏文":"神女与王会于巫山十二峰，朝化为云，暮化为雨。然欢情有极，江水无情。王每亿梦，若有所失，意不能已。叹于佳期难再而世事飘零也。","诗曰":"子有八张刀，安居事不劳;异风摇动处，犬吠万般高。","内兆":"杨花遭风"},"家宅运势":{"签文":"路险身衰暮夜归，谨防失足暗中非，家中小口遭灾祸，六甲田蚕也不亏。","解曰":"吉宅人口虽有喜气，但防冲也，还防夏秋口舌失财贼厄，门户小心田蚕有损皆因厝前受杀冲伤，宜求佛祖令旗安门上祭化，居住财丁兴旺。"},"岁君签":{"总诗":"扬花风卷消息将，恰似襄王忆梦来，夜静更残风力猛，乱飘零落洒莓苔。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基浅薄，惟防正、八、九、十一月灾难波阻，六甲妇勿近抱，吓天地化吉方保平安。","女":"小女根苗虽足，但防正、八、九、十一月灾难多事，守旧，吓月娘化吉方保平安。"},{"年龄":"4-7岁","男":"小儿之卦未美，但防正、八、九、十一月皮肤小疾，汤火小心，吓天地化吉方保平安。","女":"小女现年运限未美，但防正、八、九、十一月灾难波阻，守旧，吓月娘化吉方保平安。"},{"年龄":"8-12岁","男":"小儿之卦时令未美，虽天真，但防正、八、九、十一月小难波阻，宜吓天地化吉方保平安。","女":"小女运限未美，虽旺益上人，但防正、八、九、十一月灾疾之厄，吓天地化吉保平安。"},{"年龄":"13-15岁","男":"小童之卦时运未美，虽是聪明，但防正、八、九、十一月小疾多事，吓天地化吉方保平安。","女":"小女之卦运限未美，惟防小疾波阻，正、八、九、十一月守旧，夜勿远出，吓天地化吉保平安。"},{"年龄":"16-17岁","男":"祥造步运未美，签文杨花遭风，虽是通能，但防正、八、九、十一月小疾口舌，吓天地保平安。","女":"玉造运度美中不足，虽是贤玉，惟防正、八、九、十一月多生小疾，吓月娘化吉保平安。"},{"年龄":"18-29岁","男":"英造步运未美，似杨花遭风，虽有雄志，但正、八、九、十一月防口舌祸非，戒忍性气不可冲动，吓天地平安。","女":"玉造行运未美，似杨花遭风，防小疾波阻，正、八、九、十一月守旧，夜时勿外出，忍性，吓天地保平安。"},{"年龄":"30-55岁","男":"乾造步运未美，似杨花遭风，人虽才能，但防正、八、九、十一月不测之祸，戒忍性情，吓天地化吉平安。","女":"坤造行运未遂，虽贤淑，助益家庭，但防暗疾口舌，忌入丧门，正、八、九、十一月守旧，吓天地化吉平安。"},{"年龄":"56-69岁","男":"台造步运未美，似杨花遭风，防灾难，忌探病人，正、八、九月守旧，闲事勿理，吓天地化吉平安。","女":"坤造行运未美，虽有旺益家门财喜，但防暗疾口舌，凡事吞忍，正、八、九、十一月守旧，吓天地平安。"},{"年龄":"70岁以上","男":"福造老运不旺，惟防灾疾跌地之厄，早晚上落小心，夜时东南方勿往，守旧则吉。","女":"坤造老运不旺，虽有旺益子孙，但防暗疾风气，正、八、九、十一月守旧，勿外出则吉也。"}]},"生意":{"生意":"山高路险有阻坑，生意财利微些些，若是犬吠厚利得，藏货秋冬财利生。","生意解曰":"生意经营恐有风波阻挡，宜受旧业谨慎经营，九月起可得财，肖犬者得厚财","开铺":"卜开铺之卦宜从正直经营，忍口舌不得招灾惹祸，有小利可得，肖犬得厚财利。","合伙":"卜合伙之卦似扬花遭风，恐伙计不同心合之亏本破财!","置货":"置货初有阻失，切谨慎，要有胆智置之，秋冬月定有提价，能得财利也。"},"出外":{"出外":"卜出外一事如小船出海之兆，恐防小人生端寄祸，宜从正道小心经营免生愁。"},"谋望求财":{"谋望":"欲想前时勉强财，扪心自问尔应灾，君要安为非理事，不招祸至祸自来。","谋望解曰":"谋事恐防是非失财凡事宜从正道，候四，九月时萧犬者谋定成之，余人勿谋","求财":"正财库运未至宜守旧经营，防小人阻隔交九月起渐渐好转，有财利可得，偏财勿取若取之取恐防要失也"},"学艺功名":{"学艺":"卜学艺之卦，时运未到，学之无成，宜自己学习，候时运到时拜师学之。","功名":"功名不成，不吉也，惟肖犬者可得也。"},"行舟六畜":{"行舟":"行舟不顺 恐有破失 切宜守旧","六畜":"今岁六畜不安然，妖魔鬼怪损猪羊。耕牛若是定要养，求祷神明保吉祥。","猪羊":"猪羊之卦 恐防四 七 九月阻失 大中只猪羊及时发售 吓伯公保平安","草龙":"卜养牛之卦今年水草不调和 又防脚疾 母牛更防歹人毒害宜吓本境伯公保乎安","三鸟":"卜养三鸟之卦 不可多养 多养定失 恐防四 七九月阻疾 宜吓灶君化吉","田蚕":"田蚕晚二冬有失不吉 四季雨水不吉"},"移徙":{"移徙":"移徒危邦不入 乱邦不居 败乡不可移"},"行人":{"解曰":"行人时运不美，恐防小人阻隔波累，数年以来财信有虚无实，现年九月有佳音。","签文":"鱼沉雁杳去无踪，因旅穷途阻不通，万里故乡归不得，阳关回首白云封"},"婚姻":{"解曰":"姻缘未有，命里不相同劝君切莫听媒人话，若是暂时谋之也不长久","签文":"未有姻缘不主张，两家命里不相同，媒人只说瞒人话，媒得成来也不长。"},"官讼":{"解曰":"横祸到来，有许多不便之处，使君忧郁，如今还是以和为贵，不和祸重重。","签文":"横事有无徒地来，心中忧闷几时开，如今不若和为贵，名得将身到宪台"},"失物":{"解曰":"失物原来不是自己的家财，失去何须着意悲哀，若不遗失东西，定有灾祸飞来","签文":"原来不是自家财，何用叼叼着意猜，不想破财心折怀，纵然失得了着意。"},"占病":{"解曰":"梦人幽冥，落花有意，流水无情，凶也，危也，恐怕死有七成，宜诚心速求城皇爷保之","签文":"梦入幽冥路已斜，投神空自怨嗟嗟，落花有意随水流，流水无情恋落花"},"其他":{"灶君":"卜此灶位虽美 但嫌灶前迫塞受门窗杀冲伤宜遮盖 灶前修净 烹煮兴隆","阳基":"卜阳宅屋前烟简火烟杀及白虎有目角石杀 宜立人卦抵料 起造有是非口舌 宜理妥","六甲":"六甲生女安 生男有阻 生母若不顺 子忍不长久 宜拜契神明或过继 行善事","子息":"卜子息之卦 命带孤鸾 虽有得也难养 子息成人也恐无孝敬父母也。","祖山":"卜贵祖佳城横龙结穴 气脉足 但嫌点穴太低白虎畔空野如有利宜修繁高三 五尺 沉阳做 并填白虎畔潮顶并兜唇 财丁兴降","青草":"卜此地有橫龙结穴 气脉足旺 但嫌葬后有是非以舌阻.宜理清楚 葬时点穴宜占高 沉阳做吉 葬后财丁旺也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  13,
  '吕蒙正两世姻缘',
  '万物逢春之兆',
  '大吉之卦',
  '申猴',
  '吕蒙正前期刘氏守寒窑受虐而亡，转世为渔翁女，丽色而拳手不开。吕呼之，其掌顿开，渔翁女乃嫁吕，生子吕子骞，骞生孙亦贤。俱登科。',
  '禹门跳浪翻，鱼变化为龙;已意成君意，方为吉亨通。',
  '脱衣换锦',
  '{"签号":"第十三签","签名":"吕蒙正两世姻缘","签文类型":"万物逢春之兆","卦象":"大吉之卦","生肖":"申猴","签文简介":{"戏文":"吕蒙正前期刘氏守寒窑受虐而亡，转世为渔翁女，丽色而拳手不开。吕呼之，其掌顿开，渔翁女乃嫁吕，生子吕子骞，骞生孙亦贤。俱登科。","诗曰":"禹门跳浪翻，鱼变化为龙;已意成君意，方为吉亨通。","内兆":"脱衣换锦"},"家宅运势":{"签文":"今年不似去年贫，财禄重添遇贵宾，人口完成无盗贼，平安赛过九洲人。","解曰":"喜气洋洋，但防疾难口舌失财盗贼之厄，门户小心皆因祖山不顺，有利宜修整合课，吓佛祖保平安，并求福灯吊门上化吉，则财丁可兴旺也。"},"岁君签":{"总诗":"开花结果喜逢时，赖得天官造化机，谋望求财皆遂意，衣锦还乡事可期。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足养，八字清秀，旺益上人并茂，上春月虽有小疾无妨，吉星守命平安。","女":"小女根苗稳固，有旺益上人并茂，上春月虽有皮疾无妨，卦中吉星守命平安。"},{"年龄":"4-7岁","男":"小儿现年亨通，天真活泼，利益上人并茂，夏月水边小心，吉星守度平安。","女":"小女运限顺遂，各事伶俐，旺益上人并茂，夏月水边小心，幸吉星守命平安。"},{"年龄":"8-12岁","男":"童造现年运度叶吉，天真伶俐，可入学校读书，定卜进行，夏月水边小心，幸吉星守命平安。","女":"小女之卦时令亨通，各事活泼，有旺益上人并茂，夏月虽有小疾无妨，吉星守度平安。"},{"年龄":"13-15岁","男":"童造运度精通，各事聪明开窍，宜培养入学校读书，定卜进步，出入平安。","女":"玉造运度顺遂，活泼精巧，上春月虽有小疾无妨，吉星守命出入平安。"},{"年龄":"16-17岁","男":"吉造现年运度亨通，如鱼化龙，聪明才干，培养入学，远景有望，而且出入平安。","女":"玉造今年交上美运，如鱼化龙，助益家庭，虽有小疾无妨，吉星守度平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如鱼化龙，通能才干，可向外争取，上春月虽有小疾无妨，有贵人扶助，可得财喜平安。","女":"坤造行运交泰，如鱼化龙，贤玉技巧，有助益家庭之心，上春月小疾无妨，吉星守度玉体安康也。"},{"年龄":"30-55岁","男":"乾造步运亨通，如鱼化龙，为人才能特达，向外从正发展，有贵人扶助，可得财喜，但勿迫性平安。","女":"坤造行运交佳，如鱼化龙，贤惠有内助之称，虽有些小安吉无妨，卦中吉星守命平安。"},{"年龄":"56-69岁","男":"台造步运顺遂，为人忠诚，君家之卦如鱼化龙，上春月虽有小疾无至大害，有贵人扶助可得财运平安。","女":"坤造行运亨通，可称内助，但有小暗疾无妨，忌看病人，喜孝物勿进，幸吉星守度平安。"},{"年龄":"70岁以上","男":"福造老运得此卦太旺，虽有旺益子孙，但防灾疾跌地之厄，上春月守旧，幸贵人扶助晚景胜前平安。","女":"妇造老运安康，旺益子孙，但防暗疾多灾，上春月喜孝物勿食，宜守旧，幸吉星守命，老福绵长。"}]},"生意":{"生意":"市场货物能购收，精心保管把货留，莫怕初时有阻败，秋至价高利倍售。","生意解曰":"生意之卦初时财利稀少，但与人交易宜立志坚持候五，九，十一月可得厚财利。","开铺":"卜开铺之卦宜秋后开业可一帆风顺得财利，若春夏月开业，宜请佛祖符令贴门上化吉也。","合伙":"卜合伙之卦大吉伙计宜同心同德协力经营，候交秋冬月可得大财利也。","置货":"置货起初价不振，宜放心存留，候交秋月，货物定有振价，可得财利也。"},"出外":{"出外":"卜此出外之卦，各事亨通，有贵人扶助，应于三、五、九月往外，定有厚财利可得。"},"谋望求财":{"谋望":"玉体冰肌不可移，真心之有寒岁知，如今喜得阳和日，花落自然中满枝。","谋望解曰":"谋事有贵人扶助，交秋月可定就，但不能三心二意应一心一意，认真谋之","求财":"正财上半年稀少宜守旧刻苦经营，交五，六，十一月财利亨通，可得厚财大利，偏财初有阻隔后可得，但切须忍口舌!"},"学艺功名":{"学艺":"卜学艺之卦，时令合局，有贵人扶助，宜决心立志，寻得名师传艺也。","功名":"功名中，衣锦荣归，若九月赴试定显达。"},"行舟六畜":{"行舟":"行舟先难后易，秋后出船大吉。","六畜":"要问家中猪牛羊，精心饲养多吉祥。祈祷神明力保佑，猪肥牛壮财利长。","猪羊":"猪羊之卦 要精心饲养 求吓神明保佑饲料调和 饲养顺利 有厚財利可得","草龙":"卜养牛之卦 水草调和 使用顺利平安可旺益家道兴隆 母牛若有子宜细心吸养","三鸟":"卜养鸡彰鸭之卦 饲料调和 平安顺利 但要稍心管理可大投资金 能得大利","田蚕":"田蚕早中晚大吉可得大利 风调雨顺"},"移徙":{"移徙":"移徒未可移 守旧吉 居原厝可平安"},"行人":{"解曰":"路中停留不能回家 但行人在外特达有费人扶助 候三 五 十一月 有佳音回家也","签文":"行人心事意徘徊 路途牵连尚未回 寅卯待交辰已日 依然平地一声雷"},"婚姻":{"解曰":"郎才女貌前缘配定，美满婚姻应及早托人前往说定，定期上聘勿失良机出外;一事名事亨通有贵人扶助，应于三，五，九月往外定有厚财利可得!","签文":"才郎女貌世间稀，前缘配定不须疑，如今但愿他人准，好把聘财去定期。"},"官讼":{"解曰":"官讼要以和为费 但若是小人挑唆 被迫上公堂 自有贵人扶助 得胜回归","签文":"小辈挑唆未了宁 如今不怕上公庭 官衙自有真明镜 曲直分明免教刑"},"失物":{"解曰":"失物在东方不可乱疑平人亲友而惹起是非 要从东方仔细寻找 可得见也","签文":"浮财失去向谁将 莫把平人要细详 汝正的然西向坐 原来此物在东方"},"占病":{"解曰":"星害占度 疾病缠身 应先求神明保佑 逢凶化吉后请良医治之老少平安","签文":"皇官顺至保无愆 有病缠身不自然 若得明师来说及 不如求福谢苍开"},"其他":{"灶君":"卜此灶位分金合课 但嫌灶前久年秒气宜重做新灶 灶前修清洁 烹煮大吉","阳基":"卜起造阳基初有小阻 忍让之建大吉 老阳居坐东分金者屋前受杀 立八卦抵挡 居住不差","六甲":"六甲生男平安根基足养 应签谢天地佛祖之神恩及先祖施行美德之惠也","子息":"卜子息之卦 先女后男 命寿清格高贵 将来子总溯堂 可喜也","祖山":"卜贵祖佳城横龙转落结穴气脉足旺 但嫌葬穴孤阴 如已葬财丁不顺不旺坐向有利宜修整坟山阳气并做葬兜唇修水路胡堂之后 财丁兴旺也","青草":"此地横龙转落结穴 气脉足旺 葬时宜修阳气 并兜唇 修来水朝堂 葬后子孙兴隆也 葬时有些小口舌 宜忍让"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  14,
  '夏德海投文',
  '谋望时代之兆',
  '中平之卦',
  '未羊',
  '蔡端明母渡洛阳，遇风浪。时母腹怀端明，乃祷告上苍，若天使平安渡河，得产麟儿，必造桥以通人。告毕，风浪遂止。母平安归。后蔡端明中状元，乃偿母愿造桥，使家奴夏德投文东海龙王，求退潮。王允，桥告造成。',
  '物重须当力，黄幡因脚长;一帆风信转，消息报回乡。',
  '龙蛇混杂',
  '{"签号":"第十四签","签名":"夏德海投文","签文类型":"谋望时代之兆","卦象":"中平之卦","生肖":"未羊","签文简介":{"戏文":"蔡端明母渡洛阳，遇风浪。时母腹怀端明，乃祷告上苍，若天使平安渡河，得产麟儿，必造桥以通人。告毕，风浪遂止。母平安归。后蔡端明中状元，乃偿母愿造桥，使家奴夏德投文东海龙王，求退潮。王允，桥告造成。","诗曰":"物重须当力，黄幡因脚长;一帆风信转，消息报回乡。","内兆":"龙蛇混杂"},"家宅运势":{"签文":"不宗香火不收身，未开家门伏祀神，若要财兴人口旺，除非安谢久家神。","解曰":"吉宅人口可得喜气，但防三,四月疾难口舌，祸非失财皆因失祀祖上香灯，嫌灶君不旺，安祀祖上香灯，重做新灶吓佛祖保财丁兴旺。"},"岁君签":{"总诗":"龙蛇混杂最难分，未得风雷变化麟，一日腾云归北海，那时方得见龙津。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗虽足，但防三、四、六月灾难波阻，吓吴爷化吉，交秋返运平安。","女":"小女根基浅薄，但防三、四、六月小疾多事，吓月娘化吉，交秋返运平安。"},{"年龄":"4-7岁","男":"小儿之卦时令未美，惟防三、四、六月小疾，汤火之厄，吓吴爷，交秋返运平安。","女":"小女运限未美，惟防三、四、六月灾难，汤火小心，吓吴爷化吉，交秋返运平安。"},{"年龄":"8-12岁","男":"小儿运度未美，虽天真，防三、四、六月灾难波阻，吓吴爷化吉，交秋返运平安。","女":"小女现年运限未美，虽天真，防三、四、六月脚手痛疾，吓天地化吉，吓天地化吉，交秋返运平安。"},{"年龄":"13-15岁","男":"童造今年运度不美，惟防三、四、六月灾难波阻，勿执己僻，吓吴爷化吉，交秋返运平安。","女":"玉造现年运度未遂，但防三、四、六月小疾，汤火之厄，宜小心，吓吴爷化吉，交秋返运，出入平安。"},{"年龄":"16-17岁","男":"祥造步运未美，龙蛇混杂，防三、四、六月小疾多灾，守旧，学习文化，吓吴爷化吉，交秋转运平安。","女":"玉造人虽贤玉，但嫌自执己意，又防三、四、六月灾难，夜时勿外出，吓月娘化吉，交秋步入佳景。"},{"年龄":"18-29岁","男":"英造步运未美，龙蛇混杂，虽有智慧，但防三、四、六月口舌祸非，凡事戒忍，吓吴爷交秋转运可得财喜。","女":"玉造人虽贤玉，但美中不足，龙蛇混杂，但防三、四、六月小疾波阻，夜时东西方勿往，吓吴爷化吉平安。"},{"年龄":"30-55岁","男":"乾造步运未美，龙蛇混杂，防三、四、六月灾难祸非，宜戒性，吓天地，交秋转运，可得财喜平安。","女":"坤造行运未美，人虽清秀，但嫌心内迫杂，凡事温柔忍性，三、四、六月守旧，吓吴爷化吉方保平安。"},{"年龄":"56-69岁","男":"台造步运不美，似龙蛇混杂，人虽忠厚，但防三、四、六月不测之祸，凡事宽怀大量，闲事勿理，交秋平安。","女":"坤造行运虽有助益家庭，但嫌操心暗疾，凡事吞忍，三、四、六月守旧，忌看病人，吓天地保平安。"},{"年龄":"70岁以上","男":"福造老运不旺，诚恐交脱，早晚上落小心，忌入丧门，三、四、六月守旧，交秋大造平安。","女":"妇造老运不旺，老风暗疾，凡事静养，忌看病人，三、四、六月守旧，交秋福体安康。"}]},"生意":{"生意":"生意欲做有偏财，购货恐防假不知，货物不可多留久，守旧经营利路开。","生意解曰":"生意欲做要守旧经营，防三，四月小人拐骗累害，交易欲认真谨慎秋后可得财利。","开铺":"卜开铺之卦宜守旧经营防歹人拐骗，以假弄真购买货物谨慎秋后有财利也。","合伙":"卜合伙之卦似龙蛇混杂之兆，恐伙计不同心口舌是非多，勿合免失财利也!","置货":"卜置货物初时可有得利，但防日后阻失，所置之货不可久留，应快速发售也。"},"出外":{"出外":"卜出外一事龙蛇混杂内中有事物阻隔，做事勿三心二意，宜守旧经营则安然。"},"谋望求财":{"谋望":"两头事务尚蹉跎，见好因循本分过，自谋得来不长久，眼前求得也清磨。","谋望解曰":"卜谋事初时有阻隔，宜用劳力心处理之可以成功，但恐不久吓神明保佑也","求财":"正财虽是有得但不安稳，恐阻失宜立志刻苦经营，秋后有财利可得，偏财可取但应忍口舌!"},"学艺功名":{"学艺":"卜学技艺之卦，恐君三心两意，不定主意，难以学得手艺，候秋后择吉日从师，则可成功。","功名":"功名难得，若中之也，恐寿不久也。"},"行舟六畜":{"行舟":"行舟有阻，不吉不安，不可出行。","六畜":"六畜有阻猪牛羊，饲养恐防不吉祥。切切不可贪多养，精心勤养少财钱。","猪羊":"猪羊之卦不吉 不可养 养之恐不长久 防三 四月阻隔 用苦力 吓伯公保平安","草龙":"卜养牛之卦不吉 恐防三 四 六月阻𨺲 脚疾等病患宜苦力饲养 吓伯公保安","三鸟":"饲养三鸟之卦不吉 要养三四只为宜 不可多养 防三 四 六月阻隔 灾疾 吓怕公化吉","田蚕":"早不吉晚有失 快速收成雨水中顺"},"移徙":{"移徙":"不可移之 内有先祖家神 理妥后移之"},"行人":{"解曰":"行人少后身体健康 但无音信者是因为同伙牵连候二 五 七 十一月有佳音回家","签文":"行人去后不回家 同伴牵连不怨嗟 要见直逢王祭日 故人方始出天涯"},"婚姻":{"解曰":"婚姻不成恐被人占害，若成这恐不合或合之不久，且惹是非也","签文":"婚姻不与众人知，失却伦常邂逅迟，若不被人强占害，亦遭官府受鞭苔。"},"官讼":{"解曰":"告之理屈 既受灾刑又恐失财 和之免受刑苦 虽是破财也 不要可惜吧","签文":"人鬼相交遇妖魔 难分曲直受奔波 不如忍却心头火 免得身受苦磨多"},"失物":{"解曰":"失物难寻 现在要寻得见 须待交秋冬月便行人说知机 寻之或可见","签文":"失去浮财莫怨穷 要寻目下不能从 直交风冷寒箱至 方得傍人说实踪"},"占病":{"解曰":"有阴邪交缠 宜读圣帝经或太阳经一仟本 不但病好而且介家平安大吉","签文":"玉石难分假和真 阴阳冷暖未安宁 早用宝香焚一炷 免得阳间阴害人"},"其他":{"灶君":"卜此灶位不吉 灶迹移气不净 宜择吉日 重作做新灶 烹煮叶吉也","阳基":"卜阳宅因有香灯奉祀不周 土神太重.宜谢土神并查明奉祀 阳基起造有非口舌 宜守旧吉","六甲":"六甲生女安 若生男 在上春产育恐有阻隔 下春产育则吉 但应移房拜契保佑","子息":"子息虽有 但恐不孝 宜加强孝道教育 不要娇生世养 误了教育时机","祖山":"卜贵祖佳城横龙结穴 气脉文雅但婊葬后财丁不顺 即辰已方受峰杀冲伤 坐向有利宜修傍唇祭化之后 财丁昌盛","青草":"卜此地横龙结穴气脉足旺 但恐葬时有口舌阻 又嫌辰已方有杀冲伤应消掩冲杀 做法宜沉阳 则财丁旺也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  15,
  '诸葛亮出身',
  '谋为果决之兆',
  '大吉之卦',
  '午马',
  '诸葛亮隐居隆中躬耕垄亩，而志在天下。刘备从徐庶荐，三顾茅庐。亮感其情直义重，始与之纵论天下形势，陈治世之策，弄出助刘备逐鹿中原，建立蜀国。',
  '一日赴东升，二日水中明;春风和气暖，禄马进门庭。',
  '旭日东升',
  '{"签号":"第十五签","签名":"诸葛亮出身","签文类型":"谋为果决之兆","卦象":"大吉之卦","生肖":"午马","签文简介":{"戏文":"诸葛亮隐居隆中躬耕垄亩，而志在天下。刘备从徐庶荐，三顾茅庐。亮感其情直义重，始与之纵论天下形势，陈治世之策，弄出助刘备逐鹿中原，建立蜀国。","诗曰":"一日赴东升，二日水中明;春风和气暖，禄马进门庭。","内兆":"旭日东升"},"家宅运势":{"签文":"保得自家莫取钱，好香烧炷谢苍天，田蚕六畜皆兴旺，受佛今年胜旧年。","解曰":"吉宅人口可得喜气，但防三四月口舌涉财，主事人不义之财勿取宜虔诚当天改谢神恩，请佛祖福灯安吊门上祭化之后居住财丁兴隆也。"},"岁君签":{"总诗":"月满今霄离海边，时人感仰赖青天，清光照耀难星退，君子求谋便得官。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足养，八字清秀，旺益上人并茂，三、四月小疾无妨，吉星寿命绵长。","女":"小女根苗足旺，利益上人并茂，夏月虽有小疾无妨，有吉星守命平安。"},{"年龄":"4-7岁","男":"小儿运限叶吉，生性天真活泼，有旺益上人并茂，夏月小疾无妨，吉星守命平安。","女":"小女今年顺遂，伶俐活泼，旺益上人并茂，夏月虽有小疾无妨，出入平安。"},{"年龄":"8-12岁","男":"小童今年上运，各事伶俐，宜入学校读书，定卜进步，三、四月小疾无妨，吉星守命平安。","女":"小女运限顺吉，伶俐活泼，旺益上人并茂，三、四月小疾无妨，吉星守度平安。"},{"年龄":"13-15岁","男":"童造运度亨通，聪明开窍，可入学校读书，定卜进步，前途有望，出入平安。","女":"玉造运度叶吉，各事伶俐，三、四月虽有小皮疾无妨，有吉星照身出入平安。"},{"年龄":"16-17岁","男":"吉星步运亨通，如日东升，各事通情达理，三、四月小疾无妨，吉星守命平安。","女":"美造运度亨通，如月之明，五行清秀，三、四月小疾无妨，吉星守命渐入佳景平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如日东升，做事才能，三、四月虽有小疾无妨，有贵人扶助，可得财喜，且出入平安。","女":"玉造行运交泰，如月之明，五行清秀，四柱安和，助益家门，三、四月小疾无妨，吉星守命平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如日东升，老练经济，可得财运，但凡事从正向外发展，有贵人扶助出入平安。","女":"坤造行运交泰，如月之明，贤淑智慧，助益家庭，三、四月虽有小疾无妨，有吉星照身平安。"},{"年龄":"56-69岁","男":"台造步运亨通，如日东升，忠诚老练，有财运可得，但凡事宽怀，三、四月小疾无妨，贵人扶助平安。","女":"坤造行运叶吉，各事智慧，可称内助，但勿操迫，暗疾无妨，三、四月守旧，幸吉星守命平安。"},{"年龄":"70岁以上","男":"台造老运安康，老当益壮，有些小疾无妨，福星拱照，晚景胜前平安。","女":"妇造老运交泰，旺益子孙，有些暗疾无妨，有吉星照身，步入佳景平安。"}]},"生意":{"生意":"春夏财利虽有亏，明智壮大购货归，收购货物仓中放，秋冬出售利非微。","生意解曰":"生意之卦如龙蛇混杂，恐三,四月有阻隔应谨慎，有贵人扶助五，八，十一月有厚利。","开铺":"上春恐有阻隔小利，候秋冬月生意兴隆，有贵人扶助源广进。","合伙":"大吉有财利可得但防歹人破坏，忍口舌伙计应同心协力经营顺昌也!","置货":"卜置货初有交拼，若有胆量多取，交秋冬时节货物振价，可得厚财大利也。"},"出外":{"出外":"卜出外一事时运当权，谋事应有胆量任其向往，有贵人扶助可卜名利双全!"},"谋望求财":{"谋望":"此身相逢更遇邀，龙蛇天外拔迢迢，平生伴你营随意，云有天梯水有路。","谋望解曰":"谋事定成但有些口些舌无妨,宜立智前进有贵人扶助可得名利双成","求财":"正财取之有得但恐防三，四月阻隔，应果决进前交五，八，十一月有厚利入手，偏财有小人恐有官非破财，到底平安也!"},"学艺功名":{"学艺":"卜学技之卦，为谋为果决之兆，勿三心二意，应一心一意，下决心学习，定得名师传真艺也。","功名":"功名肖龙猴之人定可显达，余者龙猴科中。"},"行舟六畜":{"行舟":"行舟顺风，时运亨通，得利大吉。","六畜":"六畜肥大且平安，虽有小阻心莫慌。祈祷神明来保佑，猪牛羊群只只全。","猪羊":"饲养猪羊 饲料调和 但防三四月有小阻五月起养之顺利 到底可得大利","草龙":"卜养牛之卦大吉 水草调和 精心饲养 可卜体壮力强 使用顺利平安也","三鸟":"饲养三鸟饲料调和 初有小阻妨 宜精心料理到底可得厚財利","田蚕":"田蚕早中平 晚大吉 四季雨水遂意"},"移徙":{"移徙":"移徒平安 切切速移得利大吉"},"行人":{"解曰":"行人在外得运 如日东升 有赞人扶助 于二 五 八 月有佳音财帛回家也","签文":"去时曾约又相逢 今日音信又不通 阻滞淹留三五日 管教财宝物盈丰"},"婚姻":{"解曰":"前生注定男才女貌俩相配，宜诚心配偶先谢天地，夫妻可得百年皆老","签文":"前生注定是姻缘，好貌才郎登对年，要虔事心酬天地，管教夫妻两团圆。"},"官讼":{"解曰":"官讼胜但恐防要失财 还防有些小人阻隔 宜认真用智对付 定能得理回归","签文":"汝本聪明特达人 偶遇淹滯损精神 云消雨散终须静 观见祥光四海明"},"失物":{"解曰":"失物速寻 便可见之但要求吓灵神 指明方向踪迹然后寻之 便能得见","签文":"失去踪迹过别厢 如今休要乱糊详 今朝自有傍人见 便告灵神保吉祥"},"占病":{"解曰":"疾病缠身 不能驱除 是良医未至 至切寻医求 求佛祖保佑底子平安 老防危","签文":"心中无事意踌躇 终日沉吟觅巫医 自是善才难割合 谁知祸去福来随"},"其他":{"灶君":"卜此灶位分金合于八宅之课 平时灶前修理清净 烹煮大吉 可旺益财丁也","阳基":"卜旧阳宅门庭有杀冲伤 立八卦抵挡居住平安 起造新阳宅辰卫方有杀冲伤 宜掩祭起造颠吉","六甲":"此胎六甲可得男儿 平安大吉 四亲六誉贺之此乃祖上积德之报应也","子息":"卜子息之卦大吉 不但有子 而命格清秀 聪明智意 中年得者更妙也","祖山":"卜贵祖佳城有结穴气脉足旺 但嫌葬法未真 坐向有利宜修整阳气并兜唇掩青龙畔杀耀之后 财丁兴旺子孙平安","青草":"此地龙脉文雅 但兼辰已方有峰杀冲伤葬穴宜沉阳并兜唇舞时防口舌宜立胆智 果决葬之 葬后财丁两旺也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  16,
  '关公带嫂秉烛待旦',
  '重囚望赦之兆',
  '下下之卦',
  '巳蛇',
  '关羽被曹兵围困土山，为救嫂计，约三事，降汉不降曹。赴许昌途中，夜歇驿馆，曹操欲乱其君臣之礼，使关公与二嫂同处一室，关公乃秉烛立于户外，达旦无倦色。曹操见关公忠义至此，益重之。',
  '秉烛对佳人，风吹烛泪垂;且防猪与犬，恐惹闲中非。',
  '浊油点灯',
  '{"签号":"第十六签","签名":"关公带嫂秉烛待旦","签文类型":"重囚望赦之兆","卦象":"下下之卦","生肖":"巳蛇","签文简介":{"戏文":"关羽被曹兵围困土山，为救嫂计，约三事，降汉不降曹。赴许昌途中，夜歇驿馆，曹操欲乱其君臣之礼，使关公与二嫂同处一室，关公乃秉烛立于户外，达旦无倦色。曹操见关公忠义至此，益重之。","诗曰":"秉烛对佳人，风吹烛泪垂;且防猪与犬，恐惹闲中非。","内兆":"浊油点灯"},"家宅运势":{"签文":"只因不肯敬神明，惹得家中事不宁，今岁若除灾与难，除非重整久家声。","解曰":"吉宅人口可得喜气，但防四, 九，十月祸非疾难失财，肖猪狗之人恐惹祸非，宜安份守已，向佛祖奉经拜祖上香灯，做过新灶居住财丁兴旺兴。"},"岁君签":{"总诗":"浊油点灯灯自灭，方才剔起又垂微，长心烧书空劳力，何不将身忙自归。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗虽旺，但防四、六、九、十月灾难波阻，六甲妇勿近，向佛祖添油化吉平安。","女":"小女根基浅薄，惟防四、六、九、十月小疾波阻，吓佛祖化吉方保平安。"},{"年龄":"4-7岁","男":"小儿之卦运限未美，但防四、六、九、十月小疾汤火之厄，向佛祖添油化吉平安。","女":"小女现年运限未美，惟防灾难波阻，四、六、九、十月守旧，向佛祖添油化吉平安。"},{"年龄":"8-12岁","男":"童造运度现年时令未美，防波阻之厄，四、六、九、十月守旧，吓佛祖化吉平安。","女":"小女现年运限未美，四、六、九、十月防有小难灾疾，守旧，吓佛祖化吉平安。"},{"年龄":"13-15岁","男":"童造运度未美，虽聪明，但防四、六、九、十月灾难之厄，宜向佛祖添油化吉平安。","女":"玉造运度美中不足，惟防六、九、十月多生波阻水厄，向佛祖添油化吉平安。"},{"年龄":"16-17岁","男":"祥造步运未美，四、六、九、十月恐有小疾口舌，守旧，勿远出，吓佛祖化吉平安。","女":"玉造美中不足，虽技巧，但防四、六、九、十月多事，夜时勿外出，吓月娘化吉平安。"},{"年龄":"18-29岁","男":"英造步运不美，似浊油点灯，惟防六、九、十月小疾口舌，凡事戒忍，向佛祖添油化吉方保平安。","女":"玉造行运不佳，似浊油点灯，人虽贤玉，但防小疾波阻，四、六、九、月夜时勿远出，向佛祖添油平安。"},{"年龄":"30-55岁","男":"英造步运不美，似浊油点灯，人虽老练，但防六、九、十月不测之祸，宜从正不可冲动，吓天地化吉平安。","女":"坤造行运美中不足，人虽贤淑，但嫌操心迫杂，暗疾口舌，六、九、十月吞忍性气，吓老爷化吉方保平安。"},{"年龄":"56-69岁","男":"台造步运不美，虽老练，但防四、六、九、十月灾难口舌，凡事戒忍性情，闲事切勿近理，底子平安。","女":"坤造行运未美，操心暗疾，凡事吞忍，四、六、九、十月守旧，夜时切勿外出，宜静养，底子平安。"},{"年龄":"70岁以上","男":"福造老运不旺，可比风中点烛，惟防六、九、十月灾难跌地之厄，早晚上落小心，守旧则大吉平安。","女":"坤造老运美中不足，操心劳烦暗疾上身，四、六、九、十月守旧，忌看病人，喜孝物勿近则平安。"}]},"生意":{"生意":"何必次次费心机，用尽苦力财力稀，口舌欲任偏财勿，正财守旧能得利。","生意解曰":"生意似穿破鞋过水，防小人耗财，与人交易信直中直，宜苦力不从经营可得财力","开铺":"卜开铺之卦为浊油点灯，恐防大火是非口舌，小人耗财宜过旧经营平安也。","合伙":"卜合伙之卦不吉伙计多心，恐防是非口舌，亏本切勿合，合之定失!","置货":"卜现年置货小利，宜用苦心经营，恐防口舌是非，不可贪财利则吉。"},"出外":{"出外":"卜出外一事因时令不美，恐防小人生端，宜守旧经营方保无忧!"},"谋望求财":{"谋望":"覆危渡水两头难，万计千磨财利艰，守份安贫宜忍耐，忙忙劳力不如闲。","谋望解曰":"谋事不成如破鞋覆渡水，艰难重重防歹人祸害，九，十月更应谨慎防备","求财":"正财库利小九，十月有歹徒负累，宜稳重谨慎经营，见利取利得之安，偏财定失，分文勿取也!"},"学艺功名":{"学艺":"卜学技艺之卦不美，恐君主意不定，三心二意，半途而废，一无所成也。","功名":"功名不中，肖猪者若进场，恐不吉有失。"},"行舟六畜":{"行舟":"行舟不顺，切不可行，守旧平安。","六畜":"今年六畜财利疏，不可贪心想养多。阻隔须吓伯公去，保佑平安灾祸无。","猪羊":"卜猪羊之卦 恐防四 九 十月阻失 不可贪养 养中大只要及时卖 吓伯公化吉","草龙":"大武养之恐防脚疾 长肥不得 使用应小心 不可过度 宜向佛祖添油大吉也","三鸟":"饲养三鸟 恐防四 九 十月阻失 不可多养 宜向佛祖添油 逢凶化吉也","田蚕":"早蚕早晚二冬皆不吉 四季雨水中平"},"移徙":{"移徙":"移徒切不可移之 守旧平安"},"行人":{"解曰":"行人在外时令不美 恐防小人阻隔或疾难 宜向佛祖添油 保信息早日回家","签文":"身衰力弱路难行 只迟家乡万里程 且向道中求善福 免教风雨送愁声"},"婚姻":{"解曰":"婚姻不成有小人重重，纵然成之恐不长久，也许被歹徒占有","签文":"方才说起惹忧愁，想是姻缘不到头，如今若得言相许，又恐吓旁人暗里谣。"},"官讼":{"解曰":"此卦必须以和为上策 不可好胜若呈强定遭灾难 及早退却可保平安也","签文":"万事无祸一理真 何须苦苦道艰辛 不如及早回头去 到底须防宠害人"},"失物":{"解曰":"东西是因为不小心而失劫 现在难以寻回 但失去浮財可免灾害身也","签文":"昨天浮财莫认真 归来且勿怨他人 宽怀休要心头忖 破了浮财免害身"},"占病":{"解曰":"占病之卦宜请良医治之 向佛祖诵经添油灯 求佛祖保安 老凶少平安","签文":"优疑空费枉资财 流水无情去不来 半点残灯幽故尽 又遭一阵大风来"},"其他":{"灶君":"卜此灶位不净 择吉日重新作过 是戌亥方灶位切宜移徒 烹煮叶吉也","阳基":"卜新建阳宅定有口舌阴隔 又嫌水神不美 勿取之吉 卜老阳宅龙运不旺 有利宜修整居住大吉","六甲":"六甲生女吉 若生男恐有阻隔 宜移房过祖向佛祖添油 求佛祖保平安","子息":"子息虽有得 但嫌初防霉星末退 子息宜迟得 并多做善事 可望后代继承人也","祖山":"卜贵祖佳城结穴 但嫌龙运不旺 又嫌水阳走 葬后十年旺过后防破失至切宜修龙运壮旺并理水神归口 财丁足旺","青草":"此地龙脉足旺 但 戌亥方有峰杀冲伤又嫌水阳走 葬穴宜沉阳并理妥水神归口 葬后则房房子孙财丁兴旺也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  17,
  '王省就亲',
  '一牛二尾之兆',
  '中平之卦',
  '辰龙',
  '恶少番奉欲霸余三姑为妻。三姑随夫王省避居姑母家中。表兄秦招吉贪三姑色，醉王省，冒报王省名，夜敲三姑居室相戏，欲乱之时适番奉使白面虎寻杀王省，秦乃被错杀，王遂坐罪。幸包公查访重审，案情始大白。',
  '才子遇佳人，红霞映碧波;文书今日至，凡事起荣华。',
  '枯树生枝',
  '{"签号":"第十七签","签名":"王省就亲","签文类型":"一牛二尾之兆","卦象":"中平之卦","生肖":"辰龙","签文简介":{"戏文":"恶少番奉欲霸余三姑为妻。三姑随夫王省避居姑母家中。表兄秦招吉贪三姑色，醉王省，冒报王省名，夜敲三姑居室相戏，欲乱之时适番奉使白面虎寻杀王省，秦乃被错杀，王遂坐罪。幸包公查访重审，案情始大白。","诗曰":"才子遇佳人，红霞映碧波;文书今日至，凡事起荣华。","内兆":"枯树生枝"},"家宅运势":{"签文":"莫将怪梦作闲因，邪摩私祸不临神，自是行藏千里合，岂因病小危难消。","解曰":"吉宅人口可得喜气临门，但嫌六杀占宅，恐吓防六，九，十二月疾难口舌失财，向佛祖奉经保平安，求达摩祖师香火安门上祭化则财丁兴旺。"},"岁君签":{"总诗":"当时得意反成痴，今日忧疑事不危，若遇贵人相接引，十年桔树又生枝。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，惟有春夏月小疾，守旧，幸吉星守度，寿命绵长平安。","女":"小女根苗足养，旺益上人并茂，夏月小疾无妨，吉星守度平安。"},{"年龄":"4-7岁","男":"小儿运限顺遂，生性天真，旺益上人并茂，春夏月小疾无妨，寿命绵长。","女":"小女运限叶吉，天真活泼，利益上人春夏月小疾无妨，吉星守度平安。"},{"年龄":"8-12岁","男":"童造运度顺遂，各事开窍，宜培养入学读书，定卜进步，吉星守命出入平安。","女":"小女运度叶吉，各事伶俐，旺益上人并茂，夏月小疾无妨，吉星守度出入平安。"},{"年龄":"13-15岁","男":"童造今年交上运，聪明开窍，宜入学读书，定卜远景有望，且出入平安。","女":"玉造现年交上美运，旺益家门，夏月虽有小疾无妨，有吉星照身平安。"},{"年龄":"16-17岁","男":"祥造时运亨通，如枯木生枝，各事通能，认真学习文化，前途进展，出入平安。","女":"玉造交上美运，技巧清秀，有助益家庭之心，夏月虽有小疾无妨，出入平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如枯木生枝，做事有奇才机智，但凡事从正道经营，意外勿贪，有贵人扶助可得财喜。","女":"玉造今年交上美运，步入佳景，宜习收益，春夏月虽有小疾无妨，卦中吉星照身出入平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如枯木生枝，聪明奇智，宜从正道，为人义气相交，切勿妄取，有贵人扶助可得财喜。","女":"坤造行运交泰，如枯木生枝，贤淑智慧，有内助之称，但勿操迫，暗疾无妨，幸吉星守度出入平安。"},{"年龄":"56-69岁","男":"台造步运亨通，如枯木生枝，做事忠诚，但宜宽宏大量，春夏月虽有小疾无妨，贵人扶助出入平安。","女":"坤造行运交泰，如枯木生枝，虽有旺益家庭，但防暗疾之阻，宜静养，幸有吉星照身出入平安。"},{"年龄":"70岁以上","男":"吉造老运安康，但防春夏灾疾之厄，守旧，幸贵人扶助，晚景胜前。","女":"妇造老运虽有旺益子孙，但暗疾上身，忌看病人，幸吉星守命平安。"}]},"生意":{"生意":"生意经营切莫贪，牢牢记住守旧框，肖牛之人防阻失，肖羊之人厚利攀。","生意解曰":"生意有利可得但防阻失，经营要正直谨慎，肖羊者得厚利，肖牛者失财利","开铺":"卜开铺之卦不美未开勿开，已开之钥应防盗贼火灾，肖牛者失利肖羊者可得大利。","合伙":"卜合伙之卦不美失字当头，特别是肖牛者更不妙，伙计不同心有小人祸害，勿合也!","置货":"卜置货物，肖牛之人定失，肖羊之人能得利，余生肖者不可贪财利则吉也。"},"出外":{"出外":"卜出外一事虽有贵人扶助，但又防小人生端寄祸，不可在外久住，且来来往往!"},"谋望求财":{"谋望":"贪多更惹祸临身，名利从来是未真，但得忧游家道乐，知他谁是百年人。","谋望解曰":"谋事可成但有阻隔，做要稳重认真，不可贪心方免惹祸临身","求财":"正财库取利虽有微利可得，但恐防阻失，凡事业从正道，八，十一月有财利可得，偏财有阻失勿取吉也!"},"学艺功名":{"学艺":"学技艺之卦，肖羊者学之定成，肖牛者勿学为宜，其他人学习，宜刻苦用工，可成功也。","功名":"功名肖羊之人及未科，定可显达也。"},"行舟六畜":{"行舟":"行舟中吉 防凶失 合移不可也","六畜":"耕牛阻隔在今年，养猪劳苦有一期。肥猪养大及时卖，放羊牧人得财利。","猪羊":"猪羊二三只为准 但须下苦工 大猪应及时出卖 羊得厚利 可以多养也","草龙":"养牛之卦乃一牛两尾之兆 失字当头 未养勿购 养了应及早换过 则免生祸也","三鸟":"饲养三鸟 初有阻隔 不可灰心 应精心管理 各事宜吓伯公化吉 有利也","田蚕":"田蚕早晚二冬中 四季雨水中吉"},"移徙":{"移徙":"移徙初时不样有凶 后来可以大吉"},"行人":{"解曰":"行人在外身体健康 有归家之心 但路上财难回 五 七 十一月有音信回家也","签文":"不用人情说好音 人行在外有归心 虽然钱财无多少 但得平安值千金"},"婚姻":{"解曰":"婚姻大事切需要探明对方底细，不可马虎从事乱挥金钱，别把野花当红花","签文":"不须勉强费尽金，婚来合时何用寻，立志强成非好事，知人知面不知心。"},"官讼":{"解曰":"此官讼牛马两月切不可告 若告恐失败也 余月有贵 人扶助 但要和为贵","签文":"焚香祷告礼精勤 若问官实事有因 自有贵人提举力 虎头蛇尾两忘真"},"失物":{"解曰":"该因不慎 失却东西 应及早寻之 可以寻回也 若 迟慢三日 恐难寻也","签文":"只因懒惰不收藏 失去之时有记忙 用意速寻容易见 更迟三日往西方"},"占病":{"解曰":"占病之卦 有阴邪交缠 宜祭送 呼天地保佑少壮平 安 肖牛之老人防危险","签文":"灾来不是自家招 何用将钱问鬼神 但要平安登天地 依然平稳祸消涡"},"其他":{"灶君":"此灶位虽美 但嫌灶前迫塞 受杀神伤 宜遮掩杀气 灶前修净 烹煮叶吉也","阳基":"卜阳基若未分金 恐生白蚁 是青龙受龙杀 宜立 白雄鸡祭化吉","六甲":"六甲生女平安 若生男宜按枝拜契神明养育平安 若双生应小心根基不足","子息":"卜子息之卦 肖牛者有得有失 总是虚花虚果 其他 人子有可得而且善终也","祖山":"卜此祖墓龙脉真局口太小 局口欠文雅 但青龙畔受杀神伤 且骨以故 财丁旺者宜小宜慎 葬齐青龙畔相破并兜池之 后吉也","青草":"此地灵脉真气小 局口文雅但青龙畔空野受杀冲伤 来水割身葬穴不可宽阳宜占小养之 财丁可昌盛也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  18,
  '董卓收吕布',
  '蟾宫捉兔之兆',
  '以为下卦',
  '卯兔',
  '董卓弄权，欲废少帝立陈留王，丁原出与庭抗。董卓怒，欲杀之，慑于丁原义子吕布勇力，止。董谋士李肃说动吕布杀丁原，归董卓。董卓如虎添翼益专权。司徒王允行连环计，献貂蝉以间之，董卓复为吕布所弑。',
  '大鱼游曲江，蝉向柳中鸣;富无求口食，画角听三声。',
  '乌云盖月',
  '{"签号":"第十八签","签名":"董卓收吕布","签文类型":"蟾宫捉兔之兆","卦象":"以为下卦","生肖":"卯兔","签文简介":{"戏文":"董卓弄权，欲废少帝立陈留王，丁原出与庭抗。董卓怒，欲杀之，慑于丁原义子吕布勇力，止。董谋士李肃说动吕布杀丁原，归董卓。董卓如虎添翼益专权。司徒王允行连环计，献貂蝉以间之，董卓复为吕布所弑。","诗曰":"大鱼游曲江，蝉向柳中鸣;富无求口食，画角听三声。","内兆":"乌云盖月"},"家宅运势":{"签文":"旧年不利损多端，今年因何又不安，畜产田蚕防损失，更疑火盗两相残。","解曰":"吉宅人口可得喜气，但防疾难祸非失财火盗之厄，是门楼受火烟冲杀，求佛祖令旗门上祭化居住财丁兴旺，妇人有喜小心防冲杀。"},"岁君签":{"总诗":"养汝原来岁月深，龙面不见空长吟，相应只在秋江上，明月荷花何处寻。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，但防春夏月灾难水厄，六甲妇勿近抱，吓月娘交秋返运平安。","女":"小女根基虽旺，惟防春夏月小疾波阻，吓月娘化吉，交秋返运寿命绵长平安。"},{"年龄":"4-7岁","男":"小儿运限未美，惟防春夏月小疾水厄，凡水边小心，吓月娘，交秋返运出入平安。","女":"小女运度未美，但防春夏月灾难水厄，凡水边勿近，吓月娘，交秋后返运出入平安。"},{"年龄":"8-12岁","男":"小儿时令未美，惟防春夏月多事汤火，吓月娘化吉交秋返运，出入平安。","女":"小女现年运度未美，惟防春夏月灾难水厄，吓月娘化吉，交秋返运出入平安。"},{"年龄":"13-15岁","男":"童造现运未美，虽聪明，但防春夏月灾疾波阻，吓月娘，交秋返运出入平安。","女":"小女现年运度未美，惟防春夏月灾难水厄，吓月娘化吉返运出入平安。"},{"年龄":"16-17岁","男":"祥造运度未美，虽通能，但防春夏月灾难波阻，切勿自执己僻，吓月娘化吉。","女":"玉造现年运度未美，生性技巧，惟防春夏月小疾多事，宜吓月娘，可保平安。"},{"年龄":"18-29岁","男":"英造步运不佳，虽有志向，但防春夏月小人口舌祸非，宜戒性不可冲动，吓天地化吉，交秋转运平安。","女":"玉造人虽技巧清格，但防春夏月灾难口舌，凡事宜吞忍性气，宜吓月娘化吉交秋转运玉体安康。"},{"年龄":"30-55岁","男":"乾造步运未美，人虽有智谋，但防春夏月不测之祸，切勿深思远虑，交秋转运有贵人扶助平安。","女":"坤造行运美中不足，虽有助益家庭，但嫌内心操迫，暗疾口舌，春夏月守旧，交秋转运，玉体安康。"},{"年龄":"56-69岁","男":"台造步运不佳，人虽才能，但防春夏月祸非，闲事切勿近理，从正发展，交秋转运贵人扶助平安。","女":"坤造行运虽有旺益子孙，但嫌美中不足，暗疾口舌，凡事吞忍，春夏月守旧，交秋转运可卜安康。"},{"年龄":"70岁以上","男":"福造老运不旺，惟防灾难跌地之厄，早晚上落小心，忌入丧门，交秋大造平安。","女":"坤造老运不旺，身子空虚，时常暗疾，宜休养，忌看病人，交秋可卜平安。"}]},"生意":{"生意":"偏财一点不能取，正财也要守旧心，生意防阻勿贪心，现买现卖要记心。","生意解曰":"生意交易似空笼罩鸟，一嫌财利阻隔，二防小人耗劫买卖须用心谨慎","开铺":"卜开铺之卦不美防小人耗财，防盗窃火灾，交易勿贪心宜从正道。","合伙":"不美伙计训怀贪心勿合免惹是非失利亏本也!","置货":"卜置货停留，恐有阻失，至切不可贪心妄取，宜现买现卖，财利可安。"},"出外":{"出外":"卜出外一事君虽各事通灵，但嫌进令不美有小人无故生端，守旧经营免生衲害!"},"谋望求财":{"谋望":"本来无事做山翁，为受飞禽使运龙，谁料脱身天外去，方贪计尽也成空。","谋望解曰":"谋事难成，防小人阻隔恐生祸是非失财，凡事不可贪心，不可谋守旧则安","求财":"正财库取利似空笼罩鸟财利虚有，又恐小人耗劫宜用心经营，以智谋取之可保平安，偏财定失勿取也!"},"学艺功名":{"学艺":"卜学艺之卦，时令未通，小人祸害，学不成，宜守旧待时，从师学之可成也。","功名":"理运未通，功名难得。"},"行舟六畜":{"行舟":"行舟有不测 恐凶也 守可吉","六畜":"今年六畜真不详，猪犬牛羊有损伤。严防盗贼求神佑，守旧也可保平安。","猪羊":"猪羊丰时防三 六 九月阻隔 防盗贼 猪羊丰时防失 吓伯爷保平安","草龙":"卜养牛之卦 防三 六 九月阻碍 防盗贼 防失脚疾病 使用要小心 求伯爷香火带身平安","三鸟":"卜三鸟之卦 防三 六 九月阻失 不可多养 少养为佳 防盗贼 宜吓伯公化吉平安","田蚕":"早蚕早晚不安 四季雨水中平"},"移徙":{"移徙":"不可移之 宜守旧 若移之恐招祸非也"},"行人":{"解曰":"行人在外时运不通 防小人阻隔 恐信息稀少 宜求佛祖保信息早日回家","签文":"名利刀登也徘徊 身隔他乡未得回 若得江音信至 恰如临老送婴孩"},"婚姻":{"解曰":"婚姻不成，未与说时勿说,纵然说成洞房花烛结婚也不长久","签文":"今晚不管是和非，作教欢心进秀纬，但看却知林里应，五更天晓各分飞。"},"官讼":{"解曰":"和为贵 不可告 若告之 恐要受禁 但后来恰逢天赦 可以出囚回归也","签文":"三司堂上始知非 囹圄人中悔后迟 若得皇天恩赦却 放出囚人早去归"},"失物":{"解曰":"失物已落空 不得回返 若以后不慎恐还有不测 切勿谨记 以免再失","签文":"若去不把壁来修 失去浮财便意忧 天星已落灾失尽 如今却去讨踪由"},"占病":{"解曰":"天星不顺 宜当天改愿 求太阳星君保之 请良医治 之 少壮 老恐亡也","签文":"物不顺病难安 每日惶惶改旧愿 求神服药应无效 许来心愿不如还"},"其他":{"灶君":"卜此灶位虽吉 但嫌灶门太大 有利宜择吉日修整合课 则财丁兴旺也","阳基":"卜老阳基居住平安 但嫌门宇宽阔受杀 坐向有利修整过吉 起造新阳宅有阻隔勿取即大吉也","六甲":"六甲生女安 生男恐有阻隔 宜送給族内有善德之兄养育 可保平安","子息":"卜子息之卦 先女后男 但恐是单枪匹马 自创家业 若先产男 宜另移房也","祖山":"卜贵祖地有结穴 但嫌龙运不旺 又外坐向有利宜修豁水神归口 又宜修龙运壮旺又内外填兜池之后 财丁兴旺子孙绵长","青草":"此地龙脉水聚且水阳走不归口 葬此地宜去龙就局葬之则吉 但葬此地恐有祸非口舌宜理妥 葬后子孙兴旺也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  19,
  '苏秦六国封相',
  '万物逢春之兆',
  '上上之卦',
  '寅虎',
  '战国时纵横家苏秦善辩，游说六国连横合纵以抗秦，秦始敛其凶焰，不敢犯六国，六国君主推重之，乃拜苏秦为六国丞相。',
  '贝在宝山内，长生不老春;攀龙并附凤，财宝是珍珠。',
  '万物逢春',
  '{"签号":"第十九签","签名":"苏秦六国封相","签文类型":"万物逢春之兆","卦象":"上上之卦","生肖":"寅虎","签文简介":{"戏文":"战国时纵横家苏秦善辩，游说六国连横合纵以抗秦，秦始敛其凶焰，不敢犯六国，六国君主推重之，乃拜苏秦为六国丞相。","诗曰":"贝在宝山内，长生不老春;攀龙并附凤，财宝是珍珠。","内兆":"万物逢春"},"家宅运势":{"签文":"此卦求问家宅安，财丁两旺事事全，大吉之兆喜且顺，少安老福庆满堂。","解曰":"吉宅之卦签文太旺人口多则兴，人口少则衰虽有喜气可得，但嫌官非失财，皆因祖山不顺，灶君不旺宜修整合课吓佛祖保佑合家平安。岁君;云行雨施正春深，谋望求财总遂心，争公见官皆得理，贵人喜爱自相寻。"},"岁君签":{"总诗":"云行雨施正春深，谋望求财总遂心。争讼见官皆得理，贵人喜爱自相寻。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基稳固，八字清秀，有旺益上人并茂，上春月小疾无妨，吉星守命平安。","女":"小女根苗足养，有旺益上人并茂，上春月虽有小疾无妨，吉星守度平安。"},{"年龄":"4-7岁","男":"小儿运限顺遂，天真活泼，有旺益上人，上春皮肤小疾无妨，吉星照身平安。","女":"小女运限叶吉，伶俐天真，利益上辈，春夏月小疾无妨，吉星守度平安。"},{"年龄":"8-12岁","男":"小儿今年上运，各事活泼，宜入学读书，定卜进步，小疾无妨，吉星守命平安。","女":"小女之卦叶吉，凡事精巧，有旺益上人并茂，上春月小疾无妨，出入平安。"},{"年龄":"13-15岁","男":"童造上运旁通聪明开窍，培养入学，定卜前途有望，小疾无妨平安。","女":"玉造现年交上美运，各事伶俐精通，有旺益上人并茂，虽有小疾无妨，大吉平安。"},{"年龄":"16-17岁","男":"祥造步运亨通如松树之茂，聪明特达，有贵人扶助，远景无限，出入平安。","女":"玉造行运交泰，八字清秀，宜学习手艺，有吉星守度玉体安康。"},{"年龄":"18-29岁","男":"英造步运亨通如万物逢春，做事才能，正是年青有为，宜向外发展，有贵人扶助，可得财喜平安。","女":"玉造今年交上美运，为人通情达理，助益家庭，上春月虽有小疾无妨，有吉星照身出入平安。"},{"年龄":"30-55岁","男":"乾造步运亨通如万物逢春，做事心直无私但勿迫性，上春月虽有小疾无妨，有贵人扶助可得财喜平安。","女":"坤造行运甚佳，如万物逢春，可旺益家门，但宜忍性，上春月虽有小疾无妨，吉星守命平安。"},{"年龄":"56-69岁","男":"台造步运如万物逢春，心直忠诚，上春月虽有小疾无妨，卦中贵人扶助出入平安。","女":"坤造行运顺遂，如万物逢春，但嫌操心暗疾，凡事吞忍，上春月喜孝物勿食，出入平安。"},{"年龄":"70岁以上","男":"福造老运康泰，但嫌老人性迫，上春月上落小心，幸贵人扶助，晚景胜前。","女":"妇造老运安康，旺益子孙，有些暗疾无妨，卦中有吉星照身，出入平安。"}]},"生意":{"生意":"生意初时有阻缠，刻苦经营利丝丝，待交秋凉寒冬月，货如轮转得厚利。","生意解曰":"生意初时防阻，财利小宜刻苦经营于五，八月有起色，生意兴隆可得厚利","开铺":"卜开铺之卦如万物逢春之兆但初时怕有小阻，宜大胆灵活经营于五，八月起可得厚财利。","合伙":"卜合伙之卦吉利，初时有小阻，勿灰心忍口舌，刻苦经营同心同德定能得财利。","置货":"卜置货恐防购货后败市跌价，但若敢停留，到底自有振价之时。"},"出外":{"出外":"卜出外一事如枯木逢春，有贵人重重宜立胆智，于三月起往外各事平安!"},"谋望求财":{"谋望":"逢时日转好和平，谋望求财正利亨，若要经营当此际，皇都及早取功名。","谋望解曰":"谋事有成，但防谋时阻隔凡事勿贪心，不可妄取宜行正道免生祸非而成也","求财":"正财似雨后春笋取之大吉，宜立胆智经营进前占先，三，五，八月时令显达可得大利，偏财初有失，宜大胆经营获大利也!"},"学艺功名":{"学艺":"卜学技艺之卦，时令合局，宜择吉日拜师，勿骄傲，专心学习，必得名师传真艺也。","功名":"功名得中，尤其数年不进者更能显达。"},"行舟六畜":{"行舟":"行舟时运交泰，顺风得利，机不可失。","六畜":"六畜养之底平安，虽有小阻但无妨。求吓神明力保佑，大猪羊群只只全。","猪羊":"饲养猪羊有阻无妨 饲料调和 底子平安 吓伯爷保佑 可得厚利也","草龙":"饲养草龙 恐有痛疾等小阻 宜请兽医治疗 底子平安 水草调和 利也","三鸟":"卜饲养三鸟之卦 初恐有小阻 不可贪养太多 适宜为可 吓伯公保佑 有厚利也","田蚕":"田蚕早晚得利大吉 四季雨水遂意也"},"移徙":{"移徙":"移徒平安大吉 可以安居也 快速移之"},"行人":{"解曰":"行人在外木枯逢春 运泰已过 现已得志 有贵人扶 助 三 五 八月有佳音","签文":"久住他乡未到家 树枯流落在天涯 一朝得遇龙门雨 枯木依然满地花"},"婚姻":{"解曰":"婚姻成之，琴瑟和鸣天配良缘,可把家门修整择其吉日准备迎亲","签文":"人家便把兰门整，好看瑟鸣有凤声，天对姻缘更有合，如今不必问前程。"},"官讼":{"解曰":"官讼得胜大吉 自己要有见解 不能光听别人之言 有贵人扶助 吉祥平安","签文":"莫听人来说短长 虽然天理也高强 总逢官贵同为力 如今光天大吉祥"},"失物":{"解曰":"只因不慎把物失落 若要寻之应先问神明 候子午日快速寻 就能知道去向也","签文":"劝君更改不依然失 去求神问吉凶 子日午头人望处 好教仔细问行踪"},"占病":{"解曰":"占病是由于暴燥操心而起 是有旧神愿也 应当天改 谢可保安康 老者恐凶","签文":"刚强狠泪惹祸灾 病者厌床未退骸 好把心头求旧愿 免教疾病受尘埃"},"其他":{"灶君":"卜此灶位分金合课 但灶前迫窄 平时应修清净并请八卦安灶位上烹煮叶吉也","阳基":"卜阳宅新造防小人阻隔 宜理妥吉 老阳宅要修整门户埋水路 年度不合候大利可修而居之平安","六甲":"六甲生男 平安大吉 八字清秀 可旺益父母 有小疾无妨 吓神祖保平安","子息":"卜子息之卦 定有龙儿下降 寿命贵而且绵长 只宜慢慢 切勿急躁 底子安顺也","祖山":"卜贵穴龙脉旺气脉足 嫌养后有些凶灾 是填瓜魂并面前宽阳受杀冲照 修整阳气并兜唇之后 财丁兴旺","青草":"此地横龙结穴龙脉足旺 但嫌宽方有峰杀冲伤葬穴宜阳并兜唇或面前宽阳受杀冲照 葬穴宜沉阳又停兜池葬之"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  20,
  '曹操下江南',
  '破船下滩之兆',
  '下下之卦',
  '丑牛',
  '曹操百万雄师下江南，刘备从孔明谋，联吴抗曹，拟火攻。蒋干盗书，曹操中周公谨计，杀蔡瑁张允；又中连环计、苦肉计，连船练兵。于是孔明请东风，火烧赤壁，曹军战船被烧，灰飞烟灭，会军败北。',
  '四野无人到，行人路转迷;虎狼吞瞰地，险处更逢危。',
  '破船下滩',
  '{"签号":"第二十签","签名":"曹操下江南","签文类型":"破船下滩之兆","卦象":"下下之卦","生肖":"丑牛","签文简介":{"戏文":"曹操百万雄师下江南，刘备从孔明谋，联吴抗曹，拟火攻。蒋干盗书，曹操中周公谨计，杀蔡瑁张允；又中连环计、苦肉计，连船练兵。于是孔明请东风，火烧赤壁，曹军战船被烧，灰飞烟灭，会军败北。","诗曰":"四野无人到，行人路转迷;虎狼吞瞰地，险处更逢危。","内兆":"破船下滩"},"家宅运势":{"签文":"去年只望今年好，今年何缘又不宁，只为旧房多怪异，却教疑忌损人丁。","解曰":"吉宅人口旺者得喜，衰者破防失之灾，是灶君冲门祖山顺，有利应把灶君祖各宜修理合课向佛祖奉经求佛祖保佑合家平安。"},"岁君签":{"总诗":"有船无楫难撑驾，更被飘流向海洋，嗟叹世人系不得，误人如此走东西。","年龄运势":[{"年龄":"1-3岁","男":"小儿根苗足养，但防正、四、七月灾难波阻，六甲妇勿抱，吓月娘交秋返运平安。","女":"小女根苗浅薄，惟防正、四、七月小疾波阻，吓月娘化吉交秋返运平安。"},{"年龄":"4-7岁","男":"小儿之卦未美，惟防正、四、七月小疾水厄，水边小心，宜吓月娘，交秋返运平安。","女":"小女运限未美，但防灾难水厄，正、四、七月守旧，宜吓月娘，交秋返运平安。"},{"年龄":"8-12岁","男":"童造时运未美，惟防正、四、七月脚痛手疾，宜守旧，吓月娘，交秋返运，出入平安。","女":"小女之卦未美，惟防灾难水厄，逢水边小心，宜吓月娘，交秋返运平安。"},{"年龄":"13-15岁","男":"童造运度未顺遂，惟防正、四、七月小疾水厄，勿执己僻，吓月娘交秋返运平安。","女":"玉造运限美中不足，惟防灾难水厄，各事小心，吓月娘正、四、七月守旧平安。"},{"年龄":"16-17岁","男":"祥造运度不美，似行舟失楫，但防正、四、七月灾难水厄，逢船过游小心，吓妈祖化吉，交秋平安。","女":"玉造时令未美，似行舟失楫，人虽精巧，惟防脚手痛疾，水边小心，吓妈祖化吉交秋平安。"},{"年龄":"18-29岁","男":"英造步运未美，似行黍失楫，人虽通能，但防正、四、七月灾难口舌，戒忍性气，吓妈祖秋后平安。","女":"玉造行运未遂，虽有助益家庭之心，但防灾难口舌，正、四、七月守旧勿远出，吓妈祖交秋转入佳景。"},{"年龄":"30-55岁","男":"乾造老运不美，白虎星占身，但防正、四、七月小人祸非口舌，交人谨慎，吓妈祖化吉交秋转运平安。","女":"坤造行运不美，白虎星占度，嫌内心迫杂，恐有暗疾口舌，正、四、七月守旧，吓妈祖交秋转运平安。"},{"年龄":"56-69岁","男":"台造步运不美，人虽老练，但嫌性迫，多遭灾难口舌，正、四、七月闲事切勿近理，交秋转运大造平安。","女":"坤造行运虽有内助之德，但嫌操心暗疾，正、四、七月守旧，忌看病人，交秋转运玉体安康。"},{"年龄":"70岁以上","男":"妇造老运不旺，惟防正、四、七月灾难跌地之厄，早晚上落小心，忌看病人，守旧平安。","女":"坤造老运不旺，操心暗疾，忌看病人，正、四、七月守旧，夜时勿外出，交秋可卜平安。"}]},"生意":{"生意":"正直守份生意经，偏财一点取不能，货物不宜贪心购，留货秋后价会升。","生意解曰":"生意春夏月财利跋涉，宜守旧正直经营，用心刻苦维持，秋后有财利可得","开铺":"卜开铺之卦时运未通宜从正道过旧经营，秋后有发展可得财利也。","合伙":"卜合伙之卦不美勿为宜若合之定被吞没，定是亏本失利并惹起是非。","置货":"置货初时财利跋涉，还防小人累劫，货物必须小心检点，以守旧，秋后可得利。"},"出外":{"出外":"卜出外之卦不吉，有小人无故生端寄祸，且防水危宜守旧经营，则免生愁也!"},"谋望求财":{"谋望":"千谋万计事难成，枉走江山万里程，不如抽身且守耐，不然别月事来惊。","谋望解曰":"谋事难成时运未到，应该守耐之，若要谋之恐有惊阻，失财祸非之危也!","求财":"正财库取利稀少，又防小人负累，宜刻苦维持宜守旧经营，交秋时令有利可得，偏财难得不可取之，若为之定失也!!"},"学艺功名":{"学艺":"卜学技艺之卦，千谋万计事难成，宜在家自习，暂勿从师，候交泰运，拜师学也。","功名":"功名不中，还恐防失财伤身也。"},"行舟六畜":{"行舟":"行舟不吉，不可出港，若要行舟恐凶。","六畜":"六畜有组须切防，托人养之可平安。求神守旧无他事，不然就有苦加离。","猪羊":"饲养猪羊要防阻失 四七十月更要小心肪之 但可托别人养之 吓伯爷保平安","草龙":"卜养牛之卦要防四 七 十月阻疾宜用心饲养 不可贪使用 吓伯公保平安","三鸟":"卜三鸟之卦 不宜多养 防四 七十月阻疾 又防盗贼火窃 宜托别人养之 求伯公保平安","田蚕":"早蚕早晚二冬皆不安四季雨水中平"},"移徙":{"移徙":"移徒不吉此乃奔波之地 败案之处"},"行人":{"解曰":"行人在外时运不通 恐防小人阻隔信息断桥 吓妈祖 化吉 保信息早日回家","签文":"损体伤身只为财 他乡露绊未回来 行人路上逢寻舟 家下仍忧有祸灾"},"婚姻":{"解曰":"婚姻不成虽然曾经相许过，只因年命不同，小人重重若作成也恰似梦中","签文":"许了因何又不从，只因年命不相同，莫教勉强心无定，人岂相逢在梦中。"},"官讼":{"解曰":"官讼失理 和之大吉 若不和之 恐难以回避囚禁入 狱 切勿要以和为上策","签文":"官事从来好说开 乖情真理不嗔来 莫教成事难回避 只恐淹留到宪台"},"失物":{"解曰":"只因平时不慎 没有提防 故而使物失落 既失去 就是寻之也难见","签文":"闲时不慎细提 防失去如何空自忙 或问有踪觅不见未知音信是谁傍"},"占病":{"解曰":"占病恰似行舟失楫遇风 应该及早行善作福 请良医 治之 求佛祖保佑身体平安","签文":"小舟过海遇狂风 失楫临危在险中 问卜求神都是妄 不如赶早积阴功"},"其他":{"灶君":"卜此灶位虽吉 但嫌灶前阴湿程气宜时应修整清洁或做新灶 烹煮叶吉也","阳基":"卜阳宅新造有阻 但有胆智者可成 老阳宅修整大吉嫌前受杀冲伤 宜掩祭居住财丁可旺也","六甲":"六甲若逢阳月得之生男 但要小心恐不吉 若逢他月定产千金平安也","子息":"卜予息之卦 子息恐稀少 或有阻隔宜多行善事 求达摩祖师保佑","祖山":"卜贵祖龙运不旺 葬后财丁不顺 是青龙畔背后有蜂杀 寅方有峰隙修改过财丁兴旺也","青草":"此地横龙结穴 气脉足旺 但数年来财丁奔波 是寅方有峰杀 葬穴宜沉阳兜唇 防口舌 宜理妥葬后 财丁兴旺"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  21,
  '上帝收龟精',
  '鸾凤冲霄之兆',
  '大吉之卦',
  '子鼠',
  '玄天上帝修九世功德，始成正果。偶尔外出，路遇一肉牛，赞其肥美，以其心美之而犯戒遂反胃，呕出肚肠，化为龟蛇。龟蛇祸害地方，作苦百姓，玉帝察知，乃令上帝收伏龟蛇，镇于足下。',
  '一人持一笔，逢午壬龙飞;守园平地稳，得意上云梯。',
  '如鲲化鹏',
  '{"签号":"第二十一签","签名":"上帝收龟精","签文类型":"鸾凤冲霄之兆","卦象":"大吉之卦","生肖":"子鼠","签文简介":{"戏文":"玄天上帝修九世功德，始成正果。偶尔外出，路遇一肉牛，赞其肥美，以其心美之而犯戒遂反胃，呕出肚肠，化为龟蛇。龟蛇祸害地方，作苦百姓，玉帝察知，乃令上帝收伏龟蛇，镇于足下。","诗曰":"一人持一笔，逢午壬龙飞;守园平地稳，得意上云梯。","内兆":"如鲲化鹏"},"家宅运势":{"签文":"须宜另改旧门庭，人旺财兴百事宁，不但田蚕收十倍，更随四方任经营。","解曰":"吉宅可得喜气盈门，如无喜气事就恐有孝服事到来，皆因门字分金不正门庭水字不美，宜修整改正门庭分金水字求佛祖福灯吊正门上化吉保平安。"},"岁君签":{"总诗":"鲲化为鹏海浪翻，阴阳交泰太平关，庶人暮有凌云志，平地雷声倚势还。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，旺益上人并茂，正、三、五月小疾无妨，吉星守度寿命绵长。","女":"小女根苗稳固，旺益上人，正、三、五月小波疾无妨，吉星守命平安。"},{"年龄":"4-7岁","男":"小儿之卦生性天真，旺益上人，正、三、五月不可登高，小疾无妨，吉星守度平安。","女":"小女运限顺遂，旺益上人，不可登高，正、三、五月守旧，小疾无妨，有吉星照身出入平安。"},{"年龄":"8-12岁","男":"小儿运度叶吉，各事精通，培养入学，不可登高，幸吉星照身，前途有望，平安无事。","女":"小女运限亨通，凡事活泼，有旺益上人并茂，虽有小疾无妨，吉星守命平安。"},{"年龄":"13-15岁","男":"小童运度叶吉，聪明伶俐，宜入学校读书，定卜进步，远景有望，出入平安。","女":"小女运度顺遂，伶俐开窍，宜习手艺，正、三、五月小疾无妨，吉星守度平安。"},{"年龄":"16-17岁","男":"祥造步运亨通，聪明开窍，培养入学，定卜前途进展，出入平安。","女":"玉造今年交上美运，技巧开明，助益家门，正、三、五月小疾无妨，玉体安康。"},{"年龄":"18-29岁","男":"英造步运亨通，如鲲化鹏，时令特达，但勿迫性，从正发展，有贵人扶助，可得财喜，出入平安。","女":"玉造行运交泰，如鲲化鹏，各事贤玉，虽有旺益家庭，但宜温柔忍性，出入平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，人虽奇才，但防正、三、五月小人平地风波，凡事戒忍，幸贵人扶助，可得财喜平安。","女":"坤造行运甚佳，如鲲化鹏，但勿迫切，温柔大量，虽有小疾无妨，吉星守命可卜出入平安。"},{"年龄":"56-69岁","男":"台造步运亨通，为人心直性迫，凡事宽怀大量，防有不测风波，幸贵人扶助出入平安。","女":"坤造行运交泰，各事贤惠，但防暗疾口舌，凡事吞忍守旧，幸有吉星守度平安。"},{"年龄":"70岁以上","男":"福造老运得此卦太旺，惟防灾难跌地之厄，早晚上落小心，幸贵人扶助平安。","女":"妇造老运不旺，暗疾上身，正、三、五月守旧，喜孝物勿进，幸吉星守度平安。"}]},"生意":{"生意":"生意求财要有义，偏财一点不得利，肖马之人偏财得，四面八方任行时。","生意解曰":"春季生意不能得利候五，六月起似龙带雨定有财源广进，惟肖马者有偏财可得谋望;几年沉落波涛内，未得风雷志气高，今日脱身多变化，应知万里任游遨，谋事有成但防时有阻隔，用心窍候六，九月可成，但肖猴者恐惹官非失财","开铺":"卜开铺卜开铺之卦叶吉，初小利宜壮胆经营交五，六月起如鱼化鹏，可得厚财利也。","合伙":"卜合伙之卦大吉，但伙计要有仁义，要同心协力交五，六月起财源广进可得财利!","置货":"卜置货初时有惊阻，到底渐渐亨通，应于五、六、七、八月定得大利也。"},"出外":{"出外":"卜出外之卦叶吉有贵人扶助可于三，五月往外有厚利可得各事平安!"},"谋望求财":{"谋望":"几年沉落波涛内，未得风雷志气高。今日脱身多变化，应知万里任遨游。","谋望解曰":"谋事有成，但防时有阻隔，用心窍，候六、九月可成，但肖猴者恐惹官非失财。","求财":"正财库取利上春财利稀少，但宜刻苦经营秋厚转运，各事亨通可得厚利偏财唯肖马羊者得之!"},"学艺功名":{"学艺":"卜学艺之卦叶吉，按签文上春恐有阻隔，宜秋后学之，定能成功，手艺随身也。","功名":"功名成也，肖牛羊之人逢午未更能显达。"},"行舟六畜":{"行舟":"行舟初时不顺，后来行之，顺风得利。","六畜":"六畜有阻在春光，求神拜佛保平安。猪羊兴旺秋月后，快肥快大人乐观。","猪羊":"卜饲养猪羊初春有小阻 以后养之顺利 可大胆养之 秋后可得大财利也","草龙":"卜养牛之卦 水草调和 身强力壮 可旺益家庭求神保佑 有财利","三鸟":"卜饲养三鸟 初春恐有小阻 以后养之顺利 饲料调和 可下大本秋后可得厚财利","田蚕":"田蚕早晚中吉 四季雨水吉也"},"移徙":{"移徙":"移徒吉 可速移之 可得财丁贵也"},"行人":{"解曰":"行人在外时运特达 有贵人扶助 各事亨通 于五 八 十一月有音信财利回家","签文":"只望行人在眼前 如何归去又迟延 更知何日音信至 明月圆时人始还"},"婚姻":{"解曰":"精男巧女配合大吉，但要速速下聘办理，不可拖延，若迟恐祸变也","签文":"精男巧女两相当，配合婚姻启后昌，此际好求鸾风偶，迟延悔过费思量。"},"官讼":{"解曰":"官讼不宜告 和为贵 但是理出公论 曲直分明 君 不须忧虑或胡乱疑","签文":"龙虎相逢事和谐 一轮明月照天涯 已分曲直何须虑 不知君心乱疑猜"},"失物":{"解曰":"失物有见 理在虽不见 终久要见 午壬日有见之望 出见在于邻近地方也","签文":"如今已到别人边 莫把傍人作盗强 踪迹有方终久出 斯时不过渐迟延"},"占病":{"解曰":"阴邪交缠 应向四方祭送 并求太阳星君保之 请良 医治之 少壮平安 老恐危","签文":"从来祸福两无门 纵是人招不必论 正是当天求保佑 莫教明月照孤魂"},"其他":{"灶君":"此灶位分金合课 但嫌久年灶前秽气 宜作新灶 灶前修理清净 烹煮叶吉","阳基":"卜阳基吉 但嫌数年财丁奔波 是门字水字不美 有 利速改过 卜新创初时恐有阻 到底可成","六甲":"六甲生男恐有阻隔 必须移房过祖或拜契显赫神明 求佛祖保佑养育平安","子息":"卜子息初得有阻隔 后定有成章之喜可得 而且近贵 定能发展前程 振耀家声","祖山":"卜贵祖佳城横龙结穴 气脉文雅 但嫌龙运不旺 水字不美 坐向有利改过唇前水字 葬后财丁奔波 因穴位分金有错 若改过分金水字财丁昌盛","青草":"此地横龙结穴 气脉足旺 面前大案朝拱葬后显武 科 若子午未丑一山分金定旺财丁 理妥水字葬后可 保财丁两旺"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  22,
  '岳飞枪挑小梁王',
  '将军得胜之兆',
  '大吉之卦',
  '亥猪',
  '岳飞为抗金保国，偕众兄弟赴京比武。适后周主柴世宗后人小梁王为谋兵权以复柴氏江山，得朝奸讯，亦入京。岳飞因与之立下生死文书，校场比武夺魁，枪挑小梁王。权奸罪之，幸宗泽保释回家。岳母愤而刺字于其背曰：“精忠报国”，以励其志。',
  '喜赴琼林宴，金盘捧玉杯;多题龙凤榜，天下广传名。',
  '凤鸣歧山',
  '{"签号":"第二十二签","签名":"岳飞枪挑小梁王","签文类型":"将军得胜之兆","卦象":"大吉之卦","生肖":"亥猪","签文简介":{"戏文":"岳飞为抗金保国，偕众兄弟赴京比武。适后周主柴世宗后人小梁王为谋兵权以复柴氏江山，得朝奸讯，亦入京。岳飞因与之立下生死文书，校场比武夺魁，枪挑小梁王。权奸罪之，幸宗泽保释回家。岳母愤而刺字于其背曰：“精忠报国”，以励其志。","诗曰":"喜赴琼林宴，金盘捧玉杯;多题龙凤榜，天下广传名。","内兆":"凤鸣歧山"},"家宅运势":{"签文":"好整新居换新巢，远离群只兔相投，升平无事皆为福，恰似晴明月满宵","解曰":"吉宅人口之卦虽有喜气可得，但嫌家内不和气且有灾疾，是灶君不旺埕口水路不通，宜择吉方重建新灶，修通水道厝宅修整壮旺居住平安。"},"岁君签":{"总诗":"凤凰飞出林间去，振翼飞回伏众禽，一日身荣朝上国，四方钦仰尽名闻。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗稳固，有旺益上人，但正、三、四月喜孝物勿近，幸吉星守命，出入平安。","女":"小女根基足养，八字清秀，正、三、四月小疾无妨，幸吉星守度，出入平安。"},{"年龄":"4-7岁","男":"小儿运限顺遂，生性天真伶俐并旺益上人并茂，上春月小疾无妨，吉星守命平安。","女":"小女运限叶吉，各事活泼，利益上人并茂，春夏月小疾无妨，吉星守度，出入平安。"},{"年龄":"8-12岁","男":"小童运度叶吉，聪明伶俐，入学校读书进步，不可登高玩耍，幸吉星守命平安。","女":"小女运限叶吉，宜学习文化，正、三、四月虽有小疾无妨，不可登高，幸吉星守命平安。"},{"年龄":"13-15岁","男":"童造运度顺遂，聪明开窍，宜入学校读书，定卜进步，远景有望，小疾无妨平安。","女":"玉造运度甚佳，性情精巧，有旺益上人并茂，正、三、四月虽有小疾无妨，出入平安。"},{"年龄":"16-17岁","男":"吉造步运亨通，性格自然，受人疼爱，可培养入学，定卜前程远大，出入平安。","女":"玉造交上美运，技巧清秀，助益家庭，虽有小疾无妨，吉星守度平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如凤鸣岐山，奇才通能，可向外发展，有贵人扶助，可得财喜。","女":"玉造行运交泰，如凤鸣岐山，性格温柔，待人有礼，助益家庭，正、三、四月虽有小疾无妨平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，签文将军得胜，性直心慈，可得财喜，但坚心立志，有贵人扶助，可得财运平安。","女":"坤造行运交佳，性情和暖贤淑，旺益家门，但勿操迫，虽有小暗疾无妨，吉星守度出入平安。"},{"年龄":"56-69岁","男":"台造步运亨通，如凤鸣岐山，为人老成忠厚，但勿迫性，从正谋求，有贵人扶助，晚景胜前出入平安。","女":"坤造行运交佳，贤淑智慧，但勿操迫，人有些暗疾无妨，卦中有吉星守命玉体安康。"},{"年龄":"70岁以上","男":"福造老运太旺，虽安康，但防灾难交脱，早晚上落小心，守旧，幸吉星守度平安。","女":"妇造老运不旺，虽有旺益子孙，但防风气疾病，喜孝堂勿进，底子晚景胜前。"}]},"生意":{"生意":"正二五九生意时，他有则难价不知，经营勿贪尾空有，偏财得利又失利。","生意解曰":"生意经营旺相有贵人扶助，宜用智谋大胆经营于五月起可得厚财利也","开铺":"卜开铺卜开铺之卦，如将军得胜之兆，有贵人扶助宜大胆经营，五月起可得厚财利。","合伙":"卜合伙之卦似凤鸣歧山之兆，伙计要同心同德齐心协力可得大财利也。","置货":"置货物种有利可得，但嫌有尾，请勿贪心妄取，则可保财利货物平安也。"},"出外":{"出外":"卜出外一事得运，身体可平安，大胆前往于三月起有贵人扶助，可得大财利也!"},"谋望求财":{"谋望":"几年静坐守闲居，景色萧条事已虚，此去时通同泰运，名利成就一声雷。","谋望解曰":"数年谋事有虚无，现岁谋事宜立胆智敢想敢干，于三，七，十一月可成功也","求财":"正财库有利但初时空有，凡事业宜立胆智交三，八，十一月有贵人扶助，可得厚利，偏财可得恐不住勿贪也!"},"学艺功名":{"学艺":"卜学艺之卦，似将军得胜之兆，可择吉日从师学之，定能学得技艺随身也。","功名":"文武功名皆中也，捐纳营伍均可营生。"},"行舟六畜":{"行舟":"行舟平安大吉，顺风得利，有财利也。","六畜":"枯木逢春再生枝，大猪出卖趁时机。牛羊鸡犬定大吉，六畜兴旺有财利。","猪羊":"猪羊兴旺 饲料调和 中小猪养之顺利 但大猪要及时发售 可得厚利","草龙":"卜饲养大武之卦水草调和 身强力壮 使用顺利各事平安 能旺益家庭 有財利","三鸟":"卜三鸟之卦平安顺遂 饲料调和 群只兴旺 但此签有尾 大只宜及时出售 可得厚财利也","田蚕":"早蚕草早晚造皆大吉 四季雨水有利"},"移徙":{"移徙":"移徒即可移之 新居兴旺 财丁大吉"},"行人":{"解曰":"此行人在外得志 似将军得胜之兆 有贵人重重 于 三 七 十一月有佳音回家","签文":"去年又未促归装 离了家乡在路傍 子午下旬音信到 平安无事不须忙"},"婚姻":{"解曰":"婚姻可成，但宜从速下聘，切不可迟迟拖延岁月事多变","签文":"旧年夫妻去鸣琴，静里听来鸾凤音，休要蹉跎延岁月，天寒失雁杳难寻。"},"官讼":{"解曰":"卜此讼有小人欺之 吉之不吉 要以和为上策 宜往 外迴避 可保平安","签文":"今日逃飞胜碧汉 反为毛羽惜朱衣 误入深林被鹊欺 任教鼠雀角相痴"},"失物":{"解曰":"必须仔细探明失物踪迹 从速寻找 自可见之 但无 全面 若迟慢恐难寻之也","签文":"只因迟慢少遮围 失去如何得自归 便要营求方得见 不教久后受人亏"},"占病":{"解曰":"久病不俞 宜当天求北斗星君保佑平安 请良医治之 少壮平安 老人冲跳恐危","签文":"数年淹留运未通 谁知却有阴功助 吉星正照仰门中 保佑安全谢上宫"},"其他":{"灶君":"此灶分金合课 但嫌灶前秽气 有利宜原位重建 新灶 可旺旺益财丁也","阳基":"卜阳居欲新造吉但嫌带些口舌 宜理妥可成 若老阳 宅灶君不旺 厝宅也宜修整过居住平安","六甲":"此胎六甲定得男儿 全家欢喜 宜吓佛祖保佑养育平 安大吉","子息":"卜子息带有富贵之命格 能独力谋事 自创家业 荣 宗耀祖也","祖山":"贵祖佳城横龙结穴 气脉文雅 但嫌青龙畔龙运不 旺 水字不美 坐向有利改过唇前水字又兜唇之后 财丁可旺长","青草":"此地横龙结穴 气脉足旺 但葬时宜占高三五尺 占 过东面青龙畔就局葬之 可财丁昌盛也 但防是非口 舌 宜理妥"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  23,
  '颜回短寿为圣',
  '啖河止渴之兆',
  '下下之卦',
  '戌狗',
  '孔子得意弟子颜回，家极贫而性极聪慧，沉约向学而最得师道，居陋巷而其志不移，孔子嘉之；然天不怜才，终以短寿而夺其华年，孔子哭之，谓其为七十二贤人中之至圣者也。',
  '月下围棋局，谁知子落来;听琴不相识，袖手问颜回。',
  '花开遭风',
  '{"签号":"第二十三签","签名":"颜回短寿为圣","签文类型":"啖河止渴之兆","卦象":"下下之卦","生肖":"戌狗","签文简介":{"戏文":"孔子得意弟子颜回，家极贫而性极聪慧，沉约向学而最得师道，居陋巷而其志不移，孔子嘉之；然天不怜才，终以短寿而夺其华年，孔子哭之，谓其为七十二贤人中之至圣者也。","诗曰":"月下围棋局，谁知子落来;听琴不相识，袖手问颜回。","内兆":"花开遭风"},"家宅运势":{"签文":"家居不利欲搬移，惹不搬迁惹是非，只是本家人着力，好心人被小人欺。","解曰":"吉宅人口之卦虽有喜气可得，但防疾难口舌失财和盗贼之厄，吓佛祖保平安，皆因灶君不旺失祀祖上香灯，宜奉拜周到重新灶君居住兴旺也。"},"岁君签":{"总诗":"种得桃树满园林，花开遭雨又遭风，当初只望偷桃食，如今到底总成空。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗浅薄，惟防正、七、十一月灾难波阻，宜吓天地方保寿命绵长。","女":"小女根苗浅薄，惟防正、七、十一月灾难多事，守旧，吓月娘方保出入平安。"},{"年龄":"4-7岁","男":"小儿之卦未美，但防正、七、十一月小疾灾厄，守旧勿外出，宜吓月娘化吉方保平安。","女":"小女运限未美，但防正、七、十一月多生灾疾，吓月娘保平安。"},{"年龄":"8-12岁","男":"小童现年运度未美，虽伶俐，惟防波灾小事，吓天地化吉方保出入平安。","女":"小女运度未遂，虽旺盛上人，但防正、七、十一月小疾波阻，吓月娘化吉平安。"},{"年龄":"13-15岁","男":"小童之卦未美，但防波阻之厄，正、七、十一月守旧，吓天地化吉。","女":"小女现年运度美中不足，但防正、七、十一月小疾汤火之厄，吓月娘化吉。"},{"年龄":"16-17岁","男":"祥造时令未美，似花开遭风，但防正、七、十一月灾难多事，培养入学，吓天地化吉。","女":"玉造时令美中不足，人虽精巧，但防正、七、十一月灾疾之厄，吓月娘化吉。"},{"年龄":"18-29岁","男":"英造步运未美，似花开遭风，惟防正、七、十一月口舌祸非，凡事安分守己，吓天地化吉平安。","女":"玉造行运美中不足，签文花开遭风，虽有助益家庭，但防正、七、十一月小疾波阻，吓月娘保平安。"},{"年龄":"30-55岁","男":"乾造步运不美，似花开遭风，人虽忠诚，惟防正、七、十一月小人不测之祸，戒忍性气，吓天地化吉平安。","女":"坤造行运未美，似花开遭风，虽可称内助，但防暗疾口舌，凡事戒忍性气，宜吓天地化吉平安。"},{"年龄":"56-69岁","男":"台造步运未美，似花开遭风，虽老练，但防正、七、十一月灾祸口舌，凡事宽怀大量，闲事勿理平安。","女":"坤造行运虽有旺益家庭，但嫌美中不足，灾疾口舌忍性，正、七、十一月守旧夜时勿远出，底子平安。"},{"年龄":"70岁以上","男":"吉造老运不旺，虽绵长但防疾难跌地之厄，早晚上落小心，正、七、十一月守旧平安。","女":"妇造老运不旺，虽旺益子孙，防暗疾，上落小心，喜孝物勿食，正、七、十一月守旧平安。"}]},"生意":{"生意":"生意守分可经营，进出货物看市情，取财勿贪防阻失，现买同卖财利兴。","生意解曰":"生意宜守旧经营，要现买现卖，不可妄取，防小人劫物六，八，十一月有利可得","开铺":"卜开铺卜开铺之卦如花开遭风之兆，未开勿若是老铺宜注意火盗之危，吓佛祖保佑平安。","合伙":"卜合伙之卦不美似花开遭风之兆，勿合为要，若合之恐有小人盗劫财物，亏本折利!","置货":"卜置货恐防有阻失，至切探明市情，勿贪取可安，置货时认真检查验收。"},"出外":{"出外":"卜出外一事为啖河止渴，恐有小人阻隔凡事宜守旧经营各事平安!"},"谋望求财":{"谋望":"几载蟾宫折桂枝，未逢时节枉心机，寅缘等到花开日，又被连朝大雨欺。","谋望解曰":"谋事难成，恐防小人生端寄祸，累害耗财，肖猴者恐惹官非和失败","求财":"正财虽有得，但防小人累害，宜守旧经营钱财不可信中直，应防仁不仁六，八，十一月有财利也，偏财勿取!"},"学艺功名":{"学艺":"卜学艺之卦，时运未通，宜自己窗下学习，但肖羊之人合卦，可以从师学习，定能成材。","功名":"功名不中，但肖羊者年命合局显达也。"},"行舟六畜":{"行舟":"行舟不吉，恐防有阻，又防遭劫。","六畜":"六畜有阻枉心精，用尽机谋事不成。若问猪羊平安顺，求吓福德显神明。","猪羊":"猪羊有阻 平安小利 多养不吉 中大只应及时出卖 吓本境伯爷保佑平安","草龙":"卜养牛之卦 恐正 七 十一月阻隔 防脚疾 使用小心 勿过度宜吓伯公保佑平安","三鸟":"卜养三鸟之卦 正 七 十一月阻隔 防小人盗劫勿贪多养 吓伯公保佑平安","田蚕":"田蚕早晚不吉有阻 四季雨水中中"},"移徙":{"移徙":"移徒不吉 恐有灾祸切不用移也"},"行人":{"解曰":"行人在外 时令未通 有小人波阻 信息稀断 吓佛祖保信息财利早日回家","签文":"关山迢迢路艰难 去了淹留尚未还 好向神前修善福 从今跳出北门关"},"婚姻":{"解曰":"婚姻不成，对方品质作风差，若成之恐成之是娼淫惹起是非灾害，不结尾","签文":"知人知面不知心，枉使良谋费尽心，只为眼前欢共乐，谁知祸起为娼淫。"},"官讼":{"解曰":"官讼临头 宜忍之 严防笑里藏刀的伪君子 但要和为吉 若告之定埋入狱","签文":"横事临门不可逃 提防人口笑里刀 迟延不肯和平事 终久缠身到狱牢"},"失物":{"解曰":"失物难寻 不用找之 若要寻找 更不可随便胡疑人家 恐要惹起祸非也","签文":"何用滔滔着意猜 已知不是自家财 须凭大理寻归着 非义从来祸是胎"},"占病":{"解曰":"有神愿 宜当天谢天地神恩 求佛神保佑平安 但老人防冲跳 恐亡也","签文":"真病从来无药方 莫教沉重却慌忙 伊今不到天神佑 少年还事老人亡"},"其他":{"灶君":"卜此灶位不美 灶前又秽气不净 官择生气延年灶位 重新作过 烹煮叶吉","阳基":"卜阳宅龙运不旺 又嫌水神不美 新造不吉 若整旧有助 理妥吉","六甲":"六甲生男有阻 恐防根基不足 应求神明保佑养育 平安 若生女大吉","子息":"卜子息虽有得 但恐短寿 宜许吓长寿公改化 并移房拜契 可保寿命绵长也","祖山":"卜贵祖龙脉不旺 水神不美葬后财丁阻失 切宜修整龙运壮旺 并理水神归口之后 财丁昌盛","青草":"此地横龙结穴 气脉足旺 又嫌水神太散 而且阳出至切不可取之 若取葬之 恐生祸非 财丁不顺也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  24,
  '唐明皇游月宫',
  '风云际会之兆',
  '上上之卦',
  '酉鸡',
  '东海龙王敖广罪犯天条，唐相魏征魂将赴天庭监斩。敖广求救于唐王李世民，王诺。届时卓午，王邀约魏征对弈，意在拖过时辰。魏奕久困盹，魂斩敖广。敖广迁怒于唐王，魂扰唐宫，王病魂游阴曹月宫，许救济饿鬼，超度亡魂，始得还阳，重主唐朝江山。',
  '白鹤九霄鸣，空中万里声;犀牛放望月，吉庆之分明。',
  '吉庆分明',
  '{"签号":"第二十四签","签名":"唐明皇游月宫","签文类型":"风云际会之兆","卦象":"上上之卦","生肖":"酉鸡","签文简介":{"戏文":"东海龙王敖广罪犯天条，唐相魏征魂将赴天庭监斩。敖广求救于唐王李世民，王诺。届时卓午，王邀约魏征对弈，意在拖过时辰。魏奕久困盹，魂斩敖广。敖广迁怒于唐王，魂扰唐宫，王病魂游阴曹月宫，许救济饿鬼，超度亡魂，始得还阳，重主唐朝江山。","诗曰":"白鹤九霄鸣，空中万里声;犀牛放望月，吉庆之分明。","内兆":"吉庆分明"},"家宅运势":{"签文":"汝家无事不须疑，但梦如何有约期，人若安然无他事，提防暗里小人欺。","解曰":"吉宅人口之卦虽有喜气，但阴夏月小疾失财盗贼之厄，门户宜谨慎有称人承奉祀拜到财丁昌盛，妇联有喜恐无得。"},"岁君签":{"总诗":"明有当空处处辉，朗然光辉照昏迷，谋所运大家声显，富贵荣华福乐齐。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足养，八字成格旺益上人并茂，虽有小疾无妨，吉星守度平安。","女":"小女根基足养，有网易上人并茂，春夏月虽有小疾无妨，吉星守命平安。"},{"年龄":"4-7岁","男":"小儿今年运度叶吉，天真伶俐，旺益上人，不可登高玩耍，吉星守度平安。","女":"小女运限亨通，生性活泼，有旺益上人并茂，春夏月小疾无妨，出入平安。"},{"年龄":"8-12岁","男":"小儿运度顺遂，聪明开窍，宜入学读书，定卜前途远大，出入平安。","女":"小女现年运限叶吉，天真伶俐，不可登高玩耍，虽有小疾无妨，吉星守命平安。"},{"年龄":"13-15岁","男":"童造时令顺吉，生性通能，宜培养入学，将来前途进展无线，出入平安。","女":"小女运限亨通，生性活泼，有旺益上人并茂，春夏月小疾无妨，出入平安。"},{"年龄":"16-17岁","男":"祥造现年运度亨通，做事才能聪明，可学习文化，有贵人扶助，出入平安。","女":"美造时令交泰，如吉庆分明，五行坚固，性质温柔，小疾无妨，吉星守命平安。"},{"年龄":"18-29岁","男":"乾造步运亨通，如吉庆分明，奇才特达，宜立凌云壮志向外发展，有贵人扶助，可得财喜平安。","女":"坤造行运佳美，如风云际会，各事贤淑，有助益家庭之志，虽有小疾无妨，出入平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如吉庆分明，为人老练多才，但勿迫性，向外发展，自有贵人扶助，出入平安。","女":"坤造行运交泰，如风云际会，锦上添花，旺益家门财喜，但勿迫切，暗疾无妨，出入平安。"},{"年龄":"56-69岁","男":"台造步运甚佳，为人心存正气，但不可迫性，虽有小疾口舌无妨，有贵人扶助，可得财运平安。","女":"坤造行运审美，延年益寿，为人忠贞智慧，但有些暗疾无妨，吉星照身，出入平安。"},{"年龄":"70岁以上","男":"福造老运绵长，做事忠厚为家，春夏月灾疾无妨，但上落小心，幸吉星拱照，晚景胜前平安。","女":"妇造老运康泰，为人涵养，但嫌暗疾上身，凡事谨慎，步履小心，幸卦中吉星守命大造平安。"}]},"生意":{"生意":"春夏生意有小灾，守份求神能保财，交秋月圆时运转，货物出入利路开。","生意解曰":"新创生意春夏月防阻失，宜守旧经营，买卖数目应谨慎，交秋月便可得财利","开铺":"之事时令合局，为风云际会之兆宜择吉日，从速开张定有财利可以得。","合伙":"卜合伙之卦顺吉，为吉庆分明兆，但伙计要同心同德齐心协力有财利也!","置货":"置货春夏时令未通少利，如能把货停留至九、十月发售，定可得大利也。"},"出外":{"出外":"卜出外一事有贵人重重，应于三月往外，不但平安而且有厚利可得!"},"谋望求财":{"谋望":"心欲抽开事未闲，失去无处把身安，如今得有青云路，步上天梯见广寒。","谋望解曰":"谋事初进难成且有阻隔，候三，五，八，十一月用些财帛帮助，事情便可成功","求财":"正财虽有所得但防阻失，宜守早不可偷闲于三，五，十一月可得厚利，偏财恐失莫取为好!"},"学艺功名":{"学艺":"卜学艺之事可成，但宜求太阳太阴保佑，所学技艺如意遂心，肖猴者学之妙也。","功名":"功名中，文武双全，肖龙猴者更能显达。"},"行舟六畜":{"行舟":"行舟顺风得利，应趁机出船，可得利。","六畜":"今载六畜一齐开，但在初春有不得。必须待到秋冬日，猪肥牛壮财利来。","猪羊":"猪羊之卦 饲料调和 可以多养 但春月有小阻无妨定可平安 可得厚利","草龙":"卜养牛之卦饲料 水草湖和 使用顺利 春月有小阻无妨 可卜平安得利","三鸟":"卜养三鸟之卦 初春恐有小阻无妨 饲料调和 可以落资金多养 秋冬可得厚财利","田蚕":"田蚕早晚大吉 勤耕勿偷闲 雨水大利"},"移徙":{"移徙":"移徒大吉 平安可居 择吉日移之"},"行人":{"解曰":"行人在外得志 有贵人重重 于三 四 十二月有佳音财利寄回家也","签文":"只望行人在眼前 如何归去免迟延 要如何日音信至 明月圆时人正还"},"婚姻":{"解曰":"婚姻成也缘份生就，男女双方情投合，同心同德千里缘合，白头皆老","签文":"婚姻本是合团圆，何必慌忙心里悬，自是有缘千里合，管教男女共安全。"},"官讼":{"解曰":"官讼胜之是非好坏自有明官判决 君不要慌忙操心也 但还是要以和为贵","签文":"龙虎相逢事有差 一轮明月照天涯 已分玉石何须虑 君心不必乱如麻"},"失物":{"解曰":"失物能回 但恐难全归也 可是寻找的时候 切不可乱疑半时来往的人也","签文":"如今已到别人家 莫把平人作盗冤 踪迹有方终久出 斯时得见也难全"},"占病":{"解曰":"有阻邪交缠 当天求太阴娘娘保佑 用儿身菜饭 向西北方祭送 可保平安","签文":"从来祸福两无门 总是人招不必论 正好当天求保佑 莫教明月照孤神"},"其他":{"灶君":"此卜灶位分金合于八宅之卦 经常灶前修理清净 烹煮叶吉 可旺益财丁也","阳基":"阳宅吉 但嫌面前灌水并青龙畔空野受杀 宜掩祭起 造吉也","六甲":"六甲生男 根基足养 八字清格 有益父母 平安大吉 是报先祖积德之因","子息":"问子息之事 得而有阻 宜行正道 多做善事 日后自有贵子 并能显达荣升也 吉庆满堂","祖山":"贵祖佳城横龙结穴 气脉文雅 但嫌葬后财丁不美 之杀冲伤 四房有灾 由是青龙畔来水割身 并填坑路 利掩杀并理水神归口","青草":"此地横龙结穴 但嫌青龙畔背后有坑路杀冲伤 葬穴占下 阴胎阳做并兜唇做之则葬后财丁昌盛 葬时有口舌 宜忍之"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  25,
  '郭巨埋儿赐黄金',
  '铁镜重磨之兆',
  '中平之卦',
  '申猴',
  '汉郭巨家贫缺食，有子三岁，郭母每食则减与其孙，郭巨不安，谓其妻曰“我无能供母食，子又分母之食，奈何，盍埋儿可呼？子可再得，母不可复得也。”妻不敢抗。一日郭巨果埋儿，掘地至三尺，忽见黄金一釜，此天感其孝，赐金以资其养家者是也。',
  '铁树生花久，生男八十三;棘林筛月影，满地是黄金。',
  '铁镜重磨',
  '{"签号":"第二十五签","签名":"郭巨埋儿赐黄金","签文类型":"铁镜重磨之兆","卦象":"中平之卦","生肖":"申猴","签文简介":{"戏文":"汉郭巨家贫缺食，有子三岁，郭母每食则减与其孙，郭巨不安，谓其妻曰“我无能供母食，子又分母之食，奈何，盍埋儿可呼？子可再得，母不可复得也。”妻不敢抗。一日郭巨果埋儿，掘地至三尺，忽见黄金一釜，此天感其孝，赐金以资其养家者是也。","诗曰":"铁树生花久，生男八十三;棘林筛月影，满地是黄金。","内兆":"铁镜重磨"},"家宅运势":{"签文":"是非叠叠起虚惊，畜产灼危百怪兴，不是营谋不如意，尚防盗贼入门庭。","解曰":"吉宅人口可得喜气，但防夏月疾难口舌，及次次是非盗贼之厄，门前受杀冲伤，求佛祖令符安门上保财丁兴旺，坐北向南白虎畔有石碑移开。"},"岁君签":{"总诗":"求谋胜遂如君意，欲望青云路转移，守旧却宜方是吉，他时必定见荣华。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗未足，惟防上春月灾难波阻，六甲妇勿抱，吓月娘交秋返运，出入平安大吉。","女":"小女根基浅薄，但防上春月小疾多事，夜时勿外出，吓月娘交秋返运出入平安。"},{"年龄":"4-7岁","男":"小儿运限未美，但防上春月多生皮肤灾疾，吓月娘化吉，交秋返运，出入平安。","女":"小女运限未遂，惟防上春月灾难波阻，守旧并吓月娘化吉，交秋返运，出入平安。"},{"年龄":"8-12岁","男":"小儿之卦精巧开窍，但防上春月小疾波阻，守旧并吓月娘交秋返运，出入平安。","女":"小女运限未美，惟防上春月多灾多厄，宜守旧并吓月娘交秋返运，出入平安。"},{"年龄":"13-15岁","男":"小儿运度未佳，虽聪明，但防上春月小疾多事，守旧并吓月娘，交秋返运出入平安。","女":"小女之卦时令未佳，但防上春皮肤小疾，守旧并吓月娘，交秋返运，出入平安。"},{"年龄":"16-17岁","男":"祥造虽精通聪明，但防上春月灾难多事，不可自执己僻，吓天地化吉，交秋返运平安。","女":"玉造现年运限未佳，惟防春夏月小疾，夜时勿独行，宜吓月娘化吉，交秋转运平安。"},{"年龄":"18-29岁","男":"英造步运未美，似铁镜重磨，防上春月小人不测之祸，宜戒性，交秋转运，可得破财喜平安。","女":"玉造行运未美，签文铁镜重磨，防春夏月灾难口舌，吞忍性气，交秋转运，吓月娘化吉平安。"},{"年龄":"30-55岁","男":"台造步运不美，春夏月歹人祸非口舌，西方注意，吓天地化吉交秋转运，有贵人扶助财运平安。","女":"坤造行运未遂，心内迫切，宜温柔大量，春夏月暗疾口舌，凡事吞忍，吓月娘交秋转运平安。"},{"年龄":"56-69岁","男":"台造步运不旺，虽老练，但防歹人嫁祸生非，凡闲事勿近理，安分守己，交秋转运平安。","女":"坤造行运美中不足，但防春夏月暗疾口舌，凡事勿过分操迫，宜吓月娘化吉平安。"},{"年龄":"70岁以上","男":"福造老运不旺，虽忠诚，但防灾难跌地之厄，早晚上落小心，忌看病人，守旧则大造平安。","女":"坤造老运不旺，虽旺益子孙，但防暗疾上身，忌入丧门，春夏月守旧勿外出，则大造平安。"}]},"生意":{"生意":"春夏时令运未通，生意交易守旧风，谋望求财须等候，秋月圆时利倍浓。","生意解曰":"春夏利薄，宜守旧刻苦经营，秋后可得财利，肖牛者有贵人扶助，新创生意定得厚利。","开铺":"卜开铺之卦春夏小利有阻，宜求佛祖符令镇宅保平安，秋后可得财利，肖牛者可得大利。","合伙":"合伙卜合伙之卦不美伙计不同心各自有私心，恐要亏本惹出是非，勿和为好!","置货":"卜此卦开始置货时，防货物起价，但要勇气留至秋后发售，可获大利。"},"出外":{"出外":"卜出外一事上春恐防是非口舌和小人累害，宜勤谨慎守旧业，交秋后各平安。"},"谋望求财":{"谋望":"运未亨通莫强求，眼前求得也成忧，不如守旧依稀过，好得荣华在后秋。","谋望解曰":"肖牛之人谋之定成但是口舌忍之，余人运未通，候交来年或秋后成之","求财":"正财春夏月时令未通，财利稀薄宜刻苦守旧经营，秋后后转运有财利，偏财定失，肖马者得大利也!"},"学艺功名":{"学艺":"卜学技艺之事，君时运未到，应守旧，待以后时令合局，才拜师学之。","功名":"功名时运未通，不能得中，尚且不吉。"},"行舟六畜":{"行舟":"行舟春夏不吉利，交秋后定顺也。","六畜":"苦力饲养成果难，费尽心机也是空。求吓神明保大吉，秋后财利丝丝攀。","猪羊":"猪羊春夏恐防阻失 勿贪养 切记之 吓伯爷保佑平安 秋后可得小利","草龙":"卜养草龙之卦 恐春夏月有阻隔 未养者暂勿购防脚疾 防牛有僻 使用应小心 吓伯公保安","三鸟":"卜养三鸟之卦 恐防春夏月有阻 防瘟疾 防盗贼 秋后转运有财利","田蚕":"田蚕早中失 晚大吉 四季雨水不祥"},"移徙":{"移徙":"移徒不吉 移之不顺凶也 切勿移之"},"行人":{"解曰":"行人在外身体平安 安稳免疑 但为了财利而不想归也 于正 四 七月有佳音也","签文":"途中安稳不须疑 只是财中得转迟 若问归期何日到 虎头蛇尾报君知"},"婚姻":{"解曰":"婚姻虽好但内且待缘份到时便可成也","签文":"此亲虽好未为良，休要耽迷惹祸殃，且守得有缘份到，不须持早待心坚。"},"官讼":{"解曰":"官讼宜和 不可告 可保两家依然安乐吉祥 若告之 恐惹祸非忧愁也","签文":"若求胜负不宜求 守旧依然可免忧 官讼宜和方为吉 二家安乐在心头"},"失物":{"解曰":"失物的踪迹很少人知道 急寻也不能得见 待到月逢申酉日 即可寻到","签文":"遍寻踪迹少人知 不若回头且待时 等到月逢申酉日 其中方可论归期"},"占病":{"解曰":"身体健康第一 应该请良医治之 求佛祖保佑平安 七十以上老人防冲跳凶也","签文":"自古人生七十稀 只因多利染灾非 穷通大寿前皆定 但是身全第一宜"},"其他":{"灶君":"此灶位分金合课 但嫌灶前迫塞 受门窗杀冲照 宜掩遮 修净灶前 烹煮叶吉","阳基":"卜阳宅欲起造有阻 旧阳宅宜择利修整居住吉 但勿更新","六甲":"卜此胎六甲生女平安 若生男要小心 望夫之福也 宜求佛祖保佑养育平安","子息":"卜子息之卦 有贵星投怀 而且寿命绵长 但防母氏冲身 宜移房拜契 则母安子顺也","祖山":"卜贵祖地横龙结穴 气脉足旺 局口文雅 但嫌点穴未真 如要葬者点高三五尺 葬此地时宜用小利补贴 大事便可成也","青草":"卜此地龙脉足旺 但嫌面前受杀 若未点穴宜沉阳葬之 则财丁兴旺也 但应防口舌是非 宜理妥葬之吉也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  26,
  '姜太公遇文王',
  '新月如弓之兆',
  '大吉之卦',
  '未羊',
  '武吉毙人伏罪，得姜尚教化，逃脱周文王先天算法。缘此文王知姜尚为异人，必有经世奇才，往访之不遇，复斋戒沐浴，亲驾渭滨，迎请同治乱世。王让车辇以载姜尚，并为之御。姜推让，步行八十步，主周室绵历八百年之数。时姜尚八十初度，始展其志，助文王灭纣兴周。',
  '四泽春水深，静处值怀音;天书传好事，喜气入渭津。',
  '新月如弓',
  '{"签号":"第二十六签","签名":"姜太公遇文王","签文类型":"新月如弓之兆","卦象":"大吉之卦","生肖":"未羊","签文简介":{"戏文":"武吉毙人伏罪，得姜尚教化，逃脱周文王先天算法。缘此文王知姜尚为异人，必有经世奇才，往访之不遇，复斋戒沐浴，亲驾渭滨，迎请同治乱世。王让车辇以载姜尚，并为之御。姜推让，步行八十步，主周室绵历八百年之数。时姜尚八十初度，始展其志，助文王灭纣兴周。","诗曰":"四泽春水深，静处值怀音;天书传好事，喜气入渭津。","内兆":"新月如弓"},"家宅运势":{"签文":"敬神自在心头欢，门户光明万事安，不但田蚕皆兴旺，谁知失落不相干。","解曰":"吉宅可有喜气临门，但人口防四，六，九月有口舌痛疾，还防火盗之厄，是厝前受杀，白虎畔有石冲伤，宜求佛祖福灯安门上祭化居住大吉。"},"岁君签":{"总诗":"安居旺相进田蚕，天上生云地下雷，禄位高升光显达，荣华富贵入门来。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗稳固，八字清格，有旺益上人并茂，喜孝物勿近，幸吉星守度平安。","女":"小女根基足养，有旺益上人，三、四、七月小疾无妨，有吉星照身，可卜出入平安。"},{"年龄":"4-7岁","男":"小儿现年运限亨通，天真活泼，旺益上人，三、四、七月水厄小心，幸吉星守命，出入平安。","女":"小女现年运限顺遂，伶俐精神，有旺益上人，三、四、七月水边小心，吉星守命，出入平安。"},{"年龄":"8-12岁","男":"小儿运度叶吉，性质活泼，宜入学校读书，定卜进步，水边小心，吉星守命平安。","女":"小女运限顺吉，精神通畅，三、四、七月虽有小疾无妨，水边小心，幸吉星守命平安。"},{"年龄":"13-15岁","男":"童造今年交上运，各事聪明开窍，培养入学，定卜前途进展，小疾无妨，出入平安。","女":"小女今年运度甚佳，各事技巧，通情达理，三、四、七月小皮疾无妨，吉星照身平安。"},{"年龄":"16-17岁","男":"祥造现年运度亨通，签文如新月挂弓之兆，各事通能，可学习文化，定卜前途远大，出入平安。","女":"玉造行运甚美，签文新月挂弓之兆，为人贤玉智慧，三、四、七月小疾无妨，出入平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如新月挂弓，做事特达，宜向外发展，春夏月小疾无妨，贵人扶助可得财喜平安。","女":"玉造行运顺利，如新月挂弓，五行清秀，助益家庭，三、四、七月虽有小疾无妨，有吉星守度平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如新月挂弓，凡事老练经济，从正发展，定卜有贵人扶助，可得财喜出入平安。","女":"坤造行运佳美，如新月挂弓，各事贤惠，有内助之称，但勿迫切，三、四、七月虽有暗疾无妨平安。"},{"年龄":"56-69岁","男":"台造步运亨通，为人忠诚耿直，但凡事宽怀，有小人口舌无妨，卦中有贵人扶助，出入平安。","女":"坤造行运交泰，贤淑智慧，虽有旺益家庭，但嫌操心迫切，有些小暗疾无妨，出入平安。"},{"年龄":"70岁以上","男":"福造老运亨通，老当益壮，凡事涵养，三、四、七月小疾无妨，有贵人扶助，福体安康。","女":"坤造老运顺吉，旺益子孙，但有些暗疾无妨，喜孝物勿近，吉星守命，晚景胜前。"}]},"生意":{"生意":"新开商店春夏盈，旧业经营夏平平，欲问交易何时旺，中秋时节财利生。","生意解曰":"新创业春夏得厚利，宜用苦力维持，秋后可得财利","开铺":"若新开张铺户，可卜财源广进，若老铺经营春夏月小得，秋后转运可得厚利也。","合伙":"卜合伙之卦叶吉协力经营有财利可得，但恐合不长久，必须谨慎注意也!","置货":"卜置货恐购货时市情败退，但无妨，候交秋后货物振价，可得财利也。"},"出外":{"出外":"运气方盛宜出运方，有贵人扶助各事得心应想，可得名利双全!"},"谋望求财":{"谋望":"运至方得出运邦，自然财宝聚衣厢，名利喜在随人欲，却笑浮生空白忙。","谋望解曰":"谋事可成但防口舌，宜用苦力，候交秋后有贵人扶助，即可成功也!","求财":"正财取之大吉但春夏月财利稀薄，宜刻苦经营，秋后有贵人可得财利，偏财勿取恐有是非!"},"学艺功名":{"学艺":"卜学技艺之卦虽合课，但嫌虎头蛇尾，恐半途而废，若能下决心学习者，定能技艺随身。","功名":"功名不成，文武者皆不中也。"},"行舟六畜":{"行舟":"行舟平和，要刻苦勤谨。","六畜":"各类六畜各不同，冬月养猪恐阻难。牛羊养之顺又吉，鸡犬养之也平安。","猪羊":"饲养猪羊 饲料调和 但冬月养猪恐白费工夫养羊大本大利 可以多养","草龙":"卜饲养草龙之卦顺遂水草调和 使用平安 但不可过度 母牛可有孕产育平安","三鸟":"卜饲养三鸟之卦平安饲料调和 可以多养 但大只三鸟应及时出卖 可得財利","田蚕":"早蚕不利 四季雨水宜也"},"移徙":{"移徙":"移待平和 要移可居 老屋修补后可居"},"行人":{"解曰":"行人在外时令转达 似太公遇文王 有贵人扶助 四 六 九月有佳音回家也","签文":"骏马长途紧着鞭 三更月明是朝元 京都自有逍遥路 一纸音书下九天"},"婚姻":{"解曰":"婚姻定成且不用媒人，前缘注定五百年前结成同心同德，互敬互爱","签文":"好对婚姻不用谋，有心不必急相催，前生注定非今日，五百年前结果来。"},"官讼":{"解曰":"官讼自有贵人解之 息事宁人 一团和气 抽身勿理 事情便平息下来","签文":"贵人相接不相干 一团和气共一门 汝当抽身归去好 任他作福百千般"},"失物":{"解曰":"失物迟回 不须怨恨愁叹 死物却似活物 踪迹易寻 时到物自有归也","签文":"东西两岸旧人家 失去踪由果有些 死物依然作活物 不须怨恨痛咨嗟"},"占病":{"解曰":"凶星虽退 但还要求华盖星君保佑之 向北方祭送 病 能消除 身体可平安","签文":"凶星已退病又缠 华盖先行作福人 一炷心香通上表 忽然病又脱身躯"},"其他":{"灶君":"此灶位分金合课 但嫌面前迫塞秽气 宜时常修理 清净 烹煮可旺益财丁也","阳基":"卜阳宅吉 欲新建嫌白虎畔空野 宜掩祭吉 老阳宅 修井水神归口 亦大吉大昌","六甲":"卜此胎六甲生女 似新月如弓 根基足 养育平安 可喜可贺也","子息":"卜子息之卦 先得花 后得果 可贵男儿 命里清秀 来日自有发展 荣宗耀祖 可喜可贺也","祖山":"卜贵祖佳城横龙结穴 但嫌水神散出白虎畔又嫌有石冲射 宜消纳相朝并修水神 或再葬沉并兜唇之 后 财丁昌盛","青草":"卜此地横龙结穴 气脉足旺 但气散 葬穴宜沉阳又 嫌水散面前宽阳 宜填浮白虎畔朝拱 葬之大吉也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  27,
  '岳飞风波亭受害',
  '泥中取禽之兆',
  '下卦',
  '午马',
  '金兀术九伐中原受挫，乃以重金收买宋朝奸相秦桧，使设害宋帅岳飞。时岳家军正势如破竹，直捣黄龙，秦桧假传十二道金牌，追回岳飞，投于狱；并从妻谋，趁除夕风雪以“莫须有”罪名，暗害岳飞于风波亭。',
  '龙入蛇宫穴，难得伸转身;曲川进烈火，急祷旺中神。',
  '龙入蛇穴',
  '{"签号":"第二十七签","签名":"岳飞风波亭受害","签文类型":"泥中取禽之兆","卦象":"下卦","生肖":"午马","签文简介":{"戏文":"金兀术九伐中原受挫，乃以重金收买宋朝奸相秦桧，使设害宋帅岳飞。时岳家军正势如破竹，直捣黄龙，秦桧假传十二道金牌，追回岳飞，投于狱；并从妻谋，趁除夕风雪以“莫须有”罪名，暗害岳飞于风波亭。","诗曰":"龙入蛇宫穴，难得伸转身;曲川进烈火，急祷旺中神。","内兆":"龙入蛇穴"},"家宅运势":{"签文":"不祥值梦已虚惊，鸡犬无端作怪声，非是家神来取祸，只因不记旧亡灵。","解曰":"吉宅之卦签文有梦字可化成喜字，但防三，四，九月疾难口舌，是非失财，吓妈祖保佑平安，外是祖山不顺，内是灶君不旺，备事修整则居住财丁兴旺。"},"岁君签":{"总诗":"家舍惶惶主不祥，只缘先祖作祸殃，且宜作福永祈祷，更答家门香火堂。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基浅薄，惟防三、四月多有灾疾之厄，吓吴爷化吉，交秋返运平安。","女":"小女根苗足养，但防三、四月小疾波阻，吓吴爷化吉，交秋返运平安。"},{"年龄":"4-7岁","男":"小儿运限未美，惟防三、四月小疾汤火之厄，宜注意，吓吴爷交秋返运，出入平安。","女":"小女现年运限未美，三、四月但防灾难波阻，守旧，吓吴爷化吉，交秋返运平安。"},{"年龄":"8-12岁","男":"小童现年运度未美，三、四月但防灾难汤火之厄，宜谨慎，吓吴爷交秋平安。","女":"小女运度未美，但嫌执僻又防三、四月多生灾疾，守旧，吓吴爷交秋平安。"},{"年龄":"13-15岁","男":"童造虽聪明，但防三、四月灾难波阻，不可执僻，吓吴爷化吉，交秋返运平安。","女":"玉造运度未遂，僻性太重，防有小疾波阻汤火之厄，吓吴爷交秋大吉。"},{"年龄":"16-17岁","男":"祥造运度未美，似龙入蛇宫，人虽聪明，但防三、四月灾难口舌，宜学习文化，吓吴爷交秋平安。","女":"玉造现年运度不美，似龙入蛇宫，虽技巧，但防春夏月小疾波阻，吓吴爷交秋平安。"},{"年龄":"18-29岁","男":"英造步运不美，似龙入蛇宫，防三、四月小人口舌祸非，凡事勿迫性，吓吴爷交秋转运平安。","女":"坤造行运不美，似龙入蛇宫，虽有助益家庭，但防小疾口舌，三、四月东南方勿往，吓吴爷交秋平安。"},{"年龄":"30-55岁","男":"乾造步运不美，似龙入蛇宫，但嫌心内操杂，三、四月防小人不测之祸，宜守本份，交秋转运平安。","女":"坤造行运未美，似龙入蛇宫，人虽智慧，但防暗疾口舌，凡事吞忍，三、四月守旧，交秋转运平安。"},{"年龄":"56-69岁","男":"台造步运不旺，似龙入蛇宫，虽忠诚，但防三、四月小人平地风波，闲事切勿近理，交秋转运平安。","女":"坤造行运美中不足，但防暗疾口舌，凡事吞忍，三、四月守旧，夜时不可外出，交秋转运平安。"},{"年龄":"70岁以上","男":"福造老运不旺，操劳过度，常时灾疾风气之阻，春夏月守旧，忌入丧门，交秋各事平安。","女":"妇造老运不旺，虽有旺益子孙，但防暗疾上身，春夏月守旧，忌看病人，交秋各事平安。"}]},"生意":{"生意":"货物购进快出售，偏财莫取正财筹，稳重谨慎防祸劫，神明炉前好香求。","生意解曰":"生意似泥中取禽，财利得后恐防小人耗财，宜从正道谨慎经营，勿贪财利则安。","开铺":"卜开铺之卦铺面不宜扩大，宜守旧经营，货物不可进得太多，宜立财帛星君奉记吉也。","合伙":"卜合伙之卦不吉，如泥中取禽之兆，不可合也，伙计不同心，合之定失财且生是非口舌。","置货":"置货不美，防财利阻失，小心劫之，宜守旧经营则财可安也。"},"出外":{"出外":"时令不美，恐防小人生端寄祸，宜守旧课经营谨慎用心则平安。"},"谋望求财":{"谋望":"枉使贪心事已迷，不依本份强施为，一朝祸起萧墙内，徒得莺歌鹊已飞。","谋望解曰":"谋事时令不通，谋之恐失也，凡事从正道为佳，肖龙者切不可谋之，谋之定失也。","求财":"正财取利虽有得，但防小人阻隔累劫，凡事从正道守旧经营，偏财勿取，取之定失也。"},"学艺功名":{"学艺":"卜学技艺之卦不成，如龙入蛇穴之兆，君宜购书自习等候时运，才拜师学习也。","功名":"功名文武皆不得，谋事困难也。"},"行舟六畜":{"行舟":"行舟不顺，有灾厄失破也。","六畜":"养猪喂羊心莫贪，大只出售防阻难。牛羊猪马恐有失，切吓灶君保平安。","猪羊":"饲养猪羊恐防三四 人月阻失中大只及时出卖 吓灶君保佑平安","草龙":"卜养草龙之卦 水草不调恐和 恐防身脚之疾应下工夫管理或更换过 吓灶君保安","三鸟":"卜养三鸟之卦似龙人蛇之穴兆 恐有阻失 切不可多养大只及时出卖 吓灶君平安","田蚕":"田蚕早晚失之 防盗也 四季雨水平平"},"移徙":{"移徙":"移徒不祥 不可居住也 守旧大吉"},"行人":{"解曰":"行人在外身体平安 但恐有小人阻隔累害 音信稀断 吓佛祖保佑财作回家","签文":"以后三般不自由 门庭寂寞冷如秋 行人一去无消息 直到春来且莫愁"},"婚姻":{"解曰":"占来的嫁娶要惹三重官非，要好好三思不为，若为之恐惹祸非也。","签文":"占为嫁娶择二堂，意欲求神恐不良，若不三思存善恶，后来追悔受灾殃。"},"官讼":{"解曰":"对方有靠山 君虽有理安无可胜之 不如息怒和相宜 若告之恐有祸非","签文":"讼虽有理尚迟迟 不若同和事两宜 若到公堂难解脱 文词反复更难离"},"失物":{"解曰":"时运不顺 失财难寻 若到处乱寻或胡疑人家 恐要惹起祸非 应该注意","签文":"家神不合惹祸非 失去原来自己财 只是自家时运拙 何须心下自相猜"},"占病":{"解曰":"冲犯灶君 应向灶君改罪 求佛神敬送太阳经保平安 肖龙老人防冲跳凶也","签文":"命蹇时乖是与非 何须临急告神知 不日遂了心头息 莫负当初立好时"},"其他":{"灶君":"此灶位不吉 是灶迹地下有孤骨 宜择生气延年方位 重建新灶 平安大吉","阳基":"卜阳宅欲起造防口舌失财勿贪吉 卜旧阳宅是辰卫方有杀冲伤破龙运不旺 若有利修修整吉","六甲":"六甲生男 恐根基不足 宜移房拜契显赫神明保平安 若生女平安也","子息":"卜子息之卦 多生少养 宜多做善事 用些财物救济世人或捐献神明 则有后代也","祖山":"卜贵祖地横龙结穴 但嫌青龙畔受杀 兼龙运不旺 下水不美散出 坐向有利 宜修壮龙运 并理水神归口 葬之财丁旺 有做山地点宜改修","青草":"卜此地有结穴 但嫌轻重畔 辰卫方有峰杀冲伤 气脉足旺 傍边有古人 葬时防口舌失财 至切宜妥 修理合课"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  28,
  '吴春女为王后',
  '谋望遂心之兆',
  '大吉之卦',
  '巳蛇',
  '华夏文明之邦，历朝多女史。吴春女，女中佼佼者也，少聪慧，及长，明功、名富、贵之本义在天地家国之间也。乃优其民而留意于经济文章。经年，熟读兵书，精通韬略，且胆识过人，内助王成大业。王定鼎，册立吴春女为皇后。',
  '一鹿伴羊日，家中得安排;珍珠帘下立，清净得光辉。',
  '万物逢春',
  '{"签号":"第二十八签","签名":"吴春女为王后","签文类型":"谋望遂心之兆","卦象":"大吉之卦","生肖":"巳蛇","签文简介":{"戏文":"华夏文明之邦，历朝多女史。吴春女，女中佼佼者也，少聪慧，及长，明功、名富、贵之本义在天地家国之间也。乃优其民而留意于经济文章。经年，熟读兵书，精通韬略，且胆识过人，内助王成大业。王定鼎，册立吴春女为皇后。","诗曰":"一鹿伴羊日，家中得安排;珍珠帘下立，清净得光辉。","内兆":"万物逢春"},"家宅运势":{"签文":"莫将此事起疑心，虽有浮云岂久阴，此际财人两兴旺，更无火盗两相侵。","解曰":"吉宅人口有喜气临门，但防夏月口舌小疾火盗之厄，是厝前有杀冲伤，宜求佛祖七星令旗安门上祭化，有贵人扶助男女老少平安大吉。"},"岁君签":{"总诗":"贵人接引喜逢时，官非口舌门庭离，病除疾去身安稳，若问求官定得名。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足养，八字清秀，有旺益上人并茂，虽有小疾无妨，吉星守命平安。","女":"小女根苗稳固，利益上人，正、三月虽有小疾无妨，幸吉星守命平安。"},{"年龄":"4-7岁","男":"小儿运限亨通，生性天真，利益上人，正、三月虽有皮疾无妨，出入平安。","女":"小女运限叶吉，伶俐活泼，上春月虽有小疾无妨，吉星照身，出入平安。"},{"年龄":"8-12岁","男":"小童今年上运，伶俐活泼，宜入学校读书，定卜进步，上春月小疾无妨，出入平安。","女":"小女现年交上美运，各事技巧，但上春月虽有小疾无妨，吉星守命平安。"},{"年龄":"13-15岁","男":"童造运度亨通，聪明开窍，培养学习文化，前途进步，出入平安。","女":"玉造运度顺遂，可入学温习文化，上春月虽有小疾无妨，吉星守度平安。"},{"年龄":"16-17岁","男":"祥造现运顺遂，吉庆分明，各事精通，培养入学，前途远大，上春月虽有小疾无妨，贵人扶助平安。","女":"玉造现运交泰，吉庆分明八字清秀性格和暖，宜习艺业，上春月虽有小疾无妨，吉星照身平安。"},{"年龄":"18-29岁","男":"乾造步运亨通，如吉庆分明，做事精通才能，可向外发展，有贵人扶助可得财喜平安。","女":"坤造行运交佳，如风云际会，为人贤玉机机智，助益家庭，上春月虽有小疾无妨平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如吉庆分明，做事才能特达，可向外争取，有贵人扶助，可得财喜出入平安。","女":"坤造行运交佳，如吉庆分明，但嫌有些暗疾口舌，凡事温柔和气，幸有吉星守命平安。"},{"年龄":"56-69岁","男":"台造步运亨通，虽是老练，但嫌身闲心迫，凡事宽怀，底子晚景胜前。","女":"坤造行运交泰，各事贤惠，可称内助之德，虽有些暗疾无妨，吉星照身出入平安。"},{"年龄":"70岁以上","男":"福造步运交脱，人老心直，但防跌地之厄，上春月上落小心，有贵人扶助平安。","女":"坤造行运虽温柔，旺益子孙，防暗疾上身，上春月守旧，幸吉星守命平安。"}]},"生意":{"生意":"公平交易好心机，购货有阴贵人持，偏财勿取取定败，五六十月真价知。","生意解曰":"生意可得厚利，但初时有阻，幸有贵人扶助，要从正道经营秋后可得厚财利!","开铺":"卜开铺之卦叶吉如万物逢春之兆，宜忍口舌礼貌待客，防火盗之危宜请水德星君镇宅，秋后可得厚利也合伙;卜开铺之卦可成如万物逢春之兆，但伙计必同心同德，协力经营有厚财利。","合伙":"卜合伙之卦可成，如万物逢春之兆，但伙计必同心同德，协力经营，有厚财利可得也。","置货":"现年置货初防阻失，但心地宜立忠正，有贵人扶助，秋冬月可得厚财利也。"},"出外":{"出外":"卜出外一事宜从正道有贵人扶助，不但平安而且应心得想，东成西就!"},"谋望求财":{"谋望":"积善之家庆有余，吉人自有吉星持，求财心合存天理，任是凶危也消除。","谋望解曰":"谋事可成但防小人阻隔宜立正直有贵人扶助，如若亏人恐生祸非也","求财":"正财取利大吉，凡事经营宜从正道不可亏人，交六，八，十一月有贵人扶助可得厚利偏财勿取平安!"},"学艺功名":{"学艺":"卜学技艺之卦，肖羊之人合课，可学得好技艺，余人只能学得一般技艺，秋后拜师学之定可成功。","功名":"功名肖羊者显达，余者逢未科也可得也。"},"行舟六畜":{"行舟":"行舟顺风得利，大吉平安也。","六畜":"春来六畜少吉祥，饲养猪羊不及羊。七星令旗可镇宅，羊群肥猪庆丰年。","猪羊":"饲养猪羊春月有小阻无妨 可大胆多养 求令旗镇宅可保平安得利 养羊得大利","草龙":"饲养大武之卦大吉 水草调和 但使用时不可劳累过度 宜求佛祖令旗安畜舍上保安","三鸟":"卜养三鸟之卦叶吉 饲料调和 但防春月有小阻无妨可以多养 有财利可得","田蚕":"早蚕大吉 早晚二冬有收 四季雨水吉"},"移徙":{"移徙":"移徒平和 要移可居 老屋修补后可居"},"行人":{"解曰":"行人在外得意 有贵人扶助 各事如意 待到三 五 八月有佳音财利回家也","签文":"行人若问几时归 待到三三五五时 若遇贵人扶持力 不须惆怅事灾危"},"婚姻":{"解曰":"良缘巧合此际可以说成，应该长速下聘，不可迟延拖，若迟这恐生变也","签文":"良谋相对说知音，莫教错过又来春，此际好调琴瑟韵，真是风清月白人。"},"官讼":{"解曰":"官讼得胜 见官有贵人 但要以和为贵 要宽怀大量 听从傍人劝解 平安大吉","签文":"不用事投词已开 一团和气入门来 见官自有贵人力 保必忧疑挂心怀"},"失物":{"解曰":"失物后应即请人帮忙寻之 并扬言说已知道踪迹 然后速寻便可找到也","签文":"东西南北路头通 逢人便说有知踪 伊人休要辞劳力 仔细速寻不落空"},"占病":{"解曰":"请良医治病服药 要求佛祖天地保佑 四方祭送平安 大吉 但老者恐失也","签文":"作善修身风世缘 君家明德赖苍天 良医自有灵丹药 此必神功保命全"},"其他":{"灶君":"此灶位分金合于八宅之课 堂时灶前修理清洁 不要秽气 烹煮叶吉也","阳基":"卜此阳宅欲起造防口舌阻隔 心地宜正直能化吉 若私心妄为 定有口舌失财","六甲":"此胎六甲生男 平安大吉 初时有小阻无妨 吓神明保佑养育平安","子息":"卜子息之卦 君命里带孤寡 宜修心积德 多作善事 可得贵子 继承香灯也","祖山":"卜贵祖地横龙结穴 气脉足旺 但嫌葬穴孤阴 坐向有利 宜改唇前并理水字归口 占葬前之才兴旺 祖地可取大吉","青草":"此地有结穴 但嫌有口舌 是傍边有阻碍 至切理妥之 免生祸非也 葬时宜占高一点 葬后房房可财丁兴旺也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  29,
  '郭子仪拜寿',
  '春来花发之兆',
  '上上之卦',
  '辰龙',
  '唐郭子仪战功显赫，后又平定安史之乱，以年事高解封王，享厚禄而名潢天下，又适逢八十大寿，七子八婿登堂拜寿，满朝文武入府祝遐，连日喜庆，朝野称贺，热闹非凡。古今辅天地、关家国而得功成名就，福禄寿全者至于斯而已也。',
  '新荷初出来，花叶正发开;鬼抱心中斗，名传天下知。',
  '花木逢春',
  '{"签号":"第二十九签","签名":"郭子仪拜寿","签文类型":"春来花发之兆","卦象":"上上之卦","生肖":"辰龙","签文简介":{"戏文":"唐郭子仪战功显赫，后又平定安史之乱，以年事高解封王，享厚禄而名潢天下，又适逢八十大寿，七子八婿登堂拜寿，满朝文武入府祝遐，连日喜庆，朝野称贺，热闹非凡。古今辅天地、关家国而得功成名就，福禄寿全者至于斯而已也。","诗曰":"新荷初出来，花叶正发开;鬼抱心中斗，名传天下知。","内兆":"花木逢春"},"家宅运势":{"签文":"敬神自是合天心，人善神饮祸不侵，此不淹留无阻滞，田蚕十倍在深秋。","解曰":"吉宅喜气临门田蚕十倍，但嫌夏月人口有小疾口舌涉财，每逢塑望应诚心敬拜佛祖，天地保平安，埕口水道秽修通。"},"岁君签":{"总诗":"阴阳相合事亨通，如今行在明月中，琴瑟调各门户吉，荣华富贵喜重重。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，八字清秀，有旺益上人并茂，上春月虽有小疾无妨，吉星守命平安。","女":"小女根基足养，有旺益上人并茂，上春月虽有小疾无妨，吉星守命出入平安。"},{"年龄":"4-7岁","男":"小儿现年运限顺遂，利益上人，上春月小疾无妨，水边小心，吉星守命出入平安。","女":"小女现年运限叶吉，旺益上人，上春月皮疾无妨，水边小心，吉星守命出入平安。"},{"年龄":"8-12岁","男":"小童之卦时令亨通，天真伶俐，培养入学书，定卜进步，吉星照身出入平安。","女":"小女运度叶吉，各事活泼，上春月水边勿近，虽有小疾无妨，吉星守度出入平安。"},{"年龄":"13-15岁","男":"童造现年时令甚佳，各事开窍聪明，勤奋学习文化，定卜进展，出入平安。","女":"小女运度交佳，凡事伶俐精通，但水边小心，上春月虽有小疾无妨，出入平安。"},{"年龄":"16-17岁","男":"祥造运度亨通，如春来花发，做事聪明有智，不可忽视文化，将来有进展之日，出入平安。","女":"玉造行运交泰，如春来花发，凡事技巧，八字清秀，多学艺业，虽有小疾无妨，出入平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如春来花发，做事通能特达，可向外发展经营，有贵人扶助，可得财喜平安。","女":"坤造运度顺遂，如春来花发，智慧贤玉，助益家庭，上春月虽有小疾无妨，出入平安。"},{"年龄":"30-55岁","男":"乾造步运顺吉，如春来花发，来练奇才，宜立凌云壮志，发展前途有贵人扶助，可得财喜平安。","女":"坤造行运交泰，如春来花发，做事智慧，但勿操迫，有些暗疾无妨，吞忍性气，吉星守命平安。"},{"年龄":"56-69岁","男":"台造步运亨通，为人老练忠诚，签文如春来花发，上春月虽有小疾无妨，贵人扶助出入平安。","女":"坤造行运交泰，贤淑温柔，旺益家门，但有些暗疾无妨，卦中有吉星照身，可卜出入平安。"},{"年龄":"70岁以上","男":"福造老运安康，如春来花发，老当益壮，为人宽宏大，定卜晚景胜前平安。","女":"妇造老运康泰，有旺益子孙，有些暗疾无至大害，太阴星守度平安。"}]},"生意":{"生意":"山荼荷花不合丘，初时磨苦小利酬，和气待人心头记，硕果遍地大丰收。","生意解曰":"生意合伙不利有阻失，独做二，三磨苦小利，交五，八，十一月生意兴隆可得大利","开铺":"卜开铺之卦如春来花发之兆，生意兴隆可独占鳌头，五月起可得厚财利，但应忍口舌文明经商。","合伙":"卜合伙之卦不吉恐伙计各有私心防是非口舌防阻失，勿合!","置货":"置货一卦，初时劳苦，财利稀薄，八月起物价渐有提升，到底可得财利也。"},"出外":{"出外":"卜出外之卦似春花开之发，凡事勿疑有胆往外，有贵人扶助可得名利双全。"},"谋望求财":{"谋望":"十年辛苦在寒窗，一旦翻身入选场，幸得朝庭用智士，传扬天府姓名香。","谋望解曰":"谋望;定成有贵人扶助，谋之即可随意但肖龙之人切不可谋，恐祸非失财也!","求财":"正财初时稀薄，宜刻苦维持二，五，八，十一月有贵人扶助可得大财利偏财初有恐失，但到得底得大利!"},"学艺功名":{"学艺":"卜学技艺之事叶吉，宜坚心立志，勤恳向上，多问多想，自能得到名师传精艺也。","功名":"现科文武功名皆中，荣宗耀祖封妻荫子。"},"行舟六畜":{"行舟":"行舟平安，顺风得利也。","六畜":"初时六畜运未通，待到时来花自红。红花点点来庆贺，大好财利在秋冬。","猪羊":"啜养猪羊 饲料调和可大胆多养 精心管理 从小利到大利 平安大吉","草龙":"卜饲养大武之卦顺遂 水草调和 身强力壮使用顺利 能旺益家道兴隆也","三鸟":"卜养三鸟之卦叶吉 如花木逢春 生长快可大胆投资多养 秋冬月可得大財利","田蚕":"田蚕早中晚大吉 四季雨水有财有利"},"移徙":{"移徙":"吉宅可居 财丁两旺 永远流芳"},"行人":{"解曰":"行人在外 今已转运得志 不用挂心 有贵人扶助 交二 五 十月音信财利回家","签文":"关山迢迢隔田园 有客加鞭已转归 今日忧危已扫尽 忽然已归自家门"},"婚姻":{"解曰":"婚姻成之大吉，两人相合不用媒人，待月明之时便可下聘，就可成功也?","签文":"赤绳系足问前程，不用求谋事以成，丝牵月明缘份到，静坐好听凤凰鸣。"},"官讼":{"解曰":"官讼得胜 但是一德可为 不可方人 不要劳心费神 还是和为贵 平安也","签文":"你是人中恺悌人 糊为糊作损精神 人德不如阴德好 从教到底不沾身"},"失物":{"解曰":"失物可回 有失在远方 应该从速耐心寻找 自有神力扶助 一定能见踪迹","签文":"失却虽然路远斜 浮重何处难回家 急寻自有神光见 不怕重重篱壁遮"},"占病":{"解曰":"循环灾星占身 生之疾痕病难 但循环灾星退却之后 身体就可以恢复健康","签文":"天灾生定不由人 何用叨叨问鬼神 自是灾星退却日 依然体旺及身轻"},"其他":{"灶君":"此灶位分金合课 地基清净 常时灶前修理清洁 烹煮叶吉 可旺益财丁也","阳基":"卜阳宅吉起造平安 但嫌面前有耀水不顺 宜掩祭居住 住财丁兴旺也","六甲":"此胎六甲一定产育男儿 根基足养 能旺益母父 可喜可贺","子息":"卜子息之卦 先花后果 将来可有儿孙满堂 而是近贵 大有发展 福荫上辈也","祖山":"卜贵祖佳城 龙脉足旺 转结穴 但嫌葬后财丁不美 由是青龙畔有耀水到堂不美 有利宜掩祭或备唇制化之后房房叶吉 财丁足旺也","青草":"此地横龙气结穴 气脉足旺 但嫌面前或青龙畔有耀水朝见 宜将水耀消掩使之合课 葬后房房财丁昌盛也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  30,
  '王可居休妻',
  '玉镜尘埃之兆',
  '中平之卦',
  '卯兔',
  '王可居外父家有奸奴名江雄者，性极奸狠，王可居深恶而辱之。江雄怀恨，乃盗王妻金钗，并伪造情书，暗投于王可居。王果中计，疑妻有外遇，而断然休妻弃子，离异十八载。上妻忍辱负重，养育其子成材，后中状元认父，剖白前情，王始捐弃前嫌，妻与重叙旧好，合家团圆。',
  '放牛田中草，如何两尺长;孤鸣飞失落，马不及牛羊。',
  '夜雨欺花',
  '{"签号":"第三十签","签名":"王可居休妻","签文类型":"玉镜尘埃之兆","卦象":"中平之卦","生肖":"卯兔","签文简介":{"戏文":"王可居外父家有奸奴名江雄者，性极奸狠，王可居深恶而辱之。江雄怀恨，乃盗王妻金钗，并伪造情书，暗投于王可居。王果中计，疑妻有外遇，而断然休妻弃子，离异十八载。上妻忍辱负重，养育其子成材，后中状元认父，剖白前情，王始捐弃前嫌，妻与重叙旧好，合家团圆。","诗曰":"放牛田中草，如何两尺长;孤鸣飞失落，马不及牛羊。","内兆":"夜雨欺花"},"家宅运势":{"签文":"有心斋戒不宜开，恐惹祸非横祸来，归去依然修整过，免叫人口起鸣哀。","解曰":"此卦哀声出现若有六甲喜可将哀误会声消除，但防五，六，十一月口舌祸非疾难，是门字分金不美，灶君山坟不顺，有利各宜修整合课，吓佛祖保佑平安。"},"岁君签":{"总诗":"花正开时夜雨欺，月当明处被支披，寄言桃李本要笑，或者云开也有时。","年龄运势":[{"年龄":"1-3岁","男":"小儿根苗虽足，但防上春月灾难波阻，六甲妇勿近抱，吓月娘交秋返运平安。","女":"小女根苗浅薄，惟防上春月小疾波阻，宜吓太阴星化吉，交秋返运平安。"},{"年龄":"4-7岁","男":"小儿之卦运限未美，虽天真，但防上春月灾难多事，吓月娘交秋返运平安。","女":"小女时令未美，惟防上春月皮肤小疾，守旧，吓太阴娘，交秋返运平安。"},{"年龄":"8-12岁","男":"小童运度未遂，虽开窍，惟防上春多生灾难，吓月娘，交秋返运平安。","女":"小女现年时令未美，上春月防小疾波阻，守旧，吓月娘交秋返运平安。"},{"年龄":"13-15岁","男":"童造运度未达，虽聪明，但防上春月多生波阻之厄，吓月娘交秋返运平安。","女":"小女现年运度美中不足，但防上春月皮肤小疾，守旧，吓月娘交秋返运平安。"},{"年龄":"16-17岁","男":"祥造时令不美，人虽通能，但防上春月有些小波阻，凡事不可自执己僻，吓月娘交秋平安。","女":"玉造行运虽贤玉，但嫌美中不足，但防春夏月灾疾波阻，勿执己意，吓月娘交秋平安。"},{"年龄":"18-29岁","男":"英造步运不遂，似夜雨欺花，虽有志向，但防春夏月小人嫁祸，凡事戒忍，交秋转运可得财喜平安。","女":"玉造行运，人虽贤玉，但嫌美中不足，惟防春夏月灾难口舌，夜时勿独行，吓月娘交秋转运平安。"},{"年龄":"30-55岁","男":"乾造步运不美，似夜雨欺花，但防春夏月小人不测之祸，凡事戒忍，交秋转运贵人扶助平安。","女":"坤造行运虽有内助之能，但防春夏月暗疾口舌，凡事吞忍性气，吓月娘交秋转运平安。"},{"年龄":"56-69岁","男":"台造步运人虽老练，但防春夏月小人祸非口舌，闲事切勿近理，交秋转运，贵人扶助出入平安。","女":"坤造行运美中不足，夜雨欺花，惟防春夏月暗疾口舌，交秋吉星守命转运出入平安。"},{"年龄":"70岁以上","男":"福造老运不旺，虽福寿绵长，但防灾疾跌地之厄，早晚上落小心，忌看病人，交秋平安。","女":"妇造老运不旺，虽旺益子孙，但防灾难暗疾，忌入丧门，春夏月守旧，交秋转运平安。"}]},"生意":{"生意":"春夏经营难安排，恐有飞祸又破财，交秋冬日生意吉，牛羊之人利路开。","生意解曰":"春夏月磨苦无利，交秋冬月可得财利，但防小人累害，惟肖牛羊者可得厚利","开铺":"卜开铺之卦春夏月宜守旧，防小人祸害忍口舌，秋后转运可得财利，肖牛羊者可得厚财利。","合伙":"卜合伙之卦虽合成，但恐伙计不同心各自私偏，合之不长久肖牛羊者可得厚利!","置货":"卜置货春夏因时运未通，君虽能干也无利，如果把货留至秋冬，可得财利也。"},"出外":{"出外":"卜出外一事似玉镜灰尘之兆，春夏恐事务阻隔，往之不成，中秋后可出外各事平安!"},"谋望求财":{"谋望":"世间不及汝聪明，怎奈时乖事不成，且在灯光温习卷，交秋冬日取功名。","谋望解曰":"春夏时乖有小人阻隔，后来有贵人扶助，肖牛羊者定成","求财":"春夏月时令未通磨力多财利少，宜守旧交秋后返运可得厚利，偏财维肖牛羊者可得大财利也!"},"学艺功名":{"学艺":"卜学技艺之卦，君时运未至，虽有至亲之师，但也无法学得真艺，宜灯下自习，待机从师学之。","功名":"功名文成不中，上春不成下春中。"},"行舟六畜":{"行舟":"行舟不顺，只有十月大吉得财利也。","六畜":"春夏之月有阻难，切切不可太过贪。秋冬只有少利得，欲养求神保平安。","猪羊":"猪养之恐防五 六十月阻失不宜多养 大中只及时卖 吓伯爷保佑饲养平安 羊可大养 有大利","草龙":"卜养草龙之卦大吉 水草调和五言诗中有马不及牛羊之句可以大养有大利","三鸟":"卜养三鸟之卦似夜雨欺花 恐防五六 十月阻失不可多养 大只及时出卖 吓伯公保安","田蚕":"早蚕大中 四季雨水略 应勤耕种也"},"移徙":{"移徙":"移徒不吉 凶灾不尽 不可移之"},"行人":{"解曰":"春夏行人时运未通 有小人阻隔 宜吓天地 秋冬有音信 肖牛羊者锦旋","签文":"久去他乡未到家 两头丝绪乱如麻 若教云散蟾光现 方出人才免叹嗟"},"婚姻":{"解曰":"婚姻不成来配偶无缘，又加上旁人说是非，不可议亲，若议之也是不就也!","签文":"以前配偶本无缘，却被旁人说乱言，今日欲求难得见，不如归去待迟延。"},"官讼":{"解曰":"君本来无事 为他人问题惹了祸非 但不可告 应听傍人劝解 还是和为贵也","签文":"本来无事惹祸灾 只为他人生出来 君到公庭虽理直 不如私下劝和开"},"失物":{"解曰":"失物迟回 应问神佛查明踪迹 耐心寻之可见 应听可发怒人家 勿惹祸非","签文":"有心人是物心人 失去资财又问神 踪迹有方终久出 不须发怒惹嗔人"},"占病":{"解曰":"难求药 恐无效 当天改愿 还谢神恩 求神请医治之平安 但老者恐凶也","签文":"病已临身脱则难 求医无效减容颜 须知犹未还旧愿 呆免身淹枕席间"},"其他":{"灶君":"卜此灶位虽吉 但嫌灶前秽气不净 且又迫塞 宜时常修理干净 烹煮叶吉也","阳基":"卜此宅欲修造防口舌阻隔 理妥修造吉 惟白虎较受杀神伤 掩祭居之吉","六甲":"六甲去年有孕生男 今岁有怀生女且有阻 宜求佛祖保佑幼儿孕育平安","子息":"卜子息之卦 君时运未遂 先花后果 初难得子 宜修善积德 中外时可有得子而且顺养也","祖山":"卜贵祖横龙结穴 但嫌白虎畔受杀 又嫌分金碑面欺坤 端正并理水字清楚子午宜葬癸丁 如癸丁兼丑未用分金字向用之则吉 财丁兴旺平安","青草":"卜此地龙脉足旺 但丑未二山分金应理妥 又嫌白虎畔空野 穴宜阳做阴胎 葬后财丁兴旺也 葬时防口舌 忍则吉"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  31,
  '打北齐秦家比械',
  '四路虚险之兆',
  '下卦',
  '寅虎',
  '南北朝时周王吞并北齐，下晋阳，攻济南。北齐亲军护卫秦旭，武卫大将军秦彝父子毁家纾难，勤王御敌，均为周行军都总馆杨林杀害，秦家势危，家将秦安帮宁夫人负幼主秦琼突围脱险，逃难路遇程夫人，被收留回家。秦安代行主责，教幼主攻书习武，使秦家锏法得以传于秦琼。',
  '夏月逢天旱，三冬心失收;肥羊遇饿虎，遭遇恐生愁。',
  '乌云遮月',
  '{"签号":"第三十一签","签名":"打北齐秦家比械","签文类型":"四路虚险之兆","卦象":"下卦","生肖":"寅虎","签文简介":{"戏文":"南北朝时周王吞并北齐，下晋阳，攻济南。北齐亲军护卫秦旭，武卫大将军秦彝父子毁家纾难，勤王御敌，均为周行军都总馆杨林杀害，秦家势危，家将秦安帮宁夫人负幼主秦琼突围脱险，逃难路遇程夫人，被收留回家。秦安代行主责，教幼主攻书习武，使秦家锏法得以传于秦琼。","诗曰":"夏月逢天旱，三冬心失收;肥羊遇饿虎，遭遇恐生愁。","内兆":"乌云遮月"},"家宅运势":{"签文":"君家何必惹非灾，南北防七星来?，求祷福神更改吉，不然安得皱眉开。","解曰":"吉宅有七星杀占宅，防三，六，九月灾难口舌失财，火星小心，吓佛祖保平安，请令旗安门上镇宅祭化南北斗星君，居住平安妇人有喜生女勿出外。"},"岁君签":{"总诗":"心事忡忡常不宁，坐得方安又未安，兴意施为全未遂，恰似明月被云迷。","年龄运势":[{"年龄":"1-3岁","男":"小儿根苗浅薄，惟防上春月灾难波阻，守旧，宜吓月娘化吉方保寿命绵长。","女":"小女根苗虽足，防上春月小疾多事，宜吓月娘化吉守旧方保出入平安。"},{"年龄":"4-7岁","男":"小儿现年运限未美，但嫌执僻，春夏月防小灾疾，吓月娘化吉交秋返运平安。","女":"小女之卦运限未美，哭僻太重，防春夏月灾难，宜吓月娘交秋平安。"},{"年龄":"8-12岁","男":"小童现年运度未美，自执己僻，春夏月小疾波阻，知避暑，吓月娘交秋返运平安。","女":"小女今年运度未遂，春夏月惟防灾难多事，宜知避暑，吓月娘交秋返运平安。"},{"年龄":"13-15岁","男":"小童人虽精通，但防春夏月波灾多疾，吓月娘化吉交秋返运平安。","女":"小女之卦时令未美，春夏月但防灾难多事，守旧并吓月娘化吉交秋平安。"},{"年龄":"16-17岁","男":"祥造现年时令未美，似乌云遮月，虽聪明开窍，但防春夏月小疾多事，吓月娘交秋转运平安。","女":"玉造人虽技巧，但嫌美中不足，似乌云遮月，惟防春夏月多生小疾，宜吓月娘交秋返运平安。"},{"年龄":"18-29岁","男":"英造步运未美，似乌云遮月，但防春夏月灾难口舌小人祸非，戒性，交秋转运贵人扶助平安。","女":"玉造行运未美，似乌云遮月，虽有助益家庭，但防春夏月小疾，口舌吞忍，交秋转运玉体安康。"},{"年龄":"30-55岁","男":"乾造步运似乌云遮月，防春夏月小人不测之祸，凡事从正道，交秋转运贵人扶助平安。","女":"坤造行运虽旺益家庭，但嫌得此挂美中不足，惟防春夏月暗疾口舌，吞忍性气，交秋平安。"},{"年龄":"56-69岁","男":"台造步运不美，签文乌云遮月，惟防春夏月小人嫁祸，闲事切勿近理，交秋转运有贵人扶助平安。","女":"坤造行运未美，虽有旺益家庭，但嫌操心暗疾，宜吞忍口舌，忌看病人，交秋转运平安。"},{"年龄":"70岁以上","男":"福造老运不旺，惟防春夏月灾难跌地之厄，早晚上落下小心，交秋老福安康。","女":"妇造老运不旺，为人多忧多虑，凡事温柔大量，春夏月守旧，上落小心，交秋福体安康。"}]},"生意":{"生意":"春夏生意大不祥，正月守分利不偏，祈祷神明力保佑，冬至时节利可添。","生意解曰":"生意如虎上壁财难得，宜守旧业苦力经营秋后可得利，肖牛羊者恐折本招祸","开铺":"卜开铺之卦恐有阻失，肖牛羊者失更大，未开之铺勿开，若是老铺宅应防歹人祸害劫财，宜求佛祖令旗化吉。","合伙":"卜合伙之卦不美如四路虚险之兆，恐伙计有私偏恐惹是非口舌灾难，勿合为要也!","置货":"卜置货恐市情失，无货可取，若有货可取，宜停留至秋冬，可得财利也。"},"出外":{"出外":"卜出外一事四路絮险恐有小人伤害抢劫，宜在家守旧经营则免生愁!"},"谋望求财":{"谋望":"自然心下意忙忙，怎奈他人心自慌，财物如山皆分定，劝君守旧待时光。","谋望解曰":"时令不美谋事难成，肖牛羊之人更不可谋之，定失并防有祸","求财":"正财春夏月跋涉又防阻失，凡事立志经营秋后得利，偏财肖牛羊者勿取，恐吓惹是非受惊!"},"学艺功名":{"学艺":"卜学技艺之卦不美，如乌云盖月之兆，恐学不成，半途而废，寻师学之，便可成功也。","功名":"功名难得，肖牛羊者更免想录取也。"},"行舟六畜":{"行舟":"行舟不吉，仔细行事可以平安也。","六畜":"六畜时运今未通，费尽心机恐成空。借助神力来保佑，交秋月圆才见功。","猪羊":"饲猪春夏有阻 恐三六 九月之厄宜吓伯爷保平安 若养羊定失也","草龙":"卜养草龙之卦似乌云遮月恐防三 六 九月病疾之厄 宜换过 未养勿养也","三鸟":"饲养三鸟 时运未通 恐防三六 九月阻失 切不可贪多养 宜吓伯公保平安","田蚕":"田蚕早中晚大不顺 可收之物先收 雨水夏早春无"},"移徙":{"移徙":"移徒不安不祥 场地不平 守旧吉也"},"行人":{"解曰":"行人时运未通 恐有阻隔 身上穷困 要回难也 吓佛祖保财帛信息早日回家","签文":"欲问行程尚未还 归期不隔两重山 赢马程途鞭未去 只为丝丝着事攀"},"婚姻":{"解曰":"婚姻不成，媒人花言巧语不可信以为真，如浪蝶游蜂不可相亲，若成之恐不长久","签文":"花言巧语岂为真，浪蝶游蜂不可亲，不信但看园内物，一番风雨就伤神。"},"官讼":{"解曰":"事情要以和为上策 不可告讼 要忍耐之 忍得一时之气 免是百日之忧 不可告","签文":"事割心头剃自刀 任他车马团团转 不如忍耐莫辞劳 棋势虽高不沾身"},"失物":{"解曰":"失物难寻 不要因此自伤损害身体 候中旬月圆时速寻之 或能见到踪迹","签文":"失去如何又自伤 要知踪迹归何处 皆因不肯紧提防 等待中旬明月光"},"占病":{"解曰":"冲犯凡主家神 宜用菜饭银给往西方祭送 求药服之  移床位吉之","签文":"家宅无宗神鬼多 病人恍惚意嗟跎 如今若要身安健 设法求医可退魔"},"其他":{"灶君":"卜灶宅可算合课 但嫌灶前迫塞 宜经常修理干净 烹煮可旺益财丁也","阳基":"卜此吉宅要修整 必须择利而修 起造有是非口舌 守旧宜也","六甲":"此胎六甲若生男 夫有福平安 宜拜契显赫神明保佑","子息":"卜子息之卦 君命带孤鸾 虽有生育 但较难养 宜多作善事 可望子 且而顺养也","祖山":"卜贵祖地有结穴 但嫌葬后财丁不顺乃是白虎畔有杀冲伤 坐向有利欲取葬 宜掩祭复方杀气并欲吞金葬 财丁旺 此穴有口舌 宜埋清楚吉也","青草":"卜此地龙脉足旺 但嫌面前受杀冲照 寅未方有峰杀冲伤 墓穴宜沉阳又要兜唇掩祭 有口舌宜忍之 理妥则吉也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  32,
  '袁术称帝',
  '日落斜西之兆',
  '以为下卦',
  '丑牛',
  '东汉末年，十八诸侯攻董卓，孙坚得传国玉玺，传于子孙策。尔后孙策为收复江东，将玉玺向袁术换取精兵三千。袁术得玉玺，顿生野心，于淮南称帝。妄图号令天下。曹操会吕布、刘备三雄讨袁，大败袁军。袁术犯天下恶，被困迫吐血，自取灭亡于江亭。',
  '鹤在笼中内，鱼游于釜中;梨花开带雨，金菊吐无花。',
  '众星侵月',
  '{"签号":"第三十二签","签名":"袁术称帝","签文类型":"日落斜西之兆","卦象":"以为下卦","生肖":"丑牛","签文简介":{"戏文":"东汉末年，十八诸侯攻董卓，孙坚得传国玉玺，传于子孙策。尔后孙策为收复江东，将玉玺向袁术换取精兵三千。袁术得玉玺，顿生野心，于淮南称帝。妄图号令天下。曹操会吕布、刘备三雄讨袁，大败袁军。袁术犯天下恶，被困迫吐血，自取灭亡于江亭。","诗曰":"鹤在笼中内，鱼游于釜中;梨花开带雨，金菊吐无花。","内兆":"众星侵月"},"家宅运势":{"签文":"阴人灾害事如何，只为家中惹鬼多，如今要保平安日，除非寻僧礼达摩。","解曰":"吉宅人口防夏月有疾难祸非失财，是埕口水道不美，内有阴人作动又嫌祖山不顺，有利各要修整清楚向佛祖奉经请达摩祖师福灯安门平安。"},"岁君签":{"总诗":"众星侵月也当防，小口阴人起祸殃，弱也之时休改革，预先借福谢苍穹。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，八字成格，有旺益上人并茂，春夏月灾难波阻，吓天地化吉平安。","女":"小女根苗虽足，惟防三、六、九月灾难波阻，宜吓天地化吉，方保寿命绵长平安。"},{"年龄":"4-7岁","男":"小儿之卦未美，似恶星占度，但防三、六、九月小疾多事，宜守旧吓天地化吉方保平安。","女":"小女运限未美，虽有旺益上人，但防三、六、九月灾难波阻，吓天地化吉方保平安。"},{"年龄":"8-12岁","男":"小童现年运度未美，虽伶俐，但防三、六、九月多生灾疾之厄，守旧，吓天地化吉方保平安。","女":"小女现年运度美中不足，惟防三、六、九月灾难波阻，夜勿外出，吓天地化吉方保平安。"},{"年龄":"13-15岁","男":"童造今年运度未遂，虽聪明，但防三、六、九月小疾波灾，吓天地化吉方保平安。","女":"小女现年运度未佳，但防三、六、九月灾疾之厄，夜勿远出，吓天地化吉平安。"},{"年龄":"16-17岁","男":"祥造步运不佳，似花开遭雨，虽通能，但防三、六、九月小人口舌，勿在外惹祸，吓天地化吉方保平安。","女":"玉造行运美中不足，似花开遭雨，虽有助益家庭，但防三、六、九月小疾多灾，守旧，吓天地化吉平安。"},{"年龄":"18-29岁","男":"英造步运未美，人虽才能，但防三、六、九月小人口舌祸非，凡事切勿冲动，吓天地化吉方保平安。","女":"玉造行运得此卦，人虽贤玉，但嫌美中不足，三、六、九月灾难口舌，凡事吞忍，吓天地化吉玉体安康。"},{"年龄":"30-55岁","男":"乾造步运不美，人虽老练，但防三、六、九月歹人嫁祸生非，凡事戒忍性气，吓天地化吉方保平安。","女":"坤造行运不美，人虽贤惠，但防暗疾口舌，凡事吞忍性气，吓天地化吉保平安。"},{"年龄":"56-69岁","男":"台造步运未美，人虽忠诚，但嫌时令未美，惟防三、六、九月歹人不测之祸，平地风波，守旧，底子平安。","女":"坤造行运美中不足，似花开遭雨，惟防暗疾口舌，凡事吞忍性气，守旧底子平安。"},{"年龄":"70岁以上","男":"吉造老运不旺，似花开遭雨，惟防灾难跌地之厄，早晚上落小心，喜孝堂勿进，守旧底子平安。","女":"妇造老运不旺，似花开遭雨，惟防暗疾上身，忌看病人，三、六、九月守旧，底子旺益子孙平安。"}]},"生意":{"生意":"守旧经营可平安，小人劫财要提防，百事用心要谨慎，结果只能小利攀。","生意解曰":"生意不贪心妄作，要仍按旧业经营防偷劫，货款出入谨慎用心窍取利也","开铺":"卜开铺之卦不美未开者开勿，已开者必守旧经营勿贪财妄取，防小人防亏本，请佛祖符令镇宅平安。","合伙":"卜合伙之卦似众星侵月之兆，伙计有私心，防小人防亏本，勿合则吉也!","置货":"卜置货初时有阻隔，但要用心窍，后来可得财利也。"},"出外":{"出外":"卜出外一事时令不通，恐吓防小人劫劫财，勿出外宜守旧经营则可安然!"},"谋望求财":{"谋望":"古来名利与兵机，谋望虽多得者稀，若不将心且忍耐，必然失计被人欺。","谋望解曰":"谋事有小人累害有口舌，防祸非失财宜用心窍，用些财帛帮助事可成","求财":"正财利小稀薄防小人耗劫恐要亏本，宜谨慎从正道，偏财阻失不可取，取必失之!"},"学艺功名":{"学艺":"卜学技艺之卦，似众星侵月之兆，恐有小人祸害，恐惹是非，学之难成，宜候时运才学之。","功名":"功名不中，还恐惹祸破财也。"},"行舟六畜":{"行舟":"行舟中平，但恐防有盗贼也。","六畜":"今年六畜难经营，鸡犬无端怪魔王。猪牛羊鹅也有阻，后悔莫及不可行。","猪羊":"猪羊养之不安防二五八月阻失多养得小恐要亏本 吓伯爷保佑平安","草龙":"卜养草龙之卦不顺 如日落西山之兆 防二五八月阻失 脚疾 吓五爷公化吉","三鸟":"卜养三鸟之卦不美 似众星侵月 防二五人月阻失 恐失大得少 宜吓伯公保安","田蚕":"早蚕要早收 不收失 晚大吉 雨水不吉"},"移徙":{"移徙":"移徙厝地不吉 恐有失有凶也"},"行人":{"解曰":"春夏行人时运未通 有小人阻隔 信息稀无 求天地化吉 保信息财利早日回家","签文":"去时急促转来迟 何事迁延到此时 争奈途中身有阻 早求神动保无危"},"婚姻":{"解曰":"婚姻切切不可拖延，应及早下聘迎娶，若迟延恐失也，今后又恐无妇也","签文":"本来婚偶待团圆，怎奈旁人起祸端，若要事成须速早，不然迟慢守寒年。"},"官讼":{"解曰":"小人阻害 无故生端 捏造事实 寄祸于人 不可告 和为贵 以免入牢囚也","签文":"小辈无端起外非 却教有理反成亏 如今及早和平好 莫教牵连入狱囚"},"失物":{"解曰":"物失在东方 虽有人知道 但不肯言难之寻也 用心窍知露真言 后寻之","签文":"分明失却在东方 知者虽多不肯扬 若是为财难得见 牛马物件秘收藏"},"占病":{"解曰":"星辰不顺 疾病缠身 宜多做善事 四方祭送 请医治疗 求佛祖经保平安","签文":"星辰不顺祸临身 致使淹缠日耗神 及早修善灾可脱 莫教人眷损来亲"},"其他":{"灶君":"灶位不吉 地下有孤骨作动 秽气不净 宜守分金 经起净孤骨择吉方作过 烹煮吉","阳基":"卜阳宅要修造防口舌 又嫌龙运不旺水神不美 散出 宜改水神归原 则居之吉","六甲":"此胎六甲生女 但恐有阻失 根基不足 宜求佛祖保佑婴儿身体平安","子息":"卜子息之卦 君命理带天悔星 多女少男 若得男应移房拜契 可保寿命绵长也","祖山":"卜贵祖龙脉不旺 但嫌前面水神散 葬穴孤阴 葬后财丁不顺 有利即修整阳气 水神归原兜唇 掩祭杀气之后财丁兴旺 子孙绵长也","青草":"此地龙运不旺 水神散 不归口 又恐傍边古穴阴人 要怨要阻 因此 此地切不可取之"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  33,
  '赵子龙救阿斗',
  '宝剑出匣之兆',
  '上上之卦',
  '子鼠',
  '长坂坡张飞断桥失计。曹操知刘备军虚，挥师掩杀。刘备拾妻儿，携民过江。赵子龙为救刘夫人及幼主阿斗，单枪匹马，往来冲杀，血战于万军之中。曹操惜其忠勇，禁用箭失，令必活捉赵子龙，妄想收服为将。赵子龙因此得以乘机救阿斗突围，以归刘备。',
  '手挥三尺剑，志用八千兵;利刀十一口，财宝足丰盈。',
  '蛟龙得雨',
  '{"签号":"第三十三签","签名":"赵子龙救阿斗","签文类型":"宝剑出匣之兆","卦象":"上上之卦","生肖":"子鼠","签文简介":{"戏文":"长坂坡张飞断桥失计。曹操知刘备军虚，挥师掩杀。刘备拾妻儿，携民过江。赵子龙为救刘夫人及幼主阿斗，单枪匹马，往来冲杀，血战于万军之中。曹操惜其忠勇，禁用箭失，令必活捉赵子龙，妄想收服为将。赵子龙因此得以乘机救阿斗突围，以归刘备。","诗曰":"手挥三尺剑，志用八千兵;利刀十一口，财宝足丰盈。","内兆":"蛟龙得雨"},"家宅运势":{"签文":"和居新改又新修，更答家门叶满堂，喜得秋成收十倍，遇逢富贵家道和。","解曰":"吉宅喜气临门，但防夏月则口舌是非失财官厄，家兴无灾家衰失丁，主事宜团结家人则家道可得圆满，门字分金不美，应修风水居住财丁兴旺。"},"岁君签":{"总诗":"利磨龙剑快锋芒，志气冲天势敢当，一但偶时携手立，共道英雄志气刚。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，八字成格，旺益上人并茂，春夏月小疾无妨，寿命绵长出入平安。","女":"小女根苗稳固，旺益上人，春夏月虽有小疾无妨，吉星守度寿命绵长出入平安。"},{"年龄":"4-7岁","男":"小儿现年运限顺遂，生性天真，春夏月虽有小疾无妨，不可登高玩耍，吉星守度平安。","女":"小女之卦运限叶吉，有旺益上人，不可登高玩耍，春夏月小疾无妨，吉星守命出入平安。"},{"年龄":"8-12岁","男":"小童运度交泰，各事伶俐，宜入学读书，定卜进步，不可登高，幸吉星守度出入平安。","女":"小女运度顺吉，旺益上人，夏月小疾无妨，不可登高玩耍，幸吉星守度出入平安。"},{"年龄":"13-15岁","男":"童造运度顺遂，聪明开窍，宜入学校读书，定卜进步，春夏月小疾无妨，吉星守命平安。","女":"玉造运度叶吉，各事伶俐活泼，有旺益上人并茂，夏月虽有小疾无妨平安。"},{"年龄":"16-17岁","男":"祥造步运亨通，如宝剑出匣之兆，聪明特达，宜入学校读书，争取进展，贵人扶助出入平安。","女":"玉造行运交泰，如宝剑出匣，各事贤玉，八字清秀，春夏月小疾无妨，利器小心，吉星守命平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如宝剑出匣之兆，奇才通能，春夏月小疾无妨，贵人扶助可得财喜平安。","女":"玉造行运甚美，凡事贤惠，有助益家庭，但勿迫性，春夏月虽有小疾无妨，吉星守度出入平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，为人老练刚直，但勿迫性，春夏月灾疾口舌无妨，贵人扶助可得财喜平安。","女":"坤造行运甚佳，贤淑智慧，虽有旺益家门，但勿操迫，有些暗疾口舌无妨，吉星守命平安。"},{"年龄":"56-69岁","男":"台造步运亨通，做事心直老练，春夏月小疾无妨，宜宽怀大量，切勿迫性，有贵人扶助出入平安。","女":"坤造行运叶吉，做事贤惠，有内助之德，春夏月有些暗疾勿至大害，卦中有吉星照身平安。"},{"年龄":"70岁以上","男":"福造老运交脱，虽性直忠诚，但防春夏月灾疾，幸福星照度，老福安康。","女":"坤造行运交泰，虽有旺益子孙，但防暗疾上身，春夏月守旧，幸吉星守命平安。"}]},"生意":{"生意":"初时生意市价迟，磨苦只有得小利，秋冬季节时运通，结果定得厚财利。","生意解曰":"生意经营初时财利跋涉，但宜刻苦经营发展交三，六，八，十一月如龙得雨","开铺":"卜开铺之卦似龙得雨，春处夏月恐是非口舌，磨苦小利，秋后转运可得厚财利。","合伙":"卜合伙之卦叶吉但初恐磨苦小利，但伙计宜同心同德，步调一至秋后转运似龙得雨，可得厚财利!","置货":"卜置货物初时劳苦小利，如果敢把货停留，秋冬月发售，可得大利也。"},"出外":{"出外":"卜出外一事叶吉应于二，三月时令合局往之，有贵人扶助可得厚财利也。"},"谋望求财":{"谋望":"未逢雷焕便归洲，万炼千磨受苦煎，此去化龙知期日，峥嵘头上有青天。","谋望解曰":"谋事初时不成有口舌是非，宜忍性用苦力经营，候交秋后定可成就","求财":"正财初时如鱼于深渊，财利跋涉宜刻苦经营交三，六，八月返运似龙得雨可得厚财，偏财一样!"},"学艺功名":{"学艺":"卜学技艺之卦叶吉，但宜谦虚谨慎，刻苦学习，遇到困难多思考，多问师傅，定能学得精巧技艺。","功名":"功名得中，荣宗耀祖，合族欢喜。"},"行舟六畜":{"行舟":"行舟初有小阻，后平安得利也。","六畜":"养猪春夏小利收，到了秋冬大利酬。饲牛要防有小阻，切切勿贪不用愁。","猪羊":"养猪羊顺利 饲料调和可大胆多养 可得厚财利","草龙":"卜养草龙之卦春夏月恐防有小阻 防脚疾 勿贪使用 吓伯公保安","三鸟":"卜养三鸟这卦叶吉 饲料调和 防上春有小阻 用方法饲养生长快 可得厚財利","田蚕":"田蚕早中晚大吉 四季雨水有利有财"},"移徙":{"移徙":"移徒平安大吉 有利也 可速移也"},"行人":{"解曰":"行人在外得运 各事顺遂 有贵人扶助 三 六 八 十一月定有佳音财帛回爱也","签文":"剑出钢匣快似锋 行人已在半途中 若逢子午归期日 不怕关山几万重"},"婚姻":{"解曰":"有缘千里结合婚姻成就，白头皆老要及时下聘，切勿错过良机","签文":"自古婚姻岂偶成，有缘千里得通传，如今宜好团圆日，莫教琵琶向别船。"},"官讼":{"解曰":"讼以和为贵 若告之定有明官 讼可得胜","签文":"别人起事闹官司 何用怀疑费心机 自有廉明兼公道 不教行善被人欺"},"失物":{"解曰":"失物可寻得见 应急向见物地方去寻 在西北角处便能得到因由或踪迹也","签文":"此时失物莫虚忧 急向家中检点求 西北角头去定处 有人对面说因由"},"占病":{"解曰":"不怕消瘦 四方祭送 请良医治之 更可平安 肖龙老人防冲跳 恐危也","签文":"皮肤消瘦骨还坚 每日淹留未得全 但要存心为好友 何忧小病损天年"},"其他":{"灶君":"卜此灶位分金合课 但嫌灶前迫塞秽气 经常修理干净 烹煮叶吉也","阳基":"卜此宅欲修造吉 但嫌水字不美 有利宜修整过 财丁兴旺","六甲":"卜此胎六甲生男 平安大吉 合家欢喜 养育顺利 是报先祖行善备德之恩","子息":"卜子息之卦 虽有得子 但多波阻 难养也 宜移房拜契 耐心培养 有贵气 求佛祖保佑养育平安也","祖山":"卜贵祖穴葬后财丁小旺 是分金水字不美 有利宜去龙就虎畔朝拱葬之 内外分金葬之大吉并理水字归口 填白虎畔朗拱弊之","青草":"此地龙脉足旺 青龙过案 点穴宜内外分金 去龙就局 并理水神归口 填补白虎畔朝拱 葬之大吉也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  34,
  '孙膑刖足被害',
  '空鱼折足之兆',
  '中平之卦',
  '亥猪',
  '战国时庞涓、孙膑同师鬼谷子。鬼谷子知孙膑忠诚勤谨，传以秘藏兵书。后庞涓仕魏，忌孙膑能，诱请同仕魏。既入，乃刖其足使废。孙膑胸怀大志，装疯以稳涓。后为齐使营救入齐，齐王拜为上大夫；适魏犯齐，孙膑计谋魏军入马陵道，围而攻之，并乱箭射死庞涓于枯树火光之下。',
  '言语慢且待，兄弟口喃喃;落帽知无礼，衣冠整幅难。',
  '病龙行雨',
  '{"签号":"第三十四签","签名":"孙膑刖足被害","签文类型":"空鱼折足之兆","卦象":"中平之卦","生肖":"亥猪","签文简介":{"戏文":"战国时庞涓、孙膑同师鬼谷子。鬼谷子知孙膑忠诚勤谨，传以秘藏兵书。后庞涓仕魏，忌孙膑能，诱请同仕魏。既入，乃刖其足使废。孙膑胸怀大志，装疯以稳涓。后为齐使营救入齐，齐王拜为上大夫；适魏犯齐，孙膑计谋魏军入马陵道，围而攻之，并乱箭射死庞涓于枯树火光之下。","诗曰":"言语慢且待，兄弟口喃喃;落帽知无礼，衣冠整幅难。","内兆":"病龙行雨"},"家宅运势":{"签文":"怪梦频频心事忧，因何利郎不堪留，但在自已行方便，常念难逃堕九幽。","解曰":"吉宅人口可得六甲喜，但防疾难口舌失财，皆因祖山不顺，宜查明修整，如家内有金斗寿木应速墓团结做善事。"},"岁君签":{"总诗":"病龙行雨带远危，有病占身事未宜，变化升腾须有日，且宜守旧待明月。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基虽足，惟防三、六、九月灾难波阻之厄，吓吴爷化吉方保守命绵长平安。","女":"小女根苗浅薄，防三、六、九月小疾灾难，守旧，吓吴爷化吉方保寿命绵长。"},{"年龄":"4-7岁","男":"小儿现年运度未美，惟防三、六、九月脚手痛疾，汤火小心，吓吴爷化吉方保出入平安。","女":"小女现年运限未美，但防脚手痛疾，汤火小心，三、六、九月守旧，吓吴爷化吉方保平安。"},{"年龄":"8-12岁","男":"小童之卦时令未美，但嫌执僻，三、六、九月小疾波阻，吓吴爷化吉方保平安寿命绵长。","女":"小女现年时令未美，三、六、九月脚手痛疾，汤火勿近，吓吴爷化吉方保平安。"},{"年龄":"13-15岁","男":"童造虽聪明，但嫌时令未美，惟防小疾波阻，脚手小心，吓吴爷化吉方保出入平安。","女":"小女之卦未美，但嫌执僻，惟防波阻之厄，宜守旧勿远出，吓吴爷化吉平安。"},{"年龄":"16-17岁","男":"祥造现年运度未美，似病龙行雨，但防三、六、九月灾难脚手痛疾，凡工作小心，吓吴爷化吉方保平安。","女":"玉造虽贤玉，但嫌得此卦病龙行雨，美中不足，惟防三、六、九月灾难波阻，吓吴爷化吉平安。"},{"年龄":"18-29岁","男":"英造步运未美，似病龙行雨，人虽奇才，但防三、六、九月小疾多事，宜安份，吓天地化吉方保平安。","女":"玉造行运未至，似病龙行雨，防暗疾口舌，凡事吞忍，三、六、九月守旧，夜时勿外出，吓吴爷化吉平安。"},{"年龄":"30-55岁","男":"乾造步运未美，似病龙行雨，人虽老练，但防小人平地风波，三、六、九月守旧，吓吴爷化吉平安。","女":"坤造行运未美，签文病龙行雨，人虽贤淑，但防三、六、九月暗疾口舌，忍性内外和气，吓吴爷化吉平安。"},{"年龄":"56-69岁","男":"台造步运不美，人虽忠诚，但防三、六、九月不测之祸，宜守本份，闲事切勿近理，底子大造平安。","女":"坤造行运得此卦美中不足，虽有内助之能，但防暗疾口舌，三、六、九月守旧，底子大造平安。"},{"年龄":"70岁以上","男":"福造老运不旺，虽绵长，但防灾难跌地之厄，早晚上落小心，三、六、九月守旧平安。","女":"妇造老运不旺，防病疾上身，忌入丧门，三、六、九月守旧，夜勿远出平安。"}]},"生意":{"生意":"今日切防盗劫财，交易出入莫贪闲，数目切勿信他人，刻苦经营祸可排。","生意解曰":"肖羊之可得大利，但防三，四,月歹人累劫，宜谨慎，数目自检防人不仁","开铺":"卜开铺之卦宜旧守经营防是非口舌，防盗贼劫财宜求佛祖令旗镇宅，有财利也。","合伙":"卜合伙之卦恐防伙计三人四心，各有私偏防歹人劫财物，勿合为妙，若合之恐亏本惹是非也!","置货":"置货有阻失，防歹人劫货劫财，防骗，买卖须交货交款，勿信直人财则安。"},"出外":{"出外":"卜出外一事签文不美，恐防小人生端寄祸，不利外出宜守旧，在家乡工作则吉!"},"谋望求财":{"谋望":"未动未安势力衰，安排平地起风灾，晓君乐有拿龙手，弄巧反成拙事来。","谋望解曰":"谋事可成但恐成后被人诱骗,歹人生端寄祸劫之，宜谨慎不可信直中直也","求财":"春夏月跋涉防小人耗劫不可以人担认，款项防累身宜守旧，六，九月有利入手，偏财勿取也!"},"学艺功名":{"学艺":"卜学技艺之卦，似病龙行雨之兆，君时运未到，学之不成，恐惹是非，宜守旧待时，然后从师学也。","功名":"功名不中，莫想侥幸，恐惹祸非破财。"},"行舟六畜":{"行舟":"行舟阻隔，出入恐有失也。","六畜":"饲养六畜切勿贪，春夏两季有阻难。求祷神明阴力助，精心喂养小利收。","猪羊":"猪羊不样 防三 六月阻失 恐亏本钱 宜求佛祖保佑 下大工力饲养 有小利收也","草龙":"卜养牛之卦水草不调和 防脚疾 使用小心 吓伯公保安 未养者宜守旧待时","三鸟":"卜饲养三鸟之卦不吉 恐防三 六月阻失 精心饲养秋后转运 有小利收也","田蚕":"早凶晚大吉 四季雨水略略"},"移徙":{"移徙":"此处不祥 移徒不吉 恐破财有失丁也"},"行人":{"解曰":"行人在外不美 恐防小人阻隔 信息延慢 宜求佛祖保佑平安 信息早回","签文":"去时曾约便归还 等到如今岁月残 有阻途中宜作福 保安方脱万重山"},"婚姻":{"解曰":"婚姻恐不成是媒人话不真实，是闲花野草，不可看错，应详细探明情况","签文":"婚姻一事在秋天，莫听旁人说到颠，要探香花仔细看，休教招错无头莲。"},"官讼":{"解曰":"官讼不可告 和之大吉 若要告 恐惹祸上身 防止被牵连而囚禁入牢也","签文":"官讼从来祸不休 乾坤请把心来量 莫教到已入牢囚 放了些儿免出头"},"失物":{"解曰":"户暗门衰 小人偷盗 此物难寻 但可神明炉前问明踪迹方向 快速寻之","签文":"户暗门衰祸事侵 要知踪迹归何处 资财失去更难寻 物在前及山树林"},"占病":{"解曰":"染此病是阴邪缠身 宜用饭菜银向西北方祭送 求佛祖服药可平安 徒久凶也","签文":"七情伤本有灾来 妖怪临门遣不开 好早求福不旧愿 免教人眷叹悲哀"},"其他":{"灶君":"此灶位不美 地下有阴人孤骨作动 宜择延年生气 吉方 另立灶位 烹煮叶吉也","阳基":"卜吉宅要起造 防是非口舌失财 宜理妥 老宅龙运不旺 又水字不美 有利修井后 居住财丁可旺","六甲":"此墓有结穴 气脉足旺文雅 但嫌葬坟高受杀冲伤又 龙运不旺 坐向有阻 失宜立修井穴山堂低些 并 兜唇掩杀气吉有利 修井坟山大吉 财丁兴旺","子息":"卜子息之卦 虽有得 但难养也 宜移房拜契 依赖他人之福也 宜多做善事 求佛祖保佑养育平安也","祖山":"此墓有结穴 气脉足旺文雅 但嫌葬坟高受杀冲伤 又 龙运不旺 坐向有阻 失宜立修井穴山堂低些 并 兜唇掩杀气吉有利 修井坟山大吉 财丁兴旺","青草":"此地取葬 防口舌阻隔 又嫌龙运不旺 水神散出 至切不可取之 若取之 葬后财丁恐有阻失 又要涉破也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  35,
  '刘皇叔过江招亲',
  '金雉衔赦之兆',
  '上上之卦',
  '戌狗',
  '周瑜欲拘人质，以讨还荆州，与孙权谋，计谋刘备过江招亲。孔明预将锦囊计付赵云，教先入吴宣扬孙、刘联婚事；相国寺相亲，复得孙国太庇护。新婚燕尔，刘备乐不思归，赵云又依孔明计，使刘备得计娶孙夫人过江。周瑜追截不及，赔了夫人又折兵，气极吐血。',
  '腰佩黄金印，身骑白玉麟;福人多宝物，玳瑁共珍珠。',
  '金鸡报喜',
  '{"签号":"第三十五签","签名":"刘皇叔过江招亲","签文类型":"金雉衔赦之兆","卦象":"上上之卦","生肖":"戌狗","签文简介":{"戏文":"周瑜欲拘人质，以讨还荆州，与孙权谋，计谋刘备过江招亲。孔明预将锦囊计付赵云，教先入吴宣扬孙、刘联婚事；相国寺相亲，复得孙国太庇护。新婚燕尔，刘备乐不思归，赵云又依孔明计，使刘备得计娶孙夫人过江。周瑜追截不及，赔了夫人又折兵，气极吐血。","诗曰":"腰佩黄金印，身骑白玉麟;福人多宝物，玳瑁共珍珠。","内兆":"金鸡报喜"},"家宅运势":{"签文":"檐前喜鹊叫三声，报汝今年百事成，官位日升财禄进，更依门户发光明。","解曰":"家门喜气盈盈孕妇可产男儿，但嫌官非口舌失财灾火厄，是厝前受杀冲伤，宜求佛祖福灯吊门上祭化早晚火烛小心，居住财丁昌盛。"},"岁君签":{"总诗":"鸡鸣霄汉势冲天，万里程途任着鞭，官位自然财禄进，安居右庆庆时年。","年龄运势":[{"年龄":"1-3岁","男":"小儿根苗足养，八字清格，旺益上人，耐心培育，春夏月虽有小疾无妨，守命绵长。","女":"小女根苗足旺，利益上人并茂，春夏月虽有小皮疾无妨，吉星守命出入平安。"},{"年龄":"4-7岁","男":"小儿现年运限顺遂，生性活泼，有旺益上人，春夏月虽有小疾无妨，吉星守度平安。","女":"小女之卦运限顺吉，各事精巧，春夏月有些皮肤小疾无至大害，吉星守度平安。"},{"年龄":"8-12岁","男":"小童运度亨通，凡事伶俐活泼，宜培养入学读书，定卜进步，春夏月小疾无妨平安。","女":"小女今年交上运，凡事技巧开窍，有旺益上人并茂，春夏月虽有小疾无妨平安。"},{"年龄":"13-15岁","男":"童造现运顺遂，凡事聪明精通，宜入学读书，定卜前途进展，而且出入平安。","女":"玉造现运交泰，如金鸡报喜，凡事精巧，旺益上人并茂，学习艺业玉体安康。"},{"年龄":"16-17岁","男":"祥造步运亨通，如金鸡报喜，做事精通特达，多学手艺，春夏月小疾无妨，贵人扶助平安。","女":"玉造行运甚美，如金鸡报喜，做事贤玉技巧，旺益家庭，春夏月虽有小疾无妨，吉星守度平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如金鸡报喜，年轻有为，前途进展有望，但勿迫性，贵人扶助，可得财喜平安。","女":"玉造行运交上美景，如金鸡报喜，做事贤淑，旺益家庭，春夏月小疾无妨，吉星照身平安。"},{"年龄":"30-55岁","男":"乾造步运交泰，如金鸡报喜，为人奇才特达，但勿迫性，幸有贵人扶助，可得财喜平安。","女":"坤造行运亨通，如金鸡报喜，贤淑智慧，可称内助，小疾无妨，吉星守命可卜玉体安康。"},{"年龄":"56-69岁","男":"台造步运佳美，如金鸡报喜，做事忠诚，胸怀宽宏，但勿迫性，有贵人扶助，可得财喜平安。","女":"坤造行运亨通，如金鸡报喜，贤淑智慧，有内助之德，暗疾无妨，幸有吉星照身出入平安。"},{"年龄":"70岁以上","男":"妇造老运得此卦，老当益壮，性直心慈，春夏月小疾无妨，贵人扶助晚景胜前。","女":"慈造老运虽有旺益子孙，春夏月暗疾之厄，喜孝物勿食，幸吉星守命平安。"}]},"生意":{"生意":"今年生意可稀奇，春夏似鸟落毛时，六月开始至秋冬，鸟添羽毛任高低。","生意解曰":"春夏似鸟落毛生意阻隔，六月起至秋冬似海鹤添寿可大发展能得大利","开铺":"卜开铺之卦上春有阻隔，防小人祸劫，六月起转运，金鸡报喜可得厚财大利。","合伙":"卜合伙之卦大吉似金鸡报喜之兆，多人多福同心同德，协力经营可得大利。","置货":"卜置货初时有阻，但宜立但智，敢于留货，至于秋后货物振价，可有大利。"},"出外":{"出外":"卜出外一事签文叶吉凡事勿疑要有胆智往于二，五月有贵人人重重也。"},"谋望求财":{"谋望":"几年松下惜羽毛，不肯低头皆富豪，有日夺身腾碧汉，方知志气此时高。","谋望解曰":"谋事初时有小人阻隔，不可急候交秋冬事情便可成功也","求财":"正财如鸟换毛，美在后来凡事宜立胆智前进，二八，十一月可得厚利，偏财初有阻，后有大利可得!"},"学艺功名":{"学艺":"卜学艺之卦，似金鸡报喜之兆，时运合课，宜求师学之，定能得手艺随身，为创业奠下良好基础。","功名":"功名得中，荣宗耀祖，但要忍口舌是非。"},"行舟六畜":{"行舟":"行舟平安顺风得利，四方大吉。","六畜":"六畜起初有阻临，不可怕之要用心。借得神力来保佑，到底定能得财金。","猪羊":"卜猪羊养之顺利 饲料调和 可大胆多养 求佛祖保佑 可得厚财利也","草龙":"卜养牛之卦 水草调和 但初时恐有小阻 宜防治底主平安 母牛可有孕 产育平安有利也","三鸟":"卜养三鸟之卦叶吉初有小阻无妨 精心饲养 吓佛祖保佑大投资金多养 秋冬月可得大财利也","田蚕":"田蚕顺意 早晚大吉 四季雨水平安"},"移徙":{"移徙":"移徒大吉 地灵好 出入顺意"},"行人":{"解曰":"行人在外得志 有贵人重重 可得名利 交八月十一月有佳音回家 可喜可贺也","签文":"一见家资值千金 今朝报汝且欢心 程途路至家乡近 门前车马走如云"},"婚姻":{"解曰":"卜此婚事可成，不过初时有歹人说是非，但到底大吉可为长久相合之夫妻也","签文":"瑶台仙鹤惯牺梧，月里嫦娥岂有夫，惟子欲求佳偶配，及今春色上皇都。"},"官讼":{"解曰":"此讼有贵人扶持 可以得胜 但和之为贵 自古以来息事宁人 免遭祸非也","签文":"叮咛吩咐不须忧 讼至公庭不自由 中有贵人相着力 定无名字上神州"},"失物":{"解曰":"祈求神明 告诉失物踪迹 耐心寻之 终有见回也 若急性 恐要惹是非","签文":"何期一失路迢迢 此话如今还未消 再告神天阴保佑 通知踪迹在阶桥"},"占病":{"解曰":"得病速医 阴功保佑 可以平安 但老人防凶 有冲跳","签文":"灾本来是在西边 如有阴功始可延 不怕凶星并冲犯 渐时安乐免熬煎"},"其他":{"灶君":"卜此灶位分金合课 但嫌灶前秽气 经常修理干净 烹煮可旺益财丁也","阳基":"卜阳宅可居 但数年不顺者是面前沉阳受杀 宜立八卦抵挡 新造先阻后成","六甲":"卜此胎六甲 定得儿男 且根基足养 但产后婴儿夜有闹叫 宜求神化吉也","子息":"卜子息之卦 似金鸡报喜之兆 子息不但有得 而且根基足旺 带有官贵之格 宜精心养育 大可成材也","祖山":"卜贵祖有结穴 气脉足旺 但嫌葬穴太低 坐向有利修整 葬高一位并兜唇可受来水朝堂葬之大吉 财丁大顺也","青草":"卜此地横龙结穴 气脉足旺 点穴宜占高 沉阳吉 但葬此有口舌阻隔 宜理清楚 葬之大吉也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  36,
  '文王遇凤鸣',
  '凿石见金之兆',
  '上上之卦',
  '酉鸡',
  '周文王先古明君，知天任，施仁政，重教化，少刑罚，史称划地为牢，竖木为吏，垂衣而治者是也。故时世昌盛，民风敦厚。日文王进香岐山，替民祈福，有凤凰来朝帝驾。凤出则斯世盛、君圣民也良，此周朝所以称为礼乐之邦者故也。',
  '八仙同宴会，五马入门来;凤舞天地坠，金盘捧玉杯。',
  '如鱼化龙',
  '{"签号":"第三十六签","签名":"文王遇凤鸣","签文类型":"凿石见金之兆","卦象":"上上之卦","生肖":"酉鸡","签文简介":{"戏文":"周文王先古明君，知天任，施仁政，重教化，少刑罚，史称划地为牢，竖木为吏，垂衣而治者是也。故时世昌盛，民风敦厚。日文王进香岐山，替民祈福，有凤凰来朝帝驾。凤出则斯世盛、君圣民也良，此周朝所以称为礼乐之邦者故也。","诗曰":"八仙同宴会，五马入门来;凤舞天地坠，金盘捧玉杯。","内兆":"如鱼化龙"},"家宅运势":{"签文":"瑞气迎祥百事新，贵人相逢便相亲，秋冬小有淹留阻，春夏人财事事亨。","解曰":"吉宅人口之卦可得喜气临门,但签文有淹留两字，恐防夏月涉财是埕口秽气不净，宜经常修理清洁水道流通，居住财丁兴旺。"},"岁君签":{"总诗":"鱼翻浪跳当三月，此身方起化为龙，他时得位方为吉，百事无忧方变新。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足养，八字清秀，有旺益上人并茂，三、五月小疾无妨，寿命绵长。","女":"小女根苗足养，利益上人并茂，三、五、八月虽有小疾无妨，吉星照身出入平安。"},{"年龄":"4-7岁","男":"小儿之卦运限叶吉，有旺益上人，但水边小心，虽有小疾无妨，吉星守命出入平安。","女":"小女现年运限顺遂，但三、五月水边小心，幸吉星守命底子有旺益上人并茂平安。"},{"年龄":"8-12岁","男":"小童运度顺吉，各事伶俐，聪明可入学读书，定卜进步，水边小心，底子平安。","女":"小女运度顺遂，如鱼化龙，各事活泼，旺益上人，但水边小心，吉星守命平安。"},{"年龄":"13-15岁","男":"童造运度亨通，如鱼化龙，做事聪明，培养入学校读书，将来才学过人，小疾无妨平安。","女":"玉造运度顺遂，技巧开窍，有旺益上人，三、五月水边小心，吉星照身平安。"},{"年龄":"16-17岁","男":"祥造现年时令佳美，如鱼化龙，凡事聪明特达，三、五月虽有小疾无妨，贵人扶助出入平安。","女":"玉造现年时令佳美，如鱼化龙，贤玉智慧，三、五月池井边小心，虽有小疾无妨，吉星守度平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如鱼化龙，凡事通能机智，但勿迫性，三、五月小疾无妨，贵人扶助可得财运平安。","女":"玉造行运甚佳，如鱼化龙，性格柔和，五行清秀，有旺益家庭，三、五月虽有小疾无妨，出入平安。"},{"年龄":"30-55岁","男":"乾造步运时令亨通，如鱼化龙，老练经济，春夏月戒忍口舌，幸贵人扶助，可得财喜平安。","女":"坤造行运交泰，如鱼化龙，贤淑智慧，助益家庭，虽有暗疾无妨，吉星守度平安。"},{"年龄":"56-69岁","男":"台造步运得此卦，如鱼化龙上吉，心地善良，但宜宽怀大量，春夏月小疾无妨，贵人扶助平安。","女":"坤造现年时令佳美，签文如鱼化龙，性格温柔，内肋之德，虽有暗疾无至大害，吉星照身平安。"},{"年龄":"70岁以上","男":"福造老运安康，忠诚老实，三、五月虽有灾疾无妨，贵人扶助，晚景胜前。","女":"慈造老运，虽有旺益子孙，但防暗疾上身，三、五月守旧，幸吉星守命平安。"}]},"生意":{"生意":"春夏财利小小来，逢上阳月路宏开，秋冬时节物涨价，生意经营得厚财。","生意解曰":"生意可得厚财，但恐上春阻隔少利，宜刻苦经营五，九，十一月有贵人，生意兴隆","开铺":"卜开铺之卦如鱼如龙之兆，春夏磨苦小利新开铺定有小阻，但要有胆智经营，秋冬月可得大财利。","合伙":"卜合伙之卦如鱼化龙之兆，合之可成伙计宜同心同德，刻苦经营有贵人扶助，秋后有厚财利可也!","置货":"置货春夏勿贪财，候于秋冬月，如鱼得水，有大财大利也。"},"出外":{"出外":"卜出外一事身体虽平安但有阻隔，可是应有胆智敢于前往，有贵人应心得想!"},"谋望求财":{"谋望":"先时一段报君知，秋后经营遂意时，若遇三阳开泰日，即知名利两相宜。","谋望解曰":"谋事可成但防初时有阻隔，交秋冬有贵人扶助，所谋各事定能成功","求财":"正财春夏秋小利，十月超至明年三阳日大吉利!"},"学艺功名":{"学艺":"卜学艺之卦，可以成功，君可择其吉日从师学习，宜刻苦用功，他日定能学得手艺随身也。","功名":"功名得中，荣宗耀祖，成名大吉也。"},"行舟六畜":{"行舟":"行舟如意，顺风平安，但先苦后甜也。","六畜":"春夏有阻家中猪，以后平安得大利。养牛有阻不可贪，神佛保佑灾害驱。","猪羊":"猪羊春夏无利 但交秋之后 可大胆多养 饲料调和 定卜平安 可得厚利","草龙":"卜饲养草龙之卦 恐有阻隔 防脚疾之厄 勿贪使用过度 求佛祖保佑秋后转运平安","三鸟":"卜养三鸟之卦春夏养之恐有阻隔 秋后养之大吉 可投资金多养 可得厚财利","田蚕":"田蚕如意 早中平晚大吉 四季雨水吉"},"移徙":{"移徙":"移徒如意 移之大吉可居也"},"行人":{"解曰":"行人在外得运亨通 有贵人扶助 五 九 十一月有音信并财帛回归也","签文":"不诏当初要出身 如今问我求行人 若然要取归期日 待过牛羊到鼠辰"},"婚姻":{"解曰":"天配良缘水清鱼戏，情意相投,婚姻定可成功勿误时机","签文":"天配良缘合两头，那堪相合更相谋，水清看见鱼游戏，好把丝纶下钓钩。"},"官讼":{"解曰":"讼可得胜 但应一团和气 良善可为 听从调解 不用悲忧 祸自休也","签文":"啸聚山林凶恶稠 善良何必主悲忧 主人大笑出门去 不用干戈贼自休"},"失物":{"解曰":"失物速寻 但不能依赖他人 必须自己向辰巳卯寅方寻之 定可找回也","签文":"路埋踪迹似潜藏 休赖傍人说短长 若要见时何日得 但看辰巳卯寅方"},"占病":{"解曰":"疾病已久 但不可忧愁 宜修心从善 求神祭送 请良医治之 可保平安","签文":"旦夕安危自有之 勿忧久病失支枯 良药苦甜皆不若 宁可修心且待时"},"其他":{"灶君":"卜此灶位分金合课 但嫌前灶秽气 经常应修理清净 烹煮叶吉也","阳基":"卜阳宅吉 嫌面前污秽不洁 宜修通吉 卜新造防口舌 用小利理妥然后可成","六甲":"六甲逢阴月生男 余者生女 但防三四五月产妇下生 恐有凶失也","子息":"卜子息之卦 君恐多得千金 若要生男 可先就兄弟之子过继之 日后定可招男儿且聪明活泼 能起家立业也","祖山":"卜贵祖行龙尽头结穴 气脉文雅 两砂朝护 葬后昌盛 次房不美 是面前受杀 有利即掩祭 葬之 后大吉祥 如子午山头宜修外不用修内原旧吉","青草":"卜此地脉真气足 但嫌面前有曜水 宜消掩墓后则安 向曜水出何方 应就山龙下罗经 可知面前之曜水也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  37,
  '项羽困乌江自刎',
  '行船失楫之兆',
  '下下之卦',
  '申猴',
  '项羽不堪于秦朝暴政，于江东举事反秦，率八千子弟兵过江，所到响应者如云，声势日大。至下咸阳，自恃力可拔山，雄可盖世，自号西楚霸王，刚愎自用，不从士谋，无视刘邦。终致被困垓下，四面楚歌，别姬赴死，破釜沉舟，背水一战，八千子弟，无一生还。羽以无颜对江东父老，遂自刎于乌江。',
  '风冷长江静，渔船钓月明;一声孤雁过，旅客变悲声。',
  '楚汉争雄',
  '{"签号":"第三十七签","签名":"项羽困乌江自刎","签文类型":"行船失楫之兆","卦象":"下下之卦","生肖":"申猴","签文简介":{"戏文":"项羽不堪于秦朝暴政，于江东举事反秦，率八千子弟兵过江，所到响应者如云，声势日大。至下咸阳，自恃力可拔山，雄可盖世，自号西楚霸王，刚愎自用，不从士谋，无视刘邦。终致被困垓下，四面楚歌，别姬赴死，破釜沉舟，背水一战，八千子弟，无一生还。羽以无颜对江东父老，遂自刎于乌江。","诗曰":"风冷长江静，渔船钓月明;一声孤雁过，旅客变悲声。","内兆":"楚汉争雄"},"家宅运势":{"签文":"无事何须出外游，恐遭灾盗反成忧，今日切防人口损，若见平安只在秋。","解曰":"吉宅人口有喜气可得，但防夏月疾难口舌，盗火失财，求佛祖奉经保平安，山坟不顺有利宜修整壮旺，请南天天帝香火镇宅居住可保平安。"},"岁君签":{"总诗":"江水无船岂可通，波涛风浪急危饿，出入不宜须守旧，进这难也退无他。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基虽足，但防春夏月灾难波阻六甲花水，吓妈祖化吉守旧平安。","女":"小女根苗浅薄，惟防春夏月灾疾多事，守旧勿远出，吓妈祖化吉方保平安。"},{"年龄":"4-7岁","男":"小儿运限未美，春夏月惟防灾难水厄，逢水边小心，吓妈祖化吉方保寿命绵长。","女":"小女现年运限未美，但防春夏月灾难水厄，池井边小心，吓妈祖化吉，交秋返运平安。"},{"年龄":"8-12岁","男":"小童现年运限未遂，惟防小疾水厄，春夏月守旧，吓妈祖化吉，交秋平安。","女":"小女现年运限未美，但嫌执僻，防有小疾水厄，水边小心，吓妈祖化吉交秋平安。"},{"年龄":"13-15岁","男":"童造运度未遂，但防小疾水厄，春夏月守旧，外方勿出，吓妈祖交秋返运平安。","女":"玉造运度未佳，但防春夏月灾难水厄，池井边小心，吓妈祖化吉，交秋返运平安。"},{"年龄":"16-17岁","男":"祥造步运不美，虽通能，但嫌签文行舟失楫之兆，春夏月不可外出，守旧，交秋转运出入平安。","女":"玉造行运美中不足，人虽贤玉，但防春夏月多生波阻小疾，不可外出，守旧交秋转运出入平安。"},{"年龄":"18-29岁","男":"英造步运未美，春夏月防小人口舌祸非，凡事安分守己，交秋转运，有贵人扶助，可得财喜平安。","女":"玉造行运虽贤淑，但嫌得此卦不美，惟防歹人平地风波，凡事吞忍性气，交秋转运吉星守命平安。"},{"年龄":"30-55岁","男":"乾造步运不美，如行舟失楫，防歹人嫁祸生非，春夏月安分守己，交秋转运，可得财喜平安。","女":"坤造人虽贤惠，但嫌得此卦如行舟失楫，防暗疾口舌，春夏月守旧，吓佛祖交秋平安。"},{"年龄":"56-69岁","男":"台造步运不美，如行舟失楫，人虽老练，但春夏月歹人不测之祸，闲事勿理，交秋转运平安。","女":"坤造行运未美，签文行舟失楫之兆，但防暗疾口舌，凡事勿操迫，吓妈祖化吉，交秋转好运出入平安。"},{"年龄":"70岁以上","男":"台造老运不旺，签文行舟失楫之兆，但防灾难跌地之厄，早晚上落小心，外方勿出，守旧大造平安。","女":"妇造老运不旺，虽有旺益子孙，但嫌操心暗疾，春夏月远方勿往，守旧，交秋福体安康大造平安。"}]},"生意":{"生意":"防失守分心勿慌，交冬有利路不宽，偏财勿取取必失，求祷神力保平安。","生意解曰":"春夏财利跋涉，又防小人劫之交易宜谨慎稳重行事不可急性，八月起有利入手。","开铺":"卜开铺之卦不美如行船失楫之兆，未开铺勿开，若是老铺应防灾盗祸非失财之厄!宜求佛祖保佑平安。","合伙":"卜合伙之卦不美如楚汉争雄之兆，勿合为佳若合之伙计不同心恐惹祸非，口舌失财也!","置货":"置货初时定有阻失，不可操迫，宜用心窍，敢办货停留，秋冬月得利也。"},"出外":{"出外":"卜出外一事如行失楫之兆，恐防奔波小人累害，又防水厄宜守旧勿外出!"},"谋望求财":{"谋望":"天理于人岂自忘，见他富贵忽忙忙，伊君若要求名利，一旦乌江见汉王。","谋望解曰":"做事虽是精通，但性情急，恐防阻失宜用心窍智谋之，勿偏想秋冬月可成也","求财":"正财虽有利可得，但恐小人阻隔宜从正道勿贪心妄想，勿迫性则获利不失，偏财定失凶也，勿取之!"},"学艺功名":{"学艺":"卜学技艺之卦不美，如楚汉争雄之兆，学之不成，恐惹是非，勿迫性，宜守旧待时也。","功名":"屡次不中，武可中，文不及第也。"},"行舟六畜":{"行舟":"行舟不顺，不安不吉，防凶防灾也。","六畜":"月当明时被云披，时运未通勿养猪。切切忍耐心头事，守分安贪待明时。","猪羊":"猪羊阻失 中大只知卖要精心饲养 吓伯爷化吉","草龙":"卜养牛之卦 如行船失糊之兆恐防疾厄盗厄 勿贪使用 母牛有孕宜小心 吓伯公保平安","三鸟":"卜养三鸟之卦不吉 恐防癌疾或盗厄 切不可多养 精心管理 吓伯公保管","田蚕":"早晚二冬不吉 防失 四季雨水不利也"},"移徙":{"移徙":"移徒不利 移之凶也 不祥也"},"行人":{"解曰":"行人在外财运不通 小人阻隔以致音信延慢 吓妈祖保佑信至早日回家","签文":"尺尺无缘千里远 鱼沉雁杳苦难煎 慢劳回首旨光日 去客淹留在路边"},"婚姻":{"解曰":"时令未到婚姻难成，宜忍耐些时，皇天不负有心人的","签文":"眼下心事欲便成，岂知本命不相称，如今只要寻佳偶，且待黄河九渡清。"},"官讼":{"解曰":"官讼从来事不休 莫教直性入牢笼 任他风浪滔天浪 不若抽身归去好","签文":"岂知文字入官囚 不教直性被人欺 自有廉明公道在 何用疑心费计谋"},"失物":{"解曰":"失物无归 是君无缘 时运乖舛 急寻无方 待时寻之 终无归日","签文":"失却如今在海边 资财失去更难圆 要知踪迹归何处 有人对面说因缘"},"占病":{"解曰":"有方无药 鬼怪临身 宜求神化吉 早日修善 免教久卧在床席","签文":"有方无药苦难痊 莫教鬼怪遣不开 及早修心归旧愿 免教人眷叹悲哀"},"其他":{"灶君":"卜此灶位不美 仍嫌地下秽气 宜择生气兴旺 吉方建之 烹煮叶吉也","阳基":"卜起造有阻 宜用心窍可成 老屋修整理妥水字 居住则安","六甲":"六甲生女安 生男凶 宜拜契改神明保佑养育平安 孕妇勿出外 在家保妇家","子息":"卜子息之卦 君命里带孤鸾 恐多花少果 初得子 恐难养 宜多行善事 可养兄弟之子过继也","祖山":"卜贵祖龙脉不旺 葬后失财阻隔 是青龙料砂破失 又面前水阳出各宜修补并理水神归口 然后财丁足旺","青草":"卜此地横龙结穴 但嫌青龙畔砂不朝护 又来水雄出 水散 葬穴宜沉阳并兜唇掩祭之后 刑财丁兴旺也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  38,
  '哪咤出身后为神',
  '大器晚成之兆',
  '上上之卦',
  '未羊',
  '哪吒闹海，龙告于其父，托塔天王罪子，哪吒割肉还母，切骨还父，自废其身而亡。太乙真人知其天数未尽，且为异人，将有大作为，乃使之复活，并收徒授艺。哪吒从师学艺功成，下山助姜尚灭纣兴周，为先行官忠勇善战建树奇功。后人感其武勇，奉为神，建庙祀之。',
  '石中藏碧玉，老蚌含明珠;五马庭前立，能乘万里程。',
  '进身显达',
  '{"签号":"第三十八签","签名":"哪咤出身后为神","签文类型":"大器晚成之兆","卦象":"上上之卦","生肖":"未羊","签文简介":{"戏文":"哪吒闹海，龙告于其父，托塔天王罪子，哪吒割肉还母，切骨还父，自废其身而亡。太乙真人知其天数未尽，且为异人，将有大作为，乃使之复活，并收徒授艺。哪吒从师学艺功成，下山助姜尚灭纣兴周，为先行官忠勇善战建树奇功。后人感其武勇，奉为神，建庙祀之。","诗曰":"石中藏碧玉，老蚌含明珠;五马庭前立，能乘万里程。","内兆":"进身显达"},"家宅运势":{"签文":"君家明德合天心，些小淹留祸不侵，人口六畜休要说，平安二字值千金。","解曰":"吉宅人口舌签文有淹滞二字出现，恐防流泪破失，若有婚事可保无虑，是埕口水道不美，有利修整，初一吉敬拜天地平安可得财利。"},"岁君签":{"总诗":"红日当天照破云，无愁不独众人钦，君子进身应显达，荣华富贵得安宁。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足养，八字稳固，有旺益上人并茂，二、三、五月小疾无妨，吉星守命出入平安。","女":"小女根苗足养，有旺益上人并茂，二、三、五月小疾无妨，吉星守命出入平安。"},{"年龄":"4-7岁","男":"小儿运限顺吉，八字清格，有旺益上人，二、三、五月知避暑，小疾无妨，吉星守命出入平安。","女":"小女运限顺遂，各事伶俐活泼，旺益上人并茂，二、三、五月小疾无妨，吉星守度平安。"},{"年龄":"8-12岁","男":"小童运度亨通，各事精通，可培养入学，定卜前途进步，夏月知避暑，吉星守度平安。","女":"小女运度叶吉，凡事精巧，有旺益上人，二、三、五月虽有小皮疾无妨，吉星守度平安。"},{"年龄":"13-15岁","男":"童造今年上运，聪明开窍，宜入学校读书，定卜进步，远有希望，而且出入平安。","女":"玉造现年上美运，凡事伶俐，旺益上人，二、三、五月虽有小皮疾无妨，吉星守度平安。"},{"年龄":"16-17岁","男":"祥造步运亨通，如红日当空，做事通能，宜学习文化，二、三、五月虽有小疾无妨，有贵人扶助出入平安。","女":"玉造运度交泰，人贤玉温柔，但切勿迫性，二、三、五月虽有小皮疾无妨，有吉星照身出入平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如红日当空，虽才能，但凡事不可急躁，安分守己，夏月小疾口舌无妨，可得财喜平安。","女":"玉造现年运度佳美，做事贤淑有助益家庭，但勿操迫，二、三、五月虽有小疾无妨，幸吉星守命平安。"},{"年龄":"30-55岁","男":"乾造步运交泰，为人奇才特达，但勿迫性，安分守己，夏月虽有小人口舌无妨，贵人扶助，可得财喜平安。","女":"坤造行运甚佳，做事贤淑智慧，旺益家门，但勿迫性，夏月虽有暗疾口舌无妨，吉星照身平安。"},{"年龄":"56-69岁","男":"台造步运亨通，为人心直，性刚恐惹是非口舌，凡事站稳立场，夏月小疾无妨，贵人扶助出入平安。","女":"坤造行运交泰，可称内助之能，但嫌内心操迫，宜温柔大量，夏月暗疾无妨，吉星照身出入平安。"},{"年龄":"70岁以上","男":"吉造老运虽忠诚，但嫌人老性迫，凡事宽宏大量，夏月虽有灾疾无至大害，福星扶照平安。","女":"妇造老运交泰，虽有旺益子孙，但防暗疾上身，二、三、五月守旧，上落小心，幸卦中吉星守度平安。"}]},"生意":{"生意":"正道买卖勤经营，春夏可得小财经，秋冬时节有财利，肖马五八厚利升。","生意解曰":"生意取利叶吉，与人交易心地宜从正道，五、九、十一月扩大经营得厚利肖马者更佳。","开铺":"卜开铺之卦叶吉如大器晚成之兆，要公平正道经营不可亏人，秋后可得厚利，肖马者更妙。","合伙":"卜合伙之卦叶吉肖马者更妙，如大器晚成之兆伙计宜同心同德刻苦经营秋后有财利可得。","置货":"置货初时小利还要防失，但宜有胆智取之，交秋冬月振价，可得大财利也。"},"出外":{"出外":"卜出外一事身体平安但闲事勿近，宜从正道有贵人扶助，可得名利双全。"},"谋望求财":{"谋望":"天理人心两不亏，自然合道免生灾，公平感得神明佑，南北东西任所为。","谋望解曰":"卜谋事宜从正道，不可亏人，交秋月各事称心如意，定可成功。","求财":"正财取利叶吉宜从正道，不可亏人，宜谨慎勤奋经营五、九、十月亨通得厚利，肖马者冬月大胜，偏财定失。"},"学艺功名":{"学艺":"卜学艺之卦，为大器晚成之兆，肖马者宜择肖马日学之，定能得艺成师，余肖之人学之恐慢成就也。","功名":"功名成就，肖马者定可显达荣升也。"},"行舟六畜":{"行舟":"守机间已过，现在出船顺风得利。","六畜":"春夏有阻是养猪，秋后养之可顺利。求吓灶神力保佑，月圆花开得大利。","猪羊":"猪羊养之 饲料渴和 但初时有阻 不必疑之 宜吓灶君、大胆多养 秋冬得利","草龙":"卜养牛之卦 水草调和使用顺利底主平安 能旺益家庭有利也","三鸟":"卜养三鸟之卦 宜细心管理 初有困难 后可顺利大胆多养 秋冬得厚利","田蚕":"早晚二冬大吉 敢下本有倍收 雨水大吉"},"移徙":{"移徙":"时机已到 速移之 大吉大利也"},"行人":{"解曰":"行人在外得运 有贵人重重 凡事应心得想 五 八 十一月有佳音财利回家","签文":"口约虽违莫怨天 行人已有到天边 如今不必倚门望 已午逢半到家中"},"婚姻":{"解曰":"婚姻可成，但初时有小人破说双方勿认以为真，可到白头皆老生子传孙。","签文":"鸳鸯飞入凤凰窝，莫听旁人说事破，自是姻缘天配汝，两人相笑白头过。"},"官讼":{"解曰":"官讼得胜 局势很好 告之有贵人扶持 但还是和为贵也","签文":"自是有才志气高 公庭告人贵人扶 定有贵人长得力 官讼必胜大丈夫"},"失物":{"解曰":"此物虽失 但要速寻 失在近口 细心查找 便可以寻到失物也","签文":"失物于今即见时 勿把待时小见机 此件失去在近口 细心搜查方得知"},"占病":{"解曰":"小病临身勿慢看 恐加朝热也微寒 老年人是由阴邪交缠火盛 中年男女是阴火盛燥 求太阳星君保佑 服药平安","签文":"小病临身勿慢看 恐加朝热也微寒 如今正是吉星照 心当修善得平安"},"其他":{"灶君":"此灶位分金合课 但嫌灶前秽气 经常应修理清净 烹煮叶吉 可旺益财丁","阳基":"卜起造防阻 宜理妥可成 老阳宅水字不美 改过居住则安 财丁吉也","六甲":"此胎六甲肖马之人定得男儿 全家欢喜 于五月或冬月可见也","子息":"卜子息之卦 先花后果 初生男儿 恐难养也 宜多行善事 移房拜契 可保寿命绵长","祖山":"卜贵祖葬地横龙结穴 气脉足旺 但嫌葬后财不顺 是左畔目角水神不美或面前曜水 坐向有利宜掩祭 化并修龙运壮旺大吉也","青草":"卜此地骑龙结穴 气脉足旺 两砂相朝 但午方有峰可见之 傍边有古人 宜理妥并消掩八曜水 葬后子孙可显达也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  39,
  '司马懿入葫芦谷',
  '久客他乡之兆',
  '下下之卦',
  '午马',
  '司马懿中孔明诱兵之计，误入深谷，又孔明察知魏延时怀反心，欲一并除之，故预先令其入谷埋设硝药，点燃谷中烈焰，烧杀曹军。火起，魏延开马肚藏身免死，适又天降大雨灭火，司马懿也逃免灭顶之灾。孔明得报，仰天叹曰：“此乃天意也！”',
  '四野无人到，行人路转迷;虎狼吞蛇地，险处更逢危。',
  '白虎占度',
  '{"签号":"第三十九签","签名":"司马懿入葫芦谷","签文类型":"久客他乡之兆","卦象":"下下之卦","生肖":"午马","签文简介":{"戏文":"司马懿中孔明诱兵之计，误入深谷，又孔明察知魏延时怀反心，欲一并除之，故预先令其入谷埋设硝药，点燃谷中烈焰，烧杀曹军。火起，魏延开马肚藏身免死，适又天降大雨灭火，司马懿也逃免灭顶之灾。孔明得报，仰天叹曰：“此乃天意也！”","诗曰":"四野无人到，行人路转迷;虎狼吞蛇地，险处更逢危。","内兆":"白虎占度"},"家宅运势":{"签文":"畜产无灾人眷旺，无端怪声乱黄昏，如今好问秋成后，早把门庭依旧关。","解曰":"人口兴旺者可得喜气，但防产妇月内危险期及夏秋月祸非六畜，是门字分金及水道不美，查明之有利宜修整并作过灶君吓佛祖保平安。"},"岁君签":{"总诗":"忽入深山去路迷，不知何处鹧鸪啼，进退出行皆不利，切须慎防暗中欺。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基虽足养，但恐春夏月小疾灾难，守旧勿远出，吓伯公化吉平安。","女":"小女根苗浅薄，但恐春夏月灾难多事，夜时不可外出，吓伯公化吉平安。"},{"年龄":"4-7岁","男":"小儿之卦运限未美，白虎星占度，惟防正、四、七月小疾波灾，吓伯公化吉平安。","女":"小女运限未美，但嫌多生皮肤小疾，正、四、七月守旧，吓伯公交秋返运平安。"},{"年龄":"8-12岁","男":"小童现年运度未美，春夏月尤恐灾难波阻，守旧，吓伯公化吉，交秋返运平安。","女":"小女时令未美，但嫌执僻，惟恐正、四、七月多生小疾，吓伯公化吉，交秋返运平安。"},{"年龄":"13-15岁","男":"童造现年运度未遂，虽聪明，惟防正、四、七月小疾之厄，吓伯公化吉，交秋返运平安。","女":"小女今年运度不遂，惟防正、四、七、月灾难波阻，守旧，宜吓伯公化吉，交秋平安。"},{"年龄":"16-17岁","男":"吉造步运未佳，白虎星占度，但防正、四、七月灾难，不可自执己意，吓伯公化吉，交秋返运平安。","女":"玉造虽机巧贤玉，但嫌正、四、七月灾疾波阻，宜守旧，夜时勿远出，吓伯公化吉，交秋平安。"},{"年龄":"18-29岁","男":"英造步运不美，白虎星占度，防正、四、七月祸非口舌，戒忍性气，吓天地化吉交秋转运平安。","女":"玉造运度未美，虽有助益家庭，但嫌迫切小疾口舌，正、四、七月守旧，吓天地交秋转入佳景平安。"},{"年龄":"30-55岁","男":"乾造步运不美，虽有智慧，但防正、四、七月歹人嫁祸，凡事安分守己，交秋转运贵人扶助平安。","女":"坤造行运美中不足，内心操杂，防有小疾口舌，宜吞忍，正、四、七月守旧，交秋转运出入平安。"},{"年龄":"56-69岁","男":"台造步运未遂，虽老练，但嫌迫杂又防正、四、七月小人不测之祸，闲事切勿近理，交秋转运出入平安。","女":"坤造行运未美，操心迫杂，应防暗疾口舌夜时切勿远出，忌看病人，交秋转运出入平安。"},{"年龄":"70岁以上","男":"台造老运不忘，惟防灾难跌地之厄，忌看病人，春夏月守旧，交小福寿绵长。","女":"妇造老运不旺，虽旺益子孙，但防暗疾风气，忌入丧门，春夏月守旧则吉也。"}]},"生意":{"生意":"偏财一点不能来，夏月守旧没贪财，诚心诵经求神佛，交秋冬月利路开。","生意解曰":"初做平，防阻失勿贪心，防小人耗劫，宜谨慎重谋为，秋后可得厚利。","开铺":"卜开铺之卦铺宅离家乡远的勿开，恐防有祸非失财盗窃之危，铺宅在家乡的初有阻涉，勿灰心秋后可得利。","合伙":"卜合伙之卦如白虎占度之兆，凶多吉少，勿合为要若合之恐亏本，失利惹出祸非也。","置货":"置货初时勿贪，候交秋取货渐渐振价，可获财利也。"},"出外":{"出外":"卜出外一事不美，做事恐有阻隔及小人累害，宜守旧在家经营，则可无忧无虑也。"},"谋望求财":{"谋望":"走遍天涯事不成，事成又着一场惊，不如守分随时过，春到人间草木荣。","谋望解曰":"谋事初时有小人累害劫财等惊阻，宜谨慎用心窍胆智，交小阳可成也。","求财":"上春财利小，防小人劫之，宜守旧经营，谨慎稳重冬月可得财利，肖虎者得大利，偏利失也。"},"学艺功名":{"学艺":"卜学艺之卦不美，如白虎占度，有歹人祸害，恐惹是非，若肖虎牛之人能认真学习，可学之。","功名":"功名不成，惟肖虎者可得中也。"},"行舟六畜":{"行舟":"行舟不吉，防风防盗也。","六畜":"六畜有阻在今春，要养三思善意存。求吓神明力保佑，任是凶险可化分。","猪羊":"猪羊不美 先失后得 防四七十月阻失 勿贪多养 宜精心饲养 吓伯公化吉","草龙":"卜草龙之卦 白虎占度恐防疾厄惊阻 使用小心勿过度 吓佛祖保佑平安","三鸟":"卜三鸟之卦不美 白虎占度 防鑑疾厄 防歹人盗劫勿贪多养 吓伯公保平安","田蚕":"田蚕早凶晚中 四季雨水中平"},"移徙":{"移徙":"移徒不吉 不可移之 守旧待时运也"},"行人":{"解曰":"行人在外财运不通 防小人阻隔 以致没有音讯 吓天地保佑财信早日回家","签文":"若问行程人未还 忙忙回首问关山 不因留恋归何晚 只为丝丝名利攀"},"婚姻":{"解曰":"芝兰虽芳但恐经霜，婚姻虽免强成之，恐怕不长久，非尔姻缘切勿谈之。","签文":"栽种芝兰意欲芳，谁知草木怕经霜，如今若得成姻眷，进余进房不长久。"},"官讼":{"解曰":"有理反成无理亏 嗟叹好事反成非 宜和为吉 切勿争讼好胜 理不可闹之 不然有理反成无理 还要被干连入狱","签文":"有理反成无理亏 嗟叹好事反成非 只宜劝解方为吉 免得干连到狱围"},"失物":{"解曰":"失物难回也 但君心勿乱 切宜速寻之 尚可有见千 万不可痛财失志也","签文":"汝的失物本无踪 只是安排未落空 进步速寻尚或见 其时闲气勿冲冲"},"占病":{"解曰":"此病乃是阴邪交缠 宜祭送化吉 求太阳星君保之 可平安也 一来求卜二求神 药方求来多有效 人病厌厌求保身 更衣宿疾答谢神","签文":"一来求卜二求神 药方求来多有效 人病厌厌求保身 更衣宿疾答谢神"},"其他":{"灶君":"卜此灶位虽美 但嫌灶前秽气 不够干净 应经常修理清洁干净 烹煮叶吉","阳基":"卜起造恐阻不成 修老屋是埕前水字不美 即修过居住吉也","六甲":"六甲生女大吉 生男仔细平安 但防根基不足 宜拜契南北斗星君君保佑平安","子息":"子息有得 但嫌先花后果 若夏季得之 恐难养 宜移房拜契 求佛祖保寿命绵长 富贵也","祖山":"卜此地有利结穴 气脉文雅 但嫌龙运不旺水阳出 坐向有利宜修整龙运壮旺并理水神归口 又兜唇口之后财丁旺也","青草":"此地龙脉足旺 但嫌前面水散 穴宜沉阳并兜唇 理妥水神归口 葬之财丁兴旺也 葬时防口舌 宜忍之"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  40,
  '夏国美进场',
  '剑射斗牛之兆',
  '上上之卦',
  '巳蛇',
  '夏国美衍祖德而得家学，又知文章合为时而作，故留意于时世兴败、民间苦乐之间。是年恰逢大比之期，夏国美会众举子上京赴考，十人遇虎，九人噬，唯国美一人幸存。入场应试一举得魁登元。上重之吴亦以有辅于家国益于世教而成，一代国士。',
  '栽桃生贵子，白屋出公卿;骢马庭前立，名声播四方。',
  '桃李芳菲',
  '{"签号":"第四十签","签名":"夏国美进场","签文类型":"剑射斗牛之兆","卦象":"上上之卦","生肖":"巳蛇","签文简介":{"戏文":"夏国美衍祖德而得家学，又知文章合为时而作，故留意于时世兴败、民间苦乐之间。是年恰逢大比之期，夏国美会众举子上京赴考，十人遇虎，九人噬，唯国美一人幸存。入场应试一举得魁登元。上重之吴亦以有辅于家国益于世教而成，一代国士。","诗曰":"栽桃生贵子，白屋出公卿;骢马庭前立，名声播四方。","内兆":"桃李芳菲"},"家宅运势":{"签文":"忧疑无虑也无凶，闲愁莫把挂腹中，赖得福神阴力阻，门庭喜气两三重。","解曰":"吉宅喜气盈门，但嫌主事人操心劳累，夏月疾难口舌，肖牛之人防生痛涉财，是因为折虎畔迫塞宜立八卦安门上抵挡，吓佛祖保平安居住财丁兴旺。"},"岁君签":{"总诗":"鸣鹄冲天得自然，逢时喜气志昂轩，此日升平得自在，翰翔直上九重天。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足养，八字成格，旺益上辈并茂，三、四、五月虽有小疾无妨，吉星守命平安。","女":"小女根苗稳固，三、四、五月虽有小皮疾无妨，有吉星守度旺益上人并茂，出入平安。"},{"年龄":"4-7岁","男":"小儿现年时令顺吉，生性天真活泼，旺益上辈，三、四、五月小疾无妨，吉星守命平安。","女":"小女今年时令叶吉，各事伶俐天真，春夏月有些皮肤小疾无妨，吉星守命平安。"},{"年龄":"8-12岁","男":"小童之卦运限顺遂，生性聪明，可入学校读书，定卜进步，三、四、五月小疾无妨，出入平安。","女":"小女时令佳美，凡事技巧，培养学习手艺，春夏月小疾无妨，吉星守命平安。"},{"年龄":"13-15岁","男":"童造今年上运，凡事开窍精通，宜入学校读书，远景定卜有望，小疾无妨，出入平安。","女":"玉造现年交上运，技巧开明，学习艺业，三、四、五月虽有小疾无妨，吉星守命出入平安。"},{"年龄":"16-17岁","男":"祥造现年运度交佳，如桃李之茂，做事智慧，宜加强温习文化，将来自有高升之贺，而且出入平安。","女":"玉造现年交上美运，如桃李芳菲，八字清秀，性格柔和，有旺益家庭，三、四、五月虽有小疾无妨平安。"},{"年龄":"18-29岁","男":"乾造步运亨通，如桃李之茂，做事奇才特达，宜向外发展，有禄马贵人扶助，可得财喜出入平安。","女":"美造行运交泰，如桃花茂盛，做事技巧贤玉，有旺益佳美，春夏月虽有小疾无妨，有吉星守命平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如桃李芳菲，老练特达，宜向外争取，有贵人扶助可得财喜，而且出入平安。","女":"坤造行运甚美，如桃李芳菲，性格温和，有助益家庭但勿迫性，春夏月小疾无妨出入平安。"},{"年龄":"56-69岁","男":"台造步运交泰，如桃李之茂，为人老练忠诚，虽可得财运，但勿迫性，幸贵人扶助出入平安。","女":"坤造行运佳美，如桃李芳菲，贤淑智慧，有内助之能，三、四、五月虽有暗疾无妨出入平安。"},{"年龄":"70岁以上","男":"吉造老运安康，但防春夏月灾疾之厄，早晚上落小心，幸福星照身出入平安。","女":"妇造老运康泰，有旺益子孙，但防暗疾风气，三、四、五月守旧，上落小心大造平安。"}]},"生意":{"生意":"购货防阻切莫贪，偏财无望不可攀，春夏恐防有阻失，交秋冬时力路宽。","生意解曰":"生意初时阻失财利小，但宜立志维持五，九，十一月返运，生意旺可得厚利","开铺":"卜开铺之卦春夏恐有阻失，防祸非灾厄，宜用心窍刻苦经营，秋后生意兴隆有大财利也，肖牛者定失。","合伙":"卜合伙之卦宜同心同德协力经营，伙计要大公无私，大家出谋献策有大财利可得!","置货":"置货春夏有阻，不可贪财，候交秋冬月，定得得厚财利也。"},"出外":{"出外":"卜出外一事叶吉时令当权，凡事勿疑大胆出外谋生，有贵人扶助名利双成!"},"谋望求财":{"谋望":"失群鸣雁在东西，岂有相逢任飞时，今日脱尘云外去，只留声阶此人知。","谋望解曰":"谋事可成但防初时有阻隔，候九，十月有贵人扶助定可成功，肖牛者谋之不美也","求财":"初时利薄，阻隔宜立智维持于三，五，十一月得厚利偏财初有失，"},"学艺功名":{"学艺":"卜学艺之卦叶吉，宜刻苦下工夫，能学得技艺，肖羊猴之人时令合局，定能学得高超技术，肖牛之人宜待运。","功名":"功名进之中也，肖羊猴人更可显达。"},"行舟六畜":{"行舟":"行舟如意，成对失群后可回归也。","六畜":"一支利剑射半牛，好香烧炷伯公求。要养勿多一二只，灾消吉至财利酬。","猪羊":"养猪羊上春防阻失 勿贪养 一二只为妙五月起顺利 吓伯公保安","草龙":"卜养牛之卦不美 有剑射斗牛之兆 恐防病疾阻失 吓佛祖保安 未养勿养","三鸟":"卜养三鸟之卦 恐防春月阻失 五月 起养之 顺利吓伯公保佑 可得财利","田蚕":"田蚕早中晚大吉 四季雨水大吉"},"移徙":{"移徙":"移徒平安 或远或近其大吉也"},"行人":{"解曰":"行人要外得志 有贵人重重 于五 九 十一月有佳音财利回家也","签文":"几度阳关去问津 未知音信付何人 如今不必登楼望 君问归期有佳音"},"婚姻":{"解曰":"前生注定有缘份，但初时有阻有人破说，宜吓南北斗星君于，九，十月定亲","签文":"生前虽定自家人，今日相逢又定亲，争奈姻缘时未至，且宜缓缓待寅申。"},"官讼":{"解曰":"官讼初时恐要吃亏 但后来有贵人扶助 可以得理胜之 但还是要以和为贵","签文":"如今报汝勿多忧 此事终空不到头 但待贵人相借力 自然贤者得悠悠"},"失物":{"解曰":"自己不小心而致失物 今须速寻之 终久有傍人告知消息也","签文":"失去资财意转深 自家不肯提防心 莫言迅速难寻讨 终久傍人说好音"},"占病":{"解曰":"老年病是冲犯恶杀 宜用五色纸猫五只 白须老人五个祭送 肖牛恐亡 少安 吓佛祖保安 未遇身医疾未除 但得五湖明月在 不愁无处获珍珠","签文":"未遇身医疾未除 家庭肖乏莫嗟吁 但得五湖明月在 不愁无处获珍珠"},"其他":{"灶君":"卜此灶位分金合于八宅之卦 经常灶前修理清净 烹煮大吉 可旺财丁","阳基":"卜起造初有阻 若丑未分金起造之昌盛 老屋有利修整 财丁旺","六甲":"卜此胎六甲生男 但防根基不足 恐有阻隔 宜求佛祖保佑 养育平安也","子息":"卜子息之卦叶吉 为桃李芳菲之兆 开花吉果 根深基固 一生近贵 前程远大 旺益家庭也","祖山":"卜贵祖龙脉足旺 葬后财丁有阻者长四房是青龙畔失砂 有利宜填浮则房房兴盛也 但望各房要心不能存私","青草":"此地高山落龙横屏结穴 气脉足旺 面前宽阳 墓穴宜双塘 日后子孙定显达于科甲 但葬时须填妥青龙畔砂 房房可财丁兴旺"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  41,
  '姜承祖遇害',
  '螳螂捕蝉之兆',
  '中平之卦',
  '辰龙',
  '姜承祖从祖训，欲为圣朝除弄政，与民分忧，锐意改革，整朝纲，驱外侮。然正直之心多胸无城府，况虎狼当道，心狠手毒，为人君者，权重耳轻，而忠言义行，必异旧习。于是群奸每趁忠言有碍圣听，乘机奏列姜承祖罪状以触怒天颜，可怜姜承祖虽一腔义愤，也终为奸人所害。',
  '门前光出现，始见一皇天;心地行正道，经莲出水开。',
  '落花流水',
  '{"签号":"第四十一签","签名":"姜承祖遇害","签文类型":"螳螂捕蝉之兆","卦象":"中平之卦","生肖":"辰龙","签文简介":{"戏文":"姜承祖从祖训，欲为圣朝除弄政，与民分忧，锐意改革，整朝纲，驱外侮。然正直之心多胸无城府，况虎狼当道，心狠手毒，为人君者，权重耳轻，而忠言义行，必异旧习。于是群奸每趁忠言有碍圣听，乘机奏列姜承祖罪状以触怒天颜，可怜姜承祖虽一腔义愤，也终为奸人所害。","诗曰":"门前光出现，始见一皇天;心地行正道，经莲出水开。","内兆":"落花流水"},"家宅运势":{"签文":"鬼怪无端入户庭，响声入梦怪人惊，要知因甚人财蹇，只因家庭路不平。","解曰":"吉可得喜气但防夏秋月疾难失财口舌火厄，吓佛祖保平安，厝前受火烟杀冲伤，用八卦符安门上修整水道，祖上香灯拜到居住财丁兴旺。"},"岁君签":{"总诗":"落花流水两无情，家合惶惶主不宁，小中阴人招疾厄，须当急祷旺宗神。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基虽足，但防二、五、九月灾疾波阻，六甲妇勿抱近抱，吓月娘化吉平安。","女":"小女根苗浅薄，惟防二、五、九月六甲花水，夜时勿远出，吓月娘化吉平安。"},{"年龄":"4-7岁","男":"小儿之卦运限未美，但防二、五、九月小疾水厄，凡水边小心，守旧，吓妈祖化吉平安。","女":"小女现年运限未遂，二、五、九月惟防灾难水厄，逢水勿近，守旧，吓妈祖化吉平安。"},{"年龄":"8-12岁","男":"小童运度未遂，虽伶俐，但防二、五、九月灾难水厄，逢水边小心，吓妈祖化吉平安。","女":"小女之卦运度未遂，但防二、五、九月多生灾难水厄，吓妈祖化吉平安。"},{"年龄":"13-15岁","男":"童造现年运度不吉，虽聪明，但防二、五、九月小疾水厄，水边小心，吓妈祖化吉平安。","女":"玉造运度美中不足，二、五、九月尤防波阻，凡水边勿近，吓妈祖化吉平安。"},{"年龄":"16-17岁","男":"祥造步运未遂，如乌云盖月，但防二、五、九月小灾波阻，宜守旧，多学文化，吓妈祖化吉保平安。","女":"玉造现年运度美中不足，但防二、五、九月灾疾水厄，宜守旧，夜时勿远出，吓妈祖化吉平安。"},{"年龄":"18-29岁","男":"乾造步运未遂，防二、五、九月小人口舌祸非，宜戒忍性气，方免造成落花流水，吓天地化吉平安。","女":"玉造行运未遂，人虽技巧，但嫌美中不足，皆因签文落花流水，二、五、九月灾疾，吓天地化吉平安。"},{"年龄":"30-55岁","男":"乾造步运未遂，签文乌云盖月，防二、五、九月小人不测之祸，凡事安分守己，吓天地化吉平安。","女":"坤造行运，人虽贤惠，但嫌内心操杂，小人口舌，二、五、九月守旧，宜忍性，吓天地化吉平安。"},{"年龄":"56-69岁","男":"台造步运不佳，如落花流水，人虽老练忠诚，但防二、五、九月平底风波，闲事勿理，底子平安。","女":"坤造得此卦如落花流水，防暗疾多灾，二、五、九月守旧，忌看病人，底子平安。"},{"年龄":"70岁以上","男":"台造老运不旺，虽为人正直，但防灾难交脱，二、五、九月守旧，忌入丧门则吉。","女":"妇造老运不佳，惟防暗疾跌地之厄，早晚上落小心，二、五、九月守旧，底子平安。"}]},"生意":{"生意":"意外之财不可寻，春夏有阻莫贪心，正财少利偏财失，慎防小人劫财金。","生意解曰":"生意上春防阻失，防小人偷劫，宜守旧业，交易要直勿贪心，交冬可得财利","开铺":"卜开铺之卦君心地宜公平正直，不可亏人勿惹口舌，勿积货防劫厄，宜求佛祖令旗合财帛星君镇铺宅。","合伙":"卜合伙之卦如落花流水之兆，时令不吉勿合为要，若合之恐惹祸非盗劫失利!","置货":"置货恐有阻失，防人暗算，要现买现卖，不可贪，若置之定失也。"},"出外":{"出外":"出外之卦美中不足防小人祸害，心中操杂，往之不成宜在家经营免生祸非!"},"谋望求财":{"谋望":"当初有意望东楼，既抵蓬来下九洲，不肯回头归去路，即交埋没入荒丘。","谋望解曰":"谋事防人暗算，宜谨慎勿，防口舌失财之祸，心地宜从正道其事可成","求财":"正财初时有阻防小人劫之，经营从正道交秋冬月转运，可得利，偏财莫取!"},"学艺功名":{"学艺":"卜学技艺之卦，如落花流水之兆，君时运未至，若学之，恐半途而废，不成也。","功名":"功名不成，因时运未通，切勿进场，进不吉。"},"行舟六畜":{"行舟":"行舟有祸，不可行，行之失也。","六畜":"今载六畜恐有残，要养切切心莫贪。猪牛鸡犬要防失，求祷伯公保平安。","猪羊":"饲养猪羊定有阻失 不可贪养 防一五八月阻失 求伯爷保平安","草龙":"卜养草龙之卦 恐防二 五 八月阻隔 防脚疾 防盗厄 使用小心 吓伯公保佑平安","三鸟":"卜养三鸟之卦 如落花流水之兆 防二 五 人阻失 防瘟疾 防盗厄 勿贪多养 求伯公保平安","田蚕":"田蚕有祸 早晚不吉 高田吉 雨水不利"},"移徙":{"移徙":"移徒地龙不旺 不可移 移之难也失也"},"行人":{"解曰":"此行人有思家之心 只因在人在天边 路途阻隔不能回也 求佛祖保佑平安","签文":"非是其人不恋家 只因阻隔在天涯 欲求归期中朝望 十二巫山锁云断"},"婚姻":{"解曰":"此婚事不成，男求女不就，女求男莫恋，流水无情不能结合也","签文":"休想斯人入汝家，莫教惆伥怨吁嗟，落花有意随流水，流水无情恋落花。"},"官讼":{"解曰":"和为贵 不管有理无理 切不可告 有理宜退一步 若告之 改悔迟也","签文":"做事瞒心天地知 何须临事问神祇 有理但宜退一步 免遭刑累悔何迟"},"失物":{"解曰":"小人之言语勿听 全是虚情 勿信以为真 失物难寻也","签文":"傍人报汝有忧惊 梦里还迷不自醒 已失可疑势着紧 休教错认别人情"},"占病":{"解曰":"老年之病是恶星占身 防寿命不安 少年是阴邪交缠 向西北方掩送 请医治之","签文":"运蹇时乖不自由 灾来是为口中求 月过天边光明缺 人到中年万事休"},"其他":{"灶君":"灶位虽美 但嫌灶前迫塞秽气 受门窗冲杀 宜修通 灶上贴八卦符 则吉之","阳基":"卜阳居起造有是非口舌失财 宜理妥门庭水路又嫌面前受杀水神不美 掩祭大吉","六甲":"此胎六甲生女吉 生男不成 要靠天之福也 要拜契显赫神明保佑平安","子息":"卜子息之卦 多花少果 若有果儿 恐难养 君心地宜行正道 多行善积德 求佛祖保平安","祖山":"卜祖山有结穴 但嫌龙运不旺 水神不美 白虎畔有路冲伤 有利者修壮旺并理水神归口 又填白虎畔有浮颅又兜唇 做浮室大吉财丁旺","青草":"此地有龙落无结穴 水神不美 白虎畔受杀冲伤 若要葬此地 恐惹是非口舌破财 勿取之平安也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  42,
  '唐天子得国公',
  '囚人遇赦之兆',
  '上上之卦',
  '卯兔',
  '徐茂公观于星台，知定阳王先锋尉迟恭为将星，上达听天。李世民爱才如命，苦求之。尉迟恭以不事二主拒不归唐。徐茂公计杀其主刘武周。李世民屈尊为之行丧，厚葬刘武周；并屈身钻从尉迟恭鞍下过。其求将真诚至此，尉迟恭感李知遇之恩，乃助唐打定天下，立开国奇功，封史国公。',
  '否极当逢泰，云开月更明;不言来相请，宣我上蓬瀛。',
  '如鱼得水',
  '{"签号":"第四十二签","签名":"唐天子得国公","签文类型":"囚人遇赦之兆","卦象":"上上之卦","生肖":"卯兔","签文简介":{"戏文":"徐茂公观于星台，知定阳王先锋尉迟恭为将星，上达听天。李世民爱才如命，苦求之。尉迟恭以不事二主拒不归唐。徐茂公计杀其主刘武周。李世民屈尊为之行丧，厚葬刘武周；并屈身钻从尉迟恭鞍下过。其求将真诚至此，尉迟恭感李知遇之恩，乃助唐打定天下，立开国奇功，封史国公。","诗曰":"否极当逢泰，云开月更明;不言来相请，宣我上蓬瀛。","内兆":"如鱼得水"},"家宅运势":{"签文":"今年喜庆事如何，人口无休畜产多，秋去冬初些小悔，更祷神佑保融和。","解曰":"吉宅气临门，但恐防九，十一月疾难口舌，阻六畜火星小心，宜求本境地头老爷保平安，是埕口水道不美宜常修清洁居住财丁昌盛。"},"岁君签":{"总诗":"鱼游出水戏波浪，跳跃优游非等闲，喜逢泰来万事吉，更无阻险在其间。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，八字成格，有旺益上辈并茂，三、四月虽有小疾无妨，寿命绵长。","女":"小女根基足旺，利益上辈，三、四月虽有小皮疾无妨，卦中吉星守命平安。"},{"年龄":"4-7岁","男":"小儿之卦运限顺遂，生性天真，旺益上人，但三、四月消极无妨，幸吉星守命平安。","女":"小女运限叶吉，凡事伶俐活泼，旺益上人，三、四月水边小心，幸吉星守命平安。"},{"年龄":"8-12岁","男":"小儿今年上运，凡事伶俐天真，宜入学校读书，定卜进步，水边小心，底子平安。","女":"小女现年运度亨通，活泼伶俐，旺益上人并茂，三、四月水边勿近，底子平安。"},{"年龄":"13-15岁","男":"小童之卦叶吉，生性聪明开窍，宜入学校温习文化，定卜进步，远景有望，出入平安。","女":"小女现年运度未遂，三、四月有小疾无妨，但水边小心，幸有吉星守命出入平安。"},{"年龄":"16-17岁","男":"祥造时令亨通，如鱼得水，各事精通，可再培养，三、四月虽有小疾无妨，贵人扶助出入平安。","女":"玉造现年运度甚美，签文如鱼得水，八字清秀，宜学艺业，三、四月小疾无妨，吉星照身平安。"},{"年龄":"18-29岁","男":"乾造步运亨通，如鱼得水，做事才能特达，三、四月虽有小人口舌无妨，贵人扶助可得财喜平安。","女":"坤造行运交泰，签文如鱼得水，凡事贤玉，可称女界之英，三、四月虽有小疾无妨，出入平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，签文如鱼得水，性格刚直，可得财喜，但三、四月戒忍口舌，贵人扶助出入平安。","女":"坤造行运佳美，如鱼得水，可称内助，三、四月虽有小疾无妨，幸卦中吉星照身出入平安。"},{"年龄":"56-69岁","男":"台造步运上吉，为人忠诚老练，有财运美，但三、四月戒忍口舌，虽有暗疾无妨，贵人扶助平安。","女":"坤造行运甚美，签文如鱼得水，凡事贤淑智慧，但勿操迫，虽有暗疾无妨，吉星守命平安。"},{"年龄":"70岁以上","男":"台造老运安康，老当益壮，但嫌得此卦险阻二字出现，三、四月上落小心，幸福星拱照平安。","女":"妇造老运虽有旺益子孙，但防老风暗疾，三、四月守旧，忌入丧门，幸吉星守命平安。"}]},"生意":{"生意":"如今得志上青云，谋望求财总遂君，秋末冬初利更重，偏财夏阻冬成堆。","生意解曰":"现年生意兴隆，但防夏月亏本，五，九，十一月如鱼得水，有贵人可得厚财利","开铺":"卜开铺之卦如鱼得水之兆春夏月防祸非失财，秋后转运否极泰来，有厚财大利。","合伙":"卜合伙之卦叶吉，但春夏月还要防歹人有不仁之心，若伙计同心协力，秋后可得厚财利也。","置货":"卜置货初时恐亏本，但要有志气胆智，置后渐且停留，秋后振价，可得厚财利也。"},"出外":{"出外":"此次出外叶吉，但嫌心意未定，应有胆智前往三，五月有贵人扶助，可获财利!"},"谋望求财":{"谋望":"地冷天寒水作冰，安心守志待仓清，如今正遇阳和日，四海优游任往行。","谋望解曰":"谋事初阻挡不称心，须立志坚持，候交秋月有贵人扶助定可成功","求财":"正财上春跋涉宜立志维持，谨慎谋之候五，九，十一月如鱼得水，有厚财利可得，偏财也财样，但不能贪也!"},"学艺功名":{"学艺":"卜学技艺之卦，初恐不如意，但应不畏艰难坚持学习，必能得真艺也。","功名":"如龙升腾，贵人扶助，可攀丹桂也。"},"行舟六畜":{"行舟":"行舟平安，上春有小阻，下春大吉。","六畜":"君问饲养猪牛羊，劳心劳力有得钱。枯木逢春色欲华，菊吐芬芳财利长。","猪羊":"今年猪羊春夏小阻小利 五月起养之顺利 十月起可得大利 吓灶君保平安","草龙":"卜养大武之卦大吉 水草调和 恐防春夏有小阻使用小心 吓大伯公保佑平安","三鸟":"卜养三鸟之卦 为否极泰来之兆 初有小阻无防 宜下苦力大胆饲养 十月以后可得大利","田蚕":"田蚕早中不吉 晚大吉 四季雨水大吉"},"移徙":{"移徙":"移徙顺 移之大吉平安也"},"行人":{"解曰":"行人在外有阻未归 但财运亨通 有贵人 候五 九 十月有财信回归也","签文":"因为牵缠旅吉中 致教难遂扣归迟 伊今是问归期日 直待功成得团圆"},"婚姻":{"解曰":"天配良缘如鱼得水，立时可成定能同心同德，白头皆老","签文":"天设良缘两相宜，如鱼得水戏河池，此时若得成连娌，那堪相许也相依。"},"官讼":{"解曰":"小人作弄 善良被欺 但君力强 肯教贤者得安然 官讼胜之","签文":"小人白捏意伤残 要理不容人事间 肯教贤者释词难 官讼胜之大吉"},"失物":{"解曰":"物已失去 但在近水傍 细心寻找 可回也","签文":"失去何须心里忙 只因懒惰少提防 要知踪迹归何处 只在浮游水岸傍"},"占病":{"解曰":"占病应求天保佑 四方祭送 请医服药 可保平安 老人防冲跳 恐危也","签文":"天星不顺致灾殃 日月危时祷告天 但要心存行善果 可能百病得安康"},"其他":{"灶君":"卜此灶位分金合课 但嫌灶前阴湿 常时宜修理清净 烹煮叶吉 并可旺益财丁","阳基":"卜起造防口舌阻隔 理妥修造吉 惟门前水路不美 宜修整居住财丁兴旺","六甲":"此胎六甲生男 合家欢喜 养育平安","子息":"卜子息之卦 初时少果多花 后子孙有之 而且顺养 一生近贵 衣食无忧也","祖山":"卜祖地有结穴 但嫌唇前来于出水不美 有利宜修整水神配分金并填青龙砂头相朝之后 财丁兴旺","青草":"此地横龙结穴 气脉足旺 墓穴宜占高点 应理妥前面曜水 葬时宜掩祭之 葬后房房子孙 可财丁兴旺也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  43,
  '仙姬送子有日出吉',
  '蛟龙得雨之兆',
  '上上之卦',
  '寅虎',
  '董永卖身葬父，七仙女敬其勤孝厚道，下凡救助之。遂化为村姑，路逢董永，托槐树为媒，与董永结，随董永入府中为奴，并有孕。又用神功助董永，使得将三年卖身期改为百日，夫妻回家。玉帝知其已了百日姻缘，逼回天宫。七仙女与董永槐阴割别。来年花发，复送子归于董永。',
  '捷报已占魁，皇都得意回;青云今得路，黄菊应时开。',
  '谋望遂心',
  '{"签号":"第四十三签","签名":"仙姬送子有日出吉","签文类型":"蛟龙得雨之兆","卦象":"上上之卦","生肖":"寅虎","签文简介":{"戏文":"董永卖身葬父，七仙女敬其勤孝厚道，下凡救助之。遂化为村姑，路逢董永，托槐树为媒，与董永结，随董永入府中为奴，并有孕。又用神功助董永，使得将三年卖身期改为百日，夫妻回家。玉帝知其已了百日姻缘，逼回天宫。七仙女与董永槐阴割别。来年花发，复送子归于董永。","诗曰":"捷报已占魁，皇都得意回;青云今得路，黄菊应时开。","内兆":"谋望遂心"},"家宅运势":{"签文":"福星高照汝家门，些小忧疑不必论，欲安稳时财禄足，神前多把好香焚。","解曰":"吉宅可得财喜，但防夏月口舌疾难，主事人操心劳烦，是厝前受杀冲伤，每逢塑望两日应拜天地保平安，并求佛祖令旗安门上祭化平安。"},"岁君签":{"总诗":"日出扶桑万处明，贵人吉庆事皆亨，求财谋望皆如意，若问求官司定得名。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足养，八字成格，三、五月小疾无妨，旺益上人并茂，出入平安。","女":"小女之卦根苗稳固，有旺益上人并茂，三、五月虽有小疾无妨，出入平安。"},{"年龄":"4-7岁","男":"小儿今年运限顺遂，生性天真活泼，虽有小疾无妨，三、五月水边小心，吉星守命平安。","女":"小女现年运度叶吉，有旺益上人，但防三、五月小疾水厄，水边小心，幸吉星守命平安。"},{"年龄":"8-12岁","男":"小童今年上运，各事伶俐活天真，宜入学校读书，定卜远景有望，而且出入平安。","女":"小女运度叶吉，凡事精通活泼，有旺益上人并茂，三、五月小疾无妨，出入平安。"},{"年龄":"13-15岁","男":"小童运度亨通，凡事聪明开窍，宜培养入学校读书，三、五月虽有小疾无妨，出入平安。","女":"小女运度顺遂，如龙得雨，有旺益上人并茂，三、五月小疾无妨，水边小心，底子平安。"},{"年龄":"16-17岁","男":"祥造运度亨通，如龙得雨，通能特达，宜培养温习文化，定卜进展，虽有小疾无妨平安。","女":"玉造行运交泰，如龙得雨，凡事贤玉，八字清秀，旺益家门，三、五月有小皮疾无妨，出入平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如龙得雨，才能多智，但三、五月宜忍口舌，可向外发展，有贵人扶助可得财喜平安。","女":"美造交上运，如龙得雨，智慧魄力，三、五月虽有小疾口舌无妨，但宜忍性，吉星照身平安。"},{"年龄":"30-55岁","男":"乾造步运上吉，签文如龙得雨，奇才特达，可向外发展，三、五月戒性，有贵人扶助，出入平安。","女":"坤造行运甚美，如龙得雨，凡事智慧，助益家庭，三、五月宜吞忍性情，卦中吉星守度出入平安。"},{"年龄":"56-69岁","男":"台造步运亨通，如龙得雨，为人老练经济，三、五月小疾无妨，戒性，幸贵人扶助出入平安。","女":"坤造时令交泰，如龙得雨，虽有旺益家庭，但嫌操心暗疾，凡事温柔和气，吉星守命平安。"},{"年龄":"70岁以上","男":"台造得此卦太旺，惟防三、五月灾难交脱，三、五月守旧，幸贵人扶助晚景胜前。","女":"妇造老运交泰，虽有旺益子孙，但防暗疾，上落小心，幸吉星照身，福体安康。"}]},"生意":{"生意":"劳心吃苦是春时，夏季也是利丝丝，货物大胆停留下，交冬出售得厚长。","生意解曰":"生意经营上春磨苦，财利稀秋后转运，如龙得雨，生意旺相，可得厚财利","开铺":"卜开铺之卦初有小阻，要用苦力维持，秋后开之生意兴隆，肖龙者谋望遂心得大利。","合伙":"卜合伙之卦为龙得雨之兆，若伙计肖龙者定能得厚利，余人秋后也能得利也!","置货":"置货初时有阻，但渐且停留，候交冬月振价发售，可得大利，肖龙者利更大。"},"出外":{"出外":"时令合局似得雨，前途远大于三月起大胆往外，有贵人扶助平安!"},"谋望求财":{"谋望":"几年辛苦三更起，以为生平名利中，喜得太阳东海出，光明无处不亨通。","谋望解曰":"几年来谋事劳累双不成就，现年万事亨通，有贵人扶助所谋成功","求财":"正财大得利但上春还小，宜苦力坚持交五，九，十一月转运，似龙得雨，可得大利，偏财有阻，肖龙者得大利!"},"学艺功名":{"学艺":"卜学技艺之卦，现年学之得艺，但必须勤奋好学，不耻下问，定能成材也，肖龙者学之更妙。","功名":"文武功名都可得中，肖龙之人得中首榜。"},"行舟六畜":{"行舟":"行舟几年辛苦奔波，今朝顺风得利。","六畜":"起初生灾不由人，至切勤养用苦心。自是灾星退去日，秋后养之遂君心。","猪羊":"饲养生猪初有阻 候下春养之饲料调和 有大利可得 若养羊 定得厚利","草龙":"卜饲养草龙之卦如龙得雨之兆 水草调和 身强力壮使用顺利 可旺益家庭","三鸟":"卜养三鸟之卦 初春有阻宜苦心勤养 秋后转运可以大养 可得大財利也","田蚕":"田蚕早冬失 晚冬吉 四季雨水顺利吉也"},"移徙":{"移徙":"移徒平安大吉 移之财丁兴旺也"},"行人":{"解曰":"行人在外平安得志 时令当权 有贵人扶助 于至五 九月有财信回归 可喜可贺","签文":"故人走去在天涯 万水千山未得来 今日雁书传音讯 平安二字不挂怀"},"婚姻":{"解曰":"男女双方情投意合，不言富贵荣华，可以下聘成亲平安大吉，白头皆老","签文":"平生喜得自投机，正好成亲送聘仪，相爱相求无别事，勿言贪富及高低。"},"官讼":{"解曰":"是非必须摇清 不用怕刑 冤情可以雪 自有贵人 贵人一到 可和无事","签文":"是非不讲事难平 何用忧心怕杖刑 自有贵人来喝散 必无牢狱不须惊"},"失物":{"解曰":"失物为活物 不须劳心寻之见也 向东方寻之 在林前路边见回也","签文":"东西失在山林前 失去东寻在里边 此物分明是活物 不须仇恨自忧煎"},"占病":{"解曰":"老年是风气火盛 防冲跳 恐凶也 少壮是阴火盛 求太阳公或佛祖保平安","签文":"神前无事不烧香 直待临危告上苍 亦若要求身好日 细看红日出扶桑"},"其他":{"灶君":"卜此灶位分金合课 烹煮兴旺 但经常应把灶前修整清净 可保家内财丁兴隆","阳基":"卜起造初有口舌 宜忍起建吉 老阳宅水字不美 且门太高 改过居住吉也","六甲":"卜此胎六甲生男 有皇都得子之兆 但应求佛祖或太阳公保佑养育平安","子息":"卜子息之卦 自有仙女送子来 一生顺养 而且近贵 有发展之日 荣宗耀祖也","祖山":"卜祖山有结穴 气脉足旺 但嫌青龙畔不朝点穴太低 白虎畔空野不朝 坐向有利宜修葬高三五尺沉阳做填青龙畔朝护吉 修白虎畔朝护财丁旺","青草":"此地横龙结穴 气脉足旺 但青龙畔过案白虎畔空野 宜沉阳兜唇 葬之可兴旺也 葬时有些小口舌 宜忍之"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  44,
  '孙策怒斩于吉',
  '沙里淘金之兆',
  '中平之卦',
  '丑牛',
  '孙策性刚，为仇者许贡家客所伤，以华佗外出补得根治。日策饮于城楼，见百姓夹道迎拜子吉，问于陈震，曰为民驱疫者也。子吉正邪如水火，孙策却视子吉为妖人，再三不从家母及众官劝阻，怒斩子吉。子吉魂扰之，策益怒，触旧伤复发，临危传印授于其弟孙权，立嘱而亡。',
  '犬作蛇鬼哭，蛇藏脚下行;寒夜灯火灭，杜鹃叫三声。',
  '乌云盖月',
  '{"签号":"第四十四签","签名":"孙策怒斩于吉","签文类型":"沙里淘金之兆","卦象":"中平之卦","生肖":"丑牛","签文简介":{"戏文":"孙策性刚，为仇者许贡家客所伤，以华佗外出补得根治。日策饮于城楼，见百姓夹道迎拜子吉，问于陈震，曰为民驱疫者也。子吉正邪如水火，孙策却视子吉为妖人，再三不从家母及众官劝阻，怒斩子吉。子吉魂扰之，策益怒，触旧伤复发，临危传印授于其弟孙权，立嘱而亡。","诗曰":"犬作蛇鬼哭，蛇藏脚下行;寒夜灯火灭，杜鹃叫三声。","内兆":"乌云盖月"},"家宅运势":{"签文":"欲求香火福神旺，百事无侵耳目端，春夏欲知唇口事，秋冬人口得平安。","解曰":"吉宅防四，五，九月疾难口舌失财，男妇生端宜团结和气，则家道可圆，是由久年香灯神恩太重，宜改谢请上香灯拜到居住财丁兴旺。"},"岁君签":{"总诗":"乌云遮月暗朦胧，暗昧门庭事未通，且宜守旧方为吉，直待云开万事通。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足旺，但防春夏月灾难波阻，吓月娘化吉交秋返运，守命绵长平安。","女":"小女根苗虽稳固，但防春夏月小疾多事，吓月娘化吉交秋返运，可卜出入平安。"},{"年龄":"4-7岁","男":"小儿之卦运限未美，惟防春夏月多生灾难，守旧，吓月娘，交秋返运平安。","女":"小女现年运限未遂，但防春夏月皮肤小疾，夜勿远出，守旧，吓月娘交秋返运平安。"},{"年龄":"8-12岁","男":"小儿运度未美，人虽活泼，防有小波阻，春夏月守旧，吓月娘交秋返运平安。","女":"小女运度未遂，但嫌执僻，春夏月防有灾难波阻，守旧，吓月娘交秋返运平安。"},{"年龄":"13-15岁","男":"小童之卦未美，虽聪明，但防小疾波灾，春夏月守旧吓月娘化吉交秋返运平安。","女":"小女现年时令未美，嫌执僻，又防春夏月多灾之厄，吓月娘化吉，交秋返运平安。"},{"年龄":"16-17岁","男":"祥造运度未美，似乌云盖月，防春夏月小人口舌，耐心学文化，吓天地化吉，交秋转运平安。","女":"玉造时令未美，似乌云盖月，虽贤玉，但防春夏月灾疾多事，夜时勿独行，吓月娘化吉交秋转运平安。"},{"年龄":"18-29岁","男":"英造步运不美，人虽奇才，签文乌云盖月，防春夏月小人祸非，宜戒性，交秋转运平安。","女":"美造运度不佳，似乌云盖月，性格虽温和，但防春夏月灾难口舌，凡事吞忍，交秋转运出入平安。"},{"年龄":"30-55岁","男":"乾造步运不佳，如乌云盖月，防春夏月小人不测之祸，戒忍性气，交秋转运贵人扶助平安。","女":"坤造现年运气不佳，似乌云盖月，但防暗疾口舌，凡事温柔大量，春夏月守旧，交秋转运平安。"},{"年龄":"56-69岁","男":"台造步运未美，人虽忠诚，但防春夏月歹人嫁祸生非，闲事勿理，交秋转运贵人扶助平安。","女":"坤造行运美中不足，似乌云盖月，虽有内助，但嫌操心暗疾，春夏月忍口舌，交秋转运平安。"},{"年龄":"70岁以上","男":"吉造老运不旺，虽有智谋，但防春夏月灾难交脱，守旧，交秋大造平安。","女":"妇造老运不旺，但防暗疾风气，春夏月守旧，上落小心，交秋可卜大造平啊。"}]},"生意":{"生意":"春夏何必枉用心，用尽心机难得金，若得福神来添力，秋冬财利也非轻。","生意解曰":"生意似沙里淘金，春夏利小阻隔，交秋后转运得利，肖己戌者宜现买现卖，用苦力定得厚利","开铺":"卜开铺之卦似沙里淘金之兆，上春磨苦小利，注意夜间勿远行，秋后云开月明可得财金，肖蛇狗者勿开。","合伙":"卜合伙之卦肖蛇狗者勿合，余人合之则吉，但春夏磨苦小阻，秋后月明可得厚利!","置货":"置货初失，磨力小利，但须用心窍，交秋月可得利，肖巳戊者不可贪。"},"出外":{"出外":"卜出外之卦上春时令未谈通，有小人阻隔，交秋厚转运有贵人扶助，出外平安也!"},"谋望求财":{"谋望":"秋后冬前欲利交，机关用尽不能成，君能守得阳和日，雨散云开月自明。","谋望解曰":"谋事初时有小人累害劫财，宜谨慎，用心窍胆智交小阳谋之成也","求财":"正财如沙里淘金春夏磨苦跋涉，宜刻苦勤奋工作冬月可得财利，偏财不得硬求失也!"},"学艺功名":{"学艺":"卜学技艺之卦，似乌云遮月之兆，君时运未到，学之不成，肖蛇狗之人恐惹是非，宜守旧待时也。","功名":"功名不中，肖巳戌者，勿求为妙，恐惹祸非也。"},"行舟六畜":{"行舟":"行舟春不顺，交秋后顺风得利。","六畜":"春夏受苦又艰辛，休想改革守旧恨。秋冬转运宜作福，六畜有利报汝恩。","猪羊":"猪羊春夏磨苦不可贪多养 防四 九月阻隔 中大只要卖 十月后转运 吓伯爷保平安","草龙":"卜养牛之卦如鸟云遮月之兆 春夏月恐有阻隔病疾 使用小心 秋月转运平安","三鸟":"卜养三鸟之卦春夏磨苦小利 防四 九月阻失 十月后转运 可以多养 有厚财利","田蚕":"田蚕先难后易 早不吉 晚大吉 雨水中吉也"},"移徙":{"移徙":"移之不吉 不可强徙 徒而生祸也"},"行人":{"解曰":"行人有如乌云遮月 初时财利稀少 交中秋转运 有贵人扶助 可得财信回家","签文":"傍人浪说不符同 去后音信不见踪 已是船家阴德好 分明又知太平中"},"婚姻":{"解曰":"婚姻成之，但必从速下聘迎接，因有小人破说，如若迟疑恐不能得也","签文":"天配本是凤姻缘，免把旁人说短长，急慢迟延日过日，勿使琵琶向别船。"},"官讼":{"解曰":"初平如虎凶也 但终有平静之日 若君要讼 定凶也 若和之 平安吉也","签文":"初来如虎万人惊 良善慌忙意不宁 风和浪静任施行 若得洞庭归去日"},"失物":{"解曰":"积善之家 失物有归 为恶之人失之无踪 速向东西方寻之 可见踪迹也","签文":"自从失去不知踪 问卜求神也说凶 惟有本心明德重 如今踪迹在西东"},"占病":{"解曰":"肚热畏寒 心肝烦躁不安 宜当天改愿并求佛祖保平安 可令此病得平安","签文":"心烦肚热更皮寒 咒骂冤家起事端 早向神前祈福佑 能令此病得平安"},"其他":{"灶君":"灶位虽吉 但是前面阴湿不净 宜修清净 烹煮叶吉 若在已戊方宜作过 方吉","阳基":"卜阳宅欲起造防口舌失财 勿取吉 旧宅龙运不旺 有利宜修整吉居住安","六甲":"六甲生男望夫之福 恐根基浅薄 宜移房或拜契显神明保佑平安 若生女平安","子息":"卜子息之卦 虽有得男儿 但嫌根基浅薄 比较难养 宜多行善事 存心孝义 可望子成龙也","祖山":"卜贵祖龙运不旺 嫌青龙畔背后有塞 断先古山坟傍边有阴人阻隔 又改修分金顺吉 若有利即宜修整 有做山地点宜改修","青草":"此地有结穴 但嫌有是非口舌 是因为傍边有古人相碍 至切理妥 葬之免生是非和失财也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  45,
  '罗成娶妻',
  '蟾宫折桂之兆',
  '上上之卦',
  '子鼠',
  '唐程咬金代罗成议定一门亲事，罗成不就，其未婚妻美淑且多情，因羡罗成英武，终相思而亡。程咬金愤极，蓄意惩罚罗成，骗其为娶美姿娘，实乃替娶丑史大奈。迎娶路上，史大奈暴王，罗成前期魂附丑女身复活，丰颜姣好如旧，终了旧愿，与罗成遂百年欢好。',
  '一鸟庭前立，胜如争在先;深潭垂钓饵，得鲤任君才。',
  '万物萌芽',
  '{"签号":"第四十五签","签名":"罗成娶妻","签文类型":"蟾宫折桂之兆","卦象":"上上之卦","生肖":"子鼠","签文简介":{"戏文":"唐程咬金代罗成议定一门亲事，罗成不就，其未婚妻美淑且多情，因羡罗成英武，终相思而亡。程咬金愤极，蓄意惩罚罗成，骗其为娶美姿娘，实乃替娶丑史大奈。迎娶路上，史大奈暴王，罗成前期魂附丑女身复活，丰颜姣好如旧，终了旧愿，与罗成遂百年欢好。","诗曰":"一鸟庭前立，胜如争在先;深潭垂钓饵，得鲤任君才。","内兆":"万物萌芽"},"家宅运势":{"签文":"门冷户衰百怪生，人财两散梦魂惊，如今君问平安日，庶民人口进财丁。","解曰":"人财冲冠防疾难破财是非火盗，男女不和兄弟分居宜求佛祖保平安，又嫌门字灶君分金不美，宜修改合课居住财丁昌盛。"},"岁君签":{"总诗":"风雷鼓舞播乾坤，万物萌芽尽发生，如今君问平安日，待至秋冷月又明。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基足养，但防春夏月灾难波阻，宜吓月娘化吉，交秋返运出入平安。（以诗文为准）","女":"小女根苗浅薄，惟防春夏月小疾多事，宜吓月娘化吉，交秋返运出入平安。（以诗文为准）"},{"年龄":"4-7岁","男":"小儿现年运限未遂，虽精通，但防春夏月多生波阻，水边小心，吓月娘，交秋返运平安。（以诗文为准）","女":"小女运限未美，惟防春夏月灾难水厄，逢水边小心，吓月娘化吉，交秋返运平安。（以诗文为准）"},{"年龄":"8-12岁","男":"小儿之卦时令未美，春夏月尤防小疾多事，吓月娘化吉，交秋转运平安。（以诗文为准）","女":"小女运度未佳，惟防执僻，又防小疾波阻，春夏月守旧，吓月娘化吉，交秋返运平安。（以诗文为准）"},{"年龄":"13-15岁","男":"童造时令未佳，不可执僻，春夏月皮肤小疾，守旧，吓月娘，交秋返运平安。（以诗文为准）","女":"小女时运不佳，人虽清秀，但防春夏月波阻，夜勿独行，吓月娘交秋返运平安。（以诗文为准）"},{"年龄":"16-17岁","男":"祥造运度未美，人虽聪明特达，但防二、四、六月小疾波阻，吓天地化吉，交秋返运平安。（以诗文为准）","女":"玉造时令未佳，人虽贤玉，惟防波阻，春夏月切勿独行，吓月娘，交秋返运平安。（以诗文为准）"},{"年龄":"18-29岁","男":"英造步运不佳，万物萌芽虽特达，但防春夏月小人祸非，不可迫性，交秋贵人扶助，可得财喜平安。（以诗文为准）","女":"美造现年时运不佳，虽是贤淑，但防小疾多事，春夏月守旧，夜时勿远出独行，交秋转运出入平安。（以诗文为准）"},{"年龄":"30-55岁","男":"乾造步运未美，人虽老练，但嫌迫性，春夏月防小人嫁祸，凡事从正，交秋转运有贵人扶助平安。（以诗文为准）","女":"坤造行运不美，虽助益家庭，但防暗疾口舌，凡事忍住，吓月娘，交秋平安。（以诗文为准）"},{"年龄":"56-69岁","男":"台造步运不美，虽忠诚，惟防春夏月灾难，歹人不测之祸，闲事切勿近理，交秋转运平安。（以诗文为准）","女":"坤造现年运度美中不足，虽有内助之称，但嫌操心暗疾，春夏月守旧，交秋平安。（以诗文为准）"},{"年龄":"70岁以上","男":"吉造老运不旺，但嫌人老迫性，防春夏月交脱，上落小心，守旧，交秋平安。（以诗文为准）","女":"妇造老运不旺，但防暗疾跌地之厄，守旧，喜孝堂勿近，交秋可卜大造平安。（以诗文为准）"}]},"生意":{"生意":"凡事通灵营生意，春夏似月云遮去，秋冬贵人相扶助，借力谋财好局势。","生意解曰":"按旧来经营恐吓有阻失，要创新业防初时亏本，要和人合伙移他人福，可得厚财","开铺":"卜开铺之卦得鲤鱼，看君的才能，上春恐吓有阻失，秋后有贵人扶助，能上蟾宫折桂，可得厚财利。","合伙":"卜合伙之卦叶吉如万物逢春之兆，宜同心同德协力经营，秋后可得厚财利也!","置货":"卜今年置货，上春防亏本，但要立胆智置而留之，候交秋冬月，可得财利。"},"出外":{"出外":"卜出外一事签文虽安然，但嫌心意未定，要有胆智敢往，五八月有贵人重重。"},"谋望求财":{"谋望":"本是聪明特达人，恰似明月云遮清，等闲借得东风力，吹去浮云又复明。","谋望解曰":"谋事初时时运未通，防小人阻隔，但又有贵人重重，交三，五月成就，肖牛者更妙","求财":"正财上春利薄宜立志气维持秋后转运有厚利可得，偏财要托他人之福，要忍口舌是非!"},"学艺功名":{"学艺":"卜学技艺之卦叶吉，但君须勤学苦练，定能得名师传真艺，掌握技艺本领，肖牛者学之更妙。","功名":"文武皆及第，荣宗耀祖，捐纳及营伍有纳升。"},"行舟六畜":{"行舟":"行舟顺风得利，春夏中吉，秋冬大利大吉。","六畜":"初有小阻不必疑，借得神力魔可驱。莫听旁人东西说，月圆秋交有大利。","猪羊":"卜今年猪羊初有小阻 候交秋月有大利可收宜吓神明保佑平安","草龙":"卜养划龙之卦叶吉 如万物荫芽之兆 水草调和但不可使用过度 宜吓伯公保佑 有财利","三鸟":"卜饲养三鸟之卦初有小阻无防 多用方法大胆多养 吓伯爷化吉 秋后得大利","田蚕":"田蚕顺旺 早晚冬皆吉 四季雨水顺也"},"移徙":{"移徙":"移之大吉 居住平安大吉也"},"行人":{"解曰":"音信有到 但中途走失群 候待八 九鸡鸣犬叫日即可回家","签文":"音书未许寄来频 岂料中途走失群 得到鸡鸣犬吠日 行人方许得回程"},"婚姻":{"解曰":"虽有一对好姻缘，但有小人破说，不要乱听闲言宜速定配，成之大吉","签文":"本来婚姻要团圆，无奈旁人说乱言，迟定不如早定好，管教男女共完全。"},"官讼":{"解曰":"官讼和之吉 告之失理 不要为争闲气而惹是非 若要争 祸非即生","签文":"休争闲事起官灾 灾到全无洁净回 不若和平回首去 不宜再惹又牵来"},"失物":{"解曰":"迟回也 失之有归 向南方向寻之 一定能见到踪迹 找回失物","签文":"只因有事在心中 失了为何不见踪 当去南方寻旧迹 相逢必定不虚空"},"占病":{"解曰":"男女老少染此病 皆为七情伤体 老者恐凶 少壮求太阳娘保平安","签文":"祸福无门有人来 七情内里有伤情 如今若要和平乐 积善之中也要财"},"其他":{"灶君":"灶位分金不正 灶前秽气 宜改正灶位分金 灶前清净 烹煮叶吉也","阳基":"卜阳宅吉 但嫌面前有灌水并门字分金不美 宜改水神归口居住吉 新建防口舌忍之造大吉","六甲":"卜此胎六甲 喜从天降 定生男儿 合家欢喜 祈求神明 养之平安","子息":"卜子息之卦 多花少果 宜求太阴娘娘保佑 有贵子可得 无后顾之忧也","祖山":"卜此祖山落龙结穴 但嫌分金不美 改葬之后 并填浮白虎畔相朝之后 坐向有利宜修整坟埕分金修清后财丁旺","青草":"此地高山落龙结穴 气脉足旺 占穴宜高点并填浮白虎畔相朝 安葬之后 财丁大吉也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  46,
  '刘邦斩白蛇',
  '新月朦胧之兆',
  '下下之卦',
  '亥猪',
  '汉高祖刘邦初为伍长，解民工赴造长城，误期则问斩，不意遇白蛇挡路，不得行。刘邦将之腰斩，当晚刘邦梦有老妪哭诉于前曰：“白帝之子被赤帝之子所杀。”刘邦始知自身为帝王身，遂举事反秦，计败项羽，定鼎汉室。后白蛇传转为王莽，篡乱刘氏江山，以报此仇。',
  '犬儿生两口，柳眼泪珠浮;悲叹无情绪，心酸自苦忧。',
  '恶星占身',
  '{"签号":"第四十六签","签名":"刘邦斩白蛇","签文类型":"新月朦胧之兆","卦象":"下下之卦","生肖":"亥猪","签文简介":{"戏文":"汉高祖刘邦初为伍长，解民工赴造长城，误期则问斩，不意遇白蛇挡路，不得行。刘邦将之腰斩，当晚刘邦梦有老妪哭诉于前曰：“白帝之子被赤帝之子所杀。”刘邦始知自身为帝王身，遂举事反秦，计败项羽，定鼎汉室。后白蛇传转为王莽，篡乱刘氏江山，以报此仇。","诗曰":"犬儿生两口，柳眼泪珠浮;悲叹无情绪，心酸自苦忧。","内兆":"恶星占身"},"家宅运势":{"签文":"家内作怪假疑真，无端思梦又惊人，要知因甚为多事，只为伊家少福神。","解曰":"喜气临门，但防六，九，十二月口舌祸非失财，地灵不旺，灶位不美，宜择吉日修整安灵，谢土地神向佛祖奉经保佑合家平安。"},"岁君签":{"总诗":"虫蛇入梦主忧疑，慎防家门口舌非，将来运遇方为吉，进退如今未遇时。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基未足旺，但防四、六、九月小疾波阻，六甲妇勿近抱，吓月娘化吉方保平安。","女":"小女根苗浅薄，惟防四、六、九月多生皮肤灾疾，吓月娘化吉交秋平安。"},{"年龄":"4-7岁","男":"小儿现年时令未美，但防四、六、九月小疾波阻，夜时勿外出，吓天地方保平安。","女":"小女现年运度未遂，但防波阻多事，守旧，四、六、九月夜勿远出，吓月娘化吉平安。"},{"年龄":"8-12岁","男":"小儿运限未美，惟防上春月有些小波阻，学习文化，吓天地化吉方保出入平安。","女":"小女现年时令未佳，虽旺益上人，但防四、六、九月小疾多事，吓天地化吉方保平安。"},{"年龄":"13-15岁","男":"童造时令未美，虽聪明，但嫌执僻，防四、六、九月波阻，培养入学，吓天地保平安。","女":"小女时令未佳，凡事勿执僻，防四、六、九月灾难多事，宜吓天地化吉方保平安。"},{"年龄":"16-17岁","男":"祥造时令不佳，签文新月朦胧之兆，防春夏月小疾波阻，勿执己意，吓天地化吉，交秋转运平安。","女":"玉造现年运度不佳，签文新月朦胧之兆，人虽精巧但防上春月多事小疾，吓天地交秋可卜平安。"},{"年龄":"18-29岁","男":"英造步运不美，如新月不清，虽有奇才，但防上春月小人祸非口舌，吓天地交秋转运平安。","女":"美造行运不佳，人虽贤玉，但防小疾口舌，凡事吞忍，勿迫性，上春月守旧，吓天地，交秋转运平安。"},{"年龄":"30-55岁","男":"乾造步运未美，人虽才能，但签文新月不清，惟防上春月歹人嫁祸生非，戒性，交秋转运平安。","女":"坤造行运美中不足，签文新月不清，虽有智慧，但防上春月暗疾口舌，戒性，交秋转运平安。"},{"年龄":"56-69岁","男":"台造步运未美，如新月朦胧之兆，人老性迫，凡事宽怀大量，上春月闲事勿近理，交秋转运平安。","女":"坤造行运美中不足，虽可称内助之贤，但防暗疾口舌，凡事温柔忍性，春夏月宜守旧，交秋转运平安。"},{"年龄":"70岁以上","男":"福造老运不旺，惟防灾难跌地之厄，早晚上落小心，忌入丧门，守旧，交秋平安。","女":"慈造老运不旺，虽有旺益子孙，但防暗疾风气，春夏月守旧，勿看病人，则吉。"}]},"生意":{"生意":"正二两月守旧框，四九两月小人防，三心二意财难得，偏财勿取正财攀。","生意解曰":"做事不可三心二意，宜守旧业四，九月防小人累劫，秋冬可得利，肖羊之人不可原业经营","开铺":"卜开铺之卦不美如新月不清之兆，防四，六，九月阴失，宜立财帛星君镇宅，求佛祖保平安。","合伙":"卜合伙之卦不吉有恶星占身，有小人祸害，勿合为要，若要合之恐吓惹祸非破财，后悔莫及也。","置货":"二三月宜守旧，现买现卖有小利，四、五、九月防小人劫货，余月置货可得利也。"},"出外":{"出外":"卜出外之卦恶星占异，不可往，往之有小人祸累，宜从旧业勤谨工作，可保平安!"},"谋望求财":{"谋望":"心南心北尚迟疑，成否如值未遇期，名利要求非此日，宽心宜守待明时。","谋望解曰":"肖牛之人谋之定成，余者阻挡生口舌，若肖猪犬龙之人勿谋之，原业免生祸非失财","求财":"偏财至切不可取，取之有祸非，正财宜守旧并忍口舌，勿三心二意须立智经营交六，八，十一月可得中财利!"},"学艺功名":{"学艺":"卜学技艺之卦，有恶星占身，有小人祸害，君时运未至，勿学也，宜购书自学也。","功名":"功名不中，是时时运不通，捐纳也无中纳。"},"行舟六畜":{"行舟":"行舟防风不顺，不可开行。","六畜":"猪犬牛羊不平安，若要多养难保全。吓地头爷来保佑，少养只能得平安。","猪羊":"猪羊勿养倒是消心 若要养一 二只为妙 防三 六 九月阻失 吓地头爷保平安","草龙":"卜养草龙之卦不美 为恶星占身之兆恐防三 六 九月阻隔脚疾 宜吓王爷化吉保平安","三鸟":"卜养三鸟之卦 为恶星占身之兆 防三六 九月瘟疾之厄 不可养 若要以少为佳吓伯公保平安","田蚕":"田蚕不顺 早晚不吉 四季雨水平常"},"移徙":{"移徙":"移徒不安 不可移也"},"行人":{"解曰":"行人去后无音信 是因途中有阻且有小人 求佛祖保平安 迟回也","签文":"人鬼交横事不谐 如今急急早安排 至今若要逢人面 要得银蟾照碧涯"},"婚姻":{"解曰":"婚姻不成，成之无用，非远计也，如果是失夫的可娶","签文":"婚眷无缘岂易逢，也难进退两三重，从来勉强成婚事，只恐相逢在梦中。"},"官讼":{"解曰":"告之失理 和为贵 未与讼者勿讼为宜 若要告之定受鞭苔","签文":"此卦占讼恐失宜 忍得一时之口气 和之为贵两相依 免受百日久交缠"},"失物":{"解曰":"失物难寻 若要寻之 因无凭证 恐惹官非口舌 正如新月模糊 不见回也","签文":"家中曾报有惊疑 已失要寻难得见 不觉提防被贼欺 若见官府是和非"},"占病":{"解曰":"老人防冲跳 恐凶也 求佛祖保平安 青少年有神愿 宜四方祭送 吓天地保安 请医无效事最难 除非修其功果良","签文":"病若临身不可当 欲知不入南柯梦 七情内里有伤情 如今若要和平乐"},"其他":{"灶君":"卜此灶位虽美 但嫌窗杀照面 宜将窗杀遮掩 灶前经常修理清净 叶吉也","阳基":"卜阳居欲起造防口舌失财望勿取吉 卜阳宅龙神不安 若有利宜修整过居住安","六甲":"生女有阻 求神明保平安 生男望夫之福 但根基不足 需移房或拜契神明保安","子息":"卜子息这卦 虽有得子 但有恶星占身 子息恐多灾 难养 宜精心养育 多行善事 化凶为吉也","祖山":"卜贵祖龙运不旺 葬后破失 并内有阴人作弄 切宜理妥 有利即修整龙运壮旺 清明节或多烧纸扎之类","青草":"此地龙运不旺 葬后定破 又嫌内有阴人作弄 至切理修 方可葬之 若不然葬后定要阻失"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  47,
  '许宁祖平番',
  '雨湿桃腮之兆',
  '中平之卦',
  '戌狗',
  '许宁祖父祖前为权奸所害。后许宁祖入任，奸人仍不姑息，欲斩草除根，处处设害。适番邦入犯中原，群奸乘机发难，凑请皇上下旨许宁祖率兵平番。许孤军深入被困，权奸又蓄意不发救兵。许师死战，全军俱灭。许宁祖被乱箭射杀，先锋曾虎削发为僧，沉落异邦。',
  '月边添六九，牛尾两旁开;且待浮云散，光明依旧同。',
  '密云不雨',
  '{"签号":"第四十七签","签名":"许宁祖平番","签文类型":"雨湿桃腮之兆","卦象":"中平之卦","生肖":"戌狗","签文简介":{"戏文":"许宁祖父祖前为权奸所害。后许宁祖入任，奸人仍不姑息，欲斩草除根，处处设害。适番邦入犯中原，群奸乘机发难，凑请皇上下旨许宁祖率兵平番。许孤军深入被困，权奸又蓄意不发救兵。许师死战，全军俱灭。许宁祖被乱箭射杀，先锋曾虎削发为僧，沉落异邦。","诗曰":"月边添六九，牛尾两旁开;且待浮云散，光明依旧同。","内兆":"密云不雨"},"家宅运势":{"签文":"门庭暗昧鬼邪多，人眷惊忧乍奈何，若要平安须祀祖，将身快去念弥陀。","解曰":"吉宅人口有喜，但防六，九，十二月疾难是非失财，肖牛之人生痛疾，是厝前受杀冲伤，宜安八卦抵热挡向佛祖诵经，并修祖山财丁昌盛也。"},"岁君签":{"总诗":"密云不雨天边暗，却主忧疑事可防，更慎小人来害已，门前暗昧有惊烦。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基未旺，惟防三、六、九月灾难波阻，六甲妇勿近抱，吓天地化吉方保守命绵长。","女":"小女根苗浅薄，惟防春夏月灾难多事，守旧，夜时勿抱远出，吓月娘化吉平安。"},{"年龄":"4-7岁","男":"小儿之卦运限未美，但嫌执僻，春夏月但防皮肤小疾，守旧，吓月娘化吉，交秋平安。","女":"小女现年运限未遂，但防灾难波阻，春夏月守旧，吓月娘化吉，交秋返运出入平安。"},{"年龄":"8-12岁","男":"小儿现年运度未美，虽精通，但嫌执僻，春夏月小难波阻，吓月娘化吉，交秋平安。","女":"小女运度美中不足，虽伶俐，但勿执僻，春夏月皮肤小疾，吓月娘化吉，交秋平安。"},{"年龄":"13-15岁","男":"小童运度未遂，虽聪明，惟防春夏月多事波灾，培养入学，吓月娘化吉，交秋平安。","女":"小女今年还未上运，惟防小疾多事，勿执僻，春夏月守旧，吓月娘化吉，交秋平安。"},{"年龄":"16-17岁","男":"祥造时令未美，如密云不雨，做事虽通能，防春夏月小人祸非，刻苦学习文化，吓天地化吉。","女":"玉造运度未美，但防春夏月灾难口舌，宜学艺业，吓月娘化吉，夜时东北方勿往，交秋转运出入平安。"},{"年龄":"18-29岁","男":"英造步运不佳，虽有奇才特达，但防三、六、九月不测之祸，宜安分守己，不可冲动，吓天地保平安。","女":"美造行运不佳，如密云不雨，但防春夏月小疾口舌，凡事吞忍，吓月娘化吉，交秋转运出入平安。"},{"年龄":"30-55岁","男":"乾造步运未美，防三、六、九月灾难，小人平底风波，交人不可多情，方免遭小人牵连，吓天地平安。","女":"坤造行运不佳，似密云不雨，心内操迫，防暗疾口舌，春夏月守旧，吓月娘化吉，交秋平安。"},{"年龄":"56-69岁","男":"台造步运不美，签文而论虽老练，但防三、六、九月灾难小人嫁祸，凡闲事切勿近理，底子平安。","女":"坤造行运美中不足，虽旺益家庭，但嫌操心暗疾，凡事吞忍，春夏月守旧，吓月娘交秋平安。"},{"年龄":"70岁以上","男":"台造老运不旺，虽忠诚，但嫌性直心迫，三、六、九月灾难交脱，早晚上落小心，守旧则大造平安。","女":"慈造老运不旺，虽有旺益子孙，但防暗疾风气，三、六、九月守旧，忌看病人，幸孝勿近，大造平安。"}]},"生意":{"生意":"夜间怪梦惊心头，劫财抢物乱一遭，春夏两季宜守旧，秋冬两季财利高。","生意解曰":"生意防小人耗劫，春夏月勿贪心，秋冬月有小阻，但有厚利得，宜吓天地化吉","开铺":"卜开铺之卦如密云不雨之兆，交易数目宜谨慎，防歹人劫财，秋冬月有财利，肖牛者定失也。","合伙":"卜合伙之卦为密云不雨之兆，又有牛尾两旁开之句失字当头，有恐有歹人盗劫，勿合为要!","置货":"购置货物肖牛之人定失财，只有肖龙虎之人能得利，其余之人定勿贪取之。"},"出外":{"出外":"卜出外一事上春时令未同，恐有小人阻失，交秋冬月可前往，有贵人扶助。"},"谋望求财":{"谋望":"否极泰来理自然，莫交运用灾牵连，时有借得东风力，吹去浮云见碧天。","谋望解曰":"谋事肖牛之人有阻失，切勿谋之，余者候交秋冬月有贵人扶助，定可成功","求财":"上春正财不利八月得利，肖牛者无利也，偏财勿取，取定失，肖龙虎之人忍口舌取之得利!"},"学艺功名":{"学艺":"卜学技艺之卦，似密云不雨之兆，君时运未到，学之不成，若肖龙者时令合局，可以学习也。","功名":"功名春致不中，秋考中也。"},"行舟六畜":{"行舟":"行舟上春不顺应守旧，下春得利。","六畜":"春夏有阻秋冬安，贪心多养难保全。求吓神明力保佑，少养勤管可平安。","猪羊":"猪羊上春阻难 下春可得利但不宜贪心多养 宜吓伯公保佑平安","草龙":"卜养划龙之卦不美 未养者勿养为宜 防阻失也若已养了 切勿贪使用 注意管理 吓伯公化吉","三鸟":"卜养三鸟之卦 上春勿养为宜 防失也 下春月可养 但也不宜多养 精心管理 有利也","田蚕":"田蚕不遂 四季雨水无利"},"移徙":{"移徙":"秽徒不吉不利 勿移为要"},"行人":{"解曰":"行人去后无音信 是因为前途有阻 吓佛祖保佑 已午未月 有音信也","签文":"远望程途音信稀 不知凶吉是孤疑 如今若问真消息 蛇马及羊是到期"},"婚姻":{"解曰":"此婚姻不成，若成之有官非口舌，不要枉费心机君非孤寡辈无须忧疑","签文":"前缘已定枉心亏，从然求得有官非，此处无缘难着聘，何劳注意痴心为。"},"官讼":{"解曰":"和之大吉 若告定失 肖牛之人更为不妙 望勿强为 否则身败名裂","签文":"官事悠悠不肯休 嘱咐叮咛不须忧 若然龙虎相逢日 不用干戈也解愁"},"失物":{"解曰":"失的为浮财也 失后不要过恋之 就是寻之也是无影无踪 以后谨慎也","签文":"此去浮生空自忙 不知天纲暗中张 荣华得失皆前定 自古浮财不久长"},"占病":{"解曰":"阴邪染身 求太阳公保佑 应修善积德诵经保平安要修风水 肖牛老人恐危","签文":"偶然身勿遭魔 不自支持可如何 要好平安须祀祖 轻身急去念弥陀"},"其他":{"灶君":"灶位虽美 但灶前秽气 受门窗冲照 宜遮掩常时修清净 烹煮叶吉也","阳基":"卜阳居若丑未分金恐生白蚁是青龙圈受杀立白雄鸡祭之 居住则吉也","六甲":"六甲生女平安 若生男儿 要移房 要望丈夫之福也","子息":"卜子息之卦 似密云不雨之兆 先花后果 得恐难养 宜多做善事 向佛祖诵经保平安","祖山":"卜赞祖地不吉 嫌葬后財丁小安 是穴宽调打天空不过 只可安骨而已 若欲兴降 宜填青龙畔朔护 财丁两旺也","青草":"此地龙脉真气 局口文雅 但嫌青龙畔空旷露野受杀冲伤 来水割身 墓穴不可宽阳 宜占小 葬之财丁昌也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  48,
  '黄野仁遇仙',
  '九转丹成之兆',
  '大吉之卦',
  '酉鸡',
  '黄野仁者，山野之骄子也。日受大自然之引诱，出世之心生而日炽。乃刻意求仙，苦未得。日倦睡，魂游而不意遇仙。仙带回洞中炼丹。经日，九转丹成。黄野仁用之，率未成仙，仙使回家。至家，乡里中人均不相识，问及故人，连老者也不知之。黄野仁始知洞中方一日，世上已千年矣。',
  '五色祥云升，霞光满室明;蛟龙奋疾起，倾刻九里程。',
  '金蝉脱壳',
  '{"签号":"第四十八签","签名":"黄野仁遇仙","签文类型":"九转丹成之兆","卦象":"大吉之卦","生肖":"酉鸡","签文简介":{"戏文":"黄野仁者，山野之骄子也。日受大自然之引诱，出世之心生而日炽。乃刻意求仙，苦未得。日倦睡，魂游而不意遇仙。仙带回洞中炼丹。经日，九转丹成。黄野仁用之，率未成仙，仙使回家。至家，乡里中人均不相识，问及故人，连老者也不知之。黄野仁始知洞中方一日，世上已千年矣。","诗曰":"五色祥云升，霞光满室明;蛟龙奋疾起，倾刻九里程。","内兆":"金蝉脱壳"},"家宅运势":{"签文":"凶杀已去福神来，忽汝家中大发财，此际管教人物旺，秋冬百事真和谐。","解曰":"凶灾当头春夏人口奔波，疾难是非多，失财是厝前受杀冲伤，宜求佛祖令旗安门上祭化保平安，若有喜凶灾可消除。"},"岁君签":{"总诗":"宝镜新磨复见光，四方照耀任行藏，成名久有根基在，润色增光声播扬。","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，八字成格，旺益上人并茂，春夏月虽有小疾无妨，出入平安。","女":"小女根基稳固，有旺益上人并茂，春夏月虽有小疾无妨，吉星守命出入平安。"},{"年龄":"4-7岁","男":"小儿之卦时令亨通，旺益上人，但夏月汤火小心，虽有小疾无妨，吉星守命平安。","女":"小女运限顺遂，旺益上人，但防三、五月小疾水厄，逢水边小心，幸吉星守命出入平安。"},{"年龄":"8-12岁","男":"小童现年上运，各事伶俐，宜入学校读书，定卜进步，虽有小疾无妨，出入平安。","女":"小女交上美运，各事活泼，可培养温习文化，三、五月虽有小疾无妨平安。"},{"年龄":"13-15岁","男":"童造之卦运度亨通，聪明开窍，宜入学校读书，定卜进步，高迁之贺出入平安。","女":"玉造现年运度甚佳，伶俐活泼，三、五月小疾无妨，但水边小心，幸吉星守命平安。"},{"年龄":"16-17岁","男":"祥造现年运度亨通，如龙得雨，凡事通能特达，学习手艺，夏月虽有小疾无妨，贵人扶助平安。","女":"玉造行运交泰，如龙得雨，各事贤玉，八字清秀，宜学习文化，夏月虽有小疾无妨，吉星守命平安。"},{"年龄":"18-29岁","男":"英造步运亨通，如龙得雨，做事智慧特达，宜向前争取，有贵人扶助，可得财喜平安。","女":"美造行运佳美，如龙得雨，时令交泰，做事智慧，但勿操迫，夏月虽有小疾无妨平安。"},{"年龄":"30-55岁","男":"乾造步运亨通，如龙得雨，做事才能机智，但勿迫性，有贵人扶助，向外发展，可得财喜平安。","女":"坤造行运交佳，如龙得雨，有内助之贤，但勿操迫，夏月虽有小疾无妨，吉星守度出入平安。"},{"年龄":"56-69岁","男":"台造步运上吉，得此卦如龙得雨，为人心直忠诚，夏月虽有小疾无妨，贵人扶助出入平安。","女":"坤造行运甚美，如龙得雨，贤淑智慧，可称内助，但勿操心迫杂，夏月虽有小疾无妨，玉体安康。"},{"年龄":"70岁以上","男":"福造老运得此卦太旺，但防春夏月灾难交脱，守旧，忌入丧门，底子平安。","女":"慈造老运老当益壮，但防暗疾跌地之厄，上落小心，幸吉星守度晚景胜前。"}]},"生意":{"生意":"此卦求问生意经，历时凶险已消清，如今借得东风力，生意兴隆财利升。","生意解曰":"数年苦力财利难得，现岁凶险消除无阻，立冬后有厚利，肖龙之人更有财利","开铺":"卜开铺之卦为九转丹成之兆，老铺数年来波阻已过，今年可得厚财利，新开铺宜用苦力经营，冬月有厚利。","合伙":"卜合伙之卦叶吉为金蝉脱壳之兆，除有波阻，伙计宜同心同德协力经营，秋后有大财利伙计有肖龙者更妙。","置货":"置货初时宜现买现卖，且劳力费神，到底涨价，可得厚财利也。"},"出外":{"出外":"卜出外一事有贵人重重在三，五月出外，但平安而且东成西就，有厚财利可得!"},"谋望求财":{"谋望":"百炼千磨方得醇，几年静坐做闲人，如今借得良工力，富贵相逢白色新。","谋望解曰":"谋事防春月有阻，交秋冬月宜用苦力，自有贵人扶助，凡事定能遂心","求财":"正库取财初时利薄宜加苦力维持于五，九，十一月交运可得利，偏财肖龙之人得之，宜忍口舌!"},"学艺功名":{"学艺":"卜学技艺之卦，为九转丹成之兆，时令合局，但君宜下定决心，勤学苦练，定能学得技艺随身。","功名":"功名不中，是时运不通，捐纳也无中纳。"},"行舟六畜":{"行舟":"行舟先难后易，行之大吉。","六畜":"六畜兴旺人今年，大养鸡犬猪牛羊。灾消福来财喜至，鸡肥猪胖牛马壮。","猪羊":"猪羊养之顺利 饲料调和 可以大养多养 宜吓神明平安 且可得厚利也","草龙":"卜养牛这卦 初时有点小阻无防 宜用心管理 家中若有喜 饲养可顺遂 井能旺益家道也","三鸟":"卜养三鸟之卦家中若有喜 则可大投资金多养秋冬月可得大财利 若无喜 宜精心饲养 也可得也","田蚕":"田蚕先苦后甜 早晚要苦下工 后大吉"},"移徙":{"移徙":"移徒初有惊阻 整修后居之平安"},"行人":{"解曰":"行人去后本有音信寄回 皆因书信被人沉没 今需查问追源可有音信 宜吓佛祖保平安","签文":"日遇音节未得真 空劳心意靠天神 要知客处平安日 直待龙蛇到日辰"},"婚姻":{"解曰":"重夫娶之大吉，正配难成，一方有恋一方无心，正如流水无情恋落花","签文":"重整衣裳衣色新，相思比做自家人，从来只说人才好，低恐人心又染身。"},"官讼":{"解曰":"官讼必胜 公堂自有明断 但和之也不呆 息事宁人 无祸人","签文":"自古饶人不是痴 况无鬼藏加须疑 公庭自有明如镜 曲直分明无私偏"},"失物":{"解曰":"此为飞祸 切切速寻 失物回也不全 虽有些小损失 勿愁哀也","签文":"此祸飞来欲破财 如今休把家人猜 跟寻终是难全得 损失些几也勿哀"},"占病":{"解曰":"老人是风火咳 身寒肚热 求佛祖药可愉 中小男妇是败涉 经水不调 宜求神送向佛祖诵经","签文":"大祸欺人怎得知 遭遇招彰反失珠 如今及早求神佑 笑待有日病脱离"},"其他":{"灶君":"灶位地格清净 但灶前迫塞 要常修理 若有门窗杀冲 宜安八卦抵祭则吉","阳基":"卜此阳宅吉 起造平安 但嫌面前有曜水不顺 宜掩祭居住","六甲":"六甲生男 小心也 有大贵人喜也","子息":"卜子息之卦 为九转丹成之兆 先难后易 夫妇宜行善积德 定有男儿可得 而且近贵 寿命绵长","祖山":"卜贵祖龙运足旺 但嫌葬后财丁不旺由是面前有曜水朝见 有利宜掩祭之后房房皆吉 财丁兴旺","青草":"此地横龙坠气结穴 龙脉足旺 但嫌面前有曜水朝见 论分金即掩祭之后 葬之财丁昌盛也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  49,
  '孟姜女哭倒长城',
  '柳絮遭风',
  '下下之卦',
  '申猴',
  '秦始皇焚书坑儒，书生万喜良出外避难，路遇孟姜女，两人同病相怜，遂结为夫妇。花烛之夜，万喜良被秦兵强拉为役，解赴建造长城。良不堪于饥寒奇苦而殁。孟姜女送寒衣，千里寻夫，历尽艰辛欺侮，却知夫已殁，遂苦祭于长城之下，以其声其事过哀，长城乃为之腐倒。',
  '此去以先知，天高谁敢欺;乾坤高且厚，造化不自疑。',
  '风扫落叶',
  '{"签号":"第四十九签","签名":"孟姜女哭倒长城","签文类型":"柳絮遭风","卦象":"下下之卦","生肖":"申猴","签文简介":{"戏文":"秦始皇焚书坑儒，书生万喜良出外避难，路遇孟姜女，两人同病相怜，遂结为夫妇。花烛之夜，万喜良被秦兵强拉为役，解赴建造长城。良不堪于饥寒奇苦而殁。孟姜女送寒衣，千里寻夫，历尽艰辛欺侮，却知夫已殁，遂苦祭于长城之下，以其声其事过哀，长城乃为之腐倒。","诗曰":"此去以先知，天高谁敢欺;乾坤高且厚，造化不自疑。","内兆":"风扫落叶"},"家宅运势":{"签文":"口舌无端从地来，只因家中有悲哀，归来及早求神佑，合宅如今不受灾。","解曰":"吉宅人口各宜忍口舌，防是非破失，小孩子夜闹，有喜可改化，宜吓福德老爷保平安，门字灶君不旺有利宜修整。"},"岁君签":{"总诗":"群鸦集噪不为奇，慎防家门口舌欺，退步之时方见吉，若然进步主忧疑。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基浅薄，惟防春夏月灾难波阻，六甲妇勿近抱，吓天地化吉方保平安。","女":"小女根苗未足养，但防春夏月小疾波阻，守旧，勿远出，吓天地化吉方保平安。"},{"年龄":"4-7岁","男":"小儿现年运限未美，惟防春夏月多生皮肤小疾，守旧，吓天地化吉，交秋返运平安。","女":"小女运度未美，但嫌执僻，春夏月小难波阻，守旧，吓天地化吉，交秋返运平安。"},{"年龄":"8-12岁","男":"小女现年时令未美，但防春夏月小疾，不可登高，吓天地化吉，交秋返运平安。","女":"小女之卦未美，但勿执僻，又防多生皮疾，守旧，吓天地化吉，交秋返运平安。"},{"年龄":"13-15岁","男":"小童运度未美，虽聪明，但嫌好胜，春夏月守旧，吓月娘交秋返运出入平安。","女":"小女运度未遂，虽旺益上人，但防小难多疾，春夏月守旧，吓月娘交秋平安。"},{"年龄":"16-17岁","男":"祥造步运未美，似花木遭风，但防春夏月小疾多事，学习文化，守旧，交秋转运贵人扶助平安。","女":"玉造今年运度未遂，人虽贤玉清秀，但防春夏月小人口舌，夜时切勿独行，吓月娘交秋平安。"},{"年龄":"18-29岁","男":"英造步运不佳，花木遭风，防春夏月小人口舌祸非，凡事不可冲动，吓天地交秋平安。","女":"美造行运不佳，如花木遭风，人虽贤玉但防春夏月小疾平地风波，凡事吞忍，吓月娘交秋平安。"},{"年龄":"30-55岁","男":"乾造步运未美，如风扫落叶，防春夏月灾难小人嫁祸，凡事安分守己，吓天地交秋平安。","女":"坤造行运不美，如风扫落叶，防春夏月暗疾口舌，凡事吞忍，吓天地化吉，交秋转运平安。"},{"年龄":"56-69岁","男":"台造步运不美，如花木遭风，防春夏月歹人不测风波，凡闲事切勿近理，宜守本份交秋平安。","女":"坤造行运未美，虽可称内助，但嫌操心迫杂，春夏月暗疾口舌，宜吞忍，吓天地化吉，交秋平安。"},{"年龄":"70岁以上","男":"福造老运不旺，但防交脱，早晚上落小心，忌看病人，宜守旧，交秋大造平安。","女":"慈造老运不旺，惟防暗疾上身，步履小心，春夏月忌入丧门，守旧，交秋平安。"}]},"生意":{"生意":"货物购售须认真，要防小人劫财金，生意经营宜守旧，数目还防人不仁。","生意解曰":"恐防亏本和小人耗劫财帛，交易莫信忠直，防人不仁，出入货物要谨慎，钱财勿寄人","开铺":"卜开铺之卦似风扫落叶之兆，未开者勿开为妙，已开之铺恐吓防风火厄，小人劫财求佛祖化吉平安。","合伙":"卜合伙之卦似花木遭风之兆，勿合为佳，若合之恐伙计不同心，小人劫财亏本失利也。","置货":"置货不妙，恐防小人盗劫之，勿贪心依旧业经营，宜从正道，则财可得。"},"出外":{"出外":"卜出外一事身体可平安，恐防小人波阻寄祸，凡事宜守旧经营则免生愁。"},"谋望求财":{"谋望":"百炼千磨不得齐，心猿意马走东西，鹊巢作成乌鸦占，只为君家命运低。","谋望解曰":"业务虽精通但性急迫，做事不成防歹人累恐失也，宜守忍","求财":"正财库取利虽有得但防小人盗窃，恐失之，不可贪心妄想宜从正道则得这可安，偏财切不可取!"},"学艺功名":{"学艺":"卜学技艺之卦不吉，似花木遭风之兆，君恐心猿意马，三心二意，学之不成，半途而废也。","功名":"功名难中，运未通，才学虽高，但不显达。"},"行舟六畜":{"行舟":"行舟不顺不吉。","六畜":"春夏有阻猪牛羊，切切不可贪多养。求吓神明力保佑，秋后也能保安详。","猪羊":"今年猪羊定有阻失 至切不可贪多养 宜吓伯多保佑中大只及时卖 秋后平安","草龙":"卜养草龙之卦 如风扫落叶之兆 春夏月恐防阻失脚疾之厄 勿贪使用 吓伯爷保平安","三鸟":"卜养三鸟之卦 如花遭风之兆 初定有阻失 不可贪多养 宜吓伯爷保佑 秋后平安","田蚕":"田蚕不旺 两冬具有阻 四季雨水不顺"},"移徙":{"移徙":"移徒不顺 未移先被人占之"},"行人":{"解曰":"行人无音信是身体有阻难 求天地保佑平安 后定有归 如无妻室不愿归也","签文":"如今不利出行人 客路忙忙未转身 阻滞所因招疾厄 早求神力免艰辛"},"婚姻":{"解曰":"君命非孤此时非缘，等待时运，自有良缘婚姻，渐不成是野花看错","签文":"本听旁人说事狂，野花那似菊花香，自有良缘来配合，莫认乌鸦做凤凰。"},"官讼":{"解曰":"卜此讼不可告 若告定凶 和之为吉 是非自息","签文":"未到公庭分曲直 已招惊恐在心中 喧哗闹事纷纷兢 必主忧疑事立凶"},"失物":{"解曰":"只因不慎托人 今已被人遗失 勿怨别人 免惹是非","签文":"托人原因不小心 如今失去更难寻 无端惹得傍人怪 受人唇舌也难禁"},"占病":{"解曰":"病者在床乱言 少安老危 当天改愿 请神明祭之寻 良医服药治疗","签文":"灾害连身未得痊 敬神修身答苍天 操心未许除灾障 若要身安须损钱"},"其他":{"灶君":"灶位宅虽美 但嫌面前迫塞 受门窗冲杀 宜遮掩 灶前时常修清净 则吉也","阳基":"卜阳宅欲起造防口舌失财勿取吉 旧阳宅门字不美 若有利宜修整 居住则安之","六甲":"卜此胎六甲生男 但嫌根基不足 宜移或拜契显吓神明保佑平安大吉","子息":"卜子息之卦 似花木遭风之兆 虽有结果 但恐防初有阻隔 宜多做善事 求佛祖保佑","祖山":"卜贵祖地吉 但嫌青龙后背塞 若有利即修整 然后财丁可昌也","青草":"此地有结穴 但非君之福 是因为旁边有相碍 被碍者不同意你所为 望勿强行办事 以免生是非失财也"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  50,
  '唐僧取经',
  '禅门出法之兆',
  '中平之卦',
  '未羊',
  '唐高僧玄奘俗姓陈，以父遭害，母受辱，问世即被放生江上，为金山寺高僧所收养。及长，又以道行高，六根清净得观音大士点化，矢志西天取经，以救罪世。又得唐太宗资助，高徒孙悟空等帮护，历九九八十一劫数，终于到达西天，取回如来真经，并成其正果。',
  '蓬莱三岛客，万里走江山;秋风秋月起，移岭过前江。',
  '乌云盖月',
  '{"签号":"第五十签","签名":"唐僧取经","签文类型":"禅门出法之兆","卦象":"中平之卦","生肖":"未羊","签文简介":{"戏文":"唐高僧玄奘俗姓陈，以父遭害，母受辱，问世即被放生江上，为金山寺高僧所收养。及长，又以道行高，六根清净得观音大士点化，矢志西天取经，以救罪世。又得唐太宗资助，高徒孙悟空等帮护，历九九八十一劫数，终于到达西天，取回如来真经，并成其正果。","诗曰":"蓬莱三岛客，万里走江山;秋风秋月起，移岭过前江。","内兆":"乌云盖月"},"家宅运势":{"签文":"人口平安赖佛恩，四处生涯任意勤，年来春夏经营好，勿贪歧路起猜心。","解曰":"吉宅人口虽有喜气可得，但防口舌是非，男女不和，生意可为但不可贪，作物昌盛，埕口水道秽气，要时常修通，请上帝灵符贴保居住平安。"},"岁君签":{"总诗":"行藏水陆有虚疑，可虑忧疑不可欺，今定所谋前等事，劝君他去莫迟疑。","年龄运势":[{"年龄":"1-3岁","男":"小孩根基虽足养，但防三、六、七月灾难小疾，守旧吓月娘化吉，交秋返运平安。","女":"小女根苗浅薄，惟防三、六、七月皮肤小疾，宜守旧，吓月娘化吉，交秋返运出入平安。"},{"年龄":"4-7岁","男":"小儿之卦时令未美，但防三、六、七月小疾水厄，逢水边小心，吓月娘化吉，交秋返运平安。","女":"小女现年运度未美，但防多生灾难，水边池井边小心，吓月娘化吉，交秋返运平安。"},{"年龄":"8-12岁","男":"小童现年运度未遂，虽伶俐，但防三、六、七月多事，水边小心，吓月娘化吉，交秋平安。","女":"小女运限未遂，惟防灾难，逢水边小心勿近，宜吓月娘化吉，交秋返运平安。"},{"年龄":"13-15岁","男":"小童时令未美，虽活泼，但嫌执僻，三、六、七月小疾水厄，吓月娘化吉交秋平安。","女":"小女现年运限未佳，惟防皮肤小疾，水边小心，三、六、七月守旧，吓月娘交秋平安。"},{"年龄":"16-17岁","男":"祥造现年运度未美，签文禅门出法，但防三、六、七月小疾多事，学习文化，吓天地交秋转运平安。","女":"玉造行运，人虽贤玉，但嫌美中不足，防三、六、七月小疾波阻，夜时勿独行，吓月娘交秋转入佳景。"},{"年龄":"18-29岁","男":"英造时令未至，签文禅门出法，虽有奇才，但防三、六、七月小人口舌祸非，吓天地交秋可得财喜。","女":"美造今年运度未佳，春夏月诚恐有小人平地风波，凡事温柔忍性，宜吓天地化吉，交秋转运平安。"},{"年龄":"30-55岁","男":"乾造步运未美，签文禅门出法，防三、六、七月歹人祸非口舌，凡事戒性，吓天地化吉交秋可得财喜。","女":"坤造行运美中不足，虽贤淑，但嫌操心迫杂，三、六、七月防暗疾口舌，凡事吞忍，吓天地化吉交秋平安。"},{"年龄":"56-69岁","男":"台造步运不佳，签文禅门出法，虽老练，但防三、六、七月小人不测之祸，戒忍性情，交秋转运平安。","女":"坤造行运时令未美，虽有助益家庭，但防暗疾口舌，凡事温柔忍性，三、六、七月守旧，交秋平安。"},{"年龄":"70岁以上","男":"福造老运不旺，人老心迫，凡事宽宏大量，三、六、七月守旧，忌入丧门，交秋可卜福体安康。","女":"慈造老运虽绵长，但防暗疾上身，三、六、七月守旧，忌看病人，底子有旺益子孙，交秋平安。"}]},"生意":{"生意":"春夏阻失莫贪营，偏财莫取正财宁，待秋冬到可得利，正直守分财利兴。","生意解曰":"时运不通春夏月防歹人害劫之，习卖宜正直守分，交秋冬月便可得利","开铺":"卜开铺之卦似乌云盖月之兆，上春阻失恐防小人劫财，交秋月明，努力经营可是财利。","合伙":"卜合伙之卦似乌云盖月，伙计三人四心各有私偏，勿合为妙若合之恐亏本破财!","置货":"置货不宜贪心，且防小人盗劫，勿过信他人，货放自己家，秋后可得利。"},"出外":{"出外":"卜出外一事上春未得运，恐吓防阻失小人累害，宜守旧候交秋后往之平安!"},"谋望求财":{"谋望":"几年学道讨前程，岂料中途恐虚惊，千万鬼怪俱降伏，秋风清处月光明。","谋望解曰":"谋事可成但初时防歹人阻隔，宜用小利帮助有吉星拱照定可成事","求财":"正财上春利薄又防阻隔涉财，凡事宜用心窍守旧经营交秋月逐渐可得财利，偏财勿取，取定失之。"},"学艺功名":{"学艺":"卜学技艺之卦，春夏时运未到，学之不成，秋交月明时令合局，应勤学苦练，从师学之可成也。","功名":"功名不得运限未通，身防小人祸害。"},"行舟六畜":{"行舟":"行舟初时防风，秋后出行大吉昌。","六畜":"饲养六畜不顺情，任汝求神无减轻。不信请看大风至，鸡犬无端作怪声。","猪羊":"猪羊之卦不顺 恐防阻隔切勿贪养 中大只及时出卖 吓伯爷保平安","草龙":"卜养草龙之卦不美恐防三 六 七月阻疾 不可使用过度 宜精心眼养 求伯公保平安","三鸟":"卜养三鸟之卦不美 恐防三六 七月阻失 不可贪多养 大只及时出卖 吓伯公保平安","田蚕":"田蚕早晚冬皆不吉 防盗失 雨水平常"},"移徙":{"移徙":"移徒不吉 危邦不入 乱邦不居"},"行人":{"解曰":"行人有想归家 但为了财利 淹留客途 上春有小人阻隔 交七 八月有财信回家","签文":"行人久望隔阳关 万里程途在远处 任定佳期任往还 见利求财去未还"},"婚姻":{"解曰":"婚姻宜急速说合下聘则可成功，若迟延不成是小人乱言也","签文":"婚姻急速可为期，赖慢依然有所疑，只是小人言不定，说合成来乍许辞。"},"官讼":{"解曰":"官讼告之失理 宜和解也 斩不能与人较量 君宜立志图强 候机而为之","签文":"劝君学取鸿鹄志 奋力飞升红日边 要结官讼钱也用 牢笼巧鸟被相缠"},"失物":{"解曰":"财物已失 无踪无迹 难寻也 若问根苗 候交秋冬月时 可得知也","签文":"财宝失去影无踪 不去跟寻不见形 若问根苗何日出 秋冬方报在途中"},"占病":{"解曰":"有阴邪交缠 惊梦忧体 精神错乱 敬神谢天地祭送 请医治之 少安老失","签文":"枕席之间梦寐颠 狂言乱语鬼神前 虽然目下多灾病 有日精神守格坚"},"其他":{"灶君":"卜此灶位叶吉 但嫌灶前秽气 宜常时修洗清洁 烹煮兴隆 旺益财丁","阳基":"卜此阳居欲起造防口舌阻隔 心地立中正能化吉 若有私心妄为 定有口舌并失财","六甲":"六甲生女各事平安 若生男宜拜契显赫神明或和尚 保根基足旺 养育平安","子息":"卜子息之卦 恐多花少果 若得男儿宜移房拜契 求佛祖保佑 寿命绵长 而且富贵也","祖山":"卜贵祖横龙结穴 但嫌葬后财丁破失 因穴位未真 又面前受煞 有利宜修整过而后财丁复旺也","青草":"卜此地龙运气脉足旺 但嫌面前水神不美 白虎畔有杀冲伤 葬时宜理妥水神消掩峰杀 点穴宜沉墓 理妥口舌吉"}}'
);

INSERT OR REPLACE INTO lingqian (qian_num, qian_name, qian_type, gua_xiang, sheng_xiao, xi_wen, shi_yue, nei_zhao, full_json) VALUES (
  51,
  '全福签',
  '逢凶化吉之兆',
  '',
  '午马',
  '编后碣石玄武山寺明朝古戏台旧时自农历三月十二日起即开棚演戏，碣石卫中士农工商争捐戏金，故日夜连演，数月不辍。所演多三国演义故事，为连续提纲戏，间或串演正杂剧。而各地礼佛求签者也多为戏迷，故详签者投其所好，详签时兴之所至，每就其含义想通者将之互为串讲入解，如此反复再三，竟至约定俗成，此即签解中戏文之来历也。',
  '求签未诚心，罚油二三斤;送奉敬佛祖，消灾福来临。',
  '不成转喜',
  '{"签号":"第五十一签","签名":"全福签","签文类型":"逢凶化吉之兆","卦象":"","生肖":"午马","签文简介":{"戏文":"编后碣石玄武山寺明朝古戏台旧时自农历三月十二日起即开棚演戏，碣石卫中士农工商争捐戏金，故日夜连演，数月不辍。所演多三国演义故事，为连续提纲戏，间或串演正杂剧。而各地礼佛求签者也多为戏迷，故详签者投其所好，详签时兴之所至，每就其含义想通者将之互为串讲入解，如此反复再三，竟至约定俗成，此即签解中戏文之来历也。","诗曰":"求签未诚心，罚油二三斤;送奉敬佛祖，消灾福来临。","内兆":"不成转喜"},"家宅运势":{"签文":"卜吉宅人口求佛祖不诚心，阳宅龙运不旺，灶前污秽，浴盆冲犯帝君恐防九月十月有灾难破失，常时灶前宜清净，上诸圣神容宜重壮光彩，常时诚心待圣宜向佛祖送经奉油，可消改水厄，福即来临财丁兴旺。","解曰":""},"岁君签":{"总诗":"","年龄运势":[{"年龄":"1-3岁","男":"小孩根苗足养，有旺益上人并茂，虽有小疾无妨，吉星守命平安。","女":"小女根基足养夏月虽有小疾无妨，吉得守度，旺益上人平安。"},{"年龄":"4-7岁","男":"小儿之卦时令叶吉，旺益上人有些小疾无妨，向佛祖添油化吉平安。","女":"小女运限顺遂，有旺益上人，虽有些小疾无妨，向佛祖添油化吉平安。"},{"年龄":"8-12岁","男":"小儿今年运度虽美，但防有些小疾，向佛祖添油化吉，寿命绵长。","女":"小女运度顺遂，但勿执僻，虽有小疾无妨，吉星守度出入平安。"},{"年龄":"13-15岁","男":"小童今年上运，聪明开窍，培养入学，但向佛祖添油，底子平安。","女":"小女运度顺吉，虽有小疾无妨，旺益上人，吓妈祖化吉平安。"},{"年龄":"16-17岁","男":"祥造步运亨通，春夏月虽有小皮疾无妨，向佛祖添油化吉平安。","女":"玉造运度甚佳，性格柔和，小皮疾无妨，吉星守度底子平安。"},{"年龄":"18-29岁","男":"英造步运亨通，奇才特达，但勿迫性，虽有小疾口舌无妨，可得财喜，但向佛祖添油平安。","女":"玉造行运交泰，各事贤玉，虽有小皮疾无妨，吓佛祖化吉，底子吉星守命出入平安。"},{"年龄":"30-55岁","男":"乾造步运得此卦，人虽老练，但凡事戒性，不可冲动，勿惹是非，向佛祖添油，底子平安。","女":"坤造行运，人虽贤淑，助益家庭，但勿操迫，有些小皮疾无妨，吉星守度，底子平安。"},{"年龄":"56-69岁","男":"台造步运亨通，为人老练忠诚，但宜宽怀大量，忌看病人，幸贵人扶助平安。","女":"坤造行运交泰，可称内助之德，但勿操心迫杂，有些暗疾无妨，吉星守命平安。"},{"年龄":"70岁以上","男":"福造老运得此卦，虽有灾难无妨，但忌入丧门，守旧则大造安康，晚景胜前。","女":"慈造老运，虽有旺益子孙，但防有暗疾风气，守旧勿看病人，底子平安。"}]},"生意":{"生意":"卜现年生意恐防君办事烦劳操心，恐吓防歹人累害寄祸，交易谨慎，切勿贪心，宜守旧业刻苦经营维持，向佛祖奉经添油保生意兴隆，可得大财利。","生意解曰":"","开铺":"卜开铺之卦恐吓防初时小人无端生祸劫财，宜守旧经营向佛祖添油奉经，消灾改厄有财利。","合伙":"卜合伙之卦初时恐有隔，伙计宜同心同德合力经营，向佛祖送经奉油，可得财利!","置货":""},"出外":{"出外":"卜出外之事恐吓尔不全心以待，心坚者宜向佛祖奉经添油，以全心愿，但肖猪狗之人切勿想成，非非此念必绝。余人可往有利。"},"谋望求财":{"谋望":"卜谋事之卦初有有小人之阻，并防劫财祸非，宜忍口舌向佛祖诵经添油，有贵人扶助，时运显达可成功!","谋望解曰":"","求财":"正财春夏有阻失磨力勿贪偏财勿取，吓佛祖奉经添油二月小利!"},"学艺功名":{"学艺":"卜学技艺之卦，初恐有阻隔，宜向佛祖送经奉油，刻苦学习，可学得技艺，肖猪犬者学之不成。","功名":"卜现科文武功名定能得中，逢年现岁会合，若戌亥科定能高中受职，但肖戌亥之命者，切切不可进场，定生祸非失财捐纳营伍皆成，向佛祖送经奉油。"},"行舟六畜":{"行舟":"卜行船出海取利事，宜向佛祖送经添油也，此签惟肖猪狗之人宜小心，三、六、九月出海必慎重，尽可能勿出海。","猪羊":"卜今年猪羊之卦 初时恐有阻隔不顺 不可多养宜刻苦精心饲喂 向佛祖送经奉油 吓大伯爷化吉保佑猪羊平安兴旺 秋后便可得财利","草龙":"卜养草龙之卦 春夏恐防阻失 病疾之厄 宜向佛祖送经奉油 吓大伯爷化吉","三鸟":"卜养三鸟之卦 春夏恐有阻失宜向佛祖送经添油定能连凶化吉 可得财利","行船":"行舟出海利，宜向佛祖送经添油也；此签惟肖猪狗之人宜小心，三、六月出海必慎重，尽可能勿出海。"},"移徙":{"移徙":"移徒移，老居平安，初一、十五添油并向佛祖奉经，居住财丁旺；徒新有口舌，若要徒就恶忍。"},"行人":{"解曰":"行人皆因身体有疾病阻隔，艰难跋涉，数年来财利阻涉，音信稀无，宜诚心向佛祖送经添油，候九、十月时，可有音信回家也。","签文":""},"婚姻":{"解曰":"","签文":"自古婚姻定良缘，此卦定卜财喜签，财喜登门有微阻，送经运至得团圆。婚姻之事定成宜送经添油至佛祖，可化凶为吉定卜财喜双至也"},"官讼":{"解曰":"官讼之卦的告诉，求释放以及犯官非欲逃避之事，逢凶化吉，兆人有望进，但破财，和之为贵；释者肖狗之油人无望，吉有胜但破财，总计向佛祖奉经添油，自出明镜可照，各分胜负也。","签文":""},"失物":{"解曰":"失物之事，宜寻之有回，定卜快向佛祖添油送经，寻路可逢凶化吉，有贵人扶助，定有分明也，失机会。","签文":""},"占病":{"解曰":"老男妇田气抽痛，血气孤衰宜调治；少壮男者是向佛祖火盛，少妇是产内风感面带黄，速调治之，向佛祖送经添油并求药服之轻愉。","签文":""},"其他":{"灶宅":"灶宅位分金地基合课益丁，但嫌灶灶污土，活并请佛祖香符，五谷水洗灶，可卜更旺也。","阳基":"新创阳基有小人阻，官忍性勿与他人斗争而取安定；老基戌亥方有峰杀冲伤，宜掩祭并修水道，居之财丁旺。","祖山":"贵祖龙运足旺，两水合欢，葬后财丁可兴旺，有十五年，但以后数年奔波不顺，是面前出水阳走，龙运脱，戌亥方有峰杀冲碍，有利宜修整合课，财丁兴旺。","子息":"子息之卦，肖猪犬者恐命带孤鸾，难得子；其余之人虽有子可得，但应向佛祖送经添油，保佑养育平安。","青草":"此地气脉足旺，初年定旺，财丁十五年后经修整又能兴旺；若不修整恐失财生灾，这是来水不美，戌亥方有峰杀冲碍，墓时宜理清水归源消掩峰杀，忍口舌吉。"}}'
);

